globalThis.__BQ = {"basitMakine":{"ilkokul":{"kolay":[{"q":"Bir taşı tek başına kaldıramayan çocuk, altına bir sopa koyup ucuna basarak kaldırıyor. Bu sopa ne işe yarar?","fig":"<svg viewBox='0 0 320 170'><polygon points='150,120 160,140 140,140' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='100' x2='280' y2='140' stroke='#1a2b45' stroke-width='5'/><rect x='45' y='80' width='26' height='20' fill='#8d6e63' stroke='#1a2b45'/><text x='58' y='74' font-size='11' text-anchor='middle' fill='#1a2b45'>taş</text><polygon points='265,150 255,165 275,165' fill='#e0552b'/><line x1='265' y1='115' x2='265' y2='150' stroke='#e0552b' stroke-width='2'/><text x='265' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>bas</text><text x='150' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>destek</text></svg>","steps":[{"t":"Sopa ne yapar","a":"işi kolaylaştırır","d":"Sopa, az kuvvetle ağır taşı kaldırmamızı sağlar."},{"t":"Adı nedir","a":"basit makine","d":"İşimizi kolaylaştıran bu tür araçlara basit makine denir."}],"ans":"Sopa bir basit makinedir; az kuvvetle ağır işi yapmamızı sağlar."},{"q":"Aşağıdaki araçlardan hangisi işimizi kolaylaştıran bir basit makinedir: makas, taş, bulut?","steps":[{"t":"Hangisi araç","a":"makas","d":"Makas, kağıdı kolayca kesmemizi sağlayan bir araçtır."},{"t":"Karar ver","a":"makas","d":"Taş ve bulut işimizi kolaylaştırmaz, makas ise bir basit makinedir."}],"ans":"Makas bir basit makinedir; kesme işini kolaylaştırır."},{"q":"Şekildeki kuyu makarasıyla su dolu kovayı yukarı çekerken kolu hangi yöne çekeriz?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='40' r='24' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='4' fill='#1a2b45'/><line x1='136' y1='40' x2='136' y2='150' stroke='#1a2b45' stroke-width='2'/><line x1='184' y1='40' x2='184' y2='120' stroke='#1a2b45' stroke-width='2'/><rect x='124' y='150' width='24' height='18' fill='#4aa3df' stroke='#1a2b45'/><text x='136' y='178' font-size='11' text-anchor='middle' fill='#1a2b45'>kova</text><polygon points='184,120 178,108 190,108' fill='#e0552b'/><text x='200' y='112' font-size='11' fill='#1a2b45'>aşağı çek</text></svg>","steps":[{"t":"Makara ne yapar","a":"yön değiştirir","d":"Makara, çektiğimiz yönü değiştirerek işi kolaylaştırır."},{"t":"İpi nasıl çekeriz","a":"aşağı","d":"İpi aşağı çekince kova yukarı çıkar."}],"ans":"İpi aşağı çekeriz; makara yönü değiştirdiği için kova yukarı çıkar."},{"q":"Bir bisiklette kullandığımız basit makine türü nedir: dişli mi yoksa kaldıraç mı?","steps":[{"t":"Bisiklette ne döner","a":"dişliler","d":"Bisikletin pedalı dişlilere bağlıdır ve zinciri çevirir."},{"t":"Adını söyle","a":"dişli","d":"Birbirine geçen dişli çarklar bir basit makinedir."}],"ans":"Bisiklette dişli adı verilen basit makine kullanılır."},{"q":"Ağır bir bavulu merdivenden taşımak yerine rampadan (eğimli yoldan) itmek neden daha kolaydır?","fig":"<svg viewBox='0 0 320 170'><line x1='30' y1='140' x2='290' y2='40' stroke='#1a2b45' stroke-width='4'/><line x1='30' y1='140' x2='290' y2='140' stroke='#1a2b45' stroke-width='2'/><rect x='110' y='95' width='28' height='22' fill='#8d6e63' stroke='#1a2b45' transform='rotate(-21 124 106)'/><text x='150' y='75' font-size='11' fill='#1a2b45'>bavul itilir</text><polygon points='175,82 188,80 182,92' fill='#e0552b'/><text x='160' y='158' font-size='11' text-anchor='middle' fill='#1a2b45'>eğik düzlem (rampa)</text></svg>","steps":[{"t":"Rampa ne yapar","a":"eğik düzlem","d":"Eğimli yol bir eğik düzlemdir, yükü yavaş yavaş yukarı çıkarır."},{"t":"Kuvvete etkisi","a":"daha az kuvvet","d":"Dik kaldırmak yerine itince daha az kuvvet harcarız."}],"ans":"Rampa bir eğik düzlemdir; az kuvvetle yükü yukarı çıkarmamızı sağlar."}],"zor":[{"q":"Şekildeki tahterevallide ağır arkadaş ortaya, hafif arkadaş uca oturursa hafif olan ağır olanı kaldırabilir mi?","fig":"<svg viewBox='0 0 320 170'><polygon points='160,120 172,142 148,142' fill='#5b6b85' stroke='#1a2b45'/><line x1='30' y1='90' x2='290' y2='150' stroke='#1a2b45' stroke-width='5'/><circle cx='55' cy='80' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='55' y='66' font-size='10' text-anchor='middle' fill='#1a2b45'>hafif</text><circle cx='200' cy='128' r='16' fill='#8d6e63' stroke='#1a2b45'/><text x='200' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>ağır</text><text x='160' y='158' font-size='10' text-anchor='middle' fill='#1a2b45'>destek</text></svg>","steps":[{"t":"Kol uzunluğu","a":"hafif uzak","d":"Hafif arkadaş destekten uzakta, ağır arkadaş yakındadır."},{"t":"Kaldıraç kuralı","a":"evet kaldırır","d":"Destekten uzakta olan az kuvvetle çok iş yapar, bu yüzden hafif olan ağırı kaldırabilir."}],"ans":"Evet; destekten uzaktaki hafif arkadaş, kaldıraç sayesinde ağır olanı kaldırabilir."},{"q":"Bir bayrağı direğin tepesine çekerken tepedeki makarayı kullanırız. Bu makara bize kuvvetten kazanç sağlar mı?","fig":"<svg viewBox='0 0 320 180'><line x1='120' y1='20' x2='120' y2='160' stroke='#1a2b45' stroke-width='3'/><circle cx='120' cy='28' r='12' fill='#cfd8dc' stroke='#1a2b45'/><line x1='108' y1='28' x2='108' y2='150' stroke='#e0552b' stroke-width='2'/><line x1='132' y1='28' x2='132' y2='90' stroke='#1a2b45' stroke-width='2'/><rect x='132' y='90' width='30' height='20' fill='#e0552b' stroke='#1a2b45'/><text x='147' y='124' font-size='10' text-anchor='middle' fill='#1a2b45'>bayrak</text><polygon points='108,150 102,138 114,138' fill='#e0552b'/><text x='80' y='120' font-size='10' text-anchor='middle' fill='#1a2b45'>aşağı çek</text></svg>","steps":[{"t":"Sabit makara","a":"yön değiştirir","d":"Tepedeki sabit makara çekiş yönünü değiştirir."},{"t":"Kuvvete etkisi","a":"kazanç yok","d":"Sabit makara kuvvetten kazanç sağlamaz, sadece aşağı çekmeyi kolaylaştırır."}],"ans":"Bu makara kuvvetten kazanç sağlamaz; sadece çekiş yönünü değiştirip işi kolaylaştırır."},{"q":"Şekildeki vida tahtaya kolayca girer. Vidayı bir basit makine türü olan nereden türetilmiş sayarız?","fig":"<svg viewBox='0 0 320 170'><polygon points='150,30 162,30 156,150' fill='#9aa6b8' stroke='#1a2b45'/><line x1='150' y1='45' x2='162' y2='52' stroke='#1a2b45'/><line x1='150' y1='62' x2='162' y2='69' stroke='#1a2b45'/><line x1='150' y1='79' x2='162' y2='86' stroke='#1a2b45'/><line x1='150' y1='96' x2='162' y2='103' stroke='#1a2b45'/><rect x='130' y='20' width='52' height='12' fill='#5b6b85' stroke='#1a2b45'/><text x='220' y='80' font-size='11' fill='#1a2b45'>vida = sarılı</text><text x='220' y='96' font-size='11' fill='#1a2b45'>eğik düzlem</text></svg>","steps":[{"t":"Vidanın dişleri","a":"sarmal yol","d":"Vidanın etrafındaki dişler, bir silindire sarılmış eğimli yol gibidir."},{"t":"Hangi makine","a":"eğik düzlem","d":"Bu yüzden vida, sarılmış bir eğik düzlem sayılır."}],"ans":"Vida, bir silindire sarılmış eğik düzlemdir."},{"q":"İki çocuk aynı ağır kutuyu kaldıracak. Biri kısa rampa, diğeri uzun rampa kullanıyor. Hangisi daha az kuvvet harcar?","fig":"<svg viewBox='0 0 320 170'><line x1='30' y1='130' x2='120' y2='60' stroke='#1a2b45' stroke-width='3'/><text x='70' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>kısa rampa</text><line x1='160' y1='130' x2='300' y2='70' stroke='#1a2b45' stroke-width='3'/><text x='230' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>uzun rampa</text><line x1='30' y1='130' x2='120' y2='130' stroke='#1a2b45' stroke-width='1'/><line x1='160' y1='130' x2='300' y2='130' stroke='#1a2b45' stroke-width='1'/></svg>","steps":[{"t":"Rampa boyu","a":"uzun yol","d":"Uzun rampada yük daha uzun ama daha az dik bir yol izler."},{"t":"Kuvvete etkisi","a":"az kuvvet","d":"Eğim azaldıkça gereken kuvvet de azalır."}],"ans":"Uzun rampayı kullanan çocuk daha az kuvvet harcar."},{"q":"Annemiz konserve kavanozun kapağını açmak için kapağa lastik tutaç takıyor. Bu neden işi kolaylaştırır?","steps":[{"t":"Tutaç ne sağlar","a":"daha geniş çevirme","d":"Tutaç kapağı çevirirken elimizin tuttuğu çevreyi genişletir."},{"t":"Sonuç","a":"az kuvvet","d":"Daha geniş yerden çevirince daha az kuvvetle kapağı döndürürüz."}],"ans":"Tutaç, çevirme kolunu uzatarak az kuvvetle kapağı açmamızı sağlar; bu da basit makine mantığıdır."}]},"ortaokul":{"kolay":[{"q":"Basit makineler işimizi hangi üç temel yoldan kolaylaştırabilir?","steps":[{"t":"İlk iki yol","a":"kuvvet ve yön","d":"Kuvvetten kazanç sağlayabilir ya da kuvvetin yönünü değiştirebilirler."},{"t":"Üçüncü yol","a":"yoldan kazanç","d":"Bazıları da yoldan (mesafeden) kazanç sağlar."}],"ans":"Basit makineler kuvvetten kazanç sağlayarak, kuvvetin yönünü değiştirerek veya yoldan kazanç sağlayarak işi kolaylaştırır."},{"q":"Şekildeki kaldıraçta destek noktasına göre yük ve kuvvet adlandırılır. Destek ne işe yarar?","fig":"<svg viewBox='0 0 320 160'><polygon points='150,100 162,122 138,122' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='80' x2='270' y2='110' stroke='#1a2b45' stroke-width='4'/><rect x='42' y='62' width='24' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='54' y='56' font-size='11' text-anchor='middle' fill='#1a2b45'>yük</text><polygon points='255,118 248,132 262,132' fill='#e0552b'/><line x1='255' y1='112' x2='255' y2='118' stroke='#e0552b' stroke-width='2'/><text x='255' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>kuvvet</text><text x='150' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>destek</text></svg>","steps":[{"t":"Destek nedir","a":"dönme noktası","d":"Destek, kaldıracın etrafında döndüğü sabit noktadır."},{"t":"İşlevi","a":"kuvvet kazancı","d":"Yük ve kuvvet kollarının uzunluğunu belirleyerek kuvvetten kazanç sağlamamızı düzenler."}],"ans":"Destek, kaldıracın döndüğü sabit noktadır; kuvvet ve yük kollarının uzunluğunu belirler."},{"q":"Sabit makara ile hareketli makara arasındaki temel fark nedir?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='20' x2='130' y2='20' stroke='#1a2b45' stroke-width='3'/><circle cx='70' cy='34' r='13' fill='#cfd8dc' stroke='#1a2b45'/><text x='70' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>sabit</text><line x1='57' y1='34' x2='57' y2='120' stroke='#e0552b' stroke-width='2'/><line x1='83' y1='34' x2='83' y2='90' stroke='#1a2b45' stroke-width='2'/><rect x='71' y='90' width='24' height='16' fill='#8d6e63'/><circle cx='220' cy='90' r='14' fill='#cfd8dc' stroke='#1a2b45'/><text x='220' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>hareketli</text><line x1='206' y1='90' x2='206' y2='25' stroke='#1a2b45' stroke-width='2'/><line x1='234' y1='90' x2='234' y2='25' stroke='#e0552b' stroke-width='2'/><rect x='208' y='104' width='24' height='16' fill='#8d6e63'/></svg>","steps":[{"t":"Sabit makara","a":"yön değiştirir","d":"Sabit makara bir yere asılıdır; sadece kuvvetin yönünü değiştirir, kazanç sağlamaz."},{"t":"Hareketli makara","a":"kuvvet yarıya","d":"Hareketli makara yükle birlikte hareket eder ve gereken kuvveti yarıya indirir."}],"ans":"Sabit makara sadece yön değiştirir; hareketli makara ise kuvvetten kazanç sağlayıp gereken kuvveti yarıya indirir."},{"q":"Basit makinelerde 'işten kazanç olmaz' ilkesi ne anlama gelir?","steps":[{"t":"Kuvvetten kazanç","a":"yoldan kayıp","d":"Bir basit makine kuvvetten kazandırırsa, o kadar da daha uzun yol aldırır."},{"t":"İş hesabı","a":"iş aynı","d":"Kuvvet × yol çarpımı (iş) değişmez, sadece kolaylaşır."}],"ans":"Basit makineler kuvvetten kazandırdığında yoldan kaybettirir; yapılan toplam iş değişmez, yani işten kazanç olmaz."},{"q":"Mekanik avantaj nedir ve neyi gösterir?","steps":[{"t":"Tanım","a":"yük / kuvvet","d":"Mekanik avantaj, kaldırılan yükün uyguladığımız kuvvete oranıdır."},{"t":"Anlamı","a":"kaç kat kolaylık","d":"Bu sayı, makinenin işimizi kaç kat kolaylaştırdığını gösterir."}],"ans":"Mekanik avantaj, yükün uygulanan kuvvete oranıdır ve makinenin işi kaç kat kolaylaştırdığını gösterir."}],"zor":[{"q":"Şekildeki çıkrıkta kol yarıçapı 30 cm, tambur (silindir) yarıçapı 10 cm ise mekanik avantaj kaçtır?","fig":"<svg viewBox='0 0 320 170'><circle cx='150' cy='80' r='40' fill='none' stroke='#1a2b45' stroke-width='2'/><circle cx='150' cy='80' r='14' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='80' x2='190' y2='80' stroke='#e0552b' stroke-width='2'/><text x='205' y='84' font-size='10' fill='#1a2b45'>kol 30 cm</text><line x1='150' y1='80' x2='150' y2='66' stroke='#1a2b45' stroke-width='2'/><text x='118' y='56' font-size='10' fill='#1a2b45'>tambur 10 cm</text><line x1='164' y1='80' x2='164' y2='150' stroke='#1a2b45' stroke-width='2'/><rect x='152' y='150' width='24' height='14' fill='#8d6e63'/></svg>","steps":[{"t":"Bağıntı","a":"kol/tambur","d":"Çıkrıkta mekanik avantaj, kol yarıçapının tambur yarıçapına oranıdır."},{"t":"Yerine koy","a":"30 ÷ 10","d":"Kol 30 cm, tambur 10 cm değerleri yerine konur."},{"t":"Sonuç","a":"3","d":"Bölme sonucu 3 bulunur."}],"ans":"Mekanik avantaj 3'tür; yani yükün üçte biri kadar kuvvet yeterlidir."},{"q":"Bir kaldıraçta yük kolu 20 cm, kuvvet kolu 60 cm. 90 N'luk yükü kaldırmak için gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 160'><polygon points='130,100 142,122 118,122' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='84' x2='290' y2='112' stroke='#1a2b45' stroke-width='4'/><rect x='95' y='66' width='22' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='106' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>90 N</text><text x='80' y='140' font-size='10' fill='#1a2b45'>yük kolu 20 cm</text><polygon points='275,120 268,134 282,134' fill='#e0552b'/><line x1='275' y1='112' x2='275' y2='120' stroke='#e0552b' stroke-width='2'/><text x='230' y='150' font-size='10' fill='#1a2b45'>kuvvet kolu 60 cm</text></svg>","steps":[{"t":"Denge bağıntısı","a":"yük×ykol = kuvvet×kkol","d":"Kaldıraçta yük ile yük kolu çarpımı, kuvvet ile kuvvet kolu çarpımına eşittir."},{"t":"Yerine koy","a":"90×20 = F×60","d":"90 N × 20 cm = F × 60 cm denklemi kurulur."},{"t":"Çöz","a":"1800 ÷ 60","d":"1800'ü 60'a böleriz."}],"ans":"Gereken kuvvet 30 N'dur."},{"q":"Hareketli makara kullanan bir kişi 200 N'luk yükü kaldırıyor. Sürtünme yoksa uyguladığı kuvvet kaç N'dur?","fig":"<svg viewBox='0 0 320 170'><line x1='60' y1='20' x2='140' y2='20' stroke='#1a2b45' stroke-width='3'/><circle cx='150' cy='90' r='18' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><line x1='132' y1='90' x2='100' y2='20' stroke='#1a2b45' stroke-width='2'/><line x1='168' y1='90' x2='200' y2='20' stroke='#e0552b' stroke-width='2'/><polygon points='200,20 194,32 206,32' fill='#e0552b'/><text x='215' y='40' font-size='10' fill='#1a2b45'>F=?</text><rect x='138' y='108' width='24' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='150' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>200 N</text></svg>","steps":[{"t":"Hareketli makara","a":"kuvvet yarıya","d":"Tek hareketli makara, gereken kuvveti yükün yarısına indirir."},{"t":"Hesapla","a":"200 ÷ 2","d":"Yük 200 N olduğundan kuvvet 200 ÷ 2 olarak bulunur."}],"ans":"Uygulanan kuvvet 100 N'dur (yükün yarısı)."},{"q":"Boyu 4 m olan eğik düzlemin yüksekliği 1 m. Mekanik avantajı bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='30' y1='130' x2='290' y2='50' stroke='#1a2b45' stroke-width='4'/><line x1='30' y1='130' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><line x1='290' y1='50' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><text x='150' y='80' font-size='11' fill='#1a2b45'>eğik boy 4 m</text><text x='296' y='95' font-size='11' fill='#1a2b45'>1 m</text></svg>","steps":[{"t":"Bağıntı","a":"boy/yükseklik","d":"Eğik düzlemde mekanik avantaj, eğik boyun yüksekliğe oranıdır."},{"t":"Yerine koy","a":"4 ÷ 1","d":"Eğik boy 4 m, yükseklik 1 m değerleri yerine konur."},{"t":"Sonuç","a":"4","d":"Bölme sonucu 4 bulunur."}],"ans":"Mekanik avantaj 4'tür; yükün dörtte biri kadar kuvvetle yük yukarı çıkarılabilir."},{"q":"Bir kaldıraçla 50 N kuvvet uygulayarak 150 N'luk yükü kaldıran kişi, kuvveti 60 cm aşağı indirdiğinde yük kaç cm yükselir?","steps":[{"t":"İşten kazanç yok","a":"iş eşit","d":"Kuvvetin yaptığı iş, yükün yaptığı işe eşittir: kuvvet×yol = yük×yol."},{"t":"Denklemi kur","a":"50×60 = 150×h","d":"50 N × 60 cm = 150 N × h denklemi yazılır."},{"t":"Çöz","a":"3000 ÷ 150","d":"3000'i 150'ye böleriz."}],"ans":"Yük 20 cm yükselir; kuvvetten kazanılan, yoldan kaybedilir."}]},"lise":{"kolay":[{"q":"Basit makinelerin temel tanımı nedir ve neyi değiştiremezler?","steps":[{"t":"Tanım","a":"iş kolaylaştırıcı","d":"Basit makineler, uygulanan kuvvetin büyüklüğünü veya yönünü değiştirerek işi kolaylaştıran araçlardır."},{"t":"Değiştiremedikleri","a":"toplam iş","d":"Yapılan toplam işi (enerjiyi) artıramaz veya azaltamazlar."}],"ans":"Basit makineler kuvvetin büyüklüğünü veya yönünü değiştirir; ancak yapılan toplam işi değiştiremezler."},{"q":"Mekanik avantaj (MA) nasıl tanımlanır ve MA > 1 ne anlama gelir?","steps":[{"t":"Tanım","a":"yük / kuvvet","d":"Mekanik avantaj, yük kuvvetinin uygulanan kuvvete oranıdır: MA = Fyük / Fkuvvet."},{"t":"MA > 1 anlamı","a":"kuvvetten kazanç","d":"MA birden büyükse, yükten daha az kuvvet uygulanmış demektir; yani kuvvetten kazanç vardır."}],"ans":"Mekanik avantaj MA = yük/kuvvet'tir; MA > 1 ise kuvvetten kazanç sağlanmıştır."},{"q":"Şekildeki I. tip kaldıraçta destek, yük ile kuvvet arasındadır. Bu tipe günlük hayattan iki örnek veriniz.","fig":"<svg viewBox='0 0 320 150'><polygon points='160,95 172,117 148,117' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='80' x2='280' y2='110' stroke='#1a2b45' stroke-width='4'/><rect x='44' y='62' width='22' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='55' y='56' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text><polygon points='268,118 261,132 275,132' fill='#e0552b'/><text x='268' y='146' font-size='10' text-anchor='middle' fill='#1a2b45'>kuvvet</text><text x='160' y='134' font-size='10' text-anchor='middle' fill='#1a2b45'>destek</text></svg>","steps":[{"t":"Tip özelliği","a":"destek ortada","d":"I. tip kaldıraçta destek, yük ile kuvvetin arasındadır."},{"t":"Örnekler","a":"tahterevalli, makas","d":"Tahterevalli ve makas bu tipe örnektir."}],"ans":"I. tip kaldıraca tahterevalli ve makas örnek verilebilir; destek ortadadır."},{"q":"Kuvvet kolu 80 cm, yük kolu 20 cm olan kaldıracın mekanik avantajını bulunuz.","fig":"<svg viewBox='0 0 320 150'><polygon points='110,95 122,117 98,117' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='86' x2='290' y2='106' stroke='#1a2b45' stroke-width='4'/><rect x='62' y='68' width='22' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='73' y='62' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text><text x='62' y='138' font-size='10' fill='#1a2b45'>yük kolu 20 cm</text><polygon points='278,112 271,126 285,126' fill='#e0552b'/><text x='220' y='138' font-size='10' fill='#1a2b45'>kuvvet kolu 80 cm</text></svg>","steps":[{"t":"Bağıntı","a":"kuvvet kolu/yük kolu","d":"Kaldıraçta mekanik avantaj, kuvvet kolunun yük koluna oranına eşittir."},{"t":"Yerine koy","a":"80 ÷ 20","d":"Kuvvet kolu 80 cm, yük kolu 20 cm yerine konur."},{"t":"Sonuç","a":"4","d":"Bölme sonucu 4 bulunur."}],"ans":"Mekanik avantaj 4'tür."},{"q":"Tek hareketli makaranın ideal mekanik avantajı neden 2'dir?","fig":"<svg viewBox='0 0 320 170'><line x1='60' y1='18' x2='140' y2='18' stroke='#1a2b45' stroke-width='3'/><circle cx='150' cy='90' r='18' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><line x1='132' y1='90' x2='100' y2='18' stroke='#1a2b45' stroke-width='2'/><text x='90' y='60' font-size='10' fill='#1a2b45'>ip 1</text><line x1='168' y1='90' x2='200' y2='18' stroke='#e0552b' stroke-width='2'/><text x='205' y='40' font-size='10' fill='#1a2b45'>F</text><rect x='138' y='108' width='24' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='150' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text></svg>","steps":[{"t":"İp sayısı","a":"yükü iki ip taşır","d":"Hareketli makarada yük iki ip kolu tarafından taşınır."},{"t":"Kuvvet bölünür","a":"MA = 2","d":"Yük iki ipe paylaştığından gereken kuvvet yarıya iner, mekanik avantaj 2 olur."}],"ans":"Yükü iki ip kolu taşıdığı için kuvvet yarıya iner; ideal mekanik avantaj 2'dir."},{"q":"Bir eğik düzlemde mekanik avantaj hangi iki uzunluğun oranıyla bulunur?","steps":[{"t":"Uzunluklar","a":"boy ve yükseklik","d":"Eğik düzlemin eğik boyu ile dikey yüksekliği kullanılır."},{"t":"Bağıntı","a":"boy / yükseklik","d":"İdeal mekanik avantaj, eğik boyun yüksekliğe oranıdır."}],"ans":"Eğik düzlemde mekanik avantaj = eğik boy ÷ yükseklik bağıntısıyla bulunur."},{"q":"Basit makinelerde verim neden hiçbir zaman %100 olamaz?","steps":[{"t":"İdeal durum","a":"sürtünmesiz","d":"Sürtünme olmasaydı verilen iş, alınan işe eşit olur ve verim %100 olurdu."},{"t":"Gerçek durum","a":"sürtünme kaybı","d":"Gerçekte sürtünme ve parça ağırlığı bir miktar enerjiyi ısıya çevirir."}],"ans":"Sürtünme ve diğer kayıplar enerjinin bir kısmını ısıya çevirdiği için verim her zaman %100'ün altındadır."},{"q":"Şekildeki vidanın adımı (bir turda ilerlediği mesafe) 2 mm, tornavida kolunun çevrelediği yol 60 mm ise mekanik avantaj kaçtır?","fig":"<svg viewBox='0 0 320 160'><circle cx='110' cy='80' r='45' fill='none' stroke='#1a2b45' stroke-width='2'/><line x1='110' y1='80' x2='155' y2='80' stroke='#e0552b' stroke-width='2'/><text x='118' y='72' font-size='9' fill='#1a2b45'>çevre 60 mm</text><polygon points='225,40 237,40 231,140' fill='#9aa6b8' stroke='#1a2b45'/><line x1='225' y1='60' x2='237' y2='66' stroke='#1a2b45'/><line x1='225' y1='80' x2='237' y2='86' stroke='#1a2b45'/><text x='250' y='95' font-size='9' fill='#1a2b45'>adım 2 mm</text></svg>","steps":[{"t":"Bağıntı","a":"çevre yol / adım","d":"Vidada mekanik avantaj, kolun bir turda çizdiği çevre yolun vida adımına oranıdır."},{"t":"Yerine koy","a":"60 ÷ 2","d":"Çevre yol 60 mm, adım 2 mm değerleri yerine konur."},{"t":"Sonuç","a":"30","d":"Bölme sonucu 30 bulunur."}],"ans":"Mekanik avantaj 30'dur; bu yüzden vida çok yüksek kuvvet kazancı sağlar."},{"q":"İki dişliden büyük olanın 40 dişi, küçük olanın 10 dişi var. Büyük dişlinin küçüğe göre devir (dönme hızı) oranı nedir?","fig":"<svg viewBox='0 0 320 160'><circle cx='110' cy='80' r='45' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><text x='110' y='84' font-size='11' text-anchor='middle' fill='#1a2b45'>40 diş</text><circle cx='205' cy='80' r='22' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><text x='205' y='84' font-size='10' text-anchor='middle' fill='#1a2b45'>10 diş</text></svg>","steps":[{"t":"Diş ilişkisi","a":"diş çarpımı eşit","d":"Birbirine geçen dişlilerde diş sayısı × devir çarpımı eşittir."},{"t":"Oranı kur","a":"40/10 ters","d":"Büyük dişli yavaş döner; devir oranı diş sayısıyla ters orantılıdır."},{"t":"Sonuç","a":"1/4","d":"Büyük dişli, küçüğün dörtte biri hızla döner."}],"ans":"Büyük dişli, küçük dişlinin dörtte biri kadar hızla döner (devir oranı 1/4)."},{"q":"Bir kaldıraçta 100 N'luk yük, kuvvet kolu 50 cm ve yük kolu 25 cm ile dengeleniyor. Uygulanan kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 150'><polygon points='130,95 142,117 118,117' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='84' x2='290' y2='108' stroke='#1a2b45' stroke-width='4'/><rect x='86' y='66' width='22' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='97' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>100 N</text><text x='78' y='138' font-size='9' fill='#1a2b45'>25 cm</text><polygon points='278,114 271,128 285,128' fill='#e0552b'/><text x='235' y='138' font-size='9' fill='#1a2b45'>50 cm</text></svg>","steps":[{"t":"Denge bağıntısı","a":"yük×ykol = F×kkol","d":"Kaldıraç dengesinde yük ile yük kolunun çarpımı, kuvvet ile kuvvet kolunun çarpımına eşittir."},{"t":"Yerine koy","a":"100×25 = F×50","d":"100 N × 25 cm = F × 50 cm denklemi kurulur."},{"t":"Çöz","a":"2500 ÷ 50","d":"2500'ü 50'ye böleriz."}],"ans":"Uygulanan kuvvet 50 N'dur."},{"q":"Eğik düzlemde 'işten kazanç yoktur' ilkesi yük ve mesafe açısından nasıl açıklanır?","steps":[{"t":"Kuvvetten kazanç","a":"az kuvvet","d":"Eğik düzlem dik kaldırmaya göre daha az kuvvet gerektirir."},{"t":"Yoldan kayıp","a":"uzun yol","d":"Ancak yük, yüksekliğe göre çok daha uzun bir yol kateder."},{"t":"İş eşitliği","a":"iş aynı","d":"Kuvvet × eğik boy = yük × yükseklik olduğundan toplam iş değişmez."}],"ans":"Eğik düzlemde az kuvvet uygulanır ama yol uzar; kuvvet×yol çarpımı sabit kaldığından işten kazanç olmaz."},{"q":"II. tip kaldıraçta (yük ortada) mekanik avantaj neden her zaman 1'den büyüktür?","fig":"<svg viewBox='0 0 320 150'><polygon points='44,96 56,118 32,118' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='96' x2='290' y2='96' stroke='#1a2b45' stroke-width='4'/><rect x='150' y='78' width='22' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='161' y='72' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text><polygon points='280,82 273,96 287,96' fill='#e0552b'/><line x1='280' y1='76' x2='280' y2='82' stroke='#e0552b' stroke-width='2'/><text x='280' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>kuvvet</text><text x='48' y='138' font-size='10' fill='#1a2b45'>destek</text></svg>","steps":[{"t":"Kol uzunlukları","a":"kuvvet kolu uzun","d":"Yük ortada olduğundan kuvvet kolu, yük kolundan her zaman uzundur."},{"t":"MA sonucu","a":"MA > 1","d":"Mekanik avantaj kuvvet kolu/yük kolu olduğundan bu oran daima 1'den büyük çıkar."}],"ans":"Yük ortada olunca kuvvet kolu yük kolundan uzun olur; bu yüzden II. tip kaldıraçta MA daima 1'den büyüktür (el arabası gibi)."},{"q":"Çıkrıkta kol yarıçapı 50 cm, tambur yarıçapı 10 cm ise 40 N kuvvetle kaç N'luk yük kaldırılır?","fig":"<svg viewBox='0 0 320 160'><circle cx='150' cy='80' r='45' fill='none' stroke='#1a2b45' stroke-width='2'/><circle cx='150' cy='80' r='12' fill='#cfd8dc' stroke='#1a2b45'/><line x1='150' y1='80' x2='195' y2='80' stroke='#e0552b' stroke-width='2'/><text x='200' y='84' font-size='9' fill='#1a2b45'>50 cm</text><line x1='150' y1='80' x2='150' y2='68' stroke='#1a2b45' stroke-width='2'/><text x='120' y='56' font-size='9' fill='#1a2b45'>10 cm</text><line x1='162' y1='80' x2='162' y2='150' stroke='#1a2b45' stroke-width='2'/><rect x='150' y='150' width='24' height='12' fill='#8d6e63'/></svg>","steps":[{"t":"Mekanik avantaj","a":"50 ÷ 10 = 5","d":"Çıkrıkta MA, kol yarıçapının tambur yarıçapına oranıdır."},{"t":"Yükü bul","a":"yük = MA × kuvvet","d":"Yük = mekanik avantaj × uygulanan kuvvet = 5 × 40 N'dur."},{"t":"Sonuç","a":"200 N","d":"Çarpım sonucu 200 N bulunur."}],"ans":"40 N kuvvetle 200 N'luk yük kaldırılır."},{"q":"Bir el arabası bir kaldıraç türüdür; tekerleği destek, yük ortada, kollar uçtadır. Bu hangi tip kaldıraçtır?","fig":"<svg viewBox='0 0 320 160'><circle cx='60' cy='110' r='22' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><circle cx='60' cy='110' r='4' fill='#1a2b45'/><line x1='60' y1='95' x2='270' y2='60' stroke='#1a2b45' stroke-width='4'/><rect x='150' y='66' width='26' height='20' fill='#8d6e63' stroke='#1a2b45'/><text x='163' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text><polygon points='268,55 280,52 274,66' fill='#e0552b'/><text x='250' y='42' font-size='10' fill='#1a2b45'>kuvvet</text><text x='60' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>destek (teker)</text></svg>","steps":[{"t":"Sıralamaya bak","a":"yük ortada","d":"Destek bir uçta (teker), kuvvet diğer uçta, yük ise ikisinin arasındadır."},{"t":"Tipi belirle","a":"II. tip","d":"Yükün ortada olduğu kaldıraçlar II. tip kaldıraçtır."}],"ans":"El arabası, yükün ortada olduğu II. tip kaldıraçtır."},{"q":"Basit makineler altı temel tipe ayrılır. Bunları sayınız.","steps":[{"t":"İlk üçü","a":"kaldıraç, makara, eğik düzlem","d":"Kaldıraç, makara ve eğik düzlem en temel basit makinelerdir."},{"t":"Diğer üçü","a":"vida, çıkrık, dişli","d":"Vida, çıkrık (kollu döner mil) ve dişli de basit makine çeşitleridir."}],"ans":"Altı temel basit makine: kaldıraç, makara, eğik düzlem, vida, çıkrık ve dişlidir."}],"zor":[{"q":"Bir eğik düzlemin boyu 6 m, yüksekliği 1,5 m. Sürtünme yokken 300 N'luk yükü çıkarmak için gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='30' y1='130' x2='290' y2='45' stroke='#1a2b45' stroke-width='4'/><line x1='30' y1='130' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><line x1='290' y1='45' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><rect x='120' y='80' width='26' height='20' fill='#8d6e63' stroke='#1a2b45' transform='rotate(-18 133 90)'/><text x='130' y='70' font-size='10' fill='#1a2b45'>300 N</text><text x='150' y='128' font-size='10' fill='#1a2b45'>boy 6 m</text><text x='296' y='90' font-size='10' fill='#1a2b45'>1,5 m</text></svg>","steps":[{"t":"İşten kazanç yok","a":"F×boy = yük×yükseklik","d":"Sürtünmesiz eğik düzlemde kuvvet × eğik boy, yük × yükseklik çarpımına eşittir."},{"t":"Denklemi kur","a":"F×6 = 300×1,5","d":"F × 6 m = 300 N × 1,5 m denklemi yazılır."},{"t":"Çöz","a":"450 ÷ 6","d":"300 × 1,5 = 450, sonra 450'yi 6'ya böleriz."}],"ans":"Gereken kuvvet 75 N'dur."},{"q":"İki hareketli ve bir sabit makaradan oluşan palanga ile 600 N yük kaldırılıyor. Yükü 4 ip kolu taşıdığına göre uygulanan kuvvet kaç N'dur?","fig":"<svg viewBox='0 0 320 180'><line x1='90' y1='18' x2='230' y2='18' stroke='#1a2b45' stroke-width='3'/><circle cx='130' cy='40' r='13' fill='#cfd8dc' stroke='#1a2b45'/><circle cx='190' cy='40' r='13' fill='#cfd8dc' stroke='#1a2b45'/><circle cx='160' cy='110' r='16' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><line x1='117' y1='40' x2='147' y2='110' stroke='#1a2b45'/><line x1='143' y1='40' x2='160' y2='95' stroke='#1a2b45'/><line x1='177' y1='40' x2='173' y2='110' stroke='#1a2b45'/><line x1='203' y1='40' x2='230' y2='150' stroke='#e0552b' stroke-width='2'/><text x='240' y='150' font-size='10' fill='#1a2b45'>F=?</text><rect x='148' y='128' width='24' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='160' y='162' font-size='10' text-anchor='middle' fill='#1a2b45'>600 N</text></svg>","steps":[{"t":"Mekanik avantaj","a":"ip sayısı = 4","d":"Yükü taşıyan ip kolu sayısı palanganın mekanik avantajını verir; burada 4'tür."},{"t":"Kuvveti bul","a":"600 ÷ 4","d":"Uygulanan kuvvet = yük ÷ mekanik avantaj = 600 N ÷ 4'tür."},{"t":"Sonuç","a":"150 N","d":"Bölme sonucu 150 N bulunur."}],"ans":"Uygulanan kuvvet 150 N'dur."},{"q":"Mekanik avantajı 3 olan bir kaldıraçta yük 5 cm yükseliyor. Kuvvet noktası kaç cm yer değiştirir?","steps":[{"t":"İşten kazanç yok","a":"F×yol = yük×h","d":"Kaldıraçta kuvvetin yaptığı iş yükün yaptığı işe eşittir."},{"t":"MA ilişkisi","a":"yol oranı = MA","d":"Mekanik avantaj kadar kuvvetten kazanılınca, kuvvet noktası o kadar daha fazla yol alır."},{"t":"Hesapla","a":"3 × 5","d":"Kuvvet yolu = MA × yük yolu = 3 × 5 cm'dir."}],"ans":"Kuvvet noktası 15 cm yer değiştirir; kuvvetten kazanılan, yoldan kaybedilir."},{"q":"Verimi %80 olan bir eğik düzlemde 2 m yüksekliğe 500 N'luk yük çıkarmak için 6 m'lik düzlemde gerçekte ne kadar kuvvet uygulanır?","fig":"<svg viewBox='0 0 320 160'><line x1='30' y1='130' x2='290' y2='50' stroke='#1a2b45' stroke-width='4'/><line x1='30' y1='130' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><line x1='290' y1='50' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><text x='150' y='82' font-size='10' fill='#1a2b45'>boy 6 m</text><text x='296' y='92' font-size='10' fill='#1a2b45'>2 m</text><text x='60' y='124' font-size='10' fill='#1a2b45'>verim %80</text></svg>","steps":[{"t":"Faydalı iş","a":"yük×yükseklik","d":"Çıkarılması gereken faydalı iş = 500 N × 2 m = 1000 J'dür."},{"t":"Verilen iş","a":"faydalı/verim","d":"Verim %80 olduğundan verilen iş = 1000 ÷ 0,8 = 1250 J olur."},{"t":"Kuvveti bul","a":"1250 ÷ 6","d":"Verilen iş = F × eğik boy olduğundan F = 1250 J ÷ 6 m'dir."}],"ans":"Gerçekte uygulanan kuvvet yaklaşık 208,3 N'dur (sürtünme kayıpları nedeniyle ideal değerden büyüktür)."},{"q":"Diş sayıları 60 ve 20 olan iki dişliden küçük olan motora bağlı ve 300 devir/dakika dönüyor. Büyük dişli kaç devir/dakika döner?","fig":"<svg viewBox='0 0 320 160'><circle cx='110' cy='80' r='48' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><text x='110' y='84' font-size='11' text-anchor='middle' fill='#1a2b45'>60 diş</text><circle cx='205' cy='80' r='22' fill='#cfd8dc' stroke='#1a2b45' stroke-width='2'/><text x='205' y='84' font-size='9' text-anchor='middle' fill='#1a2b45'>20 diş</text><text x='205' y='120' font-size='9' text-anchor='middle' fill='#1a2b45'>300 d/dk</text></svg>","steps":[{"t":"Bağıntı","a":"diş×devir eşit","d":"Birbirine geçen dişlilerde diş sayısı × devir çarpımı her iki dişli için eşittir."},{"t":"Denklemi kur","a":"60×n = 20×300","d":"60 × büyük dişli devri = 20 × 300 denklemi yazılır."},{"t":"Çöz","a":"6000 ÷ 60","d":"20 × 300 = 6000, sonra 6000'i 60'a böleriz."}],"ans":"Büyük dişli 100 devir/dakika döner."},{"q":"Bir kaldıraçta 40 N kuvvetle 160 N yük dengeleniyor. Kuvvet kolu 1 m ise yük kolu kaç cm'dir?","fig":"<svg viewBox='0 0 320 150'><polygon points='200,95 212,117 188,117' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='110' x2='290' y2='84' stroke='#1a2b45' stroke-width='4'/><rect x='235' y='66' width='22' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='246' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>160 N</text><text x='225' y='138' font-size='9' fill='#1a2b45'>yük kolu=?</text><polygon points='55,116 48,130 62,130' fill='#e0552b'/><text x='90' y='138' font-size='9' fill='#1a2b45'>kuvvet kolu 1 m, 40 N</text></svg>","steps":[{"t":"Denge bağıntısı","a":"F×kkol = yük×ykol","d":"Kuvvet × kuvvet kolu, yük × yük koluna eşittir."},{"t":"Yerine koy","a":"40×100 = 160×ykol","d":"1 m = 100 cm alınır; 40 N × 100 cm = 160 N × ykol yazılır."},{"t":"Çöz","a":"4000 ÷ 160","d":"4000'i 160'a böleriz."}],"ans":"Yük kolu 25 cm'dir."},{"q":"Bir vidanın adımı 4 mm, döndürme kolunun yarıçapı 20 cm. Sürtünmesiz mekanik avantajını bulunuz.","steps":[{"t":"Çevre yolu hesapla","a":"2πr","d":"Kol bir turda 2π × 20 cm = yaklaşık 125,6 cm, yani 1256 mm yol çizer."},{"t":"Bağıntı","a":"çevre / adım","d":"Vidada mekanik avantaj, kolun çevre yolunun vida adımına oranıdır."},{"t":"Hesapla","a":"1256 ÷ 4","d":"1256 mm'yi 4 mm'ye böleriz."}],"ans":"Mekanik avantaj yaklaşık 314'tür; vida çok büyük kuvvet kazancı sağlar."},{"q":"Şekildeki sistemde sabit ve hareketli makara birlikte kullanılıyor. Hareketli makaranın kuvvetten, sabit makaranın ise neden kazanç sağlamadığını açıklayınız.","fig":"<svg viewBox='0 0 320 180'><line x1='60' y1='18' x2='200' y2='18' stroke='#1a2b45' stroke-width='3'/><circle cx='90' cy='38' r='13' fill='#cfd8dc' stroke='#1a2b45'/><text x='90' y='66' font-size='9' text-anchor='middle' fill='#1a2b45'>sabit</text><circle cx='180' cy='110' r='16' fill='#cfd8dc' stroke='#1a2b45'/><text x='180' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>hareketli</text><line x1='166' y1='110' x2='150' y2='18' stroke='#1a2b45'/><line x1='194' y1='110' x2='103' y2='38' stroke='#1a2b45'/><line x1='77' y1='38' x2='77' y2='150' stroke='#e0552b' stroke-width='2'/><polygon points='77,150 71,138 83,138' fill='#e0552b'/><text x='45' y='120' font-size='9' fill='#1a2b45'>F çek</text><rect x='168' y='128' width='24' height='16' fill='#8d6e63'/></svg>","steps":[{"t":"Hareketli makara","a":"yük iki ipte","d":"Hareketli makarada yük iki ip kolu tarafından taşınır, bu yüzden kuvvet yarıya iner ve MA = 2 olur."},{"t":"Sabit makara","a":"tek ip, MA=1","d":"Sabit makarada yükü tek ip taşır; gereken kuvvet değişmez, sadece yön ters çevrilir."},{"t":"Birleşik etki","a":"toplam MA","d":"Sistemin toplam mekanik avantajı, kuvvet kazancını sağlayan hareketli makaradan gelir."}],"ans":"Hareketli makara yükü iki ipe paylaştırıp MA=2 sağlar; sabit makara yükü tek iple taşıdığından MA=1'dir, sadece çekiş yönünü değiştirir."},{"q":"İdeal mekanik avantajı 5 olan bir makinede gerçek mekanik avantaj 4 ölçülüyor. Bu makinenin verimini bulunuz.","steps":[{"t":"Verim tanımı","a":"GMA / İMA","d":"Verim, gerçek mekanik avantajın ideal mekanik avantaja oranına eşittir."},{"t":"Yerine koy","a":"4 ÷ 5","d":"Gerçek MA = 4, ideal MA = 5 değerleri yerine konur."},{"t":"Yüzdeye çevir","a":"0,8 → %80","d":"0,8 değeri yüzdeye çevrilir."}],"ans":"Makinenin verimi %80'dir."},{"q":"6 m boyundaki eğik düzlemden 400 N yük 2 m yüksekliğe çıkarılıyor. Eğik düzlem boyunca uygulanan gerçek kuvvet 160 N ise verimi bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='30' y1='130' x2='290' y2='50' stroke='#1a2b45' stroke-width='4'/><line x1='30' y1='130' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><line x1='290' y1='50' x2='290' y2='130' stroke='#1a2b45' stroke-width='2'/><rect x='120' y='82' width='24' height='18' fill='#8d6e63' stroke='#1a2b45' transform='rotate(-17 132 91)'/><text x='128' y='72' font-size='10' fill='#1a2b45'>400 N</text><text x='150' y='128' font-size='10' fill='#1a2b45'>boy 6 m</text><text x='296' y='92' font-size='10' fill='#1a2b45'>2 m</text></svg>","steps":[{"t":"Faydalı iş","a":"400×2 = 800 J","d":"Faydalı iş, yükün ağırlığı ile yüksekliğin çarpımıdır: 400 N × 2 m."},{"t":"Verilen iş","a":"160×6 = 960 J","d":"Verilen iş, uygulanan gerçek kuvvet ile eğik boyun çarpımıdır: 160 N × 6 m."},{"t":"Verimi bul","a":"800 ÷ 960","d":"Faydalı işi verilen işe böleriz."}],"ans":"Verim yaklaşık %83,3'tür; aradaki kayıp sürtünmeden kaynaklanır."},{"q":"Bir kaldıraçta hem kuvvetten kazanmak istiyoruz hem de kuvvetin yönünü ters çevirmek. Hangi kaldıraç tipi seçilmeli ve neden?","fig":"<svg viewBox='0 0 320 150'><polygon points='160,95 172,117 148,117' fill='#5b6b85' stroke='#1a2b45'/><line x1='40' y1='80' x2='280' y2='110' stroke='#1a2b45' stroke-width='4'/><rect x='44' y='62' width='22' height='18' fill='#8d6e63' stroke='#1a2b45'/><text x='55' y='56' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text><polygon points='268,118 261,132 275,132' fill='#e0552b'/><text x='268' y='146' font-size='10' text-anchor='middle' fill='#1a2b45'>kuvvet</text><text x='150' y='134' font-size='10' text-anchor='middle' fill='#1a2b45'>destek ortada</text></svg>","steps":[{"t":"Yön değişimi","a":"destek ortada","d":"Kuvvetin yönünü ters çevirmek için destek, yük ile kuvvet arasında olmalıdır; bu I. tip kaldıraçtır."},{"t":"Kuvvet kazancı","a":"kuvvet kolu uzun","d":"Kuvvetten kazanmak için kuvvet kolu, yük kolundan uzun seçilmelidir, böylece MA > 1 olur."}],"ans":"I. tip kaldıraç seçilmelidir; destek ortada olduğu için yön ters çevrilir, kuvvet kolu yük kolundan uzun yapılırsa kuvvetten de kazanılır."},{"q":"Bir çıkrıkta kol yarıçapı 40 cm, tambur yarıçapı 8 cm. Verim %75 ise 250 N'luk yükü kaldırmak için gereken gerçek kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='150' cy='80' r='45' fill='none' stroke='#1a2b45' stroke-width='2'/><circle cx='150' cy='80' r='10' fill='#cfd8dc' stroke='#1a2b45'/><line x1='150' y1='80' x2='195' y2='80' stroke='#e0552b' stroke-width='2'/><text x='200' y='84' font-size='9' fill='#1a2b45'>40 cm</text><line x1='150' y1='80' x2='150' y2='70' stroke='#1a2b45' stroke-width='2'/><text x='120' y='58' font-size='9' fill='#1a2b45'>8 cm</text><line x1='160' y1='80' x2='160' y2='150' stroke='#1a2b45' stroke-width='2'/><rect x='148' y='150' width='24' height='12' fill='#8d6e63'/><text x='60' y='140' font-size='9' fill='#1a2b45'>verim %75</text></svg>","steps":[{"t":"İdeal MA","a":"40 ÷ 8 = 5","d":"İdeal mekanik avantaj, kol yarıçapının tambur yarıçapına oranıdır."},{"t":"İdeal kuvvet","a":"250 ÷ 5 = 50 N","d":"Sürtünmesiz durumda gereken kuvvet, yükün mekanik avantaja bölümüdür."},{"t":"Verimle düzelt","a":"50 ÷ 0,75","d":"Verim %75 olduğundan gerçek kuvvet = ideal kuvvet ÷ verim'dir."}],"ans":"Gereken gerçek kuvvet yaklaşık 66,7 N'dur."},{"q":"Vida ve eğik düzlem arasındaki ilişki nedir, vidanın yüksek mekanik avantajı nereden gelir?","steps":[{"t":"Vidanın yapısı","a":"sarılı eğik düzlem","d":"Vida, bir silindirin etrafına sarılmış bir eğik düzlemdir; dişler bu sarmal yolu oluşturur."},{"t":"Adım ve çevre","a":"uzun yol, kısa adım","d":"Kol bir turda büyük bir çevre yolu çizerken vida çok kısa bir adım ilerler."},{"t":"MA kaynağı","a":"çevre/adım büyük","d":"Çevre yolun adıma oranı çok büyük olduğundan mekanik avantaj yüksektir."}],"ans":"Vida, sarılmış bir eğik düzlemdir; kolun çizdiği uzun çevre yolun çok küçük vida adımına oranı büyük olduğu için yüksek mekanik avantaj sağlar."},{"q":"İki tip kaldıraçta da kuvvet kolu 3 birim, yük kolu 1 birim. I. tip ile II. tip arasında mekanik avantaj açısından fark var mıdır, açıklayınız.","steps":[{"t":"MA tanımı","a":"kuvvet kolu/yük kolu","d":"Her iki tipte de mekanik avantaj, kuvvet kolunun yük koluna oranıyla hesaplanır."},{"t":"Sayısal sonuç","a":"3 ÷ 1 = 3","d":"Kol uzunlukları aynı olduğundan iki tipte de mekanik avantaj 3 çıkar."},{"t":"Tek fark","a":"kuvvet yönü","d":"Mekanik avantaj eşittir; tek fark, I. tipte kuvvetin yönü terstir, II. tipte aynı yöndedir."}],"ans":"Mekanik avantaj iki tipte de eşittir (3); fark sadece kuvvetin yönündedir: I. tipte yön ters çevrilir, II. tipte değişmez."},{"q":"Şekildeki düzenekte 12 m'lik eğik düzlemin tepesine 600 N yük çıkarmak yerine, aynı yüksekliğe (3 m) makarayla dik kaldırma yapılsaydı yapılan iş değişir miydi?","fig":"<svg viewBox='0 0 320 170'><line x1='30' y1='140' x2='250' y2='50' stroke='#1a2b45' stroke-width='4'/><line x1='30' y1='140' x2='250' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='250' y1='50' x2='250' y2='140' stroke='#1a2b45' stroke-width='2'/><text x='130' y='88' font-size='10' fill='#1a2b45'>eğik 12 m</text><text x='256' y='98' font-size='10' fill='#1a2b45'>3 m</text><circle cx='285' cy='40' r='11' fill='#cfd8dc' stroke='#1a2b45'/><line x1='276' y1='40' x2='276' y2='110' stroke='#e0552b' stroke-width='2'/><text x='292' y='80' font-size='9' fill='#1a2b45'>dik</text></svg>","steps":[{"t":"Eğik düzlemde iş","a":"yük×yükseklik","d":"Eğik düzlemde de dik kaldırmada da faydalı iş, yükün ağırlığı ile kazanılan yüksekliğin çarpımıdır."},{"t":"İki durumu karşılaştır","a":"600×3 her ikisinde","d":"İki durumda da yük 600 N ve yükseklik 3 m olduğundan faydalı iş 1800 J'dür."},{"t":"İlke","a":"işten kazanç yok","d":"Basit makine yolu uzatıp kuvveti azaltsa da toplam işi değiştirmez."}],"ans":"Yapılan faydalı iş değişmez; her iki yolda da iş 1800 J'dür, çünkü basit makinelerde işten kazanç olmaz."}]}},"cikrik":{"ilkokul":{"kolay":[{"q":"Şekildeki kuyu çıkrığında suyu çekmek için hangi parçayı çeviririz?","fig":"<svg viewBox='0 0 320 180'><rect x='120' y='110' width='80' height='60' fill='#cdd6e5' stroke='#1a2b45' stroke-width='2'/><rect x='112' y='100' width='96' height='12' fill='#8a6d3b' stroke='#1a2b45'/><circle cx='160' cy='80' r='20' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='80' x2='205' y2='60' stroke='#1a2b45' stroke-width='3'/><circle cx='208' cy='58' r='7' fill='#e0552b' stroke='#1a2b45'/><text x='240' y='60' font-size='12' fill='#1a2b45'>kol</text><line x1='160' y1='100' x2='160' y2='150' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='150' width='20' height='14' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='178' font-size='11' text-anchor='middle' fill='#1a2b45'>kova</text></svg>","steps":[{"t":"Çıkrığın parçaları","a":"kol ve makara","d":"Çıkrıkta el ile çevirdiğimiz bir kol ve ipin sarıldığı bir makara vardır."},{"t":"Hangisini çeviririz","a":"kolu","d":"Suyu yukarı çekmek için kenardaki kolu elimizle döndürürüz."}],"ans":"Kuyu çıkrığında suyu çekmek için kenardaki kolu çeviririz."},{"q":"Kuyu çıkrığında kolu çevirince kovaya ne olur?","fig":"<svg viewBox='0 0 320 180'><rect x='40' y='30' width='240' height='14' fill='#8a6d3b' stroke='#1a2b45'/><circle cx='160' cy='37' r='12' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='37' x2='200' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='202' cy='24' r='6' fill='#e0552b' stroke='#1a2b45'/><line x1='160' y1='49' x2='160' y2='120' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='120' width='20' height='16' fill='#4aa3df' stroke='#1a2b45'/><line x1='160' y1='100' x2='148' y2='90' stroke='#e0552b' stroke-width='2'/><polygon points='160,95 152,98 158,104' fill='#e0552b'/><text x='200' y='100' font-size='12' fill='#1a2b45'>yukarı çıkar</text></svg>","steps":[{"t":"Kol döner","a":"ip sarılır","d":"Kolu çevirince makara döner ve kovanın ipi makaraya sarılır."},{"t":"Kova ne yapar","a":"yukarı gelir","d":"İp sarıldıkça kova yukarı doğru çekilir."}],"ans":"Kolu çevirince ip makaraya sarılır ve kova yukarı çıkar."},{"q":"Çıkrık bize işi nasıl kolaylaştırır?","steps":[{"t":"Çıkrığın görevi","a":"kuvveti azaltır","d":"Çıkrık, ağır bir yükü daha az kuvvetle yukarı çekmemizi sağlar."},{"t":"Sonuç","a":"daha kolay","d":"Bu yüzden dolu kovayı elle çekmek yerine çıkrıkla daha kolay çekeriz."}],"ans":"Çıkrık, ağır kovayı daha az kuvvetle çekmemizi sağlayarak işi kolaylaştırır."},{"q":"Şekildeki çıkrıkta uzun kolu çevirmek mi yoksa kovayı doğrudan iple çekmek mi daha kolaydır?","fig":"<svg viewBox='0 0 320 180'><circle cx='90' cy='90' r='22' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='90' y1='90' x2='150' y2='70' stroke='#1a2b45' stroke-width='3'/><circle cx='153' cy='68' r='7' fill='#e0552b' stroke='#1a2b45'/><text x='170' y='70' font-size='11' fill='#1a2b45'>uzun kol</text><line x1='90' y1='112' x2='90' y2='160' stroke='#1a2b45' stroke-width='1.5'/><rect x='80' y='160' width='20' height='14' fill='#4aa3df' stroke='#1a2b45'/><text x='240' y='120' font-size='11' text-anchor='middle' fill='#1a2b45'>kol kolaylaştırır</text></svg>","steps":[{"t":"Kol uzundur","a":"avantaj sağlar","d":"Çıkrığın kolu, kovanın asıldığı makaradan daha geniş bir daire çizer."},{"t":"Hangisi kolay","a":"kolu çevirmek","d":"Geniş daire sayesinde kolu çevirmek, ipi doğrudan çekmekten daha az kuvvet ister."}],"ans":"Uzun kolu çevirmek, kovayı doğrudan iple çekmekten daha kolaydır."},{"q":"Direksiyon da bir çıkrık gibi çalışır mı?","steps":[{"t":"Direksiyon büyük","a":"geniş tekerlek","d":"Direksiyon, ortasındaki ince mile bağlı büyük bir tekerlektir."},{"t":"Benzerlik","a":"çıkrığa benzer","d":"Büyük tekerleği çevirip ince mili döndürdüğü için çıkrık gibi çalışır."}],"ans":"Evet, direksiyon büyük tekerleğiyle ince mili döndürdüğü için çıkrık gibi çalışır."}],"zor":[{"q":"Şekildeki iki çıkrıktan kolu daha uzun olanı çevirmek neden daha kolaydır?","fig":"<svg viewBox='0 0 320 180'><circle cx='75' cy='80' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='75' y1='80' x2='110' y2='68' stroke='#1a2b45' stroke-width='3'/><circle cx='113' cy='66' r='6' fill='#e0552b' stroke='#1a2b45'/><text x='75' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>kısa kol</text><circle cx='235' cy='80' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='235' y1='80' x2='295' y2='58' stroke='#1a2b45' stroke-width='3'/><circle cx='298' cy='56' r='6' fill='#e0552b' stroke='#1a2b45'/><text x='250' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>uzun kol</text></svg>","steps":[{"t":"Uzun kol büyük daire","a":"daha geniş yol","d":"Uzun kol döndüğünde daha büyük bir daire çizer, kolumuz daha uzun yol gider."},{"t":"Kuvvet azalır","a":"daha az itme","d":"Aynı yükü kaldırmak için uzun kolda daha az kuvvet uygulamak yeterlidir."}],"ans":"Uzun kol daha geniş bir daire çizdiği için aynı yükü daha az kuvvetle kaldırır, bu yüzden daha kolaydır."},{"q":"Bir çocuk dolu kovayı çıkrıkla kolayca çekiyor ama boş kovayı elle çekmek zorlanmadan oluyor. Çıkrık neyi sağlamıştır?","steps":[{"t":"Dolu kova ağır","a":"çok yük","d":"İçi su dolu kova ağırdır, doğrudan çekmek çok kuvvet ister."},{"t":"Çıkrık yardımı","a":"kuvveti azaltır","d":"Çıkrık bu ağır yükü küçük bir kuvvetle çekebilmemizi sağlar."}],"ans":"Çıkrık, ağır dolu kovayı küçük bir kuvvetle çekebilmemizi sağlamıştır."},{"q":"Şekildeki kapı kolu (tokmak) neden bir çıkrığa benzetilir?","fig":"<svg viewBox='0 0 320 180'><rect x='60' y='20' width='14' height='140' fill='#8a6d3b' stroke='#1a2b45'/><circle cx='150' cy='90' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><text x='150' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>ince mil</text><line x1='150' y1='90' x2='240' y2='90' stroke='#1a2b45' stroke-width='5'/><circle cx='248' cy='90' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='240' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>uzun kol</text></svg>","steps":[{"t":"Kol uzun, mil ince","a":"farklı yarıçap","d":"Kapı kolunu tutarız, ucundaki ince mil dilciği döndürür."},{"t":"Çıkrık mantığı","a":"az kuvvet","d":"Uzun kolla küçük kuvvet uygulayıp ince mili kolayca döndürdüğümüz için çıkrığa benzer."}],"ans":"Kapı kolu, uzun koluyla küçük kuvvet uygulayıp ince mili döndürdüğü için çıkrığa benzetilir."},{"q":"Çıkrığın kolunu hızlı çevirince kova hızlı çıkar, yavaş çevirince yavaş çıkar. Bu neyi gösterir?","steps":[{"t":"Kol ile kova bağlı","a":"birlikte döner","d":"Kol ve kovanın sarıldığı makara aynı milde olduğundan birlikte döner."},{"t":"Hız ilişkisi","a":"aynı yönde","d":"Kolu ne kadar hızlı çevirirsek kova da o kadar hızlı yukarı çıkar."}],"ans":"Kol ve makara birlikte döndüğü için kolu hızlı çevirince kova da hızlı çıkar."},{"q":"Bir vinçte (kreyn) ağır yükü çıkrık benzeri bir düzenek kaldırır. İnsan bu kadar ağır yükü neden tek başına kaldıramaz da vinç kaldırır?","steps":[{"t":"Yük çok ağır","a":"insan gücü yetmez","d":"İnsanın kası, çok ağır yükü doğrudan kaldıracak kadar büyük kuvvet üretemez."},{"t":"Çıkrık avantajı","a":"kuvveti büyütür","d":"Vinçteki çıkrık düzeneği, küçük motoru güçlü bir kaldırmaya çevirir."}],"ans":"Vinçteki çıkrık düzeneği küçük kuvveti büyük bir kaldırma kuvvetine çevirdiği için ağır yükü kaldırabilir."}]},"ortaokul":{"kolay":[{"q":"Çıkrık hangi basit makinenin değişik bir biçimidir?","steps":[{"t":"Çıkrığın yapısı","a":"döner kol","d":"Çıkrık, bir mil etrafında dönen kol ve makaradan oluşur."},{"t":"Hangi makine","a":"kaldıraç","d":"Bu dönme hareketi, sürekli dönen bir kaldıraç gibi çalışır."}],"ans":"Çıkrık, mil etrafında sürekli dönen bir kaldıracın (döner kaldıraç) değişik biçimidir."},{"q":"Şekildeki çıkrıkta hangi yarıçap büyük, hangisi küçüktür?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='12' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='90' r='55' fill='none' stroke='#1a2b45' stroke-width='1' stroke-dasharray='4 4'/><line x1='160' y1='90' x2='160' y2='35' stroke='#e0552b' stroke-width='2'/><text x='168' y='60' font-size='11' fill='#e0552b'>R (kol)</text><line x1='160' y1='90' x2='172' y2='90' stroke='#2e8b57' stroke-width='3'/><text x='200' y='90' font-size='11' fill='#2e8b57'>r (dingil)</text><line x1='160' y1='90' x2='205' y2='70' stroke='#1a2b45' stroke-width='3'/><circle cx='208' cy='68' r='6' fill='#e0552b' stroke='#1a2b45'/></svg>","steps":[{"t":"İki yarıçap","a":"kol ve dingil","d":"Çıkrıkta kolun çizdiği daire büyük, ipin sarıldığı dingil (mil) ince ve küçüktür."},{"t":"Karşılaştır","a":"R > r","d":"Kol yarıçapı R, dingil yarıçapı r'den büyüktür."}],"ans":"Kolun yarıçapı R büyük, ipin sarıldığı dingilin yarıçapı r küçüktür (R > r)."},{"q":"Çıkrıkta uygulanan kuvvetin koldan, yükün ise dingilden etki etmesi neyi sağlar?","steps":[{"t":"Kuvvet büyük yarıçapta","a":"R kolunda","d":"Kuvveti büyük yarıçaplı kola uygularız."},{"t":"Avantaj","a":"yük küçük yarıçapta","d":"Yük küçük yarıçaplı dingilde olduğundan, küçük kuvvetle büyük yük kaldırılır."}],"ans":"Kuvvet büyük yarıçapta, yük küçük yarıçapta olduğu için küçük kuvvetle büyük yük kaldırılır."},{"q":"Şekildeki direksiyon sisteminde sürücü direksiyonu çevirince ince mil neden daha kolay döner?","fig":"<svg viewBox='0 0 320 180'><circle cx='150' cy='90' r='55' fill='none' stroke='#1a2b45' stroke-width='4'/><circle cx='150' cy='90' r='10' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='90' x2='205' y2='90' stroke='#1a2b45' stroke-width='3'/><line x1='95' y1='90' x2='150' y2='90' stroke='#1a2b45' stroke-width='3'/><line x1='150' y1='35' x2='150' y2='145' stroke='#1a2b45' stroke-width='3'/><text x='150' y='165' font-size='11' text-anchor='middle' fill='#1a2b45'>büyük direksiyon, ince mil</text></svg>","steps":[{"t":"Direksiyon büyük","a":"büyük R","d":"Direksiyon büyük yarıçaplı bir tekerlektir, ortasındaki mil incedir."},{"t":"Az kuvvet yeter","a":"R > r","d":"Büyük yarıçapta küçük kuvvet uygulamak, ince mili döndürmeye yeter."}],"ans":"Direksiyon büyük yarıçaplı olduğu için küçük kuvvetle ince mili kolayca döndürür."},{"q":"Çıkrıkta mekanik avantajı artırmak için kolu nasıl değiştirmeliyiz?","steps":[{"t":"Avantaj neye bağlı","a":"kol yarıçapı","d":"Çıkrıkta avantaj, kol yarıçapı R büyüdükçe artar."},{"t":"Ne yapmalı","a":"kolu uzatmalı","d":"Kolu uzatıp R'yi büyütürsek aynı yükü daha az kuvvetle kaldırırız."}],"ans":"Kolu uzatarak (R'yi büyüterek) çıkrığın mekanik avantajını artırabiliriz."}],"zor":[{"q":"Şekildeki çıkrıkta kol yarıçapı R, dingil yarıçapı r ise mekanik avantaj hangi orana eşittir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='90' x2='160' y2='30' stroke='#e0552b' stroke-width='2.5'/><text x='168' y='55' font-size='11' fill='#e0552b'>R</text><line x1='160' y1='90' x2='174' y2='90' stroke='#2e8b57' stroke-width='4'/><text x='178' y='80' font-size='11' fill='#2e8b57'>r</text><line x1='160' y1='104' x2='160' y2='150' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='150' width='20' height='16' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>Yük</text><line x1='160' y1='90' x2='110' y2='65' stroke='#1a2b45' stroke-width='3'/><circle cx='107' cy='63' r='6' fill='#e0552b' stroke='#1a2b45'/></svg>","steps":[{"t":"Avantaj tanımı","a":"yarıçap oranı","d":"Çıkrıkta mekanik avantaj, kuvvetin yarıçapının yükün yarıçapına oranıdır."},{"t":"Oranı yaz","a":"MA = R/r","d":"Kol yarıçapı R'yi dingil yarıçapı r'ye bölersek mekanik avantajı buluruz."}],"ans":"Çıkrıkta mekanik avantaj MA = R / r'dir."},{"q":"Bir çıkrıkta kol yarıçapı dingilin 4 katıdır. Bu çıkrığın mekanik avantajı kaçtır?","steps":[{"t":"Avantaj formülü","a":"MA = R/r","d":"Mekanik avantaj kol yarıçapının dingil yarıçapına oranıdır."},{"t":"Oranı koy","a":"R = 4r","d":"Kol yarıçapı dingilin 4 katı olduğundan R/r = 4r/r = 4'tür."}],"ans":"Çıkrığın mekanik avantajı 4'tür."},{"q":"Şekildeki kuyu çıkrığında 200 N'luk dolu kovayı kaldırmak için, kol yarıçapı dingilin 5 katı ise kaç N kuvvet gerekir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='80' x2='160' y2='32' stroke='#e0552b' stroke-width='2'/><text x='168' y='52' font-size='10' fill='#e0552b'>R=5r</text><line x1='160' y1='94' x2='160' y2='140' stroke='#1a2b45' stroke-width='1.5'/><rect x='148' y='140' width='24' height='18' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='174' font-size='10' text-anchor='middle' fill='#1a2b45'>200 N</text><line x1='160' y1='80' x2='110' y2='58' stroke='#1a2b45' stroke-width='3'/><circle cx='107' cy='56' r='6' fill='#e0552b' stroke='#1a2b45'/></svg>","steps":[{"t":"Denge bağıntısı","a":"F·R = Yük·r","d":"Çıkrıkta uygulanan kuvvet × kol yarıçapı, yük × dingil yarıçapına eşittir."},{"t":"Değerleri koy","a":"F·5r = 200·r","d":"R = 5r ve yük 200 N yazılır, r sadeleşir."},{"t":"Hesapla","a":"F = 200/5 = 40 N","d":"Eşitlikten kuvvet 40 N bulunur."}],"ans":"Kovayı kaldırmak için 40 N kuvvet gerekir."},{"q":"Bir çıkrıkta kol bir tam tur döndüğünde, kolun ucu mu yoksa ipin sarıldığı dingil mi daha uzun yol alır?","steps":[{"t":"Tur sayısı aynı","a":"birlikte döner","d":"Kol ve dingil aynı milde olduğundan bir turda ikisi de tam bir daire çizer."},{"t":"Yol yarıçapa bağlı","a":"R büyük","d":"Çevre 2πR olduğundan büyük yarıçaplı kolun ucu, ince dingilden daha uzun yol alır."}],"ans":"Kol yarıçapı daha büyük olduğu için bir turda kolun ucu, dingilden daha uzun yol alır."},{"q":"Çıkrık kuvvetten kazandırırken bizden ne ister? Şekildeki düzenek üzerinden açıklayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='90' r='50' fill='none' stroke='#e0552b' stroke-width='1' stroke-dasharray='4 4'/><text x='160' y='28' font-size='10' text-anchor='middle' fill='#e0552b'>kol uzun yol</text><circle cx='160' cy='90' r='18' fill='none' stroke='#2e8b57' stroke-width='1' stroke-dasharray='3 3'/><text x='205' y='118' font-size='10' fill='#2e8b57'>dingil kısa yol</text></svg>","steps":[{"t":"Kuvvetten kazanç","a":"daha az kuvvet","d":"Çıkrık aynı yükü daha az kuvvetle kaldırmamızı sağlar."},{"t":"Karşılığı","a":"daha çok yol","d":"Buna karşılık kolu, yükün çıktığı mesafeden çok daha uzun yol boyunca döndürmemiz gerekir."}],"ans":"Çıkrık kuvvetten kazandırır ama karşılığında kolu çok daha uzun bir yol boyunca çevirmemizi ister; işten kazanç olmaz."}]},"lise":{"kolay":[{"q":"Çıkrıkta denge koşulu (kuvvet momentlerinin eşitliği) nasıl yazılır?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='90' x2='160' y2='32' stroke='#e0552b' stroke-width='2.5'/><text x='168' y='55' font-size='11' fill='#e0552b'>R</text><line x1='160' y1='90' x2='176' y2='90' stroke='#2e8b57' stroke-width='4'/><text x='182' y='82' font-size='11' fill='#2e8b57'>r</text><line x1='160' y1='32' x2='130' y2='32' stroke='#e0552b' stroke-width='2'/><polygon points='130,32 138,28 138,36' fill='#e0552b'/><text x='112' y='26' font-size='10' fill='#e0552b'>F</text><line x1='160' y1='104' x2='160' y2='150' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='150' width='20' height='16' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>Yük</text></svg>","steps":[{"t":"Moment eşitliği","a":"iki moment","d":"Çıkrık dengede iken kuvvetin momenti, yükün momentine eşittir."},{"t":"İfadeyi yaz","a":"F·R = Yük·r","d":"Kuvvet F kol yarıçapı R ile, yük ise dingil yarıçapı r ile çarpılır ve eşitlenir."}],"ans":"Çıkrıkta denge koşulu F · R = Yük · r biçimindedir."},{"q":"Çıkrıkta mekanik avantaj ifadesini denge koşulundan türetiniz.","steps":[{"t":"Denge koşulu","a":"F·R = Yük·r","d":"Dengede kuvvet momenti yük momentine eşittir."},{"t":"MA tanımı","a":"Yük/F","d":"Mekanik avantaj, yükün uygulanan kuvvete oranıdır."},{"t":"Düzenle","a":"MA = R/r","d":"Eşitliği düzenleyince Yük/F = R/r çıkar; yani MA = R/r'dir."}],"ans":"Çıkrıkta mekanik avantaj MA = Yük/F = R/r'dir."},{"q":"Kol yarıçapı R = 60 cm, dingil yarıçapı r = 12 cm olan çıkrığın mekanik avantajını hesaplayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='90' x2='160' y2='30' stroke='#e0552b' stroke-width='2.5'/><text x='168' y='55' font-size='11' fill='#e0552b'>R=60 cm</text><line x1='160' y1='90' x2='178' y2='90' stroke='#2e8b57' stroke-width='4'/><text x='184' y='82' font-size='10' fill='#2e8b57'>r=12 cm</text></svg>","steps":[{"t":"Formül","a":"MA = R/r","d":"Çıkrıkta mekanik avantaj kol yarıçapının dingil yarıçapına oranıdır."},{"t":"Değerleri koy","a":"60/12","d":"R = 60 cm ve r = 12 cm yerine konur."},{"t":"Hesapla","a":"MA = 5","d":"Bölme sonucu mekanik avantaj 5 bulunur."}],"ans":"Çıkrığın mekanik avantajı 5'tir."},{"q":"Kol yarıçapı 50 cm, dingil yarıçapı 10 cm olan çıkrıkta 300 N'luk yükü dengelemek için kaç N kuvvet gerekir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='80' x2='160' y2='32' stroke='#e0552b' stroke-width='2'/><text x='168' y='52' font-size='10' fill='#e0552b'>R=50</text><line x1='160' y1='80' x2='176' y2='80' stroke='#2e8b57' stroke-width='4'/><text x='182' y='74' font-size='10' fill='#2e8b57'>r=10</text><line x1='160' y1='94' x2='160' y2='140' stroke='#1a2b45' stroke-width='1.5'/><rect x='148' y='140' width='24' height='18' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='174' font-size='10' text-anchor='middle' fill='#1a2b45'>300 N</text></svg>","steps":[{"t":"Denge koşulu","a":"F·R = Yük·r","d":"Kuvvet momenti yük momentine eşitlenir."},{"t":"Değerleri koy","a":"F·50 = 300·10","d":"R = 50 cm, r = 10 cm, yük 300 N yazılır."},{"t":"Hesapla","a":"F = 3000/50 = 60 N","d":"Eşitlikten kuvvet 60 N bulunur."}],"ans":"Yükü dengelemek için 60 N kuvvet gerekir."},{"q":"Çıkrıkta mekanik avantaj 6 ise, 90 N kuvvetle kaç N'luk yük dengelenir?","steps":[{"t":"MA tanımı","a":"MA = Yük/F","d":"Mekanik avantaj, dengelenen yükün uygulanan kuvvete oranıdır."},{"t":"Yükü yaz","a":"Yük = MA·F","d":"Eşitliği düzenleyince yük = mekanik avantaj × kuvvet olur."},{"t":"Hesapla","a":"6·90 = 540 N","d":"6 ile 90 N çarpılınca yük 540 N bulunur."}],"ans":"90 N kuvvetle 540 N'luk yük dengelenir."},{"q":"Şekildeki çıkrıkta kol bir tam tur (2πR) dönerken yük ne kadar yükselir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='90' r='50' fill='none' stroke='#e0552b' stroke-width='1.2' stroke-dasharray='5 4'/><text x='160' y='30' font-size='10' text-anchor='middle' fill='#e0552b'>kol: 2πR</text><circle cx='160' cy='90' r='20' fill='none' stroke='#2e8b57' stroke-width='1.2' stroke-dasharray='3 3'/><text x='210' y='120' font-size='10' fill='#2e8b57'>yük: 2πr</text></svg>","steps":[{"t":"Yük dingilde sarılı","a":"dingil çevresi","d":"İp dingile sarılı olduğundan bir turda yük, dingil çevresi kadar yükselir."},{"t":"İfade","a":"2πr","d":"Dingil yarıçapı r olduğundan yük bir turda 2πr kadar yükselir."}],"ans":"Kol bir tam tur dönerken yük, dingil çevresi olan 2πr kadar yükselir."},{"q":"Sürtünmenin ihmal edildiği bir çıkrıkta yapılan işler arasında nasıl bir ilişki vardır?","steps":[{"t":"İşin korunumu","a":"giren = çıkan","d":"İdeal (sürtünmesiz) çıkrıkta kuvvetin yaptığı iş, yüke aktarılan işe eşittir."},{"t":"İfade","a":"F·(2πR) = Yük·(2πr)","d":"Kuvvetin kol boyunca yaptığı iş, yükün dingilde yükselirken kazandığı işe eşittir."}],"ans":"İdeal çıkrıkta giren iş çıkan işe eşittir: F·(2πR) = Yük·(2πr); kazanç kuvvettedir, işte değildir."},{"q":"Bir kuyu çıkrığında kol yarıçapı 40 cm, dingil yarıçapı 8 cm. 25 N kuvvetle kaç N'luk kova kaldırılabilir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='78' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='78' x2='160' y2='34' stroke='#e0552b' stroke-width='2'/><text x='168' y='52' font-size='10' fill='#e0552b'>R=40</text><line x1='160' y1='78' x2='174' y2='78' stroke='#2e8b57' stroke-width='4'/><text x='180' y='72' font-size='10' fill='#2e8b57'>r=8</text><line x1='160' y1='91' x2='160' y2='138' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='138' width='20' height='16' fill='#4aa3df' stroke='#1a2b45'/></svg>","steps":[{"t":"Denge koşulu","a":"F·R = Yük·r","d":"Kuvvet momenti yük momentine eşittir."},{"t":"Değerleri koy","a":"25·40 = Yük·8","d":"F = 25 N, R = 40 cm, r = 8 cm yazılır."},{"t":"Hesapla","a":"Yük = 1000/8 = 125 N","d":"Eşitlikten yük 125 N bulunur."}],"ans":"25 N kuvvetle 125 N'luk kova kaldırılabilir."},{"q":"Çıkrıkta kol yarıçapı sabit tutulup dingil yarıçapı küçültülürse mekanik avantaj nasıl değişir?","steps":[{"t":"Formülü hatırla","a":"MA = R/r","d":"Mekanik avantaj kol yarıçapının dingil yarıçapına oranıdır."},{"t":"r küçülürse","a":"MA artar","d":"R sabitken r küçülürse oran büyür, yani mekanik avantaj artar."}],"ans":"Dingil yarıçapı küçüldükçe (R sabit) çıkrığın mekanik avantajı artar."},{"q":"Şekildeki çıkrıkta verim %100 değilse, kazanılan yük ideal değerden büyük mü küçük mü olur?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='85' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><path d='M150 99 q -8 8 0 14' fill='none' stroke='#e0552b' stroke-width='2'/><text x='112' y='112' font-size='10' fill='#e0552b'>sürtünme</text><line x1='160' y1='99' x2='160' y2='145' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='145' width='20' height='16' fill='#4aa3df' stroke='#1a2b45'/></svg>","steps":[{"t":"Sürtünme kaybı","a":"enerji harcanır","d":"Gerçek çıkrıkta milde sürtünme olur, kuvvetin bir kısmı sürtünmeyi yenmeye harcanır."},{"t":"Sonuç","a":"daha küçük yük","d":"Bu yüzden aynı kuvvetle kaldırılan gerçek yük, ideal değerden küçüktür."}],"ans":"Verim %100 olmadığında sürtünme kayıpları yüzünden kaldırılan yük, ideal değerden küçük olur."},{"q":"Direksiyon yarıçapı 18 cm, bağlı olduğu milin yarıçapı 3 cm ise mekanik avantaj kaçtır?","fig":"<svg viewBox='0 0 320 180'><circle cx='150' cy='90' r='52' fill='none' stroke='#1a2b45' stroke-width='4'/><circle cx='150' cy='90' r='10' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='38' x2='150' y2='42' stroke='#e0552b' stroke-width='2'/><text x='150' y='30' font-size='10' text-anchor='middle' fill='#e0552b'>R=18 cm</text><text x='150' y='118' font-size='10' text-anchor='middle' fill='#2e8b57'>r=3 cm</text></svg>","steps":[{"t":"Formül","a":"MA = R/r","d":"Direksiyon bir çıkrıktır; mekanik avantaj büyük yarıçapın küçük yarıçapa oranıdır."},{"t":"Değerleri koy","a":"18/3","d":"R = 18 cm, r = 3 cm yerine konur."},{"t":"Hesapla","a":"MA = 6","d":"Bölme sonucu mekanik avantaj 6 bulunur."}],"ans":"Direksiyonun mekanik avantajı 6'dır."},{"q":"Çıkrıkta yük 4 katına çıkarken kuvveti aynı tutmak istersek mekanik avantajı nasıl değiştirmeliyiz?","steps":[{"t":"İlişki","a":"Yük = MA·F","d":"Sabit kuvvette dengelenen yük, mekanik avantajla doğru orantılıdır."},{"t":"Yük 4 katı","a":"MA 4 katı","d":"Kuvvet sabitken yükü 4 katına çıkarmak için mekanik avantajı da 4 katına çıkarmalıyız."}],"ans":"Aynı kuvvetle 4 kat yükü dengelemek için mekanik avantajı 4 katına çıkarmalıyız."},{"q":"Şekildeki çıkrıkta kol yarıçapı 30 cm, dingil yarıçapı 6 cm. Kol 2 tam tur dönerse yük kaç cm yükselir? (π ≈ 3,14)","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='80' x2='160' y2='38' stroke='#e0552b' stroke-width='2'/><text x='168' y='56' font-size='10' fill='#e0552b'>R=30</text><line x1='160' y1='80' x2='173' y2='80' stroke='#2e8b57' stroke-width='4'/><text x='178' y='74' font-size='10' fill='#2e8b57'>r=6</text><line x1='160' y1='93' x2='160' y2='140' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='140' width='20' height='16' fill='#4aa3df' stroke='#1a2b45'/></svg>","steps":[{"t":"Bir turda yükselme","a":"2πr","d":"İp dingile sarılı olduğundan bir turda yük 2πr kadar yükselir."},{"t":"İki tur","a":"2·2πr","d":"İki tur için yükselme miktarı 2 ile çarpılır."},{"t":"Hesapla","a":"2·2·3,14·6 ≈ 75,4 cm","d":"r = 6 cm konunca yükselme 2·2·3,14·6 ≈ 75,4 cm bulunur."}],"ans":"Kol 2 tam tur dönerse yük yaklaşık 75,4 cm yükselir."},{"q":"Çıkrık ile sabit makaranın ortak özelliği nedir?","steps":[{"t":"İkisi de döner","a":"eksen etrafında","d":"Hem çıkrık hem sabit makara bir eksen (mil) etrafında döner."},{"t":"Kaldıraç mantığı","a":"döner kaldıraç","d":"İkisi de eksende dönen kaldıraç gibi davranır; çıkrıkta kollar farklı, sabit makarada eşittir."}],"ans":"İkisi de bir eksen etrafında dönen kaldıraç (döner kaldıraç) mantığıyla çalışır."},{"q":"Bir vinçte kol yarıçapı 80 cm, dingil yarıçapı 16 cm. 1200 N yükü kaldırmak için gereken kuvveti hesaplayınız.","steps":[{"t":"Denge koşulu","a":"F·R = Yük·r","d":"Kuvvet momenti yük momentine eşittir."},{"t":"Değerleri koy","a":"F·80 = 1200·16","d":"R = 80 cm, r = 16 cm, yük 1200 N yazılır."},{"t":"Hesapla","a":"F = 19200/80 = 240 N","d":"Eşitlikten gereken kuvvet 240 N bulunur."}],"ans":"Vinçte 1200 N yükü kaldırmak için 240 N kuvvet gerekir."}],"zor":[{"q":"Şekildeki çıkrıkta kol yarıçapı 45 cm, dingil yarıçapı 9 cm. 30 N kuvvet uygulanıyor. Kaldırılabilecek en büyük yükü ve mekanik avantajı hesaplayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='80' x2='160' y2='32' stroke='#e0552b' stroke-width='2.5'/><text x='168' y='52' font-size='10' fill='#e0552b'>R=45</text><line x1='160' y1='80' x2='176' y2='80' stroke='#2e8b57' stroke-width='4'/><text x='182' y='74' font-size='10' fill='#2e8b57'>r=9</text><line x1='160' y1='32' x2='128' y2='32' stroke='#e0552b' stroke-width='2'/><polygon points='128,32 136,28 136,36' fill='#e0552b'/><text x='110' y='26' font-size='10' fill='#e0552b'>F=30</text><line x1='160' y1='94' x2='160' y2='142' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='142' width='20' height='16' fill='#4aa3df' stroke='#1a2b45'/></svg>","steps":[{"t":"Mekanik avantaj","a":"MA = R/r","d":"MA = 45/9 = 5 bulunur."},{"t":"Yükü yaz","a":"Yük = MA·F","d":"Dengelenen yük mekanik avantaj ile kuvvetin çarpımıdır."},{"t":"Hesapla","a":"5·30 = 150 N","d":"5 ile 30 N çarpılınca en büyük yük 150 N bulunur."}],"ans":"Mekanik avantaj 5, kaldırılabilecek en büyük yük 150 N'dir."},{"q":"İdeal bir çıkrıkta 50 N kuvvet kol boyunca 6,28 m yol alıyor. Yük 250 N ise yük kaç metre yükselir?","steps":[{"t":"İşin korunumu","a":"F·hkuvvet = Yük·hyük","d":"İdeal çıkrıkta kuvvetin yaptığı iş yüke aktarılan işe eşittir."},{"t":"Değerleri koy","a":"50·6,28 = 250·hyük","d":"F = 50 N, kuvvet yolu 6,28 m, yük 250 N yazılır."},{"t":"Hesapla","a":"hyük = 314/250 = 1,256 m","d":"Eşitlikten yükün yükseldiği mesafe yaklaşık 1,256 m bulunur."}],"ans":"Yük yaklaşık 1,256 m yükselir; kuvvet daha uzun yol aldığı için işten kazanç yoktur."},{"q":"Şekildeki çıkrığın verimi %80'dir. Kol yarıçapı 60 cm, dingil 12 cm, uygulanan kuvvet 50 N ise kaldırılan gerçek yükü hesaplayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='82' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='82' x2='160' y2='34' stroke='#e0552b' stroke-width='2'/><text x='168' y='54' font-size='10' fill='#e0552b'>R=60</text><line x1='160' y1='82' x2='176' y2='82' stroke='#2e8b57' stroke-width='4'/><text x='182' y='76' font-size='10' fill='#2e8b57'>r=12</text><path d='M148 96 q -8 8 0 14' fill='none' stroke='#e0552b' stroke-width='2'/><text x='108' y='110' font-size='9' fill='#e0552b'>verim %80</text><line x1='160' y1='96' x2='160' y2='142' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='142' width='20' height='16' fill='#4aa3df' stroke='#1a2b45'/></svg>","steps":[{"t":"İdeal yük","a":"MA·F","d":"İdeal mekanik avantaj 60/12 = 5; ideal yük 5·50 = 250 N olur."},{"t":"Verimi uygula","a":"gerçek = 0,80·ideal","d":"Verim %80 olduğundan gerçek yük ideal yükün 0,80 katıdır."},{"t":"Hesapla","a":"0,80·250 = 200 N","d":"0,80 ile 250 N çarpılınca gerçek yük 200 N bulunur."}],"ans":"Verim %80 olduğunda çıkrığın kaldırdığı gerçek yük 200 N'dir."},{"q":"İki çıkrık seri bağlanmıştır: ilkinin MA değeri 4, ikincinin MA değeri 3'tür. Toplam mekanik avantaj kaçtır?","steps":[{"t":"Seri sistem","a":"avantajlar çarpılır","d":"Seri bağlı sistemlerde mekanik avantajlar birbiriyle çarpılır."},{"t":"Hesapla","a":"4·3 = 12","d":"İlk çıkrığın avantajı 4, ikincisi 3 ise toplam 4·3 = 12'dir."}],"ans":"Seri bağlı iki çıkrığın toplam mekanik avantajı 12'dir."},{"q":"Şekildeki çıkrıkta kol yarıçapı 36 cm, yük 480 N, uygulanan kuvvet 80 N ise dingil yarıçapını hesaplayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='80' x2='160' y2='32' stroke='#e0552b' stroke-width='2'/><text x='168' y='52' font-size='10' fill='#e0552b'>R=36</text><line x1='160' y1='80' x2='175' y2='80' stroke='#2e8b57' stroke-width='4'/><text x='182' y='74' font-size='10' fill='#2e8b57'>r=?</text><line x1='160' y1='94' x2='160' y2='140' stroke='#1a2b45' stroke-width='1.5'/><rect x='148' y='140' width='24' height='18' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='174' font-size='9' text-anchor='middle' fill='#1a2b45'>480 N</text></svg>","steps":[{"t":"Denge koşulu","a":"F·R = Yük·r","d":"Kuvvet momenti yük momentine eşittir."},{"t":"Değerleri koy","a":"80·36 = 480·r","d":"F = 80 N, R = 36 cm, yük 480 N yazılır."},{"t":"Hesapla","a":"r = 2880/480 = 6 cm","d":"Eşitlikten dingil yarıçapı 6 cm bulunur."}],"ans":"Çıkrığın dingil yarıçapı 6 cm'dir."},{"q":"Çıkrıkta verim formülünü iş cinsinden yazıp, kullanan iş 200 J, faydalı iş 160 J ise verimi hesaplayınız.","steps":[{"t":"Verim tanımı","a":"faydalı/kullanılan","d":"Verim, yüke aktarılan faydalı işin uygulanan toplam işe oranıdır."},{"t":"Değerleri koy","a":"160/200","d":"Faydalı iş 160 J, kullanılan iş 200 J yazılır."},{"t":"Hesapla","a":"0,80 = %80","d":"Oran 0,80 yani %80 olarak bulunur."}],"ans":"Çıkrığın verimi %80'dir (verim = faydalı iş / kullanılan iş)."},{"q":"Şekildeki çıkrıkta kola 40 N kuvvet uygulanıp dingil çevresinde 240 N yük dengeleniyor. Kol bir turda 1,5 m yol alıyorsa yük kaç metre yükselir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='85' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='85' r='48' fill='none' stroke='#e0552b' stroke-width='1' stroke-dasharray='5 4'/><text x='160' y='28' font-size='9' text-anchor='middle' fill='#e0552b'>kol: 1,5 m/tur</text><line x1='160' y1='99' x2='160' y2='150' stroke='#1a2b45' stroke-width='1.5'/><rect x='148' y='150' width='24' height='16' fill='#4aa3df' stroke='#1a2b45'/><text x='200' y='130' font-size='9' fill='#2e8b57'>Yük=240 N</text></svg>","steps":[{"t":"İşin korunumu","a":"F·skol = Yük·syük","d":"İdeal çıkrıkta kuvvetin işi yükün işine eşittir."},{"t":"Değerleri koy","a":"40·1,5 = 240·syük","d":"F = 40 N, kol yolu 1,5 m, yük 240 N yazılır."},{"t":"Hesapla","a":"syük = 60/240 = 0,25 m","d":"Eşitlikten yükün yükselmesi 0,25 m bulunur."}],"ans":"Yük bir turda 0,25 m yükselir."},{"q":"Bir çıkrıkta kol yarıçapı dingilin 8 katıdır. Aynı yükü kaldırırken kuvvet ne kadar azalır?","steps":[{"t":"Mekanik avantaj","a":"MA = R/r = 8","d":"Kol yarıçapı dingilin 8 katı olduğundan mekanik avantaj 8'dir."},{"t":"Kuvvet ilişkisi","a":"F = Yük/MA","d":"Uygulanacak kuvvet, yükün mekanik avantaja bölümüdür."},{"t":"Sonuç","a":"8'de 1'i","d":"Kuvvet, yükü doğrudan çekmeye göre 8 kat azalır (yükün sekizde biri olur)."}],"ans":"Mekanik avantaj 8 olduğundan gereken kuvvet, yükün sekizde birine düşer (8 kat azalır)."},{"q":"Şekildeki çıkrıkta kol yarıçapı 50 cm, dingil yarıçapı 10 cm, verim %90. Gerçekte 720 N yük kaldırılıyorsa uygulanan kuvveti hesaplayınız.","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='80' x2='160' y2='34' stroke='#e0552b' stroke-width='2'/><text x='168' y='54' font-size='10' fill='#e0552b'>R=50</text><line x1='160' y1='80' x2='175' y2='80' stroke='#2e8b57' stroke-width='4'/><text x='181' y='74' font-size='10' fill='#2e8b57'>r=10</text><path d='M148 94 q -7 7 0 13' fill='none' stroke='#e0552b' stroke-width='2'/><text x='108' y='108' font-size='9' fill='#e0552b'>verim %90</text><line x1='160' y1='94' x2='160' y2='140' stroke='#1a2b45' stroke-width='1.5'/><rect x='148' y='140' width='24' height='16' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='172' font-size='9' text-anchor='middle' fill='#1a2b45'>720 N</text></svg>","steps":[{"t":"İdeal kuvvet","a":"F0 = Yük·r/R","d":"İdeal durumda gereken kuvvet 720·10/50 = 144 N olur."},{"t":"Verimi uygula","a":"F = F0/verim","d":"Sürtünme kayıpları yüzünden gerçek kuvvet ideal kuvvetin verime bölümüdür."},{"t":"Hesapla","a":"144/0,90 = 160 N","d":"144 N'yi 0,90'a bölünce gerçek kuvvet 160 N bulunur."}],"ans":"Verim %90 iken 720 N yükü kaldırmak için uygulanan kuvvet 160 N'dir."},{"q":"Çıkrıkta uygulanan güç ile yüke aktarılan güç arasındaki ilişkiyi ideal durumda açıklayınız.","steps":[{"t":"Güç tanımı","a":"iş/zaman","d":"Güç, birim zamanda yapılan iştir."},{"t":"İdeal sistem","a":"giren iş = çıkan iş","d":"İdeal çıkrıkta giren ve çıkan iş eşit, süre de ortak olduğundan güçler de eşittir."}],"ans":"İdeal çıkrıkta giren iş çıkan işe eşit olduğu için uygulanan güç, yüke aktarılan güce eşittir."},{"q":"Şekildeki çıkrıkta dingile iki kat farklı çaplı silindir takılırsa (kademeli çıkrık), yük neden daha da kolay kaldırılır?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='30' fill='none' stroke='#1a2b45' stroke-width='2'/><text x='160' y='50' font-size='9' text-anchor='middle' fill='#e0552b'>kol R</text><circle cx='160' cy='90' r='16' fill='#cdd6e5' stroke='#1a2b45' stroke-width='1.5'/><circle cx='160' cy='90' r='7' fill='#5b6b85' stroke='#1a2b45' stroke-width='1.5'/><text x='210' y='95' font-size='9' fill='#2e8b57'>ince dingil r</text><line x1='160' y1='97' x2='160' y2='145' stroke='#1a2b45' stroke-width='1.5'/><rect x='150' y='145' width='20' height='14' fill='#4aa3df' stroke='#1a2b45'/></svg>","steps":[{"t":"Kademeli yapı","a":"daha ince dingil","d":"Kademeli çıkrıkta yük en ince silindire sarıldığından r daha da küçülür."},{"t":"Avantaj artar","a":"MA = R/r büyür","d":"r küçüldükçe R/r oranı büyür, yani mekanik avantaj artar."}],"ans":"Kademeli çıkrıkta yük daha ince dingile sarıldığından r küçülür, R/r oranı büyür ve yük daha kolay kaldırılır."},{"q":"Bir çıkrıkta 60 N kuvvetle 300 N yük dengeleniyor. Aynı çıkrıkta kuvveti 90 N'a çıkarırsak en fazla kaç N yük dengelenir?","steps":[{"t":"Mekanik avantaj","a":"MA = Yük/F","d":"İlk durumda MA = 300/60 = 5 bulunur; çıkrığın yarıçap oranı değişmez."},{"t":"Yeni yük","a":"Yük = MA·F","d":"Mekanik avantaj sabit kalır; yeni yük 5·90 ile bulunur."},{"t":"Hesapla","a":"5·90 = 450 N","d":"5 ile 90 N çarpılınca yeni yük 450 N bulunur."}],"ans":"Kuvvet 90 N'a çıkarılınca en fazla 450 N yük dengelenir."},{"q":"Şekildeki çıkrıkta yük dingilden, kuvvet ise koldan etki ediyor. Kuvvet kolu yatayken neden en etkilidir?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='90' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='90' x2='250' y2='90' stroke='#1a2b45' stroke-width='3'/><circle cx='256' cy='90' r='8' fill='#e0552b' stroke='#1a2b45'/><line x1='256' y1='90' x2='256' y2='130' stroke='#e0552b' stroke-width='2'/><polygon points='256,130 251,120 261,120' fill='#e0552b'/><text x='270' y='115' font-size='10' fill='#e0552b'>F</text><text x='200' y='80' font-size='9' fill='#1a2b45'>kol yatay</text></svg>","steps":[{"t":"Moment kolu","a":"dik uzaklık","d":"Momenti belirleyen, eksene olan dik uzaklıktır; kuvvet kola dik etkidiğinde bu uzaklık en büyüktür."},{"t":"Yatay kol","a":"tam moment","d":"Kuvvet düşey, kol yatay olunca kuvvet kola tam dik gelir ve momenti en büyük olur."}],"ans":"Kol yatayken kuvvet kola tam dik etki eder; moment kolu (dik uzaklık) en büyük olduğundan kuvvet en etkilidir."},{"q":"İdeal bir çıkrıkta mekanik avantaj 5'tir. Yükü 2 m yükseltmek için kolu kaç metre döndürmek gerekir?","steps":[{"t":"Yol oranı","a":"hkuvvet/hyük = MA","d":"İdeal makinede kuvvetin aldığı yolun yükün yoluna oranı, mekanik avantaja eşittir."},{"t":"Kuvvet yolu","a":"hkuvvet = MA·hyük","d":"Kolu döndürme yolu, mekanik avantaj ile yük yolunun çarpımıdır."},{"t":"Hesapla","a":"5·2 = 10 m","d":"5 ile 2 m çarpılınca kolun döndürülmesi gereken yol 10 m bulunur."}],"ans":"Yükü 2 m yükseltmek için kolu 10 m boyunca döndürmek gerekir."},{"q":"Şekildeki çıkrıkta kol yarıçapı 25 cm, dingil yarıçapı 5 cm. Bir kişi kola en fazla 70 N uygulayabiliyor. Bu kişi 400 N'luk bir yükü bu çıkrıkla kaldırabilir mi?","fig":"<svg viewBox='0 0 320 180'><circle cx='160' cy='80' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='80' x2='160' y2='36' stroke='#e0552b' stroke-width='2'/><text x='168' y='56' font-size='10' fill='#e0552b'>R=25</text><line x1='160' y1='80' x2='173' y2='80' stroke='#2e8b57' stroke-width='4'/><text x='180' y='74' font-size='10' fill='#2e8b57'>r=5</text><line x1='160' y1='94' x2='160' y2='140' stroke='#1a2b45' stroke-width='1.5'/><rect x='148' y='140' width='24' height='18' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='174' font-size='9' text-anchor='middle' fill='#1a2b45'>400 N</text></svg>","steps":[{"t":"Mekanik avantaj","a":"MA = R/r = 5","d":"MA = 25/5 = 5 bulunur."},{"t":"Kaldırılabilen yük","a":"MA·F","d":"En büyük kuvvet 70 N ile kaldırılabilen yük 5·70 = 350 N'dir."},{"t":"Karşılaştır","a":"350 < 400","d":"Kaldırılabilen 350 N, gereken 400 N'dan küçük olduğundan yetmez."}],"ans":"Hayır; bu çıkrıkla en fazla 350 N kaldırılabilir, 400 N'luk yük için kuvvet yetmez."}]}},"disliCark":{"ilkokul":{"kolay":[{"q":"Şekilde birbirine geçmiş iki dişli çark var. Soldaki çarkı sağa döndürürsek diğeri ne yapar?","fig":"<svg viewBox='0 0 320 170'><circle cx='110' cy='85' r='42' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='200' cy='85' r='42' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='110' cy='85' r='8' fill='#1a2b45'/><circle cx='200' cy='85' r='8' fill='#1a2b45'/><path d='M110 30 A55 55 0 0 1 145 55' fill='none' stroke='#e0552b' stroke-width='2.5'/><polygon points='145,55 150,45 137,49' fill='#e0552b'/><path d='M200 30 A55 55 0 0 0 165 55' fill='none' stroke='#e0552b' stroke-width='2.5'/><polygon points='165,55 160,45 173,49' fill='#e0552b'/><text x='110' y='150' font-size='12' text-anchor='middle' fill='#1a2b45'>1. çark</text><text x='200' y='150' font-size='12' text-anchor='middle' fill='#1a2b45'>2. çark</text></svg>","steps":[{"t":"Dişler birbirini iter","a":"temas eder","d":"İki dişlinin dişleri birbirine geçer ve biri dönünce diğerini iter."},{"t":"Yöne bak","a":"ters yön","d":"Birbirine geçen dişliler her zaman zıt yönde döner."}],"ans":"Soldaki çark sağa dönerse diğeri ters yönde, yani sola döner."},{"q":"İki dişli çark yan yana takılı. Biri saat yönünde dönerken öteki hangi yöne döner?","fig":"<svg viewBox='0 0 320 170'><circle cx='105' cy='85' r='40' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='190' cy='85' r='40' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='105' cy='85' r='7' fill='#1a2b45'/><circle cx='190' cy='85' r='7' fill='#1a2b45'/><path d='M105 33 A52 52 0 0 1 140 58' fill='none' stroke='#e0552b' stroke-width='2.5'/><polygon points='140,58 145,48 132,52' fill='#e0552b'/><path d='M190 33 A52 52 0 0 0 155 58' fill='none' stroke='#e0552b' stroke-width='2.5'/><polygon points='155,58 150,48 163,52' fill='#e0552b'/><text x='148' y='160' font-size='12' text-anchor='middle' fill='#1a2b45'>birbirine geçmiş dişliler</text></svg>","steps":[{"t":"Temas eden dişliler","a":"birbirini döndürür","d":"Birbirine geçen iki dişli birbirini iterek döndürür."},{"t":"Yön kuralı","a":"zıt yön","d":"Biri saat yönünde dönerse diğeri saatin tersi yönde döner."}],"ans":"Öteki dişli, saatin tersi yönde döner."},{"q":"Bir büyük bir küçük dişli birbirine geçmiş. Sence hangisi daha hızlı döner?","fig":"<svg viewBox='0 0 320 170'><circle cx='95' cy='90' r='52' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='185' cy='90' r='26' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='95' cy='90' r='8' fill='#1a2b45'/><circle cx='185' cy='90' r='6' fill='#1a2b45'/><text x='95' y='95' font-size='12' text-anchor='middle' fill='#1a2b45'>büyük</text><text x='185' y='94' font-size='11' text-anchor='middle' fill='#1a2b45'>küçük</text><text x='160' y='160' font-size='12' text-anchor='middle' fill='#1a2b45'>hangisi daha hızlı?</text></svg>","steps":[{"t":"Diş sayısına bak","a":"küçükte az diş","d":"Küçük dişlinin dişi azdır, bir turu daha çabuk tamamlar."},{"t":"Hız kuralı","a":"küçük hızlı","d":"Az dişli olan küçük çark daha hızlı döner."}],"ans":"Küçük dişli daha hızlı döner."},{"q":"Üç dişli çark sıra sıra birbirine geçmiş. İlki sağa dönerse en sondaki ne yöne döner?","fig":"<svg viewBox='0 0 320 160'><circle cx='70' cy='80' r='32' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='140' cy='80' r='32' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='210' cy='80' r='32' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='70' cy='80' r='6' fill='#1a2b45'/><circle cx='140' cy='80' r='6' fill='#1a2b45'/><circle cx='210' cy='80' r='6' fill='#1a2b45'/><text x='70' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>1</text><text x='140' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>2</text><text x='210' y='135' font-size='11' text-anchor='middle' fill='#1a2b45'>3</text></svg>","steps":[{"t":"Birinci ve ikinci","a":"ters döner","d":"1. çark sağa dönerse, ona değen 2. çark sola döner."},{"t":"İkinci ve üçüncü","a":"yine ters","d":"2. çark sola dönerse, ona değen 3. çark tekrar sağa döner."}],"ans":"En sondaki çark, ilki gibi sağa döner."},{"q":"Bisikletin pedalını çevirince zincirin arka tekerlekteki dişliyi döndürmesi neye benzer?","fig":"<svg viewBox='0 0 320 160'><circle cx='90' cy='80' r='38' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='235' cy='80' r='20' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='90' cy='80' r='7' fill='#1a2b45'/><circle cx='235' cy='80' r='5' fill='#1a2b45'/><line x1='90' y1='42' x2='235' y2='60' stroke='#1a2b45' stroke-width='3'/><line x1='90' y1='118' x2='235' y2='100' stroke='#1a2b45' stroke-width='3'/><text x='90' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>pedal dişlisi</text><text x='235' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>teker dişlisi</text></svg>","steps":[{"t":"Zincir bağı","a":"zincirle döner","d":"Zincir, ön dişlinin hareketini arka dişliye taşır."},{"t":"Yön kuralı","a":"aynı yön","d":"Zincirle bağlı dişliler aynı yönde döner."}],"ans":"Zincirle bağlı dişliler aynı yönde döner; pedal dişlisi arka dişliyi de aynı yöne döndürür."}],"zor":[{"q":"Şekildeki iki dişliden büyük olanı bir tam tur attığında, küçük olan daha çok mu az mı tur atar?","fig":"<svg viewBox='0 0 320 170'><circle cx='100' cy='90' r='54' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='200' cy='90' r='27' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='90' r='8' fill='#1a2b45'/><circle cx='200' cy='90' r='6' fill='#1a2b45'/><text x='100' y='94' font-size='12' text-anchor='middle' fill='#1a2b45'>büyük</text><text x='200' y='94' font-size='10' text-anchor='middle' fill='#1a2b45'>küçük</text><text x='160' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>büyük 1 tur atarsa?</text></svg>","steps":[{"t":"Küçükte az diş var","a":"çabuk biter","d":"Küçük çarkın dişi az olduğu için bir turu daha kısa sürede tamamlar."},{"t":"Tur sayısı","a":"daha çok tur","d":"Büyük bir kez dönerken küçük birden fazla kez döner."}],"ans":"Küçük dişli, büyük bir tur atarken birkaç tur atar; yani daha çok döner."},{"q":"Çamaşır kurutma rafının kolu büyük bir dişliye bağlı, bu da küçük bir dişliyi döndürüyor. Kolu yavaş çevirsek bile çıkış neden hızlı olur?","steps":[{"t":"Büyükten küçüğe","a":"hız artar","d":"Hareket büyük dişliden küçüğe geçince küçük dişli daha hızlı döner."},{"t":"Sonuç","a":"hızlı çıkış","d":"Bu yüzden kolu yavaş çevirsek bile küçük dişli hızlı döner."}],"ans":"Büyük dişli küçüğü döndürünce hız arttığı için yavaş çevirsek de çıkış hızlı olur."},{"q":"Şekilde dört dişli çark sırayla birbirine geçmiş. En baştaki saat yönünde dönerse 1, 2, 3 ve 4. çarklar hangi yönde döner?","fig":"<svg viewBox='0 0 320 150'><circle cx='55' cy='75' r='28' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='118' cy='75' r='28' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='181' cy='75' r='28' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='244' cy='75' r='28' fill='#f3b0c3' stroke='#1a2b45' stroke-width='2'/><circle cx='55' cy='75' r='5' fill='#1a2b45'/><circle cx='118' cy='75' r='5' fill='#1a2b45'/><circle cx='181' cy='75' r='5' fill='#1a2b45'/><circle cx='244' cy='75' r='5' fill='#1a2b45'/><text x='55' y='125' font-size='11' text-anchor='middle' fill='#1a2b45'>1</text><text x='118' y='125' font-size='11' text-anchor='middle' fill='#1a2b45'>2</text><text x='181' y='125' font-size='11' text-anchor='middle' fill='#1a2b45'>3</text><text x='244' y='125' font-size='11' text-anchor='middle' fill='#1a2b45'>4</text></svg>","steps":[{"t":"Her komşu ters döner","a":"sıra ile değişir","d":"Birbirine değen dişliler hep ters yönde döner, yön sırayla değişir."},{"t":"Sırayı yaz","a":"saat, ters, saat, ters","d":"1 saat yönü, 2 ters, 3 saat yönü, 4 ters yönde döner."}],"ans":"1 ve 3. çark saat yönünde, 2 ve 4. çark saatin tersi yönde döner."},{"q":"Bir oyuncak vinçte küçük dişli büyük dişliyi döndürüyor. Yükü kaldırmak neden kolaylaşır?","steps":[{"t":"Küçükten büyüğe","a":"güç artar","d":"Hareket küçük dişliden büyüğe geçince döndürme gücü (tork) artar."},{"t":"Sonuç","a":"yük kolay kalkar","d":"Güç arttığı için ağır yükü kaldırmak kolaylaşır."}],"ans":"Küçük dişli büyüğü döndürünce güç arttığı için yükü kaldırmak kolaylaşır."},{"q":"İki dişli çarktan birinin 20 dişi, diğerinin 10 dişi var. 20 dişli olan bir tur dönerse, 10 dişli olan kaç tur döner?","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='48' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='195' cy='85' r='24' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='195' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='12' text-anchor='middle' fill='#1a2b45'>20 diş</text><text x='195' y='89' font-size='10' text-anchor='middle' fill='#1a2b45'>10 diş</text></svg>","steps":[{"t":"Aynı sayıda diş geçer","a":"20 diş geçer","d":"Büyük çark bir tur dönünce 20 diş karşı çarka aktarılır."},{"t":"Küçüğün turu","a":"20 ÷ 10","d":"Küçük çarkın 10 dişi olduğu için 20 dişi alınca 2 tur döner."}],"ans":"10 dişli çark 2 tur döner."}]},"ortaokul":{"kolay":[{"q":"Birbirine geçmiş iki dişli çarkın temas noktasında dişlerin hareketi neden ters yön oluşturur, açıklayınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='110' cy='85' r='44' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='205' cy='85' r='44' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='110' cy='85' r='8' fill='#1a2b45'/><circle cx='205' cy='85' r='8' fill='#1a2b45'/><path d='M110 28 A57 57 0 0 1 148 56' fill='none' stroke='#e0552b' stroke-width='2.5'/><polygon points='148,56 154,46 140,50' fill='#e0552b'/><path d='M205 28 A57 57 0 0 0 167 56' fill='none' stroke='#e0552b' stroke-width='2.5'/><polygon points='167,56 161,46 175,50' fill='#e0552b'/><text x='157' y='158' font-size='11' text-anchor='middle' fill='#1a2b45'>temas noktası</text></svg>","steps":[{"t":"Temas yüzeyi","a":"birbirini iter","d":"Temas noktasında bir çarkın dişi, diğerinin dişini iter."},{"t":"Yön sonucu","a":"zıt yön","d":"İtme aynı doğrultuda olunca çarklar zıt yönde dönmek zorunda kalır."}],"ans":"Temas noktasında dişler birbirini ittiği için birbirine geçen dişliler zıt yönde döner."},{"q":"40 dişli bir çark, 20 dişli bir çarkı döndürüyor. Diş sayısı oranına göre küçük çark büyüğün kaç katı hızla döner?","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='50' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='195' cy='85' r='25' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='195' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='12' text-anchor='middle' fill='#1a2b45'>40 diş</text><text x='195' y='89' font-size='10' text-anchor='middle' fill='#1a2b45'>20 diş</text></svg>","steps":[{"t":"Oranı kur","a":"40 ÷ 20","d":"Hız oranı, diş sayılarının tersine eşittir; büyük diş sayısını küçüğe böleriz."},{"t":"Sonuç","a":"2 kat","d":"40'ı 20'ye bölünce 2 çıkar; küçük çark 2 kat hızlı döner."}],"ans":"Küçük çark, büyük çarkın 2 katı hızla döner."},{"q":"Zincirle bağlı iki dişli (bisiklet gibi) neden aynı yönde döner, kısaca açıklayınız.","fig":"<svg viewBox='0 0 320 160'><circle cx='85' cy='80' r='40' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='235' cy='80' r='22' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='85' cy='80' r='7' fill='#1a2b45'/><circle cx='235' cy='80' r='5' fill='#1a2b45'/><line x1='85' y1='40' x2='235' y2='58' stroke='#1a2b45' stroke-width='3'/><line x1='85' y1='120' x2='235' y2='102' stroke='#1a2b45' stroke-width='3'/><path d='M85 33 A47 47 0 0 1 120 52' fill='none' stroke='#e0552b' stroke-width='2'/><polygon points='120,52 126,43 112,46' fill='#e0552b'/><text x='160' y='148' font-size='11' text-anchor='middle' fill='#1a2b45'>zincirle bağlı</text></svg>","steps":[{"t":"Zincir gergin tarafı","a":"aynı yöne çeker","d":"Zincir, ön dişlinin üst tarafını çekince arka dişlinin de üst tarafını aynı yöne çeker."},{"t":"Yön sonucu","a":"aynı yön","d":"Bu yüzden zincir/kayışla bağlı dişliler aynı yönde döner, birbirine geçenler ise ters."}],"ans":"Zincir her iki dişliyi aynı yönde çektiği için zincirle bağlı dişliler aynı yönde döner."},{"q":"Küçük bir dişliden büyük bir dişliye geçildiğinde hız ve döndürme kuvveti (tork) nasıl değişir?","steps":[{"t":"Hıza etki","a":"hız azalır","d":"Büyük dişli daha çok dişe sahip olduğu için daha yavaş döner."},{"t":"Torka etki","a":"tork artar","d":"Hız azalırken döndürme kuvveti (tork) artar; büyük dişli daha güçlüdür."}],"ans":"Küçükten büyüğe geçince hız azalır, döndürme kuvveti (tork) artar."},{"q":"Şekildeki dişli treninde 1. çark döndürülüyor. Ortadaki ara çark yön bakımından ne işe yarar?","fig":"<svg viewBox='0 0 320 150'><circle cx='65' cy='75' r='32' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='150' cy='75' r='25' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='228' cy='75' r='32' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='65' cy='75' r='6' fill='#1a2b45'/><circle cx='150' cy='75' r='5' fill='#1a2b45'/><circle cx='228' cy='75' r='6' fill='#1a2b45'/><text x='65' y='128' font-size='11' text-anchor='middle' fill='#1a2b45'>1</text><text x='150' y='128' font-size='11' text-anchor='middle' fill='#1a2b45'>ara</text><text x='228' y='128' font-size='11' text-anchor='middle' fill='#1a2b45'>3</text></svg>","steps":[{"t":"Ara çarkın etkisi","a":"yönü çevirir","d":"Araya bir çark eklenince çıkış yönü değişir; 1 ile 3 aynı yöne döner."},{"t":"Hıza etkisi","a":"oranı değiştirmez","d":"Ara çark, giriş ile çıkış arasındaki hız oranını değiştirmez, sadece yönü ayarlar."}],"ans":"Ara çark çıkış yönünü değiştirir (1 ve 3 aynı yöne döner) ama hız oranını etkilemez."},{"q":"Diş sayısı 30 olan çark dakikada 10 tur atıyor. Buna geçen 15 dişli çark dakikada kaç tur atar?","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='48' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='192' cy='85' r='24' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='192' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>30 diş</text><text x='192' y='89' font-size='10' text-anchor='middle' fill='#1a2b45'>15 diş</text></svg>","steps":[{"t":"İlişkiyi kur","a":"N₁·n₁ = N₂·n₂","d":"Diş sayısı × devir çarpımı iki dişlide eşittir."},{"t":"Yerine koy","a":"30·10 = 15·n₂","d":"Soldaki çarpım 300'dür, bunu 15'e bölmeliyiz."},{"t":"Sonuç","a":"300 ÷ 15 = 20","d":"15 dişli çark dakikada 20 tur atar."}],"ans":"15 dişli çark dakikada 20 tur atar."}],"zor":[{"q":"24 dişli çark, 8 dişli çarkı döndürüyor. 24 dişli olan 5 tur attığında küçük çark kaç tur atar?","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='52' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='192' cy='85' r='20' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='192' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='12' text-anchor='middle' fill='#1a2b45'>24 diş</text><text x='192' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>8 diş</text></svg>","steps":[{"t":"İlişkiyi kur","a":"N₁·n₁ = N₂·n₂","d":"Birbirine geçen dişlilerde diş sayısı ile devir çarpımı eşittir."},{"t":"Yerine koy","a":"24·5 = 8·n₂","d":"Büyük çarkın çarpımı 120'dir, bunu küçüğün diş sayısına böleriz."},{"t":"Sonuç","a":"120 ÷ 8 = 15","d":"Küçük çark 15 tur atar."}],"ans":"8 dişli küçük çark 15 tur atar."},{"q":"İki dişlide devir oranı n₂/n₁ ile diş sayısı oranı N₁/N₂ arasındaki bağıntıyı açıklayınız.","steps":[{"t":"Temel kural","a":"diş geçişi eşit","d":"Temas noktasında her iki çarktan aynı sayıda diş geçer, bu yüzden N₁·n₁ = N₂·n₂'dir."},{"t":"Oranı düzenle","a":"n₂/n₁ = N₁/N₂","d":"Eşitliği düzenleyince devir oranı, diş sayısı oranının tersine eşit çıkar."}],"ans":"Devir oranı diş sayısı oranının tersidir: n₂/n₁ = N₁/N₂; az dişli çark daha hızlı döner."},{"q":"Şekildeki dişli treninde 36 dişli giriş çarkı, 12 dişli ara çark üzerinden 18 dişli çıkış çarkını döndürüyor. Giriş 6 tur atarsa çıkış kaç tur atar?","fig":"<svg viewBox='0 0 320 160'><circle cx='62' cy='80' r='38' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='140' cy='80' r='22' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='220' cy='80' r='30' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='62' cy='80' r='6' fill='#1a2b45'/><circle cx='140' cy='80' r='5' fill='#1a2b45'/><circle cx='220' cy='80' r='6' fill='#1a2b45'/><text x='62' y='84' font-size='10' text-anchor='middle' fill='#1a2b45'>36</text><text x='140' y='84' font-size='9' text-anchor='middle' fill='#1a2b45'>12</text><text x='220' y='84' font-size='10' text-anchor='middle' fill='#1a2b45'>18</text><text x='62' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>giriş</text><text x='140' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>ara</text><text x='220' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>çıkış</text></svg>","steps":[{"t":"Ara çark elenir","a":"oran giriş/çıkış","d":"Ara çark hız oranını etkilemez; oran sadece giriş ve çıkış diş sayılarına bağlıdır."},{"t":"İlişkiyi kur","a":"36·6 = 18·n","d":"Giriş diş × devir = çıkış diş × devir eşitliğini kurarız."},{"t":"Sonuç","a":"216 ÷ 18 = 12","d":"Çıkış çarkı 12 tur atar."}],"ans":"Çıkış çarkı 12 tur atar (ara çark sadece yönü değiştirir)."},{"q":"Bir bisiklette 48 dişli ön (pedal) dişlisi, 16 dişli arka dişliyi döndürüyor. Pedal 1 tur dönünce arka teker kaç tur döner?","fig":"<svg viewBox='0 0 320 160'><circle cx='90' cy='80' r='46' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='240' cy='80' r='18' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='90' cy='80' r='7' fill='#1a2b45'/><circle cx='240' cy='80' r='5' fill='#1a2b45'/><line x1='90' y1='34' x2='240' y2='62' stroke='#1a2b45' stroke-width='3'/><line x1='90' y1='126' x2='240' y2='98' stroke='#1a2b45' stroke-width='3'/><text x='90' y='84' font-size='11' text-anchor='middle' fill='#1a2b45'>48</text><text x='240' y='84' font-size='9' text-anchor='middle' fill='#1a2b45'>16</text></svg>","steps":[{"t":"İlişkiyi kur","a":"N₁·n₁ = N₂·n₂","d":"Zincirle bağlı dişlilerde de diş × devir çarpımı eşittir."},{"t":"Yerine koy","a":"48·1 = 16·n₂","d":"Ön çarpım 48'dir, bunu arka diş sayısına böleriz."},{"t":"Sonuç","a":"48 ÷ 16 = 3","d":"Arka dişli (ve teker) 3 tur döner."}],"ans":"Pedal 1 tur dönünce arka teker 3 tur döner."},{"q":"60 dişli çark dakikada 8 tur atıyor. Bu çark 40 dişli bir çarkı döndürüyorsa küçük çarkın devir sayısını bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='50' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='198' cy='85' r='34' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='198' cy='85' r='6' fill='#1a2b45'/><text x='100' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>60 diş</text><text x='198' y='89' font-size='10' text-anchor='middle' fill='#1a2b45'>40 diş</text></svg>","steps":[{"t":"İlişkiyi kur","a":"N₁·n₁ = N₂·n₂","d":"Diş sayısı ile devir çarpımı iki çarkta eşittir."},{"t":"Yerine koy","a":"60·8 = 40·n₂","d":"Soldaki çarpım 480'dir, bunu 40'a böleriz."},{"t":"Sonuç","a":"480 ÷ 40 = 12","d":"40 dişli çark dakikada 12 tur atar."}],"ans":"40 dişli çark dakikada 12 tur atar."}]},"lise":{"kolay":[{"q":"Birbirine geçen iki dişlide diş sayısı oranı ile devir (frekans) oranı arasındaki temel bağıntı nedir?","steps":[{"t":"Çizgisel hız eşit","a":"temas noktasında v eşit","d":"Temas noktasında her iki çarkın çizgisel hızı aynıdır, bu yüzden geçen diş sayısı eşittir."},{"t":"Bağıntı","a":"N₁·n₁ = N₂·n₂","d":"Buradan n₁/n₂ = N₂/N₁ çıkar; devir oranı diş sayısı oranının tersidir."}],"ans":"N₁·n₁ = N₂·n₂'dir; devir oranı diş sayısı oranının tersidir (az dişli hızlı döner)."},{"q":"Birbirine geçen iki dişli neden zıt yönde, zincirle bağlı iki dişli neden aynı yönde döner?","fig":"<svg viewBox='0 0 320 180'><circle cx='75' cy='55' r='30' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='140' cy='55' r='30' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><path d='M75 22 A33 33 0 0 1 100 38' fill='none' stroke='#e0552b' stroke-width='2'/><polygon points='100,38 106,29 92,32' fill='#e0552b'/><path d='M140 22 A33 33 0 0 0 115 38' fill='none' stroke='#e0552b' stroke-width='2'/><polygon points='115,38 109,29 123,32' fill='#e0552b'/><text x='107' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>geçmiş: ters</text><circle cx='220' cy='130' r='24' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='285' cy='130' r='16' fill='#f3b0c3' stroke='#1a2b45' stroke-width='2'/><line x1='220' y1='106' x2='285' y2='114' stroke='#1a2b45' stroke-width='2'/><line x1='220' y1='154' x2='285' y2='146' stroke='#1a2b45' stroke-width='2'/><text x='250' y='172' font-size='10' text-anchor='middle' fill='#1a2b45'>zincir: aynı</text></svg>","steps":[{"t":"Doğrudan temas","a":"itme zıt yön","d":"Birbirine geçen dişlilerde temas noktasındaki itme, çarkları zıt yönde döndürür."},{"t":"Zincir/kayış","a":"aynı yön","d":"Zincir her iki kasnağın aynı tarafını aynı yönde çektiği için aynı yönde dönerler."}],"ans":"Doğrudan temasta dişler birbirini ittiği için ters yön; zincir/kayış aynı tarafı çektiği için aynı yön oluşur."},{"q":"45 dişli çark dakikada 12 tur atıyor. Buna geçen 15 dişli çarkın devir sayısını bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='52' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='192' cy='85' r='20' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='192' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>45 diş</text><text x='192' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>15 diş</text></svg>","steps":[{"t":"Bağıntı","a":"N₁·n₁ = N₂·n₂","d":"Diş sayısı ile devir çarpımı iki çarkta eşittir."},{"t":"Yerine koy","a":"45·12 = 15·n₂","d":"Soldaki çarpım 540'tır, bunu 15'e böleriz."},{"t":"Sonuç","a":"540 ÷ 15 = 36","d":"15 dişli çark dakikada 36 tur atar."}],"ans":"15 dişli çark dakikada 36 tur atar."},{"q":"Bir dişli sisteminde küçük dişliden büyük dişliye geçildiğinde devir sayısı ve tork nasıl değişir?","steps":[{"t":"Devre etki","a":"devir azalır","d":"Büyük dişlinin diş sayısı fazla olduğu için daha az devir (yavaş) yapar."},{"t":"Güç korunumu","a":"tork artar","d":"Güç korunduğundan (P = M·ω) devir azalırken tork (döndürme momenti) artar."}],"ans":"Küçükten büyüğe geçince devir sayısı azalır, tork (döndürme momenti) artar."},{"q":"Şekildeki dişli treninde 30 dişli giriş, 10 dişli ara, 30 dişli çıkış çarkına bağlı. Giriş ve çıkış arasındaki devir oranı kaçtır?","fig":"<svg viewBox='0 0 320 150'><circle cx='62' cy='75' r='34' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='140' cy='75' r='18' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='215' cy='75' r='34' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='62' cy='75' r='6' fill='#1a2b45'/><circle cx='140' cy='75' r='4' fill='#1a2b45'/><circle cx='215' cy='75' r='6' fill='#1a2b45'/><text x='62' y='79' font-size='10' text-anchor='middle' fill='#1a2b45'>30</text><text x='140' y='79' font-size='9' text-anchor='middle' fill='#1a2b45'>10</text><text x='215' y='79' font-size='10' text-anchor='middle' fill='#1a2b45'>30</text></svg>","steps":[{"t":"Ara çark elenir","a":"oran giriş/çıkış","d":"Ara çark hız oranını değiştirmez, sadece çıkış yönünü çevirir."},{"t":"Oranı kur","a":"30/30 = 1","d":"Giriş ve çıkış diş sayıları eşit olduğu için devir oranı 1'dir."}],"ans":"Giriş ile çıkış devir oranı 1'dir; aynı hızda, ara çark sayesinde aynı yönde dönerler."},{"q":"İki dişlinin diş sayıları 50 ve 20'dir. Devir oranı n(20diş)/n(50diş) kaçtır?","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='52' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='194' cy='85' r='26' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='194' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>50 diş</text><text x='194' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>20 diş</text></svg>","steps":[{"t":"Bağıntı","a":"n₂/n₁ = N₁/N₂","d":"Devir oranı, diş sayısı oranının tersine eşittir."},{"t":"Yerine koy","a":"50 ÷ 20","d":"Küçük çarkın devrini büyüğünkine bölmek, büyük diş/küçük diş oranını verir."},{"t":"Sonuç","a":"2,5","d":"50'yi 20'ye bölünce 2,5 çıkar."}],"ans":"Devir oranı 2,5'tir; 20 dişli çark, 50 dişlinin 2,5 katı hızla döner."},{"q":"Dişli treninde 'ara çark' (rölanti dişlisi) sistemin devir oranını neden etkilemez?","fig":"<svg viewBox='0 0 320 150'><circle cx='62' cy='75' r='32' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='140' cy='75' r='22' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='220' cy='75' r='28' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='62' cy='75' r='5' fill='#1a2b45'/><circle cx='140' cy='75' r='5' fill='#1a2b45'/><circle cx='220' cy='75' r='5' fill='#1a2b45'/><text x='140' y='128' font-size='10' text-anchor='middle' fill='#1a2b45'>ara (rölanti)</text></svg>","steps":[{"t":"Çift rol","a":"hem giriş hem çıkış","d":"Ara çark, kendinden önceki çarkça döndürülür ve sonraki çarkı döndürür."},{"t":"Oranlar sadeleşir","a":"sadeleşir","d":"N₁/Nₐ × Nₐ/N₂ çarpımında ara çark diş sayısı Nₐ sadeleşir, sonuç N₁/N₂ kalır."}],"ans":"Ara çarkın diş sayısı çarpımda sadeleştiği için devir oranını etkilemez; yalnızca çıkış yönünü değiştirir."},{"q":"60 dişli ve 15 dişli iki çark birbirine geçmiş. 60 dişli olan dakikada 6 tur atarsa 15 dişlinin devrini bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='54' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='190' cy='85' r='18' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='190' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>60 diş</text><text x='190' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>15 diş</text></svg>","steps":[{"t":"Bağıntı","a":"N₁·n₁ = N₂·n₂","d":"Diş sayısı ile devir çarpımı eşittir."},{"t":"Yerine koy","a":"60·6 = 15·n₂","d":"Soldaki çarpım 360'tır, bunu 15'e böleriz."},{"t":"Sonuç","a":"360 ÷ 15 = 24","d":"15 dişli çark dakikada 24 tur atar."}],"ans":"15 dişli çark dakikada 24 tur atar."},{"q":"İki dişlinin yarıçapları temas için belirleyicidir. Diş aralığı (modül) eşitse diş sayısı ile yarıçap arasında nasıl bir ilişki vardır?","steps":[{"t":"Modül tanımı","a":"diş büyüklüğü eşit","d":"İç içe geçen dişlilerde diş aralığı (modül) aynı olmalıdır."},{"t":"İlişki","a":"N ∝ r","d":"Aynı modülde çarkın çevresi diş sayısıyla orantılı olduğundan, diş sayısı yarıçapla doğru orantılıdır."}],"ans":"Aynı modülde diş sayısı yarıçapla doğru orantılıdır; büyük yarıçaplı çarkın dişi daha çoktur."},{"q":"Bir kayışla bağlı iki kasnaktan büyük olanı (R = 20 cm) dakikada 10 tur atıyor. Küçük kasnak (r = 5 cm) kaç tur atar?","fig":"<svg viewBox='0 0 320 160'><circle cx='85' cy='80' r='44' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='235' cy='80' r='18' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='85' cy='80' r='6' fill='#1a2b45'/><circle cx='235' cy='80' r='4' fill='#1a2b45'/><line x1='85' y1='36' x2='235' y2='62' stroke='#1a2b45' stroke-width='2'/><line x1='85' y1='124' x2='235' y2='98' stroke='#1a2b45' stroke-width='2'/><text x='85' y='84' font-size='10' text-anchor='middle' fill='#1a2b45'>R=20</text><text x='235' y='84' font-size='9' text-anchor='middle' fill='#1a2b45'>r=5</text></svg>","steps":[{"t":"Çizgisel hız eşit","a":"R·n eşit","d":"Kayışla bağlı kasnaklarda çizgisel hız aynıdır: R₁·n₁ = R₂·n₂."},{"t":"Yerine koy","a":"20·10 = 5·n₂","d":"Soldaki çarpım 200'dür, bunu 5'e böleriz."},{"t":"Sonuç","a":"200 ÷ 5 = 40","d":"Küçük kasnak dakikada 40 tur atar."}],"ans":"Küçük kasnak dakikada 40 tur atar."},{"q":"Dişli kutusunda 'düşürme' (yavaşlatma) istendiğinde giriş ve çıkış dişlilerinin diş sayıları nasıl seçilir?","steps":[{"t":"Hedef","a":"çıkış yavaş","d":"Yavaşlatma için çıkış devrinin girişten küçük olması istenir."},{"t":"Diş seçimi","a":"çıkış dişi çok","d":"Çıkış dişlisinin diş sayısı girişten büyük seçilir; böylece devir düşer, tork artar."}],"ans":"Çıkış dişlisi girişten daha çok dişe sahip seçilir; böylece devir düşer (yavaşlar), tork artar."},{"q":"40 dişli ve 10 dişli iki çarktan oluşan sistemde küçük çarkın devri 200 tur/dk. Büyük çarkın devrini bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='105' cy='85' r='52' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='198' cy='85' r='18' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='105' cy='85' r='7' fill='#1a2b45'/><circle cx='198' cy='85' r='5' fill='#1a2b45'/><text x='105' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>40 diş</text><text x='198' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>10 diş</text></svg>","steps":[{"t":"Bağıntı","a":"N₁·n₁ = N₂·n₂","d":"Diş sayısı ile devir çarpımı eşittir."},{"t":"Yerine koy","a":"40·n₁ = 10·200","d":"Sağdaki çarpım 2000'dir, bunu 40'a böleriz."},{"t":"Sonuç","a":"2000 ÷ 40 = 50","d":"40 dişli büyük çark dakikada 50 tur atar."}],"ans":"40 dişli büyük çark dakikada 50 tur atar."},{"q":"Dişli sisteminde verim kayıpları ihmal edilirse giriş ve çıkış güçleri için ne söylenebilir?","steps":[{"t":"Enerji korunumu","a":"güç korunur","d":"Sürtünme ihmal edilirse giriş gücü çıkış gücüne eşittir (P = M·ω sabit)."},{"t":"Sonuç","a":"M·ω sabit","d":"Devir artarsa tork azalır, devir azalırsa tork artar; çarpımları sabit kalır."}],"ans":"İdeal durumda giriş ve çıkış güçleri eşittir; tork ile açısal hızın çarpımı sabit kalır."},{"q":"Bir bisiklette ön dişli 52 diş, arka dişli 13 diş. Pedalın 1 turunda arka tekerin kaç tur döndüğünü bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='90' cy='80' r='48' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='245' cy='80' r='16' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='90' cy='80' r='7' fill='#1a2b45'/><circle cx='245' cy='80' r='4' fill='#1a2b45'/><line x1='90' y1='32' x2='245' y2='64' stroke='#1a2b45' stroke-width='3'/><line x1='90' y1='128' x2='245' y2='96' stroke='#1a2b45' stroke-width='3'/><text x='90' y='84' font-size='11' text-anchor='middle' fill='#1a2b45'>52</text><text x='245' y='84' font-size='9' text-anchor='middle' fill='#1a2b45'>13</text></svg>","steps":[{"t":"Bağıntı","a":"N₁·n₁ = N₂·n₂","d":"Zincirle bağlı dişlilerde diş × devir çarpımı eşittir."},{"t":"Yerine koy","a":"52·1 = 13·n₂","d":"Ön çarpım 52'dir, bunu arka diş sayısına böleriz."},{"t":"Sonuç","a":"52 ÷ 13 = 4","d":"Arka teker 4 tur döner."}],"ans":"Pedal 1 tur dönünce arka teker 4 tur döner."},{"q":"Birbirine geçen iki dişlide temas noktasındaki çizgisel hızların eşit olması neden devir oranını belirler?","fig":"<svg viewBox='0 0 320 160'><circle cx='105' cy='80' r='46' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='205' cy='80' r='30' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='105' cy='80' r='7' fill='#1a2b45'/><circle cx='205' cy='80' r='5' fill='#1a2b45'/><line x1='151' y1='80' x2='175' y2='80' stroke='#e0552b' stroke-width='3'/><text x='162' y='66' font-size='10' text-anchor='middle' fill='#e0552b'>v eşit</text><text x='105' y='84' font-size='10' text-anchor='middle' fill='#1a2b45'>r₁</text><text x='205' y='84' font-size='10' text-anchor='middle' fill='#1a2b45'>r₂</text></svg>","steps":[{"t":"Hız eşitliği","a":"v = ω·r","d":"Temas noktasında kaymama varsa iki çarkın çizgisel hızı eşittir: ω₁·r₁ = ω₂·r₂."},{"t":"Devre bağla","a":"ω ∝ 1/r","d":"Açısal hız (ve devir), yarıçap (dolayısıyla diş sayısı) ile ters orantılı çıkar."}],"ans":"Temas hızı eşit olduğu için ω₁·r₁ = ω₂·r₂'dir; devir, diş sayısıyla ters orantılı olur."}],"zor":[{"q":"36 dişli giriş çarkı, 12 dişli çıkış çarkını döndürüyor. Giriş 100 tur/dk atarsa çıkış devrini ve devir oranını bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='52' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='192' cy='85' r='20' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='192' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>36 diş</text><text x='192' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>12 diş</text></svg>","steps":[{"t":"Bağıntı","a":"N₁·n₁ = N₂·n₂","d":"Diş sayısı ile devir çarpımı eşittir."},{"t":"Yerine koy","a":"36·100 = 12·n₂","d":"Soldaki çarpım 3600'dür, bunu 12'ye böleriz."},{"t":"Sonuç","a":"300 tur/dk","d":"Çıkış devri 300 tur/dk, devir oranı 300/100 = 3'tür."}],"ans":"Çıkış devri 300 tur/dk, devir oranı 3'tür (çıkış girişin 3 katı hızlı)."},{"q":"Bir dişli kutusunda giriş torku 6 N·m, dişli oranı (çıkış diş/giriş diş) 3. İdeal verimle çıkış torkunu bulunuz.","steps":[{"t":"Tork-oran ilişkisi","a":"M ∝ N","d":"İdeal sistemde tork, diş sayısıyla doğru orantılıdır; büyük çarkta tork büyür."},{"t":"Yerine koy","a":"6 × 3","d":"Çıkış dişlisi girişin 3 katı dişe sahip olduğundan tork 3 katına çıkar."},{"t":"Sonuç","a":"18 N·m","d":"6 N·m ile 3 çarpılınca 18 N·m bulunur."}],"ans":"Çıkış torku 18 N·m'dir; devir 3 kat azalırken tork 3 kat artmıştır."},{"q":"Şekildeki iki kademeli dişli treninde 40 dişli giriş, aynı milde 30 ve 10 dişli ara çiftine, oradan 50 dişli çıkışa bağlı (40→30, 10→50). Giriş 150 tur/dk ise çıkış devrini bulunuz.","fig":"<svg viewBox='0 0 320 170'><circle cx='60' cy='60' r='30' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><text x='60' y='64' font-size='10' text-anchor='middle' fill='#1a2b45'>40</text><circle cx='130' cy='60' r='24' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><text x='130' y='64' font-size='9' text-anchor='middle' fill='#1a2b45'>30</text><circle cx='130' cy='60' r='10' fill='#ffd54a' stroke='#1a2b45' stroke-width='1.5'/><text x='130' y='110' font-size='9' text-anchor='middle' fill='#1a2b45'>30 ve 10 aynı mil</text><circle cx='130' cy='128' r='10' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><text x='130' y='132' font-size='8' text-anchor='middle' fill='#1a2b45'>10</text><circle cx='225' cy='128' r='34' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><text x='225' y='132' font-size='10' text-anchor='middle' fill='#1a2b45'>50</text></svg>","steps":[{"t":"1. kademe","a":"40·150 = 30·nₐ","d":"İlk çift 40→30: ara mil devri 6000 ÷ 30 = 200 tur/dk olur."},{"t":"2. kademe","a":"10·200 = 50·n","d":"Aynı milde 10 dişli çark 200 tur/dk döner; bu 50 dişli çıkışı döndürür."},{"t":"Sonuç","a":"2000 ÷ 50 = 40","d":"Çıkış devri 40 tur/dk bulunur."}],"ans":"Çıkış devri 40 tur/dk'dır (iki kademeli yavaşlatma)."},{"q":"24 dişli ve 8 dişli iki çark birbirine geçmiş. Küçük çark 600 tur/dk dönerken büyük çarkın devrini ve birinin diğerine göre dönme yönünü açıklayınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='105' cy='85' r='52' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='192' cy='85' r='20' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='105' cy='85' r='7' fill='#1a2b45'/><circle cx='192' cy='85' r='5' fill='#1a2b45'/><path d='M105 33 A52 52 0 0 0 70 58' fill='none' stroke='#e0552b' stroke-width='2'/><polygon points='70,58 64,48 78,52' fill='#e0552b'/><path d='M192 65 A20 20 0 0 1 210 80' fill='none' stroke='#e0552b' stroke-width='2'/><polygon points='210,80 217,72 205,71' fill='#e0552b'/><text x='105' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>24</text><text x='192' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>8</text></svg>","steps":[{"t":"Devri bul","a":"8·600 = 24·n","d":"Çarpım 4800'dür, bunu 24'e bölünce büyük çark 200 tur/dk döner."},{"t":"Yönü belirle","a":"zıt yön","d":"Birbirine geçen dişliler olduğu için büyük çark, küçüğün tersi yönde döner."}],"ans":"Büyük çark 200 tur/dk döner ve küçük çarkın tersi yönde döner."},{"q":"Bir dişli sisteminde giriş gücü 120 W. Giriş çarkı 60 dişli, çıkış çarkı 20 dişli ve giriş 30 tur/dk. İdeal sistemde çıkış torkunu bulunuz.","steps":[{"t":"Çıkış devri","a":"60·30 = 20·n","d":"Çarpım 1800'dür, bunu 20'ye bölünce çıkış 90 tur/dk olur."},{"t":"Açısal hız","a":"ω = 2π·n","d":"90 tur/dk = 1,5 tur/s; ω = 2π·1,5 ≈ 9,42 rad/s'dir."},{"t":"Torku bul","a":"M = P/ω","d":"İdeal güç korunduğundan M = 120 ÷ 9,42 ≈ 12,7 N·m bulunur."}],"ans":"Çıkış torku yaklaşık 12,7 N·m'dir (devir artarken güç korunduğundan tork ona göre belirlenir)."},{"q":"İki dişlide diş sayıları toplamı 60, devir oranı (büyük/küçük diş) ise 2'dir. Her iki çarkın diş sayısını bulunuz.","steps":[{"t":"Oranı yaz","a":"N₁ = 2·N₂","d":"Büyük çark diş sayısı, küçüğün 2 katıdır."},{"t":"Toplama koy","a":"2N₂ + N₂ = 60","d":"İki diş sayısı toplamı 60 olduğundan 3·N₂ = 60 olur."},{"t":"Sonuç","a":"N₂=20, N₁=40","d":"Küçük çark 20, büyük çark 40 dişlidir."}],"ans":"Küçük çark 20, büyük çark 40 dişlidir."},{"q":"50 dişli çark 18 tur/dk dönerken birbirine geçtiği çarkı 45 tur/dk döndürüyor. Karşı çarkın diş sayısını bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='100' cy='85' r='50' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='192' cy='85' r='28' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='7' fill='#1a2b45'/><circle cx='192' cy='85' r='5' fill='#1a2b45'/><text x='100' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>50 diş</text><text x='192' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>N=?</text></svg>","steps":[{"t":"Bağıntı","a":"N₁·n₁ = N₂·n₂","d":"Diş sayısı ile devir çarpımı eşittir."},{"t":"Yerine koy","a":"50·18 = N₂·45","d":"Soldaki çarpım 900'dür, bunu karşı çarkın devrine böleriz."},{"t":"Sonuç","a":"900 ÷ 45 = 20","d":"Karşı çark 20 dişlidir."}],"ans":"Karşı çark 20 dişlidir."},{"q":"Bir vinçte motor 16 dişli çarka bağlı, bu da 64 dişli tambur çarkını döndürüyor. Motor 8 N·m tork üretiyorsa ideal durumda tamburdaki torku ve devir oranını bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='95' cy='85' r='22' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='205' cy='85' r='52' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='95' cy='85' r='5' fill='#1a2b45'/><circle cx='205' cy='85' r='7' fill='#1a2b45'/><text x='95' y='89' font-size='9' text-anchor='middle' fill='#1a2b45'>16</text><text x='205' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>64 diş</text><text x='95' y='128' font-size='9' text-anchor='middle' fill='#1a2b45'>motor</text></svg>","steps":[{"t":"Devir oranı","a":"16/64 = 1/4","d":"Çıkış (64 diş) girişin 1/4'ü hızla döner; yani 4 kat yavaşlar."},{"t":"Torku bul","a":"M ∝ N","d":"İdeal sistemde tork diş sayısıyla doğru orantılı: tambur torku 8 × (64/16) olur."},{"t":"Sonuç","a":"8 × 4 = 32 N·m","d":"Tambur torku 32 N·m bulunur."}],"ans":"Tambur torku 32 N·m, çıkış devri girişin 1/4'üdür; yavaşlayıp güçlenir."},{"q":"İki kademeli redüktörde her kademe devri 1/3 oranında düşürüyor. Giriş 900 tur/dk ise çıkış devrini bulunuz.","steps":[{"t":"1. kademe","a":"900 × 1/3","d":"İlk kademe sonunda devir 900'ün 1/3'ü, yani 300 tur/dk olur."},{"t":"2. kademe","a":"300 × 1/3","d":"İkinci kademe de 1/3 düşürür: 300'ün 1/3'ü 100 tur/dk'dır."},{"t":"Toplam oran","a":"1/9","d":"İki kademe çarpılır: toplam oran (1/3)² = 1/9'dur."}],"ans":"Çıkış devri 100 tur/dk'dır; toplam yavaşlatma oranı 1/9'dur."},{"q":"30 dişli ve 45 dişli iki çark birbirine geçmiş. 30 dişli çark saat yönünde 60 tur/dk dönüyor. 45 dişlinin devri ve dönme yönünü bulunuz.","fig":"<svg viewBox='0 0 320 170'><circle cx='100' cy='85' r='40' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='200' cy='85' r='54' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='100' cy='85' r='6' fill='#1a2b45'/><circle cx='200' cy='85' r='8' fill='#1a2b45'/><path d='M100 45 A40 40 0 0 1 130 62' fill='none' stroke='#e0552b' stroke-width='2'/><polygon points='130,62 137,54 124,52' fill='#e0552b'/><path d='M200 31 A54 54 0 0 0 165 56' fill='none' stroke='#e0552b' stroke-width='2'/><polygon points='165,56 159,46 173,50' fill='#e0552b'/><text x='100' y='89' font-size='10' text-anchor='middle' fill='#1a2b45'>30</text><text x='200' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>45 diş</text></svg>","steps":[{"t":"Devri bul","a":"30·60 = 45·n","d":"Çarpım 1800'dür, bunu 45'e bölünce 45 dişli çark 40 tur/dk döner."},{"t":"Yönü belirle","a":"saatin tersi","d":"Birbirine geçtikleri için 45 dişli çark, saat yönünün tersine döner."}],"ans":"45 dişli çark 40 tur/dk ve saatin tersi yönde döner."},{"q":"Bir dişli treninde 20→40→? sırasıyla bağlı üç çark var; ilki ile sonuncu arasında devir oranı 1/4 isteniyor. Sonuncu çarkın diş sayısını bulunuz.","steps":[{"t":"Ara çark elenir","a":"oran ilk/son","d":"40 dişli ara çark devir oranını etkilemez; oran yalnızca ilk (20) ve son çark diş sayısına bağlıdır."},{"t":"Oranı kur","a":"n_son/n_ilk = N_ilk/N_son","d":"İstenen 1/4 oranı için N_ilk/N_son = 1/4, yani 20/N_son = 1/4 olur."},{"t":"Sonuç","a":"N_son = 80","d":"20'yi 1/4 oranına bölünce sonuncu çark 80 diş bulunur."}],"ans":"Sonuncu çark 80 dişlidir; ara çark yalnızca yönü değiştirir, orana etkisi yoktur."},{"q":"Şekildeki üç dişli treninde diş sayıları 12, 24, 12. Giriş 12 dişli çark 200 tur/dk dönerse çıkış 12 dişli çarkın devrini ve yön ilişkisini bulunuz.","fig":"<svg viewBox='0 0 320 150'><circle cx='58' cy='75' r='24' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='140' cy='75' r='42' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='222' cy='75' r='24' fill='#a6d8a8' stroke='#1a2b45' stroke-width='2'/><circle cx='58' cy='75' r='5' fill='#1a2b45'/><circle cx='140' cy='75' r='6' fill='#1a2b45'/><circle cx='222' cy='75' r='5' fill='#1a2b45'/><text x='58' y='79' font-size='9' text-anchor='middle' fill='#1a2b45'>12</text><text x='140' y='79' font-size='10' text-anchor='middle' fill='#1a2b45'>24</text><text x='222' y='79' font-size='9' text-anchor='middle' fill='#1a2b45'>12</text></svg>","steps":[{"t":"Ara çark elenir","a":"oran giriş/çıkış","d":"24 dişli ara çark devir oranını etkilemez; giriş ve çıkış diş sayıları eşittir (12 = 12)."},{"t":"Devri bul","a":"oran = 1","d":"Giriş ve çıkış diş sayısı eşit olduğundan çıkış da 200 tur/dk döner."},{"t":"Yönü belirle","a":"aynı yön","d":"İki ters yön değişimi olduğundan (giriş→ara→çıkış) çıkış, giriş ile aynı yöne döner."}],"ans":"Çıkış çarkı 200 tur/dk ve giriş ile aynı yönde döner."},{"q":"Bir dişli oranı, çıkış torkunu girişe göre 5 katına çıkarıyor. Çıkış devri girişin kaç katıdır ve bu fiziksel olarak ne anlama gelir?","steps":[{"t":"Tork-devir ters orantı","a":"güç korunur","d":"İdeal sistemde tork × açısal hız sabittir; tork 5 kat artarsa açısal hız 1/5'e iner."},{"t":"Sonuç","a":"1/5 katı","d":"Çıkış devri girişin 1/5'i olur, yani sistem 5 kat yavaşlar."}],"ans":"Çıkış devri girişin 1/5'idir; sistem 5 kat yavaşlayıp 5 kat güçlenmiştir (güç korunur)."},{"q":"15 dişli ve 45 dişli iki çark birbirine geçmiş. 15 dişli çark 12 tam tur attığında 45 dişli çarkın attığı tur sayısını ve aralarındaki geçen toplam diş sayısını bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='95' cy='85' r='26' fill='#cfe0f5' stroke='#1a2b45' stroke-width='2'/><circle cx='200' cy='85' r='52' fill='#ffd54a' stroke='#1a2b45' stroke-width='2'/><circle cx='95' cy='85' r='5' fill='#1a2b45'/><circle cx='200' cy='85' r='7' fill='#1a2b45'/><text x='95' y='89' font-size='10' text-anchor='middle' fill='#1a2b45'>15</text><text x='200' y='89' font-size='11' text-anchor='middle' fill='#1a2b45'>45 diş</text></svg>","steps":[{"t":"Geçen diş sayısı","a":"15·12 = 180","d":"15 dişli çark 12 tur atınca temas noktasından 180 diş geçer."},{"t":"45 dişlinin turu","a":"180 ÷ 45","d":"Aynı 180 diş 45 dişli çarka aktarılır; 180'i 45'e bölünce 4 tur çıkar."},{"t":"Sonuç","a":"4 tur, 180 diş","d":"45 dişli çark 4 tur atar, toplam geçen diş 180'dir."}],"ans":"45 dişli çark 4 tur atar; aralarında toplam 180 diş geçer."},{"q":"40 dişli bir çark, kendisine geçmiş 10 dişli bir çarkı döndürüyor. Büyük çark dakikada 30 devir yaparsa küçük çark dakikada kaç devir yapar?","steps":[{"t":"Dişli kuralı","a":"Diş sayısı × devir korunur","d":"Birbirine geçen dişlilerde N₁·n₁ = N₂·n₂; diş sayısı ile devir ters orantılıdır."},{"t":"Hesap","a":"120 devir","d":"40·30 = 10·n₂ → n₂ = 1200/10 = 120 devir/dakika. Küçük çark daha hızlı döner."}],"ans":"120 devir/dakika"}]}},"egikDuzlem":{"ilkokul":{"kolay":[{"q":"Şekildeki gibi ağır bir bavulu yukarı kaldırmak yerine rampadan ittiğimizde işimiz neden kolaylaşır?","fig":"<svg viewBox='0 0 320 180'><line x1='40' y1='150' x2='280' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='60,150 260,150 260,60' fill='#cdd6e4' stroke='#1a2b45'/><rect x='190' y='78' width='30' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='205' y='95' font-size='10' text-anchor='middle' fill='#fff'>yük</text><polygon points='185,90 150,118 158,122 193,94' fill='#e0552b'/><line x1='185' y1='90' x2='150' y2='118' stroke='#e0552b' stroke-width='3'/><text x='150' y='138' font-size='11' text-anchor='middle' fill='#1a2b45'>itme</text><text x='250' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>rampa</text></svg>","steps":[{"t":"Rampa nedir","a":"eğimli yol","d":"Rampa, yere göre eğimli duran düz bir yoldur, eğik düzlem de denir."},{"t":"Neden kolay","a":"daha az kuvvet","d":"Yükü dik kaldırmak yerine eğimli yoldan iterek daha az kuvvetle yukarı çıkarırız."}],"ans":"Rampa kullanınca yükü daha az kuvvetle yukarı çıkardığımız için işimiz kolaylaşır."},{"q":"Bir tekerlekli sandalye için kaldırım kenarına neden basamak değil de rampa yapılır?","fig":"<svg viewBox='0 0 320 170'><line x1='30' y1='140' x2='290' y2='140' stroke='#1a2b45' stroke-width='2'/><polygon points='70,140 240,140 240,80' fill='#cdd6e4' stroke='#1a2b45'/><circle cx='150' cy='110' r='14' fill='none' stroke='#1a2b45' stroke-width='3'/><circle cx='150' cy='110' r='4' fill='#5b6b85'/><text x='160' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>rampa</text></svg>","steps":[{"t":"Basamak zor","a":"dik çıkış","d":"Basamak diktir, tekerlekli sandalyeyi yukarı kaldırmak çok güç ister."},{"t":"Rampa kolay","a":"eğimli","d":"Rampa eğimli olduğu için tekerlek az kuvvetle yukarı itilir."}],"ans":"Rampa eğimli olduğu için tekerlekli sandalye yukarıya az kuvvetle, kolayca çıkar."},{"q":"Şekildeki iki rampadan hangisinden yükü itmek daha kolaydır: dik olan mı, yatık (az eğimli) olan mı?","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='140' x2='300' y2='140' stroke='#1a2b45' stroke-width='2'/><polygon points='40,140 90,140 90,60' fill='#cdd6e4' stroke='#1a2b45'/><text x='65' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>dik</text><polygon points='160,140 290,140 290,90' fill='#cdd6e4' stroke='#1a2b45'/><text x='225' y='132' font-size='10' text-anchor='middle' fill='#1a2b45'>yatık</text></svg>","steps":[{"t":"Eğime bak","a":"yatık az eğimli","d":"Yatık rampa daha az eğimlidir, yol daha uzun ve yumuşaktır."},{"t":"Kolay olan","a":"yatık olan","d":"Az eğimli rampada yükü itmek için daha az kuvvet gerekir."}],"ans":"Az eğimli (yatık) rampadan yükü itmek daha kolaydır."},{"q":"Kamyona fıçıları yüklerken işçiler neden uzun bir tahta rampa kullanır?","fig":"<svg viewBox='0 0 320 180'><rect x='40' y='70' width='90' height='70' fill='#5b6b85' stroke='#1a2b45'/><text x='85' y='110' font-size='11' text-anchor='middle' fill='#fff'>kamyon</text><polygon points='130,140 250,140 130,80' fill='#cda86b' stroke='#1a2b45'/><text x='200' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>rampa</text><circle cx='175' cy='112' r='12' fill='#8a5a2b' stroke='#1a2b45'/><text x='175' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>fıçı</text></svg>","steps":[{"t":"Dik kaldırmak zor","a":"ağır iş","d":"Fıçıyı doğrudan kamyona kaldırmak çok ağırdır."},{"t":"Rampa yardımı","a":"yuvarlayarak","d":"Rampa sayesinde fıçı eğimli yoldan az kuvvetle yukarı itilir."}],"ans":"Rampa, ağır fıçıları kamyona daha az kuvvetle çıkarmayı sağladığı için kullanılır."},{"q":"Eğik düzlemden (rampadan) yükü çıkarırken kuvvetten kazanırız ama bunun bir bedeli vardır. Bu bedel nedir?","steps":[{"t":"Kuvvet az","a":"kolaylık","d":"Rampada yükü itmek için daha az kuvvet harcarız."},{"t":"Yol uzun","a":"daha uzun yol","d":"Buna karşılık yükü daha uzun bir yol boyunca itmemiz gerekir."}],"ans":"Rampada kuvvetten kazanırız ama yükü daha uzun bir yol boyunca itmek zorunda kalırız."}],"zor":[{"q":"Şekilde aynı yüksekliğe çıkan iki rampa var. Uzun rampadan mı yoksa kısa rampadan mı yükü itmek daha az kuvvet ister?","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='150' x2='300' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='40,150 110,150 40,90' fill='#cdd6e4' stroke='#1a2b45'/><text x='70' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>kısa</text><line x1='30' y1='90' x2='30' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='18' y='122' font-size='9' fill='#1a2b45'>h</text><polygon points='160,150 290,150 160,90' fill='#cdd6e4' stroke='#1a2b45'/><text x='235' y='142' font-size='10' text-anchor='middle' fill='#1a2b45'>uzun</text><line x1='150' y1='90' x2='150' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='138' y='122' font-size='9' fill='#1a2b45'>h</text></svg>","steps":[{"t":"Yükseklik aynı","a":"h eşit","d":"İki rampa da aynı yüksekliğe çıkıyor, ama uzun rampa daha az eğimli."},{"t":"Kuvveti karşılaştır","a":"uzun rampa","d":"Uzun (az eğimli) rampada yükü itmek daha az kuvvet ister."}],"ans":"Uzun rampadan itmek daha az kuvvet ister, çünkü o rampa daha az eğimlidir."},{"q":"Bir bahçıvan el arabasındaki toprağı yüksek bir set üstüne çıkaracak. Neden seti dolaşıp uzun bir eğimli yol seçmesi onu daha az yorar?","steps":[{"t":"Dik çıkış","a":"çok kuvvet","d":"Seti dik çıkmak çok büyük bir kuvvet gerektirir, yorucudur."},{"t":"Eğimli yol","a":"az kuvvet","d":"Uzun eğimli yol az eğimli olduğundan daha az kuvvetle çıkılır."}],"ans":"Uzun eğimli yol az eğimli olduğu için bahçıvan daha az kuvvet harcar ve daha az yorulur."},{"q":"Vidanın yüzeyindeki yiv (dişler) aslında bir eğik düzlemdir. Bu neden vidayı tahtaya batırmayı kolaylaştırır?","fig":"<svg viewBox='0 0 320 170'><rect x='140' y='30' width='30' height='30' fill='#9aa6b8' stroke='#1a2b45'/><polygon points='140,60 170,60 155,140' fill='#9aa6b8' stroke='#1a2b45'/><line x1='142' y1='72' x2='168' y2='66' stroke='#1a2b45' stroke-width='1'/><line x1='145' y1='88' x2='165' y2='82' stroke='#1a2b45' stroke-width='1'/><line x1='148' y1='104' x2='162' y2='98' stroke='#1a2b45' stroke-width='1'/><text x='220' y='90' font-size='11' fill='#1a2b45'>yivler =</text><text x='220' y='108' font-size='11' fill='#1a2b45'>eğik düzlem</text></svg>","steps":[{"t":"Yiv nedir","a":"sarılmış rampa","d":"Vida dişleri, gövdeye sarılmış bir eğik düzlem gibidir."},{"t":"Kolaylık","a":"az kuvvet","d":"Eğik düzlem sayesinde vida az kuvvetle döne döne tahtaya batar."}],"ans":"Vida yivleri eğik düzlem gibi çalışır, böylece vida az kuvvetle tahtaya batırılır."},{"q":"Dağ yolları neden düz yukarı çıkmaz da viraj viraj (zikzak) tırmanır?","fig":"<svg viewBox='0 0 320 170'><polygon points='30,150 290,150 160,30' fill='#cdd6e4' stroke='#1a2b45'/><polyline points='60,150 200,120 90,95 180,70 140,45' fill='none' stroke='#e0552b' stroke-width='3'/><text x='220' y='110' font-size='11' fill='#1a2b45'>zikzak yol</text></svg>","steps":[{"t":"Düz çıkış","a":"çok dik","d":"Dağa düz çıkmak çok dik olur, araçlar zorlanır."},{"t":"Zikzak yol","a":"az eğimli","d":"Zikzak yol daha uzundur ama eğimi azdır, çıkmak kolaylaşır."}],"ans":"Zikzak yol daha uzun ama az eğimli olduğu için araçlar dağa daha kolay tırmanır."},{"q":"Bir çocuk kızağını tepeye iterken yokuşun dik kısmında neden daha çok zorlanır?","fig":"<svg viewBox='0 0 320 170'><path d='M30 150 Q120 150 170 90 Q210 45 290 40' fill='none' stroke='#1a2b45' stroke-width='2'/><rect x='180' y='70' width='22' height='12' fill='#5b6b85' stroke='#1a2b45'/><text x='191' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>kızak</text><text x='240' y='30' font-size='10' fill='#1a2b45'>dik kısım</text></svg>","steps":[{"t":"Dik kısım","a":"eğim fazla","d":"Yokuşun dik kısmında eğim büyüktür."},{"t":"Kuvvet artar","a":"daha çok güç","d":"Eğim arttıkça kızağı yukarı itmek için daha çok kuvvet gerekir."}],"ans":"Yokuşun dik kısmında eğim fazla olduğu için kızağı itmek daha çok kuvvet ister."}]},"ortaokul":{"kolay":[{"q":"Şekildeki eğik düzlemde sürtünme yokken yükü yukarı çıkarmak için gereken itme kuvveti hangi büyüklüklere bağlıdır?","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='150' x2='300' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='50,150 270,150 270,60' fill='#cdd6e4' stroke='#1a2b45'/><rect x='200' y='80' width='28' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='214' y='96' font-size='10' text-anchor='middle' fill='#fff'>yük</text><polygon points='195,92 162,116 169,121 202,97' fill='#e0552b'/><line x1='195' y1='92' x2='162' y2='116' stroke='#e0552b' stroke-width='3'/><text x='160' y='136' font-size='11' text-anchor='middle' fill='#1a2b45'>F itme</text><line x1='275' y1='60' x2='275' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='284' y='108' font-size='11' fill='#1a2b45'>h</text><text x='150' y='165' font-size='11' text-anchor='middle' fill='#1a2b45'>L uzunluk</text></svg>","steps":[{"t":"Bağıntıyı yaz","a":"F = Yük × h / L","d":"Sürtünmesiz eğik düzlemde itme kuvveti, yük ile yüksekliğin çarpımının uzunluğa bölümüdür."},{"t":"Bağımlılık","a":"yük, h, L","d":"Kuvvet; yüke, eğik düzlemin yüksekliğine ve uzunluğuna bağlıdır."}],"ans":"Gereken kuvvet, yük × yükseklik ÷ uzunluk (F = Yük·h/L) bağıntısına, yani yük, yükseklik ve uzunluğa bağlıdır."},{"q":"Eğik düzlemde mekanik avantaj (kuvvet kazancı) nasıl hesaplanır?","steps":[{"t":"Tanım","a":"yol oranı","d":"Mekanik avantaj, eğik düzlemin uzunluğunun yüksekliğine oranıdır."},{"t":"Bağıntı","a":"MA = L / h","d":"Bu oran ne kadar büyükse kuvvetten o kadar çok kazanılır."}],"ans":"Eğik düzlemde mekanik avantaj MA = L / h (uzunluk ÷ yükseklik) bağıntısıyla bulunur."},{"q":"Uzunluğu 6 m, yüksekliği 2 m olan bir rampanın mekanik avantajını hesaplayınız.","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='140' x2='300' y2='140' stroke='#1a2b45' stroke-width='2'/><polygon points='50,140 270,140 270,60' fill='#cdd6e4' stroke='#1a2b45'/><text x='150' y='133' font-size='11' text-anchor='middle' fill='#1a2b45'>L = 6 m</text><line x1='276' y1='60' x2='276' y2='140' stroke='#1a2b45' stroke-width='1'/><text x='284' y='104' font-size='11' fill='#1a2b45'>h = 2 m</text></svg>","steps":[{"t":"Bağıntı","a":"MA = L/h","d":"Mekanik avantaj, uzunluğun yüksekliğe bölünmesiyle bulunur."},{"t":"Yerine koy","a":"6 ÷ 2","d":"Uzunluk 6 m, yükseklik 2 m değerleri yerine konur."},{"t":"Sonuç","a":"3","d":"Bölme sonucu 3 bulunur."}],"ans":"Mekanik avantaj 3'tür; rampa kuvveti 3 kat azaltır."},{"q":"Bir rampanın eğimi azaltılırsa (uzunluğu artırılırsa) yükü itmek için gereken kuvvet nasıl değişir?","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='40,145 110,145 40,85' fill='#cdd6e4' stroke='#1a2b45'/><text x='72' y='137' font-size='9' text-anchor='middle' fill='#1a2b45'>kısa</text><polygon points='150,145 290,145 150,85' fill='#cdd6e4' stroke='#1a2b45'/><text x='225' y='137' font-size='9' text-anchor='middle' fill='#1a2b45'>uzun, az eğimli</text></svg>","steps":[{"t":"Bağıntıya bak","a":"F = Yük·h/L","d":"Uzunluk L paydadadır; L büyürse kuvvet küçülür."},{"t":"Sonuç","a":"kuvvet azalır","d":"Eğim azaldıkça (rampa uzadıkça) gereken itme kuvveti azalır."}],"ans":"Eğim azaltılıp rampa uzatılınca gereken itme kuvveti azalır."},{"q":"Eğik düzlem kuvvetten kazandırır ama işten kazandırmaz. Bu ne demektir?","steps":[{"t":"Kuvvet kazancı","a":"az kuvvet","d":"Rampada yükü kaldırmak için daha az kuvvet harcarız."},{"t":"İş eşit","a":"yol uzar","d":"Ama yol uzadığı için kuvvet × yol çarpımı (iş) aynı kalır."}],"ans":"Eğik düzlemde kuvvetten kazanırız fakat yol uzadığından yapılan iş (kuvvet × yol) değişmez."}],"zor":[{"q":"Şekildeki sürtünmesiz eğik düzlemde 300 N ağırlığındaki yük, uzunluğu 5 m ve yüksekliği 2 m olan rampadan itiliyor. Gereken itme kuvvetini bulunuz.","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='150' x2='300' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='50,150 270,150 270,60' fill='#cdd6e4' stroke='#1a2b45'/><rect x='200' y='80' width='28' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='214' y='96' font-size='9' text-anchor='middle' fill='#fff'>300 N</text><polygon points='195,92 162,116 169,121 202,97' fill='#e0552b'/><line x1='195' y1='92' x2='162' y2='116' stroke='#e0552b' stroke-width='3'/><text x='160' y='136' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><line x1='276' y1='60' x2='276' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='284' y='108' font-size='10' fill='#1a2b45'>2 m</text><text x='150' y='166' font-size='10' text-anchor='middle' fill='#1a2b45'>L = 5 m</text></svg>","steps":[{"t":"Bağıntı","a":"F = Yük·h/L","d":"Sürtünmesiz eğik düzlemde kuvvet, yük ile yüksekliğin çarpımının uzunluğa bölümüdür."},{"t":"Yerine koy","a":"300 × 2 / 5","d":"Yük 300 N, h = 2 m, L = 5 m değerleri yerine konur."},{"t":"Sonuç","a":"120 N","d":"600'ü 5'e bölünce 120 N bulunur."}],"ans":"Gereken itme kuvveti 120 N'dur."},{"q":"Uzunluğu 8 m, yüksekliği 2 m olan rampada 400 N'luk yükü yukarı çıkarmak için gereken kuvveti (sürtünmesiz) hesaplayınız.","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='40,145 280,145 280,75' fill='#cdd6e4' stroke='#1a2b45'/><rect x='210' y='95' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='223' y='110' font-size='8' text-anchor='middle' fill='#fff'>400 N</text><line x1='286' y1='75' x2='286' y2='145' stroke='#1a2b45' stroke-width='1'/><text x='292' y='113' font-size='10' fill='#1a2b45'>2 m</text><text x='150' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>L = 8 m</text></svg>","steps":[{"t":"Bağıntı","a":"F = Yük·h/L","d":"İtme kuvveti, yük × yükseklik ÷ uzunluk biçiminde bulunur."},{"t":"Yerine koy","a":"400 × 2 / 8","d":"Yük 400 N, h = 2 m, L = 8 m yerine konur."},{"t":"Sonuç","a":"100 N","d":"800'ü 8'e bölünce 100 N bulunur."}],"ans":"Gereken kuvvet 100 N'dur."},{"q":"Mekanik avantajı 4 olan bir eğik düzlemde 600 N'luk yük itiliyor. Sürtünme yoksa gereken kuvvet kaç N'dur?","steps":[{"t":"MA tanımı","a":"MA = Yük/F","d":"Mekanik avantaj, yükün uygulanan kuvvete oranıdır."},{"t":"Kuvveti yaz","a":"F = Yük/MA","d":"Buradan gereken kuvvet, yükün mekanik avantaja bölümüdür."},{"t":"Yerine koy","a":"600 ÷ 4","d":"Yük 600 N, MA = 4 yerine konur."}],"ans":"Gereken kuvvet 150 N'dur."},{"q":"Sürtünmesiz bir rampada 200 N'luk kasayı 1,5 m yükseğe çıkarmak için yapılan işi hesaplayınız (rampa uzunluğu önemli mi?).","steps":[{"t":"İş tanımı","a":"W = Yük × h","d":"Eğik düzlemde yapılan yararlı iş, ağırlık ile yükseklik değişiminin çarpımıdır."},{"t":"Yerine koy","a":"200 × 1,5","d":"Yük 200 N, yükseklik 1,5 m yerine konur; rampa uzunluğu işi değiştirmez."},{"t":"Sonuç","a":"300 J","d":"200 ile 1,5 çarpılınca 300 J bulunur."}],"ans":"Yapılan iş 300 joule'dür; rampa uzunluğu işi değiştirmez, sadece kuvveti ve yolu değiştirir."},{"q":"Şekildeki rampanın uzunluğu 10 m, yüksekliği 2,5 m'dir. Mekanik avantajı bulup 500 N'luk yük için gereken kuvveti hesaplayınız.","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='40,145 285,145 285,70' fill='#cdd6e4' stroke='#1a2b45'/><rect x='215' y='92' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='228' y='107' font-size='8' text-anchor='middle' fill='#fff'>500 N</text><line x1='291' y1='70' x2='291' y2='145' stroke='#1a2b45' stroke-width='1'/><text x='296' y='110' font-size='9' fill='#1a2b45'>2,5 m</text><text x='150' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>L = 10 m</text></svg>","steps":[{"t":"Mekanik avantaj","a":"MA = L/h = 10/2,5 = 4","d":"Uzunluğu yüksekliğe bölerek MA = 4 buluruz."},{"t":"Kuvveti yaz","a":"F = Yük/MA","d":"Gereken kuvvet, yükün mekanik avantaja bölümüdür."},{"t":"Sonuç","a":"500 ÷ 4 = 125 N","d":"500 N'luk yük 4'e bölününce 125 N bulunur."}],"ans":"Mekanik avantaj 4'tür ve gereken kuvvet 125 N'dur."}]},"lise":{"kolay":[{"q":"Sürtünmesiz eğik düzlemde yükü dengede tutacak (yukarı çıkaracak) itme kuvveti hangi bağıntıyla bulunur?","steps":[{"t":"Kuvvet bileşeni","a":"ağırlığın eğim bileşeni","d":"Yükü eğim boyunca aşağı çeken bileşen, ağırlığın eğim yönündeki izdüşümüdür."},{"t":"Bağıntı","a":"F = G·h/L","d":"Bu bileşen, ağırlık G ile yüksekliğin uzunluğa oranının çarpımına eşittir (G·sinθ = G·h/L)."}],"ans":"Sürtünmesiz eğik düzlemde itme kuvveti F = G·h/L (yani G·sinθ) bağıntısıyla bulunur."},{"q":"Eğik düzlemin mekanik avantajı geometrik olarak hangi orana eşittir?","steps":[{"t":"Tanım","a":"MA = Yük/F","d":"Mekanik avantaj, yükün uygulanan kuvvete oranıdır."},{"t":"Geometrik karşılık","a":"L/h = 1/sinθ","d":"Sürtünmesizde bu oran, eğik düzlem uzunluğunun yüksekliğine oranına (1/sinθ) eşittir."}],"ans":"İdeal mekanik avantaj MA = L/h = 1/sinθ'dır; uzunluk ne kadar büyükse kazanç o kadar çoktur."},{"q":"Şekildeki sürtünmesiz eğik düzlemde G = 500 N, L = 5 m, h = 2 m. Gereken itme kuvvetini bulunuz.","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='150' x2='300' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='50,150 270,150 270,60' fill='#cdd6e4' stroke='#1a2b45'/><rect x='200' y='80' width='28' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='214' y='96' font-size='9' text-anchor='middle' fill='#fff'>500 N</text><polygon points='195,92 162,116 169,121 202,97' fill='#e0552b'/><line x1='195' y1='92' x2='162' y2='116' stroke='#e0552b' stroke-width='3'/><text x='158' y='136' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><line x1='276' y1='60' x2='276' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='284' y='108' font-size='10' fill='#1a2b45'>h=2 m</text><text x='150' y='166' font-size='10' text-anchor='middle' fill='#1a2b45'>L = 5 m</text></svg>","steps":[{"t":"Bağıntı","a":"F = G·h/L","d":"Sürtünmesiz eğik düzlemde kuvvet, ağırlık × yükseklik ÷ uzunluktur."},{"t":"Yerine koy","a":"500 × 2 / 5","d":"G = 500 N, h = 2 m, L = 5 m yerine konur."},{"t":"Sonuç","a":"200 N","d":"1000'i 5'e bölünce 200 N bulunur."}],"ans":"Gereken itme kuvveti 200 N'dur."},{"q":"Eğim açısı 30° olan sürtünmesiz eğik düzlemde 400 N'luk yükü çıkarmak için gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 175'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='50,145 270,145 270,82' fill='#cdd6e4' stroke='#1a2b45'/><path d='M90 145 A40 40 0 0 1 78 122' fill='none' stroke='#e0552b' stroke-width='1.5'/><text x='100' y='138' font-size='10' fill='#1a2b45'>30°</text><rect x='205' y='100' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='218' y='115' font-size='8' text-anchor='middle' fill='#fff'>400 N</text></svg>","steps":[{"t":"Bağıntı","a":"F = G·sinθ","d":"Sürtünmesizde kuvvet, ağırlık ile eğim açısının sinüsünün çarpımıdır."},{"t":"Yerine koy","a":"400 × sin30°","d":"sin30° = 0,5 olduğundan 400 × 0,5 hesaplanır."},{"t":"Sonuç","a":"200 N","d":"Çarpım sonucu 200 N bulunur."}],"ans":"Gereken kuvvet 200 N'dur (G·sin30° = 400 × 0,5)."},{"q":"L = 8 m, h = 2 m olan bir eğik düzlemin ideal (sürtünmesiz) mekanik avantajını bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='20' y1='140' x2='300' y2='140' stroke='#1a2b45' stroke-width='2'/><polygon points='40,140 280,140 280,75' fill='#cdd6e4' stroke='#1a2b45'/><text x='150' y='133' font-size='10' text-anchor='middle' fill='#1a2b45'>L = 8 m</text><line x1='286' y1='75' x2='286' y2='140' stroke='#1a2b45' stroke-width='1'/><text x='292' y='110' font-size='10' fill='#1a2b45'>h=2 m</text></svg>","steps":[{"t":"Bağıntı","a":"MA = L/h","d":"İdeal mekanik avantaj, uzunluğun yüksekliğe oranıdır."},{"t":"Yerine koy","a":"8 ÷ 2","d":"L = 8 m, h = 2 m yerine konur."},{"t":"Sonuç","a":"4","d":"Bölme sonucu 4 bulunur."}],"ans":"İdeal mekanik avantaj 4'tür."},{"q":"Eğik düzlemde yapılan yararlı iş (yükü h yükseğe çıkarma işi) hangi bağıntıyla hesaplanır?","steps":[{"t":"İş tanımı","a":"W = G × h","d":"Yararlı iş, ağırlık ile kazanılan yüksekliğin çarpımıdır."},{"t":"Yol etkisi yok","a":"L'den bağımsız","d":"Rampa uzunluğu yararlı işi değiştirmez; yalnız kuvveti ve gidilen yolu değiştirir."}],"ans":"Yararlı iş W = G × h bağıntısıyla bulunur ve rampa uzunluğundan bağımsızdır."},{"q":"Sürtünmeli eğik düzlemde verim (verimlilik) nasıl tanımlanır?","steps":[{"t":"Tanım","a":"yararlı/verilen iş","d":"Verim, alınan yararlı işin (G·h) makineye verilen iş enerjisine (F·L) oranıdır."},{"t":"Bağıntı","a":"η = (G·h)/(F·L)","d":"Sürtünme arttıkça verilen iş artar, verim düşer; sürtünmesizde verim %100'dür."}],"ans":"Verim η = yararlı iş / verilen iş = (G·h)/(F·L) olarak tanımlanır."},{"q":"İdeal mekanik avantajı 5 olan bir eğik düzlemde 1000 N'luk yük için gereken kuvveti (sürtünmesiz) bulunuz.","steps":[{"t":"Bağıntı","a":"F = G/MA","d":"Gereken kuvvet, yükün mekanik avantaja bölümüdür."},{"t":"Yerine koy","a":"1000 ÷ 5","d":"G = 1000 N, MA = 5 yerine konur."},{"t":"Sonuç","a":"200 N","d":"Bölme sonucu 200 N bulunur."}],"ans":"Gereken kuvvet 200 N'dur."},{"q":"Şekildeki eğik düzlemde eğim açısı arttırılırsa gereken itme kuvveti nasıl değişir?","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='40,145 110,145 40,70' fill='#cdd6e4' stroke='#1a2b45'/><text x='70' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>büyük θ</text><polygon points='160,145 290,145 160,95' fill='#cdd6e4' stroke='#1a2b45'/><text x='225' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>küçük θ</text></svg>","steps":[{"t":"Bağıntı","a":"F = G·sinθ","d":"Kuvvet, eğim açısının sinüsüyle doğru orantılıdır."},{"t":"Açı artarsa","a":"sinθ artar","d":"Açı büyüdükçe sinθ büyür, dolayısıyla gereken kuvvet artar."}],"ans":"Eğim açısı arttıkça sinθ büyüdüğü için gereken itme kuvveti artar."},{"q":"Bir eğik düzlemin uzunluğu 6 m, yüksekliği 3 m'dir. Eğim açısının sinüsünü ve ideal mekanik avantajı bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='20' y1='140' x2='300' y2='140' stroke='#1a2b45' stroke-width='2'/><polygon points='50,140 250,140 250,55' fill='#cdd6e4' stroke='#1a2b45'/><text x='150' y='133' font-size='10' text-anchor='middle' fill='#1a2b45'>L = 6 m</text><line x1='256' y1='55' x2='256' y2='140' stroke='#1a2b45' stroke-width='1'/><text x='262' y='100' font-size='10' fill='#1a2b45'>h=3 m</text></svg>","steps":[{"t":"sinθ","a":"sinθ = h/L","d":"Eğim açısının sinüsü, yüksekliğin uzunluğa oranıdır: 3/6 = 0,5."},{"t":"MA","a":"MA = L/h = 1/sinθ","d":"İdeal mekanik avantaj 6/3 = 2'dir, yani 1/sinθ = 1/0,5 = 2."}],"ans":"sinθ = 0,5 (θ = 30°) ve ideal mekanik avantaj 2'dir."},{"q":"Eğik düzlem kullanmak yapılan toplam işi azaltır mı? Açıklayınız.","steps":[{"t":"İş korunur","a":"W = G·h sabit","d":"Yükü h yükseğe çıkarmak için gereken yararlı iş hep aynıdır."},{"t":"Kuvvet-yol takası","a":"F küçük, L büyük","d":"Eğik düzlem kuvveti azaltır ama yolu o oranda uzatır, çarpımları (iş) değişmez."}],"ans":"Hayır; eğik düzlem işi azaltmaz, sadece kuvvetten kazandırıp yolu uzatır (sürtünmesizde iş korunur)."},{"q":"Sürtünmenin var olması eğik düzlemin verimini neden %100'ün altına düşürür?","steps":[{"t":"Ek kuvvet","a":"sürtünme kuvveti","d":"Sürtünme, harekete karşı koyar; yükü itmek için ekstra kuvvet gerekir."},{"t":"Enerji kaybı","a":"ısıya dönüşür","d":"Bu ekstra işin bir kısmı ısıya dönüşüp kaybolur, yararlı işe katkı sağlamaz."}],"ans":"Sürtünme, verilen işin bir kısmını ısıya dönüştürerek kaybettiğinden verim %100'ün altına düşer."},{"q":"İdeal mekanik avantaj ile gerçek (sürtünmeli) mekanik avantaj arasındaki fark nedir?","steps":[{"t":"İdeal MA","a":"MA = L/h","d":"İdeal mekanik avantaj yalnız geometriye bağlıdır, sürtünme yok sayılır."},{"t":"Gerçek MA","a":"MA = G/F","d":"Gerçek mekanik avantaj, gerçekte uygulanan (sürtünme dahil daha büyük) kuvvetle hesaplanır ve idealden küçüktür."}],"ans":"İdeal MA = L/h geometriktir; gerçek MA = Yük/uygulanan kuvvet olup sürtünme nedeniyle idealden küçüktür."},{"q":"Bir kasayı 2 m yükseğe çıkarmak 600 J yararlı iş gerektiriyor. Sürtünmesiz rampada bu iş ne kadar olur?","steps":[{"t":"İş korunumu","a":"sürtünme yok","d":"Sürtünme olmadığında verilen iş, yararlı işe eşittir."},{"t":"Sonuç","a":"600 J","d":"Bu yüzden harcanan iş de 600 J'dür, rampa uzunluğundan bağımsızdır."}],"ans":"Sürtünmesiz rampada verilen iş de 600 J'dür; uzunluk yalnız kuvveti değiştirir, işi değiştirmez."},{"q":"Aynı yüksekliğe çıkan iki rampadan uzun olanının kuvvet kazancı neden daha fazladır?","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='40,145 110,145 40,80' fill='#cdd6e4' stroke='#1a2b45'/><text x='72' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>kısa</text><line x1='32' y1='80' x2='32' y2='145' stroke='#1a2b45' stroke-width='1'/><text x='22' y='115' font-size='8' fill='#1a2b45'>h</text><polygon points='150,145 290,145 150,80' fill='#cdd6e4' stroke='#1a2b45'/><text x='225' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>uzun</text><line x1='142' y1='80' x2='142' y2='145' stroke='#1a2b45' stroke-width='1'/><text x='132' y='115' font-size='8' fill='#1a2b45'>h</text></svg>","steps":[{"t":"MA bağıntısı","a":"MA = L/h","d":"Mekanik avantaj uzunlukla doğru orantılıdır, yükseklik aynıdır."},{"t":"Uzun rampa","a":"MA büyük","d":"L büyüdükçe MA artar, yani daha az kuvvetle iş görülür."}],"ans":"Yükseklik aynıyken uzun rampanın L'si büyük olduğundan MA = L/h oranı, dolayısıyla kuvvet kazancı daha fazladır."}],"zor":[{"q":"Şekildeki sürtünmesiz eğik düzlemde 800 N'luk yük, L = 10 m ve h = 4 m olan rampadan itiliyor. Gereken kuvveti ve ideal mekanik avantajı bulunuz.","fig":"<svg viewBox='0 0 320 180'><line x1='20' y1='150' x2='300' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='50,150 275,150 275,60' fill='#cdd6e4' stroke='#1a2b45'/><rect x='205' y='82' width='28' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='219' y='98' font-size='8' text-anchor='middle' fill='#fff'>800 N</text><polygon points='200,94 167,118 174,123 207,99' fill='#e0552b'/><line x1='200' y1='94' x2='167' y2='118' stroke='#e0552b' stroke-width='3'/><text x='162' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><line x1='281' y1='60' x2='281' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='288' y='108' font-size='9' fill='#1a2b45'>h=4 m</text><text x='150' y='166' font-size='10' text-anchor='middle' fill='#1a2b45'>L = 10 m</text></svg>","steps":[{"t":"Mekanik avantaj","a":"MA = L/h = 10/4 = 2,5","d":"Uzunluğu yüksekliğe bölerek ideal mekanik avantajı buluruz."},{"t":"Kuvvet bağıntısı","a":"F = G·h/L","d":"Gereken kuvvet, ağırlık × yükseklik ÷ uzunluktur."},{"t":"Sonuç","a":"800 × 4 / 10 = 320 N","d":"3200'ü 10'a bölünce 320 N bulunur."}],"ans":"İdeal mekanik avantaj 2,5 ve gereken kuvvet 320 N'dur."},{"q":"Eğim açısı 30° olan sürtünmeli bir eğik düzlemde 600 N'luk yükü çıkarmak için gerçekte 400 N uygulanıyor. Rampa uzunluğu 4 m ise verimi bulunuz.","fig":"<svg viewBox='0 0 320 175'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='50,145 270,145 270,82' fill='#cdd6e4' stroke='#1a2b45'/><path d='M90 145 A38 38 0 0 1 79 123' fill='none' stroke='#e0552b' stroke-width='1.5'/><text x='100' y='138' font-size='10' fill='#1a2b45'>30°</text><rect x='205' y='100' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='218' y='115' font-size='8' text-anchor='middle' fill='#fff'>600 N</text><text x='150' y='162' font-size='9' text-anchor='middle' fill='#1a2b45'>L = 4 m, F = 400 N</text></svg>","steps":[{"t":"Yüksekliği bul","a":"h = L·sin30° = 2 m","d":"Yükseklik, uzunluk ile sin30°'nin çarpımıdır: 4 × 0,5 = 2 m."},{"t":"İşleri hesapla","a":"yararlı 1200 J, verilen 1600 J","d":"Yararlı iş = 600 × 2 = 1200 J; verilen iş = 400 × 4 = 1600 J."},{"t":"Verim","a":"η = 1200/1600","d":"Yararlı işi verilen işe bölünce 0,75 yani %75 bulunur."}],"ans":"Eğik düzlemin verimi %75'tir."},{"q":"Sürtünmesiz bir eğik düzlemde mekanik avantaj 5'tir. Yük 1500 N ise hem gereken kuvveti hem de yükü 3 m yükseğe çıkarmak için katedilen rampa uzunluğunu bulunuz.","steps":[{"t":"Kuvvet","a":"F = G/MA = 1500/5 = 300 N","d":"Gereken kuvvet, yükün mekanik avantaja bölümüdür."},{"t":"Uzunluk","a":"L = MA × h","d":"MA = L/h olduğundan L = mekanik avantaj × yükseklik = 5 × 3'tür."},{"t":"Sonuç","a":"L = 15 m","d":"5 ile 3 m çarpılınca rampa uzunluğu 15 m bulunur."}],"ans":"Gereken kuvvet 300 N, katedilen rampa uzunluğu 15 m'dir."},{"q":"Şekildeki eğik düzlemde 1000 N'luk yük 2 m yükseğe çıkarılıyor. Sürtünme nedeniyle gerçekte 8 m'lik rampada 350 N uygulanıyor. Verimi hesaplayınız.","fig":"<svg viewBox='0 0 320 175'><line x1='20' y1='150' x2='300' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='40,150 285,150 285,82' fill='#cdd6e4' stroke='#1a2b45'/><rect x='215' y='100' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='228' y='115' font-size='8' text-anchor='middle' fill='#fff'>1000 N</text><polygon points='210,112 178,132 184,137 215,117' fill='#e0552b'/><line x1='210' y1='112' x2='178' y2='132' stroke='#e0552b' stroke-width='3'/><text x='172' y='148' font-size='9' fill='#1a2b45'>F=350 N</text><line x1='291' y1='82' x2='291' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='296' y='118' font-size='8' fill='#1a2b45'>2 m</text><text x='140' y='166' font-size='9' text-anchor='middle' fill='#1a2b45'>L = 8 m</text></svg>","steps":[{"t":"Yararlı iş","a":"W = 1000 × 2 = 2000 J","d":"Yararlı iş, ağırlık ile yüksekliğin çarpımıdır."},{"t":"Verilen iş","a":"W = 350 × 8 = 2800 J","d":"Verilen iş, uygulanan kuvvet ile rampa uzunluğunun çarpımıdır."},{"t":"Verim","a":"η = 2000/2800 ≈ 0,714","d":"Yararlı işi verilen işe bölünce yaklaşık 0,714 bulunur."}],"ans":"Eğik düzlemin verimi yaklaşık %71,4'tür."},{"q":"İki rampa aynı 3 m yüksekliğe çıkıyor; biri 6 m biri 12 m uzunlukta. 900 N'luk yük için her birinde gereken kuvvetleri (sürtünmesiz) karşılaştırınız.","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='40,145 130,145 40,80' fill='#cdd6e4' stroke='#1a2b45'/><text x='85' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>L=6 m</text><polygon points='160,145 290,145 160,80' fill='#cdd6e4' stroke='#1a2b45'/><text x='225' y='138' font-size='9' text-anchor='middle' fill='#1a2b45'>L=12 m</text><line x1='152' y1='80' x2='152' y2='145' stroke='#1a2b45' stroke-width='1'/><text x='140' y='115' font-size='8' fill='#1a2b45'>h=3</text></svg>","steps":[{"t":"6 m rampa","a":"F = 900·3/6 = 450 N","d":"Kuvvet, yük × yükseklik ÷ uzunluk bağıntısıyla 450 N bulunur."},{"t":"12 m rampa","a":"F = 900·3/12 = 225 N","d":"Aynı bağıntıyla uzun rampada kuvvet 225 N'dur."},{"t":"Karşılaştır","a":"yarısı","d":"Uzunluk iki katına çıkınca gereken kuvvet yarıya iner."}],"ans":"6 m rampada 450 N, 12 m rampada 225 N gerekir; uzun rampa kuvveti yarıya indirir."},{"q":"Eğim açısı 37° olan sürtünmesiz eğik düzlemde 500 N'luk yükü çıkarmak için gereken kuvveti bulunuz (sin37° = 0,6).","fig":"<svg viewBox='0 0 320 175'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='50,145 270,145 270,72' fill='#cdd6e4' stroke='#1a2b45'/><path d='M92 145 A40 40 0 0 1 78 120' fill='none' stroke='#e0552b' stroke-width='1.5'/><text x='102' y='138' font-size='10' fill='#1a2b45'>37°</text><rect x='205' y='95' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='218' y='110' font-size='8' text-anchor='middle' fill='#fff'>500 N</text></svg>","steps":[{"t":"Bağıntı","a":"F = G·sinθ","d":"Sürtünmesizde kuvvet, ağırlık ile eğim açısının sinüsünün çarpımıdır."},{"t":"Yerine koy","a":"500 × 0,6","d":"sin37° = 0,6 olduğundan 500 × 0,6 hesaplanır."},{"t":"Sonuç","a":"300 N","d":"Çarpım sonucu 300 N bulunur."}],"ans":"Gereken kuvvet 300 N'dur."},{"q":"Verimi %80 olan bir eğik düzlemde 1200 N'luk yükü 2,5 m yükseğe çıkarmak için verilen toplam işi bulunuz.","steps":[{"t":"Yararlı iş","a":"W = 1200 × 2,5 = 3000 J","d":"Yararlı iş, ağırlık ile yüksekliğin çarpımıdır."},{"t":"Verim bağıntısı","a":"verilen = yararlı/η","d":"Verim = yararlı/verilen olduğundan verilen iş = yararlı iş ÷ verimdir."},{"t":"Sonuç","a":"3000 ÷ 0,8 = 3750 J","d":"3000 J'yi 0,8'e bölünce 3750 J bulunur."}],"ans":"Verilen toplam iş 3750 joule'dür."},{"q":"Sürtünmeli bir eğik düzlemde (L = 5 m, h = 3 m) 600 N'luk yükü çıkarmak için 450 N uygulanıyor. İdeal kuvveti, gerçek kuvveti ve verimi karşılaştırınız.","fig":"<svg viewBox='0 0 320 175'><line x1='20' y1='150' x2='300' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='50,150 260,150 260,55' fill='#cdd6e4' stroke='#1a2b45'/><rect x='195' y='80' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='208' y='95' font-size='8' text-anchor='middle' fill='#fff'>600 N</text><polygon points='190,92 160,114 166,119 195,97' fill='#e0552b'/><line x1='190' y1='92' x2='160' y2='114' stroke='#e0552b' stroke-width='3'/><text x='156' y='134' font-size='9' fill='#1a2b45'>F=450 N</text><line x1='266' y1='55' x2='266' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='272' y='105' font-size='8' fill='#1a2b45'>h=3 m</text><text x='150' y='166' font-size='9' text-anchor='middle' fill='#1a2b45'>L = 5 m</text></svg>","steps":[{"t":"İdeal kuvvet","a":"F = 600·3/5 = 360 N","d":"Sürtünmesiz olsaydı gereken kuvvet 360 N olurdu."},{"t":"Gerçek kuvvet","a":"450 N","d":"Sürtünme yüzünden gerçekte 450 N uygulanıyor, idealden fazla."},{"t":"Verim","a":"η = 360/450 = 0,8","d":"İdeal kuvveti gerçek kuvvete bölünce (veya işler oranıyla) %80 bulunur."}],"ans":"İdeal kuvvet 360 N, gerçek kuvvet 450 N'dur; verim %80'dir."},{"q":"Bir eğik düzlemin ideal mekanik avantajı 4, gerçek mekanik avantajı 3'tür. Bu eğik düzlemin verimini bulunuz.","steps":[{"t":"Verim bağıntısı","a":"η = gerçek MA / ideal MA","d":"Verim, gerçek mekanik avantajın ideal mekanik avantaja oranına eşittir."},{"t":"Yerine koy","a":"3 ÷ 4","d":"Gerçek MA = 3, ideal MA = 4 yerine konur."},{"t":"Sonuç","a":"0,75","d":"Bölme sonucu 0,75 yani %75 bulunur."}],"ans":"Eğik düzlemin verimi %75'tir."},{"q":"Şekildeki 12 m uzunluğundaki rampa 3 m yüksekliğe çıkıyor. 240 N'luk kuvvetle hangi ağırlıktaki yük çıkarılabilir (sürtünmesiz)?","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='40,145 285,145 285,82' fill='#cdd6e4' stroke='#1a2b45'/><rect x='215' y='100' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='228' y='115' font-size='8' text-anchor='middle' fill='#fff'>G=?</text><polygon points='210,112 180,132 186,137 215,117' fill='#e0552b'/><line x1='210' y1='112' x2='180' y2='132' stroke='#e0552b' stroke-width='3'/><text x='174' y='148' font-size='8' fill='#1a2b45'>240 N</text><line x1='291' y1='82' x2='291' y2='145' stroke='#1a2b45' stroke-width='1'/><text x='296' y='115' font-size='8' fill='#1a2b45'>3 m</text><text x='140' y='162' font-size='9' text-anchor='middle' fill='#1a2b45'>L = 12 m</text></svg>","steps":[{"t":"Bağıntıyı düzenle","a":"G = F·L/h","d":"F = G·h/L ifadesinden yük = kuvvet × uzunluk ÷ yüksekliktir."},{"t":"Yerine koy","a":"240 × 12 / 3","d":"F = 240 N, L = 12 m, h = 3 m yerine konur."},{"t":"Sonuç","a":"960 N","d":"2880'i 3'e bölünce 960 N bulunur."}],"ans":"240 N'luk kuvvetle 960 N ağırlığındaki yük çıkarılabilir."},{"q":"Aynı yükü aynı yüksekliğe çıkarırken sürtünmeli rampada işçi neden sürtünmesiz duruma göre daha çok iş yapar?","steps":[{"t":"Yararlı iş aynı","a":"G·h sabit","d":"Yükü h yükseğe çıkarmak için gereken yararlı iş her iki durumda da aynıdır."},{"t":"Sürtünme işi","a":"ek enerji","d":"Sürtünmeli durumda sürtünmeyi yenmek için fazladan iş yapılır, bu ısıya gider."}],"ans":"Sürtünmeli rampada işçi, yararlı işe ek olarak sürtünmeyi yenecek işi de yaptığından toplam işi daha fazladır."},{"q":"Eğim açısı 45° olan sürtünmesiz eğik düzlemde itme kuvveti, yükün ağırlığının kaç katıdır (sin45° ≈ 0,71)?","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='145' x2='300' y2='145' stroke='#1a2b45' stroke-width='2'/><polygon points='60,145 230,145 230,-25' fill='#cdd6e4' stroke='#1a2b45'/><path d='M100 145 A38 38 0 0 1 88 117' fill='none' stroke='#e0552b' stroke-width='1.5'/><text x='110' y='138' font-size='10' fill='#1a2b45'>45°</text><rect x='180' y='80' width='24' height='18' fill='#5b6b85' stroke='#1a2b45'/><text x='192' y='93' font-size='8' text-anchor='middle' fill='#fff'>G</text></svg>","steps":[{"t":"Bağıntı","a":"F = G·sinθ","d":"Sürtünmesizde kuvvet, ağırlık ile eğim açısının sinüsünün çarpımıdır."},{"t":"Oranı yaz","a":"F/G = sin45°","d":"Kuvvetin ağırlığa oranı, eğim açısının sinüsüne eşittir."},{"t":"Sonuç","a":"≈ 0,71","d":"sin45° ≈ 0,71 olduğundan kuvvet ağırlığın yaklaşık 0,71 katıdır."}],"ans":"İtme kuvveti yükün ağırlığının yaklaşık 0,71 (sin45°) katıdır."},{"q":"600 N'luk yükü 4 m'lik rampadan 2 m yükseğe çıkarırken sürtünme kuvveti 50 N'dur. Gereken toplam itme kuvvetini bulunuz.","steps":[{"t":"İdeal kuvvet","a":"F = 600·2/4 = 300 N","d":"Sürtünmesiz bileşen, yük × yükseklik ÷ uzunluk = 300 N'dur."},{"t":"Sürtünmeyi ekle","a":"300 + 50","d":"Sürtünme harekete karşı koyduğundan ideal kuvvete eklenir."},{"t":"Sonuç","a":"350 N","d":"300 N ile 50 N toplanınca 350 N bulunur."}],"ans":"Gereken toplam itme kuvveti 350 N'dur (300 N ideal + 50 N sürtünme)."},{"q":"Şekildeki sürtünmesiz eğik düzlemde mekanik avantaj 2,5'tir. 500 N'luk yük çıkarılırken hem kuvvet kazancını hem de yol kaybını yorumlayınız.","fig":"<svg viewBox='0 0 320 175'><line x1='20' y1='150' x2='300' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='50,150 270,150 270,60' fill='#cdd6e4' stroke='#1a2b45'/><rect x='200' y='82' width='28' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='214' y='98' font-size='8' text-anchor='middle' fill='#fff'>500 N</text><polygon points='195,94 163,118 170,123 202,99' fill='#e0552b'/><line x1='195' y1='94' x2='163' y2='118' stroke='#e0552b' stroke-width='3'/><text x='158' y='138' font-size='9' fill='#1a2b45'>F</text><text x='150' y='166' font-size='9' text-anchor='middle' fill='#1a2b45'>MA = 2,5</text></svg>","steps":[{"t":"Kuvvet kazancı","a":"F = 500/2,5 = 200 N","d":"Gereken kuvvet, yükün mekanik avantaja bölümüdür; 500'ü dik kaldırmak yerine 200 N yeter."},{"t":"Yol kaybı","a":"yol 2,5 katı","d":"Mekanik avantaj kadar yol uzar; yükü 2,5 kat daha uzun mesafe boyunca itmek gerekir."}],"ans":"Kuvvet 500 N'dan 200 N'a düşer (2,5 kat kazanç), buna karşılık katedilen yol 2,5 kat uzar; iş değişmez."},{"q":"Bir eğik düzlemin verimi %60'tır. 800 N'luk yükü 3 m yükseğe çıkarmak için verilen toplam iş ve sürtünmede kaybolan enerji ne kadardır?","steps":[{"t":"Yararlı iş","a":"W = 800 × 3 = 2400 J","d":"Yararlı iş, ağırlık ile yüksekliğin çarpımıdır."},{"t":"Verilen iş","a":"2400 ÷ 0,6 = 4000 J","d":"Verim = yararlı/verilen olduğundan verilen iş, yararlı işin verime bölümüdür."},{"t":"Kayıp enerji","a":"4000 − 2400 = 1600 J","d":"Sürtünmede kaybolan enerji, verilen iş ile yararlı işin farkıdır."}],"ans":"Verilen toplam iş 4000 J, sürtünmede ısıya dönüşen kayıp ise 1600 J'dür."}]}},"hareketliMakara":{"ilkokul":{"kolay":[{"q":"Şekildeki hareketli makarada makaranın ekseni yüke bağlıdır. Yükü yukarı kaldırınca makara nereye gider?","fig":"<svg viewBox='0 0 240 220'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='80' y1='30' x2='80' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='30' x2='160' y2='90' stroke='#e0552b' stroke-width='2'/><circle cx='120' cy='120' r='28' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><path d='M 92 120 A 28 28 0 0 1 148 120' fill='none' stroke='#1a2b45' stroke-width='1'/><line x1='120' y1='148' x2='120' y2='180' stroke='#1a2b45' stroke-width='2'/><rect x='100' y='180' width='40' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='200' font-size='12' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"Eksen yüke bağlı","a":"birlikte","d":"Hareketli makaranın ortasındaki eksen yüke bağlı olduğu için makara ve yük birlikte hareket eder."},{"t":"Yön","a":"yukarı","d":"Yükü yukarı kaldırınca makara da yükle beraber yukarı çıkar."}],"ans":"Hareketli makara, ekseni yüke bağlı olduğu için yükle birlikte yukarı çıkar."},{"q":"Sabit makarayla bir yükü kaldırırken kuvvet azalmaz. Hareketli makara kullanınca kuvvetten kazanır mıyız?","steps":[{"t":"Hareketli makaranın faydası","a":"kuvvet azalır","d":"Hareketli makara yükü iki ip kolu taşıdığı için uyguladığımız kuvvet azalır."},{"t":"Sonuç","a":"kazanırız","d":"Daha az kuvvetle yükü kaldırdığımız için kuvvetten kazanırız."}],"ans":"Evet, hareketli makara kullanınca daha az kuvvetle kaldırdığımız için kuvvetten kazanırız."},{"q":"Şekildeki hareketli makarada yükü iki ip kolu taşıyor. Bu yüzden çekme kuvveti yükten az mı çok mu olur?","fig":"<svg viewBox='0 0 240 220'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='110' stroke='#1a2b45' stroke-width='2'/><text x='75' y='75' font-size='11' fill='#1a2b45'>ip</text><line x1='150' y1='30' x2='150' y2='110' stroke='#1a2b45' stroke-width='2'/><text x='158' y='75' font-size='11' fill='#1a2b45'>ip</text><circle cx='120' cy='130' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='156' x2='120' y2='185' stroke='#1a2b45' stroke-width='2'/><rect x='100' y='185' width='40' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='203' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"Yükü kim taşıyor","a":"iki ip","d":"Hareketli makarada yük, makaranın iki yanındaki iki ip kolu tarafından paylaşılarak taşınır."},{"t":"Kuvvet","a":"daha az","d":"Yük iki ip arasında paylaşıldığı için her ipe düşen kuvvet yükten azdır."}],"ans":"Yükü iki ip paylaştığı için çekme kuvveti yükten daha az olur."},{"q":"Bir çocuk hareketli makarayla ağır bir kovayı kuyudan çıkarıyor. Bu makara çocuğa hangi konuda yardım eder?","steps":[{"t":"Hareketli makaranın işi","a":"kuvvetten kazanç","d":"Hareketli makara uygulanan kuvveti azaltarak işi kolaylaştırır."},{"t":"Çocuğa faydası","a":"daha kolay","d":"Çocuk, kovayı doğrudan kaldırmaktan daha az kuvvetle yukarı çeker."}],"ans":"Hareketli makara, kovayı daha az kuvvetle kaldırmasını sağlayarak çocuğa yardım eder."},{"q":"Şekildeki hareketli makarada yükü 20 cm yukarı kaldırmak istiyoruz. İpi yukarıdan çekiyoruz. İpi mi yoksa yükü mü daha uzun bir yol kat eder?","fig":"<svg viewBox='0 0 240 230'><line x1='40' y1='25' x2='200' y2='25' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='25' x2='90' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='25' x2='150' y2='90' stroke='#e0552b' stroke-width='2'/><text x='170' y='55' font-size='11' fill='#1a2b45'>çekme</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='195' stroke='#1a2b45' stroke-width='2'/><rect x='100' y='195' width='40' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='213' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"İki ip kısalmalı","a":"iki kat ip","d":"Yük yukarı çıkarken makaranın iki yanındaki ipin de kısalması gerekir."},{"t":"Çekilen ip","a":"daha uzun","d":"Bu yüzden çektiğimiz ip, yükün çıktığı yolun iki katı kadar olur."}],"ans":"Çektiğimiz ip, yükün çıktığı yoldan daha uzundur; yük 20 cm çıkarken ipi 40 cm çekeriz."}],"zor":[{"q":"Şekildeki hareketli makarayla 30 kg'lık bir yük kaldırılıyor. Bir çocuk yükün yarısı kadar kuvvetle çekebiliyorsa kaç kg'lık kuvvetle çekmesi yeter?","fig":"<svg viewBox='0 0 240 220'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='110' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><text x='168' y='60' font-size='11' fill='#1a2b45'>çekme</text><circle cx='120' cy='130' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='156' x2='120' y2='184' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='184' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='202' font-size='11' text-anchor='middle' fill='#fff'>30 kg</text></svg>","steps":[{"t":"Yarısı kadar kuvvet","a":"yük ÷ 2","d":"Hareketli makarada kuvvet yükün yarısına iner."},{"t":"Hesapla","a":"30 ÷ 2 = 15","d":"30 kg'ın yarısı 15 kg'dır."}],"ans":"Çocuğun 15 kg'lık kuvvete denk bir çekmeyle yükü kaldırması yeter."},{"q":"Hareketli makarayla bir yükü 50 cm yukarı kaldırmak için ipi kaç cm çekmek gerekir?","steps":[{"t":"İp yolu iki kat","a":"yol × 2","d":"Hareketli makarada çekilen ip, yükün çıktığı yolun iki katıdır."},{"t":"Hesapla","a":"50 × 2 = 100","d":"50 cm'in iki katı 100 cm'dir."}],"ans":"İpi 100 cm (1 metre) çekmek gerekir."},{"q":"Şekildeki hareketli makarada bir kişi yükü doğrudan kaldırsa 40 birim kuvvet uygulaması gerekiyor. Hareketli makarayla kaç birim kuvvet uygular?","fig":"<svg viewBox='0 0 240 220'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='110' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='85' stroke='#e0552b' stroke-width='2'/><circle cx='120' cy='130' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='156' x2='120' y2='184' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='184' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='202' font-size='11' text-anchor='middle' fill='#fff'>40 br</text></svg>","steps":[{"t":"Kuvvet yarıya iner","a":"40 ÷ 2","d":"Hareketli makara kuvveti yarıya indirir."},{"t":"Hesapla","a":"20","d":"40'ın yarısı 20'dir."}],"ans":"Hareketli makarayla yalnızca 20 birim kuvvet uygular."},{"q":"Hareketli makara kuvveti yarıya indiriyor ama bir bedeli var. Bu kazancın karşılığında ne uzar?","steps":[{"t":"Kuvvet azalınca","a":"yol artar","d":"Hareketli makarada kuvvet yarıya inerken çekilen ip yolu iki katına çıkar."},{"t":"Sonuç","a":"çekilen ip uzar","d":"Az kuvvetle çalışmanın bedeli, daha uzun ip çekmektir."}],"ans":"Kuvvetten kazanırken çekmemiz gereken ip uzar; ip yolu iki katına çıkar."},{"q":"Şekildeki hareketli makarada makara hangi yöne dönerken yük yukarı çıkar diye düşünelim. Hareketli makara çekme yönümüzü değiştirir mi?","fig":"<svg viewBox='0 0 240 220'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='110' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='75' stroke='#e0552b' stroke-width='2'/><text x='160' y='55' font-size='11' fill='#1a2b45'>yukarı çek</text><circle cx='120' cy='130' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='156' x2='120' y2='184' stroke='#1a2b45' stroke-width='2'/><rect x='100' y='184' width='40' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='202' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"İpi nereye çekiyoruz","a":"yukarı","d":"Tek başına hareketli makarada ipi yukarı doğru çekeriz, yük de yukarı çıkar."},{"t":"Yön","a":"değişmez","d":"Yön aynı kaldığı için hareketli makara çekme yönümüzü değiştirmez."}],"ans":"Hayır, hareketli makara çekme yönünü değiştirmez; ipi yukarı çekeriz, yük yukarı çıkar."}]},"ortaokul":{"kolay":[{"q":"Şekildeki hareketli makarada 60 N ağırlığındaki yük asılıdır. Sürtünme ve makara ağırlığı önemsizse uygulanması gereken kuvvet kaç N olur?","fig":"<svg viewBox='0 0 240 230'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='115' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><defs><marker id='ok1' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='80' x2='150' y2='55' stroke='#e0552b' stroke-width='2' marker-end='url(#ok1)'/><text x='168' y='65' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='135' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='161' x2='120' y2='190' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='190' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='208' font-size='11' text-anchor='middle' fill='#fff'>60 N</text></svg>","steps":[{"t":"Kuvvet formülü","a":"F = Yük / 2","d":"Hareketli makarada uygulanan kuvvet, yükün yarısına eşittir."},{"t":"Hesapla","a":"60 / 2 = 30","d":"60 N'un yarısı 30 N'dur."}],"ans":"Uygulanması gereken kuvvet 30 N'dur."},{"q":"Hareketli makarada uygulanan kuvvetin yükün yarısı olmasının nedeni nedir?","steps":[{"t":"Yükü iki ip taşır","a":"iki ip kolu","d":"Hareketli makarayı sarıp tutan iki ip kolu, yükü aralarında eşit paylaşır."},{"t":"Paylaşım","a":"yarı yarıya","d":"Yük iki ipe eşit dağıldığı için her ipteki gerilme, dolayısıyla uyguladığımız kuvvet yükün yarısı olur."}],"ans":"Yük, makarayı taşıyan iki ip kolu arasında eşit paylaşıldığı için uygulanan kuvvet yükün yarısıdır."},{"q":"Şekildeki hareketli makarayla yük 25 cm yukarı kaldırılıyor. İpin serbest ucu kaç cm çekilmiştir?","fig":"<svg viewBox='0 0 240 230'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='115' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><text x='166' y='62' font-size='11' fill='#1a2b45'>çek</text><circle cx='120' cy='135' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='161' x2='120' y2='190' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='190' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='208' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"İp yolu iki kat","a":"ip = 2 × yük yolu","d":"Hareketli makarada çekilen ip, yükün çıktığı yolun iki katıdır."},{"t":"Hesapla","a":"2 × 25 = 50","d":"25 cm'in iki katı 50 cm'dir."}],"ans":"İpin serbest ucu 50 cm çekilmiştir."},{"q":"Hareketli makaranın mekanik avantajı (kuvvet kazancı) kaçtır?","steps":[{"t":"Mekanik avantaj tanımı","a":"Yük / Kuvvet","d":"Mekanik avantaj, yükün uygulanan kuvvete oranıdır."},{"t":"Hareketli makarada","a":"2","d":"Kuvvet yükün yarısı olduğu için Yük / (Yük/2) = 2 çıkar."}],"ans":"Hareketli makaranın mekanik avantajı 2'dir."},{"q":"Şekildeki hareketli makarada yükün ağırlığı iki ip arasında paylaşılıyor. Yük 80 N ise her bir ipteki gerilme kaç N olur?","fig":"<svg viewBox='0 0 240 230'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='88' y1='30' x2='88' y2='118' stroke='#1a2b45' stroke-width='2'/><text x='72' y='80' font-size='11' fill='#1a2b45'>T</text><line x1='152' y1='30' x2='152' y2='118' stroke='#1a2b45' stroke-width='2'/><text x='160' y='80' font-size='11' fill='#1a2b45'>T</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='192' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>80 N</text></svg>","steps":[{"t":"İki ip eşit paylaşır","a":"T = Yük / 2","d":"Yük iki ip kolu arasında eşit dağıldığı için her ipteki gerilme yükün yarısıdır."},{"t":"Hesapla","a":"80 / 2 = 40","d":"80 N'un yarısı 40 N'dur."}],"ans":"Her bir ipteki gerilme 40 N'dur."}],"zor":[{"q":"Şekildeki hareketli makarada yük 90 N'dur ve serbest uçtan F kuvveti uygulanmaktadır. Hem F kuvvetini hem de yükü 30 cm kaldırmak için çekilmesi gereken ip uzunluğunu bulunuz.","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><defs><marker id='oz1' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='80' x2='150' y2='52' stroke='#e0552b' stroke-width='2' marker-end='url(#oz1)'/><text x='166' y='65' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='96' y='192' width='48' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>90 N</text></svg>","steps":[{"t":"Kuvveti bul","a":"F = 90 / 2 = 45 N","d":"Hareketli makarada kuvvet yükün yarısıdır, 90 / 2 = 45 N."},{"t":"İp yolu","a":"ip = 2 × 30","d":"Çekilen ip yükün çıktığı yolun iki katıdır."},{"t":"Hesapla","a":"60 cm","d":"2 × 30 = 60 cm bulunur."}],"ans":"Uygulanan kuvvet 45 N, çekilmesi gereken ip 60 cm'dir."},{"q":"Şekildeki hareketli makarada serbest uçtan 25 N kuvvet uygulanarak yük dengede tutuluyor. Sürtünme ve makara ağırlığı önemsizse yükün ağırlığı kaç N'dur?","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><defs><marker id='oz2' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='80' x2='150' y2='52' stroke='#e0552b' stroke-width='2' marker-end='url(#oz2)'/><text x='162' y='65' font-size='11' fill='#1a2b45'>25 N</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='192' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>G=?</text></svg>","steps":[{"t":"Bağıntıyı tersine çevir","a":"Yük = 2 × F","d":"Kuvvet yükün yarısı olduğundan yük, kuvvetin iki katıdır."},{"t":"Hesapla","a":"2 × 25 = 50","d":"25 N'un iki katı 50 N'dur."}],"ans":"Yükün ağırlığı 50 N'dur."},{"q":"Şekildeki hareketli makarada ip serbest uçtan 80 cm çekilmiştir. Yük kaç cm yukarı çıkar?","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='78' stroke='#e0552b' stroke-width='2'/><text x='160' y='60' font-size='11' fill='#1a2b45'>80 cm çek</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='192' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"Bağıntıyı kur","a":"yük yolu = ip / 2","d":"Çekilen ip, yük yolunun iki katı olduğundan yük yolu ipin yarısıdır."},{"t":"Hesapla","a":"80 / 2 = 40","d":"80 cm'in yarısı 40 cm'dir."}],"ans":"Yük 40 cm yukarı çıkar."},{"q":"Hareketli makara kuvvetten kazandırır ama işten kazandırmaz. 60 N'luk yük 0,5 m kaldırılırken yapılan işin değişmediğini hesapla.","steps":[{"t":"Yüke yapılan iş","a":"60 × 0,5 = 30 J","d":"Yüke yapılan iş, ağırlık çarpı yükün çıktığı yoldur: 60 N × 0,5 m = 30 J."},{"t":"Kuvvetle yapılan iş","a":"30 × 1 = 30 J","d":"Kuvvet 30 N, ip yolu 1 m (iki kat); iş 30 N × 1 m = 30 J olur."},{"t":"Karşılaştır","a":"eşit","d":"Her iki iş de 30 J çıktığı için makara işten kazandırmaz."}],"ans":"Kuvvet yarıya inerken yol iki katına çıktığı için iş 30 J olarak aynı kalır; işten kazanç yoktur."},{"q":"Şekildeki hareketli makarada makaranın kendi ağırlığı 10 N, yük 70 N'dur. İdeal kabul edilmeyip makara ağırlığı da hesaba katılırsa uygulanması gereken kuvvet kaç N olur?","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><text x='164' y='62' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><text x='120' y='142' font-size='10' text-anchor='middle' fill='#fff'>10 N</text><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='192' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>70 N</text></svg>","steps":[{"t":"Toplam asılı ağırlık","a":"70 + 10 = 80 N","d":"Makaranın ekseni yükle birlikte iki ip tarafından taşındığı için yük ve makara ağırlığı toplanır."},{"t":"İkiye böl","a":"80 / 2 = 40","d":"Toplam ağırlık iki ip kolu arasında paylaşılır, her ipe düşen kuvvet 40 N olur."}],"ans":"Makara ağırlığı da katılınca uygulanması gereken kuvvet 40 N'dur."}]},"lise":{"kolay":[{"q":"İdeal (sürtünmesiz, ağırlıksız) bir hareketli makarada uygulanan kuvvet ile yük arasındaki bağıntıyı yazınız.","steps":[{"t":"Yükü iki ip taşır","a":"iki kol","d":"Hareketli makarayı saran ipin iki kolu yükü taşır ve gerilmeleri eşittir."},{"t":"Bağıntı","a":"F = Yük / 2","d":"Yük iki eşit ip gerilmesi arasında paylaşıldığından uygulanan kuvvet yükün yarısıdır."}],"ans":"İdeal hareketli makarada F = Yük / 2 bağıntısı geçerlidir."},{"q":"Şekildeki ideal hareketli makarada yük 120 N'dur. Uygulanması gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><defs><marker id='lk1' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='80' x2='150' y2='52' stroke='#e0552b' stroke-width='2' marker-end='url(#lk1)'/><text x='164' y='65' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='94' y='192' width='52' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>120 N</text></svg>","steps":[{"t":"Bağıntıyı yaz","a":"F = Yük / 2","d":"İdeal hareketli makarada kuvvet yükün yarısıdır."},{"t":"Hesapla","a":"120 / 2 = 60","d":"120 N'un yarısı 60 N'dur."}],"ans":"Uygulanması gereken kuvvet 60 N'dur."},{"q":"İdeal bir hareketli makarada uygulanan kuvvet 35 N ise dengede tutulan yükün ağırlığı kaç N'dur?","steps":[{"t":"Bağıntıyı tersine çevir","a":"Yük = 2F","d":"F = Yük / 2 bağıntısından yük, kuvvetin iki katı olur."},{"t":"Hesapla","a":"2 × 35 = 70","d":"35 N'un iki katı 70 N'dur."}],"ans":"Yükün ağırlığı 70 N'dur."},{"q":"Hareketli makaranın mekanik avantajını tanımdan yola çıkarak bulunuz.","steps":[{"t":"Tanım","a":"MA = Yük / F","d":"Mekanik avantaj, yükün uygulanan kuvvete oranıdır."},{"t":"Yerine koy","a":"Yük / (Yük/2)","d":"Hareketli makarada F = Yük/2 olduğundan oran Yük / (Yük/2) olur."},{"t":"Sadeleştir","a":"2","d":"Bu oran sadeleşince 2 çıkar."}],"ans":"Hareketli makaranın mekanik avantajı 2'dir."},{"q":"Şekildeki ideal hareketli makarada yük 50 cm yukarı kaldırılmıştır. İpin serbest ucunun aldığı yolu bulunuz.","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><text x='164' y='62' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><defs><marker id='lk2' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#5b6b85'/></marker></defs><line x1='175' y1='200' x2='175' y2='175' stroke='#5b6b85' stroke-width='2' marker-end='url(#lk2)'/><text x='190' y='195' font-size='10' fill='#1a2b45'>h</text><rect x='98' y='192' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"Yol bağıntısı","a":"ip = 2 × yük yolu","d":"Hareketli makarada serbest ucun aldığı yol, yükün çıktığı yolun iki katıdır."},{"t":"Hesapla","a":"2 × 50 = 100","d":"50 cm'in iki katı 100 cm'dir."}],"ans":"İpin serbest ucu 100 cm (1 m) yol almıştır."},{"q":"İdeal hareketli makarada yükü taşıyan iki ip kolunun gerilmeleri arasındaki ilişkiyi açıklayınız.","steps":[{"t":"Aynı ip","a":"tek ip","d":"İki kol da aynı ipin parçası olduğu ve makara sürtünmesiz döndüğü için ip boyunca gerilme sabittir."},{"t":"Sonuç","a":"eşit","d":"Bu yüzden iki kolun gerilmesi birbirine eşittir ve her biri yükün yarısını taşır."}],"ans":"İdeal makarada iki ip kolunun gerilmeleri eşittir; her biri yükün yarısını taşır."},{"q":"Şekildeki ideal hareketli makarada yük 200 N'dur. Yükü taşıyan her bir ip kolundaki gerilmeyi bulunuz.","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='88' y1='30' x2='88' y2='120' stroke='#1a2b45' stroke-width='2'/><text x='70' y='82' font-size='11' fill='#1a2b45'>T</text><line x1='152' y1='30' x2='152' y2='120' stroke='#1a2b45' stroke-width='2'/><text x='160' y='82' font-size='11' fill='#1a2b45'>T</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='194' stroke='#1a2b45' stroke-width='2'/><rect x='94' y='194' width='52' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='212' font-size='11' text-anchor='middle' fill='#fff'>200 N</text></svg>","steps":[{"t":"Yük iki ipe paylaşılır","a":"T = Yük / 2","d":"İki eşit gerilme yükü dengeler, dolayısıyla her gerilme yükün yarısıdır."},{"t":"Hesapla","a":"200 / 2 = 100","d":"200 N'un yarısı 100 N'dur."}],"ans":"Her bir ip kolundaki gerilme 100 N'dur."},{"q":"İdeal bir hareketli makarada serbest uçtan 90 cm ip çekildiğinde yük kaç cm yükselir?","steps":[{"t":"Yol bağıntısı","a":"yük yolu = ip / 2","d":"Çekilen ip yük yolunun iki katı olduğundan yük yolu çekilen ipin yarısıdır."},{"t":"Hesapla","a":"90 / 2 = 45","d":"90 cm'in yarısı 45 cm'dir."}],"ans":"Yük 45 cm yükselir."},{"q":"Hareketli makarada yapılan işten neden kazanç olmadığını kuvvet ve yol ilişkisiyle açıklayınız.","steps":[{"t":"Kuvvet yarıya iner","a":"F = Yük/2","d":"Hareketli makara uygulanan kuvveti yarıya indirir."},{"t":"Yol iki katına çıkar","a":"ip = 2h","d":"Buna karşılık çekilen ip yolu, yükün çıktığı yolun iki katı olur."},{"t":"İş çarpımı","a":"F × yol sabit","d":"Kuvvet yarıya inerken yol iki katına çıktığı için iş (kuvvet × yol) değişmez."}],"ans":"Kuvvet yarıya inerken yol iki katına çıktığından iş sabit kalır; bu yüzden işten kazanç olmaz."},{"q":"Şekildeki ideal hareketli makarada 48 N'luk yük dengede tutulmaktadır. Uygulanan kuvveti ve mekanik avantajı birlikte bulunuz.","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><defs><marker id='lk3' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='80' x2='150' y2='52' stroke='#e0552b' stroke-width='2' marker-end='url(#lk3)'/><text x='164' y='65' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='96' y='192' width='48' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>48 N</text></svg>","steps":[{"t":"Kuvveti bul","a":"F = 48 / 2 = 24 N","d":"İdeal hareketli makarada kuvvet yükün yarısıdır, 48 / 2 = 24 N."},{"t":"Mekanik avantaj","a":"MA = 48 / 24 = 2","d":"Yükün kuvvete oranı 2 çıkar."}],"ans":"Uygulanan kuvvet 24 N, mekanik avantaj 2'dir."},{"q":"Bir hareketli makarada ip serbest ucunun hızı 0,6 m/s ise yükün yükselme hızı kaç m/s olur?","steps":[{"t":"Yol oranı hıza taşınır","a":"v_yük = v_ip / 2","d":"İp yolu yük yolunun iki katı olduğundan, ipin hızı da yükün hızının iki katıdır."},{"t":"Hesapla","a":"0,6 / 2 = 0,3","d":"0,6 m/s'nin yarısı 0,3 m/s'dir."}],"ans":"Yükün yükselme hızı 0,3 m/s'dir."},{"q":"Şekildeki ideal hareketli makarada yük 36 N, makara ağırlıksız kabul edilmiştir. Yük 20 cm yukarı çıkarken yapılan işi (yüke yapılan iş) hesaplayınız.","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><text x='164' y='62' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='192' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>36 N</text></svg>","steps":[{"t":"İş formülü","a":"W = Yük × h","d":"Yüke yapılan iş, ağırlık çarpı yükün çıktığı yüksekliktir."},{"t":"Birim çevir","a":"20 cm = 0,2 m","d":"Yol metreye çevrilir: 20 cm = 0,2 m."},{"t":"Hesapla","a":"36 × 0,2 = 7,2 J","d":"36 N × 0,2 m = 7,2 J bulunur."}],"ans":"Yüke yapılan iş 7,2 J'dür."},{"q":"İdeal hareketli makara hareket yönünü değiştirir mi? Sabit makarayla farkını açıklayınız.","steps":[{"t":"Hareketli makara","a":"yön aynı","d":"Tek hareketli makarada ipi yukarı çekeriz, yük de yukarı çıkar; yön değişmez."},{"t":"Sabit makara","a":"yön değişir","d":"Sabit makara kuvvetten kazandırmaz ama çekme yönünü ters çevirir."}],"ans":"Hareketli makara yönü değiştirmez ama kuvvetten kazandırır; sabit makara ise yönü değiştirir, kuvvetten kazandırmaz."},{"q":"Şekildeki ideal hareketli makarada kuvvet 15 N uygulanarak yük dengede tutuluyor. Yükü 0,4 m kaldırmak için kuvvetin yaptığı işi bulunuz.","fig":"<svg viewBox='0 0 240 235'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='80' stroke='#e0552b' stroke-width='2'/><defs><marker id='lk4' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='80' x2='150' y2='52' stroke='#e0552b' stroke-width='2' marker-end='url(#lk4)'/><text x='162' y='65' font-size='11' fill='#1a2b45'>15 N</text><circle cx='120' cy='138' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='164' x2='120' y2='192' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='192' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='210' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"İp yolu","a":"ip = 2 × 0,4 = 0,8 m","d":"Yük 0,4 m çıkarken serbest uç iki katı, yani 0,8 m yol alır."},{"t":"İş formülü","a":"W = F × ip yolu","d":"Kuvvetin işi, kuvvet çarpı ipin aldığı yoldur."},{"t":"Hesapla","a":"15 × 0,8 = 12 J","d":"15 N × 0,8 m = 12 J bulunur."}],"ans":"Kuvvetin yaptığı iş 12 J'dür."},{"q":"Hareketli makarada yük iki katına çıkarılırsa uygulanması gereken kuvvet nasıl değişir?","steps":[{"t":"Bağıntı","a":"F = Yük / 2","d":"Kuvvet yükle doğru orantılıdır; yükün yarısına eşittir."},{"t":"Yük 2 kat olunca","a":"F de 2 kat","d":"Yük iki katına çıkınca kuvvet de iki katına çıkar; oran (yarı) sabit kalır."}],"ans":"Yük iki katına çıkarsa uygulanması gereken kuvvet de iki katına çıkar."}],"zor":[{"q":"Şekildeki ideal hareketli makarada yük 240 N'dur. Yükü 60 cm yukarı kaldırmak için gereken kuvveti, çekilecek ip uzunluğunu ve mekanik avantajı bulunuz.","fig":"<svg viewBox='0 0 240 240'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='82' stroke='#e0552b' stroke-width='2'/><defs><marker id='lz1' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='82' x2='150' y2='54' stroke='#e0552b' stroke-width='2' marker-end='url(#lz1)'/><text x='164' y='68' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='196' stroke='#1a2b45' stroke-width='2'/><rect x='94' y='196' width='52' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='214' font-size='11' text-anchor='middle' fill='#fff'>240 N</text></svg>","steps":[{"t":"Kuvvet","a":"F = 240 / 2 = 120 N","d":"İdeal hareketli makarada kuvvet yükün yarısıdır."},{"t":"İp uzunluğu","a":"ip = 2 × 60 = 120 cm","d":"Çekilen ip, yük yolunun iki katıdır."},{"t":"Mekanik avantaj","a":"MA = 240 / 120 = 2","d":"Yükün kuvvete oranı 2 çıkar."}],"ans":"Gereken kuvvet 120 N, çekilecek ip 120 cm, mekanik avantaj 2'dir."},{"q":"Bir hareketli makarada makaranın kendi ağırlığı 20 N, yük 160 N'dur. İpler düşeyse uygulanması gereken kuvveti bulunuz.","steps":[{"t":"Toplam asılı ağırlık","a":"160 + 20 = 180 N","d":"Makaranın ekseni yükle birlikte iki ip tarafından taşındığından makara ağırlığı yüke eklenir."},{"t":"İki ip paylaşır","a":"F = 180 / 2","d":"Toplam ağırlık iki eşit ip gerilmesi arasında paylaşılır."},{"t":"Hesapla","a":"90 N","d":"180 / 2 = 90 N bulunur."}],"ans":"Makara ağırlığı da hesaba katılınca uygulanması gereken kuvvet 90 N'dur."},{"q":"Şekildeki ideal hareketli makarada kuvvet 0,5 m/s sabit hızla ip çekiyor. Yük 300 N ise kuvvetin gücünü (P = F·v) hesaplayınız.","fig":"<svg viewBox='0 0 240 240'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='82' stroke='#e0552b' stroke-width='2'/><defs><marker id='lz2' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='82' x2='150' y2='54' stroke='#e0552b' stroke-width='2' marker-end='url(#lz2)'/><text x='160' y='68' font-size='11' fill='#1a2b45'>v=0,5</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='196' stroke='#1a2b45' stroke-width='2'/><rect x='94' y='196' width='52' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='214' font-size='11' text-anchor='middle' fill='#fff'>300 N</text></svg>","steps":[{"t":"Kuvveti bul","a":"F = 300 / 2 = 150 N","d":"İdeal hareketli makarada kuvvet yükün yarısıdır."},{"t":"Güç formülü","a":"P = F × v","d":"Güç, kuvvet çarpı kuvvetin uygulandığı noktanın (ip ucunun) hızıdır."},{"t":"Hesapla","a":"150 × 0,5 = 75 W","d":"150 N × 0,5 m/s = 75 W bulunur."}],"ans":"Kuvvetin gücü 75 W'tır."},{"q":"İdeal hareketli makarada yük 0,3 m yükseldiğinde 18 J iş yapılmıştır. Yükün ağırlığını ve uygulanan kuvveti bulunuz.","steps":[{"t":"Yükü bul","a":"Yük = W / h","d":"İş, ağırlık çarpı yükseklik olduğundan ağırlık, iş bölü yüksekliktir."},{"t":"Hesapla","a":"18 / 0,3 = 60 N","d":"18 J ÷ 0,3 m = 60 N bulunur."},{"t":"Kuvvet","a":"F = 60 / 2 = 30 N","d":"Hareketli makarada kuvvet yükün yarısıdır."}],"ans":"Yükün ağırlığı 60 N, uygulanan kuvvet 30 N'dur."},{"q":"Şekildeki ideal hareketli makarada serbest uçtan 1,2 m ip çekilmiş ve kuvvet 25 N uygulanmıştır. Yükün çıktığı yolu ve yükün ağırlığını bulunuz.","fig":"<svg viewBox='0 0 240 240'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='82' stroke='#e0552b' stroke-width='2'/><defs><marker id='lz3' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='82' x2='150' y2='54' stroke='#e0552b' stroke-width='2' marker-end='url(#lz3)'/><text x='160' y='68' font-size='11' fill='#1a2b45'>25 N</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='196' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='196' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='214' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"Yük yolu","a":"1,2 / 2 = 0,6 m","d":"Yük yolu, çekilen ipin yarısıdır."},{"t":"Yükü bul","a":"Yük = 2 × 25","d":"Hareketli makarada yük, kuvvetin iki katıdır."},{"t":"Hesapla","a":"50 N","d":"2 × 25 = 50 N bulunur."}],"ans":"Yük 0,6 m çıkmıştır ve yükün ağırlığı 50 N'dur."},{"q":"Bir hareketli makara sisteminde verim %100 (ideal) kabul edilirse 80 N'luk yükü kaldırmak için kuvvet 40 N olmalıdır. Verim %80'e düşerse uygulanması gereken kuvvet kaç N olur?","steps":[{"t":"İdeal kuvvet","a":"80 / 2 = 40 N","d":"İdeal durumda kuvvet yükün yarısı, yani 40 N'dur."},{"t":"Verim bağıntısı","a":"F = ideal F / verim","d":"Gerçek kuvvet, ideal kuvvetin verime bölümüyle artar."},{"t":"Hesapla","a":"40 / 0,8 = 50 N","d":"40 ÷ 0,8 = 50 N bulunur."}],"ans":"Verim %80 olunca uygulanması gereken kuvvet 50 N'dur."},{"q":"Şekildeki ideal hareketli makarada yük 90 N'dur ve ip ucundaki kuvvet sabittir. Yük 40 cm yükselirken kuvvetin yaptığı işle yüke yapılan işin eşit olduğunu hesapla.","fig":"<svg viewBox='0 0 240 240'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='82' stroke='#e0552b' stroke-width='2'/><defs><marker id='lz4' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='82' x2='150' y2='54' stroke='#e0552b' stroke-width='2' marker-end='url(#lz4)'/><text x='164' y='68' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='196' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='196' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='214' font-size='11' text-anchor='middle' fill='#fff'>90 N</text></svg>","steps":[{"t":"Yüke yapılan iş","a":"90 × 0,4 = 36 J","d":"Yüke yapılan iş, ağırlık çarpı yüksekliktir: 90 N × 0,4 m = 36 J."},{"t":"Kuvvet ve ip yolu","a":"F = 45 N, ip = 0,8 m","d":"Kuvvet 90/2 = 45 N, ip yolu 2 × 0,4 = 0,8 m'dir."},{"t":"Kuvvetin işi","a":"45 × 0,8 = 36 J","d":"45 N × 0,8 m = 36 J; iki iş de eşittir."}],"ans":"Her iki iş de 36 J'dür; hareketli makara işten kazandırmaz, kuvvetten kazandırır."},{"q":"İki özdeş hareketli makara üst üste değil, yük yine tek hareketli makaraya asılı. Sadece tek hareketli makara için yük 144 N ise her ip kolundaki gerilmeyi ve kuvveti karşılaştırınız.","steps":[{"t":"Gerilme","a":"T = 144 / 2 = 72 N","d":"Yük iki eşit ip kolu arasında paylaşılır, her gerilme 72 N olur."},{"t":"Uygulanan kuvvet","a":"F = 72 N","d":"Serbest uçtan uygulanan kuvvet, ip gerilmesine eşit olduğundan 72 N'dur."},{"t":"Karşılaştır","a":"eşit","d":"İdeal makarada serbest uçtaki kuvvet, ip gerilmesiyle aynıdır; her ikisi de yükün yarısıdır."}],"ans":"Her ip kolundaki gerilme 72 N'dur ve serbest uca uygulanan kuvvet de 72 N'dur; ikisi eşittir."},{"q":"Şekildeki ideal hareketli makarada kuvvet 30 N uygulanıyor ve yük 4 s'de 0,6 m yükseliyor. Yapılan faydalı işi ve gücü bulunuz.","fig":"<svg viewBox='0 0 240 240'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='82' stroke='#e0552b' stroke-width='2'/><defs><marker id='lz5' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='82' x2='150' y2='54' stroke='#e0552b' stroke-width='2' marker-end='url(#lz5)'/><text x='160' y='68' font-size='11' fill='#1a2b45'>30 N</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='196' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='196' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='214' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"Yükü bul","a":"Yük = 2 × 30 = 60 N","d":"Hareketli makarada yük, kuvvetin iki katıdır."},{"t":"Faydalı iş","a":"60 × 0,6 = 36 J","d":"Yüke yapılan faydalı iş, ağırlık çarpı yüksekliktir: 60 N × 0,6 m = 36 J."},{"t":"Güç","a":"36 / 4 = 9 W","d":"Güç, iş bölü zamandır: 36 J ÷ 4 s = 9 W."}],"ans":"Faydalı iş 36 J, güç 9 W'tır."},{"q":"İdeal hareketli makarada yükün hızı 0,2 m/s ise serbest uçtaki ipin çekilme hızını ve bu durumda kuvvet 50 N iken yükü bulunuz.","steps":[{"t":"İp hızı","a":"v_ip = 2 × 0,2 = 0,4 m/s","d":"İp yolu yük yolunun iki katı olduğundan ip hızı da yük hızının iki katıdır."},{"t":"Yükü bul","a":"Yük = 2 × 50","d":"Hareketli makarada yük, kuvvetin iki katıdır."},{"t":"Hesapla","a":"100 N","d":"2 × 50 = 100 N bulunur."}],"ans":"İpin çekilme hızı 0,4 m/s, yükün ağırlığı 100 N'dur."},{"q":"Şekildeki ideal hareketli makarada ipin bir ucu tavana bağlı, diğer ucundan F çekiliyor. Yük 320 N ise her ip kolundaki gerilmeyi ve uygulanan F'yi bulunuz.","fig":"<svg viewBox='0 0 240 245'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='88' y1='30' x2='88' y2='122' stroke='#1a2b45' stroke-width='2'/><text x='66' y='84' font-size='11' fill='#1a2b45'>T</text><text x='62' y='46' font-size='10' fill='#1a2b45'>tavan</text><line x1='152' y1='30' x2='152' y2='84' stroke='#e0552b' stroke-width='2'/><defs><marker id='lz6' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='152' y1='84' x2='152' y2='56' stroke='#e0552b' stroke-width='2' marker-end='url(#lz6)'/><text x='166' y='70' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='142' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='168' x2='120' y2='198' stroke='#1a2b45' stroke-width='2'/><rect x='94' y='198' width='52' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='216' font-size='11' text-anchor='middle' fill='#fff'>320 N</text></svg>","steps":[{"t":"Gerilme","a":"T = 320 / 2 = 160 N","d":"Yük iki eşit ip kolu (biri tavana bağlı, biri çekilen) arasında paylaşılır."},{"t":"F gerilmeye eşit","a":"F = T = 160 N","d":"Serbest uçtan uygulanan F, ip gerilmesine eşittir."}],"ans":"Her ip kolundaki gerilme 160 N'dur ve uygulanan kuvvet F = 160 N'dur."},{"q":"İdeal hareketli makarada yük 50 N'dan 75 N'a çıkarılıyor. Uygulanması gereken kuvvetteki artışı bulunuz.","steps":[{"t":"İlk kuvvet","a":"50 / 2 = 25 N","d":"İlk durumda kuvvet yükün yarısı, 25 N'dur."},{"t":"Son kuvvet","a":"75 / 2 = 37,5 N","d":"Yük 75 N olunca kuvvet 37,5 N olur."},{"t":"Artış","a":"37,5 − 25 = 12,5 N","d":"İki kuvvetin farkı 12,5 N'dur."}],"ans":"Uygulanması gereken kuvvet 12,5 N artar."},{"q":"Şekildeki ideal hareketli makarada yükü 1 m kaldırmak için yapılan toplam iş 200 J'dür. Yükün ağırlığını, uygulanan kuvveti ve çekilen ip uzunluğunu bulunuz.","fig":"<svg viewBox='0 0 240 240'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='82' stroke='#e0552b' stroke-width='2'/><defs><marker id='lz7' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='82' x2='150' y2='54' stroke='#e0552b' stroke-width='2' marker-end='url(#lz7)'/><text x='164' y='68' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='196' stroke='#1a2b45' stroke-width='2'/><rect x='98' y='196' width='44' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='214' font-size='11' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"Yükü bul","a":"Yük = W / h = 200 / 1","d":"İdeal makarada toplam iş yüke yapılan işe eşittir; ağırlık iş bölü yüksekliktir."},{"t":"Yük ve kuvvet","a":"Yük = 200 N, F = 100 N","d":"Yük 200 N, kuvvet yükün yarısı 100 N'dur."},{"t":"İp uzunluğu","a":"2 × 1 = 2 m","d":"Çekilen ip yük yolunun iki katı, yani 2 m'dir."}],"ans":"Yük 200 N, uygulanan kuvvet 100 N, çekilen ip 2 m'dir."},{"q":"Hareketli makarada mekanik avantajın 2 olması, kuvvetten ne kadar tasarruf sağlandığını gösterir? Yorum yapınız.","steps":[{"t":"MA anlamı","a":"yükü 2 kat","d":"Mekanik avantaj 2, aynı kuvvetle iki kat ağır yükü kaldırabilmek demektir."},{"t":"Kuvvet açısından","a":"yarı kuvvet","d":"Aynı yük için yalnızca yarısı kadar kuvvet uygulamak yeterlidir."},{"t":"Bedeli","a":"iki kat yol","d":"Bu kazanç karşılığında ip iki kat uzun çekilir; iş korunur."}],"ans":"MA = 2 olması, yükü yarısı kadar kuvvetle kaldırmayı sağlar; ancak ip iki kat uzun çekildiği için işten kazanç yoktur."},{"q":"Şekildeki ideal hareketli makarada yük 180 N'dur. Yükü 45 cm yükseltmek için uygulanan kuvvetin yaptığı işi, çekilen ip uzunluğu üzerinden hesaplayınız.","fig":"<svg viewBox='0 0 240 240'><line x1='40' y1='30' x2='200' y2='30' stroke='#1a2b45' stroke-width='4'/><line x1='90' y1='30' x2='90' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='30' x2='150' y2='82' stroke='#e0552b' stroke-width='2'/><defs><marker id='lz8' markerWidth='8' markerHeight='8' refX='6' refY='3' orient='auto'><polygon points='0,0 7,3 0,6' fill='#e0552b'/></marker></defs><line x1='150' y1='82' x2='150' y2='54' stroke='#e0552b' stroke-width='2' marker-end='url(#lz8)'/><text x='164' y='68' font-size='11' fill='#1a2b45'>F</text><circle cx='120' cy='140' r='26' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='120' y1='166' x2='120' y2='196' stroke='#1a2b45' stroke-width='2'/><rect x='94' y='196' width='52' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='120' y='214' font-size='11' text-anchor='middle' fill='#fff'>180 N</text></svg>","steps":[{"t":"Kuvvet ve ip yolu","a":"F = 90 N, ip = 0,9 m","d":"Kuvvet yükün yarısı 90 N; ip yolu yük yolunun iki katı 2 × 0,45 = 0,9 m'dir."},{"t":"İş formülü","a":"W = F × ip yolu","d":"Kuvvetin işi, kuvvet çarpı ipin aldığı yoldur."},{"t":"Hesapla","a":"90 × 0,9 = 81 J","d":"90 N × 0,9 m = 81 J bulunur (yüke yapılan iş 180 × 0,45 = 81 J ile aynıdır)."}],"ans":"Çekilen ip 0,9 m'dir ve kuvvetin yaptığı iş 81 J'dür; bu, yüke yapılan işe eşittir."}]}},"kaldirac":{"ilkokul":{"kolay":[{"q":"Şekildeki tahterevallinin ortasındaki sivri dayanak noktasına ne ad verilir?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='110' x2='280' y2='110' stroke='#1a2b45' stroke-width='6'/><polygon points='160,110 140,150 180,150' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='168' font-size='12' text-anchor='middle' fill='#1a2b45'>dayanak</text><circle cx='70' cy='98' r='12' fill='#5b6b85' stroke='#1a2b45'/><circle cx='250' cy='98' r='12' fill='#5b6b85' stroke='#1a2b45'/></svg>","steps":[{"t":"Tahterevalli neyin üstünde döner?","a":"sivri destek","d":"Tahtanın ortasındaki üçgen destek, tahtanın dengede dönmesini sağlar."},{"t":"Bu noktanın adı","a":"dayanak (destek) noktası","d":"Kaldıracın üzerinde döndüğü sabit noktaya dayanak ya da destek noktası denir."}],"ans":"Tahterevallinin ortasındaki sivri noktaya dayanak (destek) noktası denir; kaldıraç bu noktanın üzerinde döner."},{"q":"Şekilde tahterevallinin iki ucunda eşit ağırlıkta iki çocuk, ortadan eşit uzaklıkta oturuyor. Tahterevalli ne yapar?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='110' x2='280' y2='110' stroke='#1a2b45' stroke-width='6'/><polygon points='160,110 140,150 180,150' fill='#e0552b' stroke='#1a2b45'/><circle cx='70' cy='95' r='14' fill='#5b6b85' stroke='#1a2b45'/><circle cx='250' cy='95' r='14' fill='#5b6b85' stroke='#1a2b45'/><text x='70' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>eşit</text><text x='250' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>eşit</text></svg>","steps":[{"t":"Ağırlıklar ve uzaklıklar","a":"eşit","d":"İki çocuk hem aynı ağırlıkta hem de ortaya aynı uzaklıkta oturuyor."},{"t":"Sonuç","a":"dengede kalır","d":"Eşit ağırlıklar eşit uzaklıkta olunca tahterevalli yatay kalır, hiçbir taraf inmez."}],"ans":"Eşit ağırlıktaki çocuklar ortaya eşit uzaklıkta oturduğu için tahterevalli dengede kalır, yatay durur."},{"q":"Şekilde ağır olan büyük bir çocuk ile hafif olan küçük bir çocuk tahterevalliye binmiş. Hangi taraf aşağı iner?","fig":"<svg viewBox='0 0 320 175'><line x1='45' y1='95' x2='275' y2='125' stroke='#1a2b45' stroke-width='6'/><polygon points='160,110 140,150 180,150' fill='#e0552b' stroke='#1a2b45'/><circle cx='250' cy='108' r='18' fill='#5b6b85' stroke='#1a2b45'/><text x='250' y='160' font-size='11' text-anchor='middle' fill='#1a2b45'>ağır</text><circle cx='70' cy='78' r='10' fill='#5b6b85' stroke='#1a2b45'/><text x='70' y='65' font-size='11' text-anchor='middle' fill='#1a2b45'>hafif</text></svg>","steps":[{"t":"Kim daha ağır?","a":"büyük çocuk","d":"Büyük çocuk küçük çocuktan daha ağırdır."},{"t":"Ağır taraf ne yapar?","a":"aşağı iner","d":"Daha ağır olan taraf tahterevalliyi kendine doğru aşağı çeker."}],"ans":"Ağır olan büyük çocuğun olduğu taraf aşağı iner, hafif çocuğun olduğu taraf yukarı kalkar."},{"q":"Makasla bir kağıdı keserken makas hangi basit makineye örnektir?","steps":[{"t":"Makas nasıl çalışır?","a":"ortadan döner","d":"Makasın iki kolu ortadaki vidanın çevresinde döner."},{"t":"Hangi makine?","a":"kaldıraç","d":"Sabit bir nokta etrafında dönerek iş gören araçlar kaldıraçtır; makas da kaldıraçtır."}],"ans":"Makas bir kaldıraçtır; ortadaki vida dayanak noktası olur ve kollar bu noktada dönerek kağıdı keser."},{"q":"Şekilde küçük bir çocuk tahterevallinin ucunda, ağır bir çuval ise dayanağa daha yakın oturuyor. Çocuk çuvalı kaldırabilir mi?","fig":"<svg viewBox='0 0 320 175'><line x1='40' y1='110' x2='280' y2='110' stroke='#1a2b45' stroke-width='6'/><polygon points='160,110 140,150 180,150' fill='#e0552b' stroke='#1a2b45'/><circle cx='60' cy='96' r='11' fill='#5b6b85' stroke='#1a2b45'/><text x='60' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>çocuk</text><rect x='196' y='88' width='26' height='22' fill='#8d6e63' stroke='#1a2b45'/><text x='209' y='140' font-size='11' text-anchor='middle' fill='#1a2b45'>çuval</text></svg>","steps":[{"t":"Kim dayanağa uzak?","a":"çocuk","d":"Çocuk dayanaktan uzakta, çuval ise dayanağa yakın oturuyor."},{"t":"Uzaklık ne sağlar?","a":"kolaylık","d":"Dayanaktan uzakta oturmak az kuvvetle ağır yükü kaldırmayı sağlar."}],"ans":"Çocuk dayanaktan daha uzakta olduğu için az kuvvetiyle dayanağa yakın duran ağır çuvalı kaldırabilir."}],"zor":[{"q":"Şekilde tahterevallinin solunda 20 birim ağırlık dayanaktan 3 adım, sağında 30 birim ağırlık ise dayanaktan 2 adım uzaklıkta. Tahterevalli dengede midir?","fig":"<svg viewBox='0 0 320 175'><line x1='40' y1='105' x2='280' y2='105' stroke='#1a2b45' stroke-width='6'/><polygon points='160,105 140,148 180,148' fill='#e0552b' stroke='#1a2b45'/><rect x='62' y='80' width='26' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='75' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>20</text><text x='115' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>3 adım</text><rect x='225' y='82' width='24' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='237' y='72' font-size='11' text-anchor='middle' fill='#1a2b45'>30</text><text x='205' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>2 adım</text></svg>","steps":[{"t":"Sol tarafı çarp","a":"20 × 3 = 60","d":"Ağırlığı uzaklıkla çarparız: 20 birim × 3 adım = 60."},{"t":"Sağ tarafı çarp","a":"30 × 2 = 60","d":"Aynı şekilde: 30 birim × 2 adım = 60."},{"t":"Karşılaştır","a":"60 = 60","d":"İki tarafın çarpımı eşit olduğu için tahterevalli dengededir."}],"ans":"Sol taraf 20 × 3 = 60, sağ taraf 30 × 2 = 60 olduğu için çarpımlar eşittir ve tahterevalli dengede kalır."},{"q":"Şekilde 40 birimlik bir taş dayanaktan 1 adım uzakta. Çocuk dayanaktan 4 adım uzakta oturuyor. Çocuğun taşı kaldırması için kaç birim ağırlığı olmalıdır?","fig":"<svg viewBox='0 0 320 175'><line x1='40' y1='105' x2='280' y2='105' stroke='#1a2b45' stroke-width='6'/><polygon points='150,105 130,148 170,148' fill='#e0552b' stroke='#1a2b45'/><rect x='172' y='80' width='26' height='24' fill='#8d6e63' stroke='#1a2b45'/><text x='185' y='70' font-size='11' text-anchor='middle' fill='#1a2b45'>40</text><text x='175' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>1</text><circle cx='62' cy='92' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='95' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>4 adım</text></svg>","steps":[{"t":"Yük tarafı","a":"40 × 1 = 40","d":"Taşın ağırlığını uzaklıkla çarparız: 40 × 1 = 40."},{"t":"Çocuk tarafı eşit olmalı","a":"K × 4 = 40","d":"Dengede olması için çocuğun ağırlığı × 4 adım = 40 olmalıdır."},{"t":"Bul","a":"K = 10","d":"40 ÷ 4 = 10 birim ağırlık yeterlidir."}],"ans":"Çocuk dayanaktan 4 adım uzakta olduğu için 40 ÷ 4 = 10 birim ağırlığıyla taşı dengeleyip kaldırabilir."},{"q":"İki çocuktan biri tahterevallinin ucuna, diğeri dayanağa yakın oturuyor. İkisi de aynı ağırlıkta. Hangisi tarafı aşağı iner?","steps":[{"t":"Ağırlıklar eşit","a":"fark uzaklıkta","d":"İki çocuk aynı ağırlıkta olduğu için fark, dayanağa uzaklıklarındadır."},{"t":"Uzak olan üstün gelir","a":"uçtaki","d":"Dayanaktan uzakta oturan çocuğun döndürme etkisi daha büyüktür."}],"ans":"Ağırlıklar eşit olduğu için dayanaktan daha uzakta (uçta) oturan çocuğun olduğu taraf aşağı iner."},{"q":"Şekilde bir el arabasında tekerlek (dayanak), kova ile taşınan toprak (yük) ve tutma kolundan uygulanan kuvvet gösteriliyor. Kolu kaldırmak neden kolaydır?","fig":"<svg viewBox='0 0 320 175'><circle cx='80' cy='120' r='18' fill='#1a2b45'/><circle cx='80' cy='120' r='6' fill='#cfd8e3'/><text x='80' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>dayanak</text><line x1='80' y1='120' x2='270' y2='80' stroke='#8d6e63' stroke-width='5'/><rect x='110' y='92' width='34' height='26' fill='#5b6b85' stroke='#1a2b45'/><text x='127' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text><line x1='255' y1='85' x2='255' y2='55' stroke='#e0552b' stroke-width='4'/><polygon points='255,55 250,67 260,67' fill='#e0552b'/><text x='280' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>kuvvet</text></svg>","steps":[{"t":"Kuvvet nerede?","a":"uçta, uzakta","d":"Tutma kolundan uygulanan kuvvet, dayanak olan tekerlekten çok uzaktadır."},{"t":"Yük nerede?","a":"dayanağa yakın","d":"Toprak yükü tekerleğe yakın durduğu için kısa kolla taşınır."}],"ans":"Kuvvet dayanaktan uzakta, yük ise yakında olduğu için az kuvvetle ağır yük kolayca kaldırılır; el arabası bir kaldıraçtır."},{"q":"Şekilde tahterevallinin solunda 10 birim ağırlık dayanaktan 4 adım uzakta. Sağda dayanaktan 2 adım uzağa kaç birim ağırlık konulursa denge sağlanır?","fig":"<svg viewBox='0 0 320 175'><line x1='40' y1='105' x2='280' y2='105' stroke='#1a2b45' stroke-width='6'/><polygon points='160,105 140,148 180,148' fill='#e0552b' stroke='#1a2b45'/><rect x='58' y='82' width='24' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='70' y='72' font-size='11' text-anchor='middle' fill='#1a2b45'>10</text><text x='105' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>4 adım</text><rect x='205' y='82' width='24' height='22' fill='#8d6e63' stroke='#1a2b45'/><text x='217' y='72' font-size='11' text-anchor='middle' fill='#1a2b45'>?</text><text x='205' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>2 adım</text></svg>","steps":[{"t":"Sol tarafı çarp","a":"10 × 4 = 40","d":"Ağırlık × uzaklık = 10 × 4 = 40."},{"t":"Sağ tarafı eşitle","a":"? × 2 = 40","d":"Denge için sağ tarafın çarpımı da 40 olmalı: ağırlık × 2 = 40."},{"t":"Bul","a":"20 birim","d":"40 ÷ 2 = 20 birim ağırlık gerekir."}],"ans":"Sol taraf 10 × 4 = 40 olduğu için sağda 2 adım uzağa 40 ÷ 2 = 20 birim ağırlık konulmalıdır."}]},"ortaokul":{"kolay":[{"q":"Bir kaldıracı oluşturan üç temel öğe nedir?","steps":[{"t":"Sabit nokta","a":"destek (dayanak)","d":"Kaldıracın üzerinde döndüğü sabit noktaya destek ya da dayanak noktası denir."},{"t":"Diğer iki öğe","a":"yük ve kuvvet","d":"Kaldırılacak ağırlık yük, onu hareket ettirmek için uygulanan etki ise kuvvettir."}],"ans":"Bir kaldıraç destek (dayanak) noktası, yük ve uygulanan kuvvet olmak üzere üç temel öğeden oluşur."},{"q":"Şekilde destek noktası ile kuvvetin uygulandığı yer arası 'kuvvet kolu', destek ile yük arası 'yük kolu' olarak gösterilmiş. Bu iki kol neyi ifade eder?","fig":"<svg viewBox='0 0 320 165'><line x1='40' y1='100' x2='285' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='190,100 172,138 208,138' fill='#e0552b' stroke='#1a2b45'/><rect x='55' y='80' width='26' height='20' fill='#5b6b85' stroke='#1a2b45'/><text x='68' y='74' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text><line x1='270' y1='100' x2='270' y2='70' stroke='#e0552b' stroke-width='3'/><polygon points='270,70 265,80 275,80' fill='#e0552b'/><text x='270' y='62' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><line x1='68' y1='118' x2='190' y2='118' stroke='#1a2b45' stroke-width='1'/><text x='128' y='132' font-size='10' text-anchor='middle' fill='#1a2b45'>yük kolu</text><line x1='190' y1='150' x2='270' y2='150' stroke='#1a2b45' stroke-width='1'/><text x='230' y='162' font-size='10' text-anchor='middle' fill='#1a2b45'>kuvvet kolu</text></svg>","steps":[{"t":"Yük kolu","a":"destek–yük arası","d":"Destek noktası ile yükün uygulandığı nokta arasındaki uzaklık yük koludur."},{"t":"Kuvvet kolu","a":"destek–kuvvet arası","d":"Destek noktası ile kuvvetin uygulandığı nokta arasındaki uzaklık kuvvet koludur."}],"ans":"Yük kolu destek ile yük arasındaki, kuvvet kolu ise destek ile uygulanan kuvvet arasındaki uzaklıktır."},{"q":"Bir kaldıracın dengede olması için sağlanması gereken bağıntı nedir?","steps":[{"t":"Döndürme etkisi","a":"ağırlık × kol","d":"Her iki tarafta döndürme etkisi, ağırlık ile koldan oluşur."},{"t":"Denge koşulu","a":"çarpımlar eşit","d":"Denge için yükün ve kuvvetin döndürme etkileri eşitlenir."}],"ans":"Kaldıracın dengesi için Yük × Yük kolu = Kuvvet × Kuvvet kolu bağıntısı sağlanmalıdır."},{"q":"Şekildeki kaldıraçta yük 200 N ve yük kolu 1 m, kuvvet kolu ise 4 m. Kaldıracı dengede tutan kuvvet kaç N'dir?","fig":"<svg viewBox='0 0 320 165'><line x1='40' y1='100' x2='285' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='100,100 84,138 116,138' fill='#e0552b' stroke='#1a2b45'/><rect x='55' y='78' width='26' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='68' y='72' font-size='10' text-anchor='middle' fill='#1a2b45'>200 N</text><text x='84' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>1 m</text><line x1='270' y1='100' x2='270' y2='66' stroke='#e0552b' stroke-width='3'/><polygon points='270,66 265,77 275,77' fill='#e0552b'/><text x='270' y='58' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><text x='195' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>4 m</text></svg>","steps":[{"t":"Bağıntıyı yaz","a":"Y×Yk = F×Fk","d":"Denge: 200 N × 1 m = F × 4 m."},{"t":"Kuvveti çöz","a":"F = 200/4","d":"200 = 4F ⇒ F = 50 N."}],"ans":"Denge bağıntısından 200 × 1 = F × 4 olur; buradan F = 50 N bulunur."},{"q":"Bir kaldıraçta kuvvet kolu yük kolundan uzun olursa kuvvetten kazanç sağlanır mı?","steps":[{"t":"Bağıntıyı düşün","a":"Y×Yk = F×Fk","d":"Denge bağıntısında kuvvet kolu büyüdükçe gereken kuvvet küçülür."},{"t":"Sonuç","a":"kazanç var","d":"Kuvvet kolu uzun olduğunda yükten daha küçük bir kuvvetle denge sağlanır."}],"ans":"Evet; kuvvet kolu yük kolundan uzun olduğunda yükten daha az kuvvet gerekir, böylece kuvvetten kazanç sağlanır."}],"zor":[{"q":"Şekildeki kaldıraçta 600 N yük, destek noktasına 0,5 m uzakta. Kuvvet ise destekten 1,5 m uzaktan uygulanıyor. Dengedeki kuvvet kaç N'dir?","fig":"<svg viewBox='0 0 320 165'><line x1='40' y1='100' x2='290' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='120,100 104,138 136,138' fill='#e0552b' stroke='#1a2b45'/><rect x='70' y='76' width='28' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='84' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>600 N</text><text x='100' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>0,5 m</text><line x1='275' y1='100' x2='275' y2='64' stroke='#e0552b' stroke-width='3'/><polygon points='275,64 270,75 280,75' fill='#e0552b'/><text x='275' y='56' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><text x='205' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>1,5 m</text></svg>","steps":[{"t":"Denge bağıntısı","a":"Y×Yk = F×Fk","d":"600 N × 0,5 m = F × 1,5 m."},{"t":"Çöz","a":"F = 300/1,5","d":"300 = 1,5F ⇒ F = 200 N."}],"ans":"600 × 0,5 = F × 1,5 olduğundan 300 = 1,5F ve F = 200 N bulunur."},{"q":"Bir kaldıraçta yük 100 N, yük kolu 2 m, kuvvet kolu 5 m'dir. Bu kaldıraçta kaç kat kuvvet kazancı vardır?","steps":[{"t":"Gereken kuvvet","a":"F = 40 N","d":"100 × 2 = F × 5 ⇒ F = 40 N."},{"t":"Kazancı bul","a":"Yük/Kuvvet","d":"Kuvvet kazancı = Yük ÷ Kuvvet = 100 ÷ 40 = 2,5 kat."}],"ans":"Dengede F = 40 N olur; kuvvet kazancı 100 ÷ 40 = 2,5 kattır (kuvvet kolu yük kolunun 2,5 katı olduğu için)."},{"q":"Şekilde bir el arabasında destek (tekerlek), 300 N'luk yük tekerlekten 0,4 m, tutma yeri ise 1,2 m uzakta. Kaldırmak için uygulanması gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 170'><circle cx='70' cy='120' r='16' fill='#1a2b45'/><circle cx='70' cy='120' r='5' fill='#cfd8e3'/><text x='70' y='158' font-size='9' text-anchor='middle' fill='#1a2b45'>destek</text><line x1='70' y1='120' x2='280' y2='80' stroke='#8d6e63' stroke-width='5'/><rect x='110' y='90' width='30' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='125' y='84' font-size='9' text-anchor='middle' fill='#1a2b45'>300 N</text><text x='100' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>0,4 m</text><line x1='270' y1='82' x2='270' y2='52' stroke='#e0552b' stroke-width='3'/><polygon points='270,52 265,63 275,63' fill='#e0552b'/><text x='270' y='44' font-size='9' text-anchor='middle' fill='#1a2b45'>F</text><text x='210' y='118' font-size='9' text-anchor='middle' fill='#1a2b45'>1,2 m</text></svg>","steps":[{"t":"Bağıntıyı kur","a":"300 × 0,4 = F × 1,2","d":"Yük × yük kolu = Kuvvet × kuvvet kolu."},{"t":"Çöz","a":"F = 120/1,2","d":"120 = 1,2F ⇒ F = 100 N."}],"ans":"300 × 0,4 = F × 1,2 olduğundan 120 = 1,2F ve uygulanması gereken kuvvet F = 100 N'dir."},{"q":"Bir tahterevallinin solunda 30 kg'lık çocuk dayanaktan 1,5 m, sağında 45 kg'lık çocuk dayanaktan x metre uzakta otururken denge sağlanıyor. x kaç metredir?","steps":[{"t":"Denge bağıntısı","a":"30×1,5 = 45×x","d":"Ağırlıklar kütleyle orantılı olduğundan kütle × kol eşitliği yazılır."},{"t":"Çöz","a":"x = 45/45","d":"45 = 45x ⇒ x = 1 m."}],"ans":"30 × 1,5 = 45 × x olduğundan 45 = 45x ve x = 1 m bulunur; ağır çocuk dayanağa daha yakın oturmalıdır."},{"q":"Şekilde destek noktasının solunda 2 m uzakta 50 N, 1 m uzakta 100 N yük var. Sağda destekten 4 m uzağa uygulanacak dengeleyici kuvvet kaç N'dir?","fig":"<svg viewBox='0 0 320 170'><line x1='30' y1='100' x2='300' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='210,100 192,138 228,138' fill='#e0552b' stroke='#1a2b45'/><rect x='55' y='78' width='22' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='66' y='72' font-size='9' text-anchor='middle' fill='#1a2b45'>50 N</text><text x='66' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>2 m</text><rect x='140' y='78' width='22' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='151' y='72' font-size='9' text-anchor='middle' fill='#1a2b45'>100 N</text><text x='151' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>1 m</text><line x1='285' y1='100' x2='285' y2='66' stroke='#e0552b' stroke-width='3'/><polygon points='285,66 280,77 290,77' fill='#e0552b'/><text x='285' y='58' font-size='9' text-anchor='middle' fill='#1a2b45'>F</text><text x='250' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>4 m</text></svg>","steps":[{"t":"Sol döndürme","a":"50×2 + 100×1","d":"İki yükün döndürme etkileri toplanır: 100 + 100 = 200."},{"t":"Sağ ile eşitle","a":"F × 4 = 200","d":"Denge için sağdaki kuvvetin etkisi 200 olmalı: 4F = 200."},{"t":"Çöz","a":"F = 50 N","d":"200 ÷ 4 = 50 N."}],"ans":"Sol toplam döndürme 50×2 + 100×1 = 200'dür; F × 4 = 200 olduğundan dengeleyici kuvvet F = 50 N'dir."}]},"lise":{"kolay":[{"q":"Bir kuvvetin bir noktaya göre moment (tork) büyüklüğü nasıl tanımlanır?","steps":[{"t":"Moment ne demek?","a":"döndürme etkisi","d":"Moment, bir kuvvetin sabit bir nokta etrafında oluşturduğu döndürme etkisidir."},{"t":"Büyüklüğü","a":"M = F · d","d":"Moment, kuvvet (F) ile kuvvetin doğrultusunun döndürme noktasına dik uzaklığının (d, moment kolu) çarpımıdır."}],"ans":"Moment M = F · d ile tanımlanır; burada d, kuvvet doğrultusunun dönme noktasına dik uzaklığı (moment kolu) olup birimi N·m'dir."},{"q":"Şekilde 80 N'luk yük destekten 0,5 m, kuvvet ise destekten 2 m uzakta. Kaldıracın dengede olması için gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='35' y1='100' x2='290' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='115,100 99,138 131,138' fill='#e0552b' stroke='#1a2b45'/><rect x='65' y='76' width='28' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='79' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>80 N</text><text x='98' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>0,5 m</text><line x1='275' y1='100' x2='275' y2='64' stroke='#e0552b' stroke-width='3'/><polygon points='275,64 270,75 280,75' fill='#e0552b'/><text x='275' y='56' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><text x='200' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>2 m</text></svg>","steps":[{"t":"Moment dengesi","a":"ΣM = 0","d":"Dengede saat yönü ve ters yöndeki momentler eşittir: F·2 = 80·0,5."},{"t":"Çöz","a":"F = 40/2","d":"2F = 40 ⇒ F = 20 N."}],"ans":"Moment dengesinden F · 2 = 80 · 0,5 olur; buradan F = 20 N bulunur."},{"q":"Bir kaldıraçta denge bağıntısı Yük × Yük kolu = Kuvvet × Kuvvet kolu ifadesinin moment kavramıyla ilişkisi nedir?","steps":[{"t":"Her terim bir moment","a":"F·d","d":"Yük × yük kolu yükün momenti, Kuvvet × kuvvet kolu ise uygulanan kuvvetin momentidir."},{"t":"Denge koşulu","a":"ΣM = 0","d":"İki moment ters yönde döndürdüğünden eşit olmaları cismi dengede tutar."}],"ans":"Bu bağıntı moment dengesinin (ΣM = 0) ifadesidir; yükün momenti ile kuvvetin momenti ters yönde eşit olduğu için kaldıraç dengededir."},{"q":"Bir kaldıraçta kuvvetten kazanç sağlanmasının koşulu nedir?","steps":[{"t":"Kazanç tanımı","a":"Yük/Kuvvet > 1","d":"Yükten daha küçük kuvvetle denge sağlanırsa kuvvet kazancı 1'den büyük olur."},{"t":"Kol koşulu","a":"Fk > Yk","d":"Y·Yk = F·Fk bağıntısında F'nin Y'den küçük olması için kuvvet kolunun yük kolundan uzun olması gerekir."}],"ans":"Kuvvetten kazanç için kuvvet kolu yük kolundan uzun (Fk > Yk) olmalıdır; o zaman gereken kuvvet yükten küçük olur."},{"q":"Şekilde yatay bir kaldıraç çubuğu destekten solda 0,8 m uzakta 150 N'luk yükle, sağda 1,2 m uzakta F kuvvetiyle dengede. F kaç N'dir?","fig":"<svg viewBox='0 0 320 165'><line x1='30' y1='100' x2='295' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='160,100 144,138 176,138' fill='#e0552b' stroke='#1a2b45'/><rect x='70' y='76' width='28' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='84' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>150 N</text><text x='118' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>0,8 m</text><line x1='275' y1='100' x2='275' y2='66' stroke='#e0552b' stroke-width='3'/><polygon points='275,66 270,77 280,77' fill='#e0552b'/><text x='275' y='58' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><text x='220' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>1,2 m</text></svg>","steps":[{"t":"Moment dengesi","a":"150·0,8 = F·1,2","d":"Yükün momenti kuvvetin momentine eşitlenir."},{"t":"Çöz","a":"F = 120/1,2","d":"120 = 1,2F ⇒ F = 100 N."}],"ans":"150 · 0,8 = F · 1,2 olduğundan 120 = 1,2F ve F = 100 N bulunur."},{"q":"Birinci tip (örneğin tahterevalli, makas) kaldıraçta destek noktasının konumu nasıldır?","steps":[{"t":"Tipin tanımı","a":"destek ortada","d":"Birinci tip kaldıraçta destek noktası, yük ile kuvvetin arasında bulunur."},{"t":"Özelliği","a":"yön değiştirir","d":"Kuvvet bir yöne uygulanırken yük ters yönde hareket eder; kollara göre kazanç değişebilir."}],"ans":"Birinci tip kaldıraçta destek noktası yük ile kuvvet arasında yer alır; tahterevalli, makas ve pense bu tipe örnektir."},{"q":"Şekilde 2 m uzunluğundaki türdeş ve ağırlığı önemsiz bir çubuğun bir ucuna 60 N yük asılı, destek diğer uçtan 0,5 m içeride. Yükü destekten 0,5 m uzaktaki kuvvetle dengelemek için F kaç N'dir? (Yük destekten 1,5 m uzakta.)","fig":"<svg viewBox='0 0 320 165'><line x1='30' y1='100' x2='295' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='240,100 224,138 256,138' fill='#e0552b' stroke='#1a2b45'/><rect x='42' y='78' width='26' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='55' y='72' font-size='10' text-anchor='middle' fill='#1a2b45'>60 N</text><text x='150' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>1,5 m</text><line x1='285' y1='100' x2='285' y2='66' stroke='#e0552b' stroke-width='3'/><polygon points='285,66 280,77 290,77' fill='#e0552b'/><text x='285' y='58' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><text x='268' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>0,5 m</text></svg>","steps":[{"t":"Moment dengesi","a":"60·1,5 = F·0,5","d":"Yükün momenti kuvvetin momentine eşitlenir."},{"t":"Çöz","a":"F = 90/0,5","d":"90 = 0,5F ⇒ F = 180 N."}],"ans":"60 · 1,5 = F · 0,5 olduğundan 90 = 0,5F ve F = 180 N gerekir; kuvvet kolu kısa olduğundan kuvvet yükten büyüktür (kazanç yoktur)."},{"q":"Bir kuvvetin doğrultusu dönme noktasından geçiyorsa bu kuvvetin momenti ne olur?","steps":[{"t":"Moment kolunu bul","a":"d = 0","d":"Kuvvet doğrultusu dönme noktasından geçtiğinde dik uzaklık (moment kolu) sıfırdır."},{"t":"Momenti hesapla","a":"M = F·0","d":"M = F · d = F · 0 = 0 olur."}],"ans":"Kuvvet doğrultusu dönme noktasından geçtiği için moment kolu sıfırdır; dolayısıyla momenti de sıfırdır ve döndürme etkisi yapmaz."},{"q":"Şekilde bir kaldıraçta yük 240 N, yük kolu 0,3 m, kuvvet kolu 1,2 m. Kuvveti ve kuvvet kazancını bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='30' y1='100' x2='295' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='105,100 89,138 121,138' fill='#e0552b' stroke='#1a2b45'/><rect x='58' y='76' width='28' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='72' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>240 N</text><text x='97' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>0,3 m</text><line x1='278' y1='100' x2='278' y2='64' stroke='#e0552b' stroke-width='3'/><polygon points='278,64 273,75 283,75' fill='#e0552b'/><text x='278' y='56' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><text x='200' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>1,2 m</text></svg>","steps":[{"t":"Kuvveti bul","a":"F = 72/1,2","d":"240 · 0,3 = F · 1,2 ⇒ 72 = 1,2F ⇒ F = 60 N."},{"t":"Kazancı bul","a":"240/60","d":"Kuvvet kazancı = Yük ÷ Kuvvet = 240 ÷ 60 = 4."}],"ans":"F = 60 N ve kuvvet kazancı 240 ÷ 60 = 4'tür (kuvvet kolu yük kolunun 4 katı olduğu için)."},{"q":"İkinci tip kaldıraçta (örneğin el arabası) yük, destek ve kuvvet nasıl dizilir ve kuvvetten kazanç hep var mıdır?","steps":[{"t":"Diziliş","a":"yük ortada","d":"İkinci tip kaldıraçta yük, destek ile kuvvet arasında bulunur."},{"t":"Kol karşılaştırması","a":"Fk > Yk","d":"Kuvvet, yükten daha uzakta uygulandığından kuvvet kolu daima yük kolundan uzundur."}],"ans":"İkinci tip kaldıraçta yük, destek ile kuvvet arasındadır; kuvvet kolu hep yük kolundan uzun olduğu için kuvvetten her zaman kazanç sağlanır."},{"q":"Şekilde dönme noktasından 0,4 m uzaktaki bir noktaya, çubukla 60° açı yapacak biçimde 50 N kuvvet uygulanıyor. Bu kuvvetin momenti kaç N·m'dir? (sin60° = 0,87)","fig":"<svg viewBox='0 0 320 170'><circle cx='60' cy='120' r='6' fill='#1a2b45'/><text x='60' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>O</text><line x1='60' y1='120' x2='230' y2='120' stroke='#8d6e63' stroke-width='4'/><text x='150' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>0,4 m</text><line x1='200' y1='120' x2='245' y2='55' stroke='#e0552b' stroke-width='3'/><polygon points='245,55 234,60 242,68' fill='#e0552b'/><text x='255' y='52' font-size='10' fill='#1a2b45'>F=50 N</text><text x='215' y='105' font-size='10' fill='#1a2b45'>60°</text></svg>","steps":[{"t":"Dik bileşeni al","a":"F·sin60°","d":"Momenti yapan, kuvvetin çubuğa dik bileşenidir: 50 · sin60° = 50 · 0,87 = 43,5 N."},{"t":"Momenti hesapla","a":"M = 43,5·0,4","d":"M = (F·sin60°)·d = 43,5 · 0,4 ≈ 17,4 N·m."}],"ans":"Kuvvetin dik bileşeni 50·sin60° = 43,5 N olduğundan moment M = 43,5 · 0,4 ≈ 17,4 N·m'dir."},{"q":"Bir kaldıraçta kuvvet kolu yük koluna eşitse (örneğin eşit kollu terazi) durum ne olur?","steps":[{"t":"Denge bağıntısı","a":"Y·d = F·d","d":"Kollar eşit olduğunda Y · d = F · d olur, d'ler sadeleşir."},{"t":"Sonuç","a":"F = Y","d":"Gereken kuvvet yüke eşittir; kuvvetten kazanç yoktur, yalnızca yön değişebilir."}],"ans":"Kollar eşit olduğunda F = Y olur; kuvvetten kazanç sağlanmaz ama yük tartılabilir veya yön değiştirilir (eşit kollu terazi örneği)."},{"q":"Şekilde 2 m'lik çubuğun bir ucu duvara menteşelenmiş (destek), diğer ucundan 40 N'luk yük sarkıyor. Çubuğun tam ortasına aşağı uygulanan 40 N'luk kuvvetin momenti yükü dengeler mi?","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='30' x2='40' y2='150' stroke='#1a2b45' stroke-width='4'/><circle cx='40' cy='90' r='5' fill='#1a2b45'/><text x='40' y='80' font-size='9' text-anchor='middle' fill='#1a2b45'>O</text><line x1='40' y1='90' x2='280' y2='90' stroke='#8d6e63' stroke-width='4'/><line x1='160' y1='90' x2='160' y2='125' stroke='#e0552b' stroke-width='3'/><polygon points='160,125 155,114 165,114' fill='#e0552b'/><text x='160' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>40 N (1 m)</text><line x1='280' y1='90' x2='280' y2='130' stroke='#2e7d32' stroke-width='3'/><polygon points='280,130 275,119 285,119' fill='#2e7d32'/><text x='280' y='145' font-size='9' text-anchor='middle' fill='#1a2b45'>40 N (2 m)</text></svg>","steps":[{"t":"Yükün momenti","a":"40·2 = 80","d":"Uçtaki yük destekten 2 m uzakta: M = 40 · 2 = 80 N·m."},{"t":"Kuvvetin momenti","a":"40·1 = 40","d":"Ortadaki kuvvet destekten 1 m uzakta: M = 40 · 1 = 40 N·m."}],"ans":"Yükün momenti 80 N·m, kuvvetin momenti yalnızca 40 N·m'dir; 40 < 80 olduğu için kuvvet yükü dengeleyemez, çubuk yük yönünde döner."},{"q":"Moment (tork) niceliğinin SI birimi nedir ve neden iş birimiyle (joule) karıştırılmamalıdır?","steps":[{"t":"Birimi bul","a":"N·m","d":"Moment, kuvvet (N) ile dik uzaklığın (m) çarpımı olduğundan birimi newton·metredir."},{"t":"Joule'den farkı","a":"farklı kavram","d":"Sayısal olarak N·m, joule ile aynı boyutta görünse de moment bir döndürme etkisidir, iş ise enerji aktarımıdır; ayrım için tork N·m olarak yazılır."}],"ans":"Momentin birimi N·m'dir; sayısal olarak joule ile eşdeğer görünse de moment döndürme etkisi, joule ise iş/enerji olduğundan tork N·m birimiyle ifade edilip joule denmez."},{"q":"Şekilde bir kaldıraçta 360 N yük destekten 0,25 m, kuvvet destekten 1,5 m uzakta uygulanıyor. Dengedeki kuvveti ve kuvvet kazancını bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='30' y1='100' x2='295' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='100,100 84,138 116,138' fill='#e0552b' stroke='#1a2b45'/><rect x='52' y='76' width='28' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='66' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>360 N</text><text x='92' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>0,25 m</text><line x1='278' y1='100' x2='278' y2='64' stroke='#e0552b' stroke-width='3'/><polygon points='278,64 273,75 283,75' fill='#e0552b'/><text x='278' y='56' font-size='10' text-anchor='middle' fill='#1a2b45'>F</text><text x='198' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>1,5 m</text></svg>","steps":[{"t":"Kuvveti bul","a":"360·0,25 = F·1,5","d":"Moment dengesi: 90 = 1,5F ⇒ F = 60 N."},{"t":"Kazancı bul","a":"360/60","d":"Kuvvet kazancı = Yük ÷ Kuvvet = 360 ÷ 60 = 6."}],"ans":"360·0,25 = F·1,5 ⇒ 90 = 1,5F ⇒ F = 60 N; kuvvet kazancı 360 ÷ 60 = 6'dır (kuvvet kolu yük kolunun 6 katı)."}],"zor":[{"q":"Şekilde 4 m uzunluğunda ve ağırlığı önemsenmeyen yatay bir çubuk, sol ucundan 0,8 m içeride desteklenmiş. Sol uca 300 N yük asılı; çubuğu yatay tutmak için sağ uca uygulanması gereken düşey kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='30' y1='95' x2='300' y2='95' stroke='#1a2b45' stroke-width='5'/><polygon points='90,95 74,133 106,133' fill='#e0552b' stroke='#1a2b45'/><rect x='34' y='72' width='26' height='23' fill='#5b6b85' stroke='#1a2b45'/><text x='47' y='66' font-size='9' text-anchor='middle' fill='#1a2b45'>300 N</text><text x='70' y='126' font-size='9' text-anchor='middle' fill='#1a2b45'>0,8 m</text><line x1='292' y1='95' x2='292' y2='128' stroke='#e0552b' stroke-width='3'/><polygon points='292,128 287,117 297,117' fill='#e0552b'/><text x='292' y='143' font-size='9' text-anchor='middle' fill='#1a2b45'>F</text><text x='195' y='126' font-size='9' text-anchor='middle' fill='#1a2b45'>3,2 m</text></svg>","steps":[{"t":"Kolları belirle","a":"0,8 m ve 3,2 m","d":"Yük destekten 0,8 m solda; sağ uç destekten 4 − 0,8 = 3,2 m sağdadır."},{"t":"Moment dengesi","a":"300·0,8 = F·3,2","d":"ΣM = 0 koşulundan 240 = 3,2F."},{"t":"Çöz","a":"F = 240/3,2","d":"F = 75 N."}],"ans":"Yük kolu 0,8 m, kuvvet kolu 3,2 m'dir; 300·0,8 = F·3,2 ⇒ 240 = 3,2F ⇒ F = 75 N gerekir."},{"q":"Şekilde türdeş bir çubuk uzunluğu 2 m, ağırlığı 60 N. Çubuk sol ucundan menteşeli (destek), sağ ucu yatayla 0°'de düşey iple tutuluyor. İpteki gerilmeyi bulunuz.","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='25' x2='40' y2='140' stroke='#1a2b45' stroke-width='4'/><circle cx='40' cy='100' r='5' fill='#1a2b45'/><text x='40' y='90' font-size='9' text-anchor='middle' fill='#1a2b45'>O</text><line x1='40' y1='100' x2='270' y2='100' stroke='#8d6e63' stroke-width='4'/><line x1='270' y1='100' x2='270' y2='40' stroke='#e0552b' stroke-width='3'/><polygon points='270,40 265,51 275,51' fill='#e0552b'/><text x='285' y='60' font-size='9' fill='#1a2b45'>T</text><line x1='155' y1='100' x2='155' y2='135' stroke='#2e7d32' stroke-width='3'/><polygon points='155,135 150,124 160,124' fill='#2e7d32'/><text x='155' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>G=60 N</text></svg>","steps":[{"t":"Ağırlık nerede etkir","a":"orta nokta, 1 m","d":"Türdeş çubuğun ağırlığı tam ortasında, destekten 1 m uzakta etki eder."},{"t":"Moment dengesi","a":"T·2 = 60·1","d":"Destek noktasına göre ΣM = 0: ipin momenti ağırlığın momentine eşit."},{"t":"Çöz","a":"T = 60/2","d":"2T = 60 ⇒ T = 30 N."}],"ans":"Ağırlık ortada (1 m) etki ettiğinden T·2 = 60·1 olur; buradan ipteki gerilme T = 30 N bulunur."},{"q":"Şekilde destek noktasının solunda 1 m'de 200 N ve 2 m'de 100 N yük var; sağında ise 2,5 m uzakta F kuvveti çubuğu dengeliyor. F kaç N'dir?","fig":"<svg viewBox='0 0 320 175'><line x1='25' y1='100' x2='305' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='205,100 189,138 221,138' fill='#e0552b' stroke='#1a2b45'/><rect x='130' y='76' width='24' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='142' y='70' font-size='9' text-anchor='middle' fill='#1a2b45'>200 N</text><text x='142' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>1 m</text><rect x='55' y='76' width='24' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='67' y='70' font-size='9' text-anchor='middle' fill='#1a2b45'>100 N</text><text x='67' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>2 m</text><line x1='292' y1='100' x2='292' y2='66' stroke='#e0552b' stroke-width='3'/><polygon points='292,66 287,77 297,77' fill='#e0552b'/><text x='292' y='58' font-size='9' text-anchor='middle' fill='#1a2b45'>F</text><text x='255' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>2,5 m</text></svg>","steps":[{"t":"Sol toplam moment","a":"200·1 + 100·2","d":"Soldaki yüklerin momentleri toplanır: 200 + 200 = 400 N·m."},{"t":"Moment dengesi","a":"F·2,5 = 400","d":"Sağ momenti sol momente eşitleriz."},{"t":"Çöz","a":"F = 400/2,5","d":"F = 160 N."}],"ans":"Sol toplam moment 200·1 + 100·2 = 400 N·m'dir; F·2,5 = 400 ⇒ F = 160 N bulunur."},{"q":"Şekilde yatay çubuğa destekten 0,6 m uzakta, çubukla 30° açı yapan 100 N'luk kuvvet uygulanıyor. Çubuğun diğer yanında destekten 0,5 m uzakta düşey yük var. Kuvvetin momentini ve dengelenebilen yükü bulunuz. (sin30° = 0,5)","fig":"<svg viewBox='0 0 320 175'><circle cx='160' cy='100' r='5' fill='#1a2b45'/><text x='160' y='90' font-size='9' text-anchor='middle' fill='#1a2b45'>O</text><line x1='40' y1='100' x2='280' y2='100' stroke='#8d6e63' stroke-width='4'/><rect x='70' y='102' width='24' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='82' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>Y (0,5 m)</text><line x1='220' y1='100' x2='262' y2='52' stroke='#e0552b' stroke-width='3'/><polygon points='262,52 251,57 259,65' fill='#e0552b'/><text x='275' y='48' font-size='9' fill='#1a2b45'>100 N</text><text x='232' y='90' font-size='9' fill='#1a2b45'>30°</text><text x='205' y='118' font-size='9' fill='#1a2b45'>0,6 m</text></svg>","steps":[{"t":"Dik bileşen","a":"100·sin30°","d":"Momenti yapan dik bileşen: 100 · 0,5 = 50 N."},{"t":"Kuvvetin momenti","a":"50·0,6 = 30","d":"M = (F·sin30°)·d = 50 · 0,6 = 30 N·m."},{"t":"Yükü bul","a":"Y·0,5 = 30","d":"Denge için yükün momenti de 30 olmalı: Y = 30 ÷ 0,5 = 60 N."}],"ans":"Kuvvetin dik bileşeni 50 N, momenti 50·0,6 = 30 N·m'dir; bu, destekten 0,5 m'deki 30 ÷ 0,5 = 60 N'luk yükü dengeler."},{"q":"Bir kaldıraçta yük 500 N, yük kolu 0,2 m, kuvvet kolu 1,0 m. Kuvvetin yükü 0,1 m kaldırması için kuvvetin alması gereken yolu ve yapılan işi karşılaştırınız (ideal, kayıpsız).","steps":[{"t":"Kuvveti bul","a":"F = 100 N","d":"500·0,2 = F·1,0 ⇒ F = 100 N (kuvvet kazancı 5)."},{"t":"Yolları kıyasla","a":"x = 0,5 m","d":"Kollar oranı 5 olduğundan kuvvet, yükün yolunun 5 katını alır: 0,1·5 = 0,5 m. Kuvvetten kazanç yoldan kayıpla telafi edilir."},{"t":"İşi karşılaştır","a":"eşit","d":"Yükün işi 500·0,1 = 50 J; kuvvetin işi 100·0,5 = 50 J. İdeal makinede iki iş eşittir."}],"ans":"F = 100 N (5 kat kazanç), kuvvet 0,5 m yol alır; kuvvetin işi 100·0,5 = 50 J, yükün işi 500·0,1 = 50 J olup eşittir. Kaldıraç kuvvetten kazandırır ama işten kazandırmaz."},{"q":"Şekilde 3 m'lik türdeş çubuğun ağırlığı 90 N. Çubuk sol ucundan 1 m içeride destekleniyor. Sol uca 120 N yük asılıdır. Çubuk dengede midir, değilse hangi yöne döner?","fig":"<svg viewBox='0 0 320 170'><line x1='25' y1='100' x2='300' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='110,100 94,138 126,138' fill='#e0552b' stroke='#1a2b45'/><rect x='30' y='76' width='24' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='42' y='70' font-size='9' text-anchor='middle' fill='#1a2b45'>120 N</text><text x='80' y='130' font-size='9' text-anchor='middle' fill='#1a2b45'>1 m</text><line x1='205' y1='100' x2='205' y2='135' stroke='#2e7d32' stroke-width='3'/><polygon points='205,135 200,124 210,124' fill='#2e7d32'/><text x='205' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>G=90 N</text><text x='160' y='90' font-size='9' text-anchor='middle' fill='#1a2b45'>orta: 0,5 m sağda</text></svg>","steps":[{"t":"Yükün momenti (sol)","a":"120·1 = 120","d":"Sol uçtaki yük destekten 1 m solda: M = 120 · 1 = 120 N·m, sola döndürür."},{"t":"Ağırlığın momenti (sağ)","a":"90·0,5 = 45","d":"Türdeş çubuğun ağırlık merkezi ortada (1,5 m'de), destekten 0,5 m sağda: M = 90 · 0,5 = 45 N·m, sağa döndürür."},{"t":"Karşılaştır","a":"120 > 45","d":"Sol moment sağ momentten büyüktür; dengelenemez."}],"ans":"Sol moment 120 N·m, sağ moment yalnızca 45 N·m'dir; 120 > 45 olduğu için çubuk dengede değildir ve yük tarafına (sola) döner."},{"q":"Şekilde 4 m'lik ağırlıksız çubuk iki destekle taşınıyor: sol uçta A, sağ uçta B desteği var. Çubuğun A'dan 1 m uzağına 600 N yük konuyor. A ve B desteklerinin tepki kuvvetlerini bulunuz.","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='90' x2='290' y2='90' stroke='#1a2b45' stroke-width='5'/><polygon points='50,90 38,120 62,120' fill='#e0552b' stroke='#1a2b45'/><text x='50' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>A</text><polygon points='280,90 268,120 292,120' fill='#e0552b' stroke='#1a2b45'/><text x='280' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>B</text><rect x='100' y='66' width='26' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='113' y='60' font-size='9' text-anchor='middle' fill='#1a2b45'>600 N</text><text x='80' y='150' font-size='9' text-anchor='middle' fill='#1a2b45'>A→yük: 1 m</text></svg>","steps":[{"t":"A'ya göre moment","a":"600·1 = B·4","d":"A noktasını dönme merkezi alırız: yükün momenti B'nin momentine eşit. 600·1 = N_B·4 ⇒ N_B = 150 N."},{"t":"Düşey denge","a":"N_A + N_B = 600","d":"Toplam yukarı tepkiler toplam yüke eşit: N_A = 600 − 150 = 450 N."}],"ans":"A'ya göre moment alınınca N_B = 600·1/4 = 150 N; düşey dengeden N_A = 600 − 150 = 450 N bulunur."},{"q":"Bir el arabasında (ikinci tip kaldıraç) tekerlek destek, yük destekten 0,5 m, eller destekten 1,5 m uzakta. Yük 450 N ise eller hangi kuvvetle ne kadar kazançla kaldırır?","steps":[{"t":"Kuvveti bul","a":"450·0,5 = F·1,5","d":"Moment dengesi: 225 = 1,5F ⇒ F = 150 N."},{"t":"Kazancı bul","a":"450/150","d":"Kuvvet kazancı = Yük ÷ Kuvvet = 450 ÷ 150 = 3."}],"ans":"Moment dengesinden F = 150 N; kuvvet kazancı 450 ÷ 150 = 3'tür, yani el arabası yükü 3 kat daha az kuvvetle kaldırtır."},{"q":"Şekilde yatay çubuk destekten solda 0,4 m'de 250 N yük taşıyor. Kuvvet destekten sağda 1,0 m uzakta, çubukla 53° açıyla uygulanıyor. Çubuğu dengede tutan kuvvetin büyüklüğünü bulunuz. (sin53° = 0,8)","fig":"<svg viewBox='0 0 320 175'><circle cx='170' cy='100' r='5' fill='#1a2b45'/><text x='170' y='90' font-size='9' text-anchor='middle' fill='#1a2b45'>O</text><line x1='40' y1='100' x2='290' y2='100' stroke='#8d6e63' stroke-width='4'/><rect x='100' y='102' width='24' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='112' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>250 N (0,4 m)</text><line x1='270' y1='100' x2='245' y2='45' stroke='#e0552b' stroke-width='3'/><polygon points='245,45 244,57 253,52' fill='#e0552b'/><text x='258' y='42' font-size='9' fill='#1a2b45'>F</text><text x='255' y='90' font-size='9' fill='#1a2b45'>53°</text><text x='250' y='118' font-size='9' fill='#1a2b45'>1,0 m</text></svg>","steps":[{"t":"Yükün momenti","a":"250·0,4 = 100","d":"Yükün döndürme etkisi: 250 · 0,4 = 100 N·m."},{"t":"Kuvvetin momenti","a":"(F·sin53°)·1,0","d":"Yalnızca dik bileşen moment yapar: M = F·0,8·1,0 = 0,8F."},{"t":"Eşitle ve çöz","a":"0,8F = 100","d":"0,8F = 100 ⇒ F = 125 N."}],"ans":"Yükün momenti 100 N·m'dir; kuvvetin dik bileşeni F·0,8 olduğundan 0,8F·1,0 = 100 ⇒ F = 125 N bulunur."},{"q":"Üçüncü tip kaldıraçta (örneğin kürek, insan ön kolu) kuvvet, yük ve destek nasıl dizilir ve kuvvet kolu hakkında ne söylenir? Kuvvetten kazanç var mıdır?","steps":[{"t":"Diziliş","a":"kuvvet ortada","d":"Üçüncü tip kaldıraçta kuvvet, destek ile yük arasında uygulanır."},{"t":"Kol karşılaştırması","a":"Fk < Yk","d":"Kuvvet desteğe yük kolundan daha yakın uygulandığından kuvvet kolu daima yük kolundan kısadır."},{"t":"Kazanç durumu","a":"kuvvetten kazanç yok","d":"Fk < Yk olduğu için gereken kuvvet yükten büyüktür; ancak yüke daha büyük hız/yol kazandırır."}],"ans":"Üçüncü tip kaldıraçta kuvvet destek ile yük arasındadır; kuvvet kolu yük kolundan kısa olduğundan kuvvetten kazanç yoktur, fakat yükün hareketinden (hız ve yoldan) kazanç sağlanır."},{"q":"Şekilde V biçimli iki kollu bir kaldıraçta destekten 0,3 m'de 90 N, destekten 0,9 m'de F kuvveti var ama kuvvet kolu çubukla 60° açıyla uygulanıyor. F kaç N'dir? (sin60° = 0,87)","fig":"<svg viewBox='0 0 320 175'><polygon points='170,100 154,138 186,138' fill='#e0552b' stroke='#1a2b45'/><line x1='40' y1='100' x2='290' y2='100' stroke='#8d6e63' stroke-width='4'/><rect x='110' y='76' width='24' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='122' y='70' font-size='9' text-anchor='middle' fill='#1a2b45'>90 N</text><text x='122' y='128' font-size='9' text-anchor='middle' fill='#1a2b45'>0,3 m</text><line x1='265' y1='100' x2='240' y2='45' stroke='#e0552b' stroke-width='3'/><polygon points='240,45 239,57 248,52' fill='#e0552b'/><text x='252' y='42' font-size='9' fill='#1a2b45'>F</text><text x='250' y='90' font-size='9' fill='#1a2b45'>60°</text><text x='248' y='118' font-size='9' fill='#1a2b45'>0,9 m</text></svg>","steps":[{"t":"Yükün momenti","a":"90·0,3 = 27","d":"Yükün döndürme etkisi: 90 · 0,3 = 27 N·m."},{"t":"Kuvvetin etkin momenti","a":"F·sin60°·0,9","d":"Dik bileşen: F·0,87, kolu 0,9 m ⇒ moment = 0,783F."},{"t":"Eşitle ve çöz","a":"0,783F = 27","d":"F = 27 ÷ 0,783 ≈ 34,5 N."}],"ans":"Yükün momenti 27 N·m'dir; kuvvetin etkin momenti F·sin60°·0,9 = 0,783F olduğundan 0,783F = 27 ⇒ F ≈ 34,5 N bulunur."},{"q":"İki çocuk 4 m'lik bir tahterevallide oynuyor. 50 kg'lık çocuk solda ortadan 1,5 m uzakta. 30 kg'lık çocuk dengeyi sağlamak için sağda nereye oturmalıdır? (g'yi sadeleştir.)","steps":[{"t":"Denge bağıntısı","a":"m₁·d₁ = m₂·d₂","d":"Ağırlıklar kütleyle orantılı olduğundan g sadeleşir: 50·1,5 = 30·d₂."},{"t":"Çöz","a":"d₂ = 75/30","d":"75 = 30·d₂ ⇒ d₂ = 2,5 m."},{"t":"Sınır kontrolü","a":"2,5 > 2 m","d":"Tahterevallinin yarı uzunluğu 2 m olduğundan 2,5 m mümkün değildir."}],"ans":"Denge için 50·1,5 = 30·d₂ ⇒ d₂ = 2,5 m gerekir; ancak tahtanın yarısı 2 m olduğu için çocuk yeterince uzağa oturamaz ve denge tek başına sağlanamaz."},{"q":"Şekilde bir levyenin (sökme demiri) destek ucu yere dayalı; çivi destekten 0,05 m, el destekten 0,75 m uzakta kuvvet uyguluyor. Çiviyi çıkarmak için 800 N gerekiyorsa el kaç N uygulamalı ve kazanç kaçtır?","fig":"<svg viewBox='0 0 320 170'><line x1='50' y1='130' x2='280' y2='60' stroke='#8d6e63' stroke-width='5'/><polygon points='50,130 38,150 62,150' fill='#e0552b' stroke='#1a2b45'/><text x='50' y='165' font-size='9' text-anchor='middle' fill='#1a2b45'>destek</text><rect x='62' y='115' width='18' height='16' fill='#5b6b85' stroke='#1a2b45'/><text x='95' y='128' font-size='9' fill='#1a2b45'>çivi 0,05 m</text><line x1='265' y1='66' x2='265' y2='36' stroke='#e0552b' stroke-width='3'/><polygon points='265,36 260,47 270,47' fill='#e0552b'/><text x='265' y='28' font-size='9' text-anchor='middle' fill='#1a2b45'>F (0,75 m)</text></svg>","steps":[{"t":"Moment dengesi","a":"800·0,05 = F·0,75","d":"Yük (çivi direnci) × yük kolu = Kuvvet × kuvvet kolu: 40 = 0,75F."},{"t":"Kuvveti çöz","a":"F = 40/0,75","d":"F ≈ 53,3 N."},{"t":"Kazancı bul","a":"800/53,3","d":"Kuvvet kazancı = 800 ÷ 53,3 ≈ 15 (kol oranı 0,75/0,05 = 15)."}],"ans":"800·0,05 = F·0,75 ⇒ F ≈ 53,3 N; kuvvet kazancı kol oranına eşittir: 0,75 ÷ 0,05 = 15 kat. Levye çok küçük kuvvetle büyük direnci yener."},{"q":"Şekilde yatay bir çubuk destekten solda 1,2 m'de 150 N yükle, sağda 0,8 m'de 100 N ve 1,6 m'de F kuvvetiyle dengede. F kaç N'dir?","fig":"<svg viewBox='0 0 320 175'><line x1='25' y1='100' x2='305' y2='100' stroke='#1a2b45' stroke-width='5'/><polygon points='150,100 134,138 166,138' fill='#e0552b' stroke='#1a2b45'/><rect x='58' y='76' width='24' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='70' y='70' font-size='9' text-anchor='middle' fill='#1a2b45'>150 N</text><text x='70' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>1,2 m</text><rect x='200' y='76' width='22' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='211' y='70' font-size='9' text-anchor='middle' fill='#1a2b45'>100 N</text><text x='211' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>0,8 m</text><line x1='290' y1='100' x2='290' y2='66' stroke='#e0552b' stroke-width='3'/><polygon points='290,66 285,77 295,77' fill='#e0552b'/><text x='290' y='58' font-size='9' text-anchor='middle' fill='#1a2b45'>F</text><text x='262' y='132' font-size='9' text-anchor='middle' fill='#1a2b45'>1,6 m</text></svg>","steps":[{"t":"Sol moment","a":"150·1,2 = 180","d":"Sol yükün döndürme etkisi: 150 · 1,2 = 180 N·m."},{"t":"Sağ momentleri kur","a":"100·0,8 + F·1,6","d":"Sağda iki etki var: 100·0,8 = 80 N·m ve F·1,6; ikisi sol momenti dengelemeli."},{"t":"Çöz","a":"80 + 1,6F = 180","d":"1,6F = 100 ⇒ F = 62,5 N."}],"ans":"Sol moment 180 N·m'dir; sağda 100·0,8 + F·1,6 = 180 ⇒ 80 + 1,6F = 180 ⇒ F = 62,5 N bulunur."},{"q":"Bir makas (birinci tip kaldıraç) ile kalın bir teli keserken teli vidaya (desteğe) yakın mı yoksa makas ucuna mı koymak daha kolaydır? Moment ile açıklayınız.","steps":[{"t":"Kuvvet kolu sabit","a":"el uçta","d":"Elin uyguladığı kuvvet, makasın uzun kollarının ucundadır; bu kuvvet kolu büyüktür ve sabittir."},{"t":"Yük kolunu değiştir","a":"vidaya yakın = kısa","d":"Teli vidaya (desteğe) yakın koyarsak yük kolu küçülür; aynı kuvvet daha büyük döndürme etkisi (kesme kuvveti) üretir."},{"t":"Sonuç","a":"vidaya yakın kolay","d":"Y·Yk = F·Fk bağıntısında Yk küçülünce kesilen yüke uygulanan kuvvet artar."}],"ans":"Teli vidaya (desteğe) yakın koymak daha kolaydır; yük kolu kısaldığı için aynı el kuvveti daha büyük bir kesme kuvveti üretir (Fk sabitken Yk küçülünce kazanç artar)."}]}},"kaldiracTur":{"ilkokul":{"kolay":[{"q":"Şekildeki tahterevallide destek (D) tam ortadadır. Bu tahterevalli hangi tür kaldıraçtır?","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='110' x2='280' y2='110' stroke='#1a2b45' stroke-width='5'/><polygon points='160,110 145,140 175,140' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='155' font-size='12' text-anchor='middle' fill='#1a2b45'>Destek</text><circle cx='70' cy='98' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='70' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Kuvvet</text><circle cx='250' cy='98' r='12' fill='#4aa3df' stroke='#1a2b45'/><text x='250' y='80' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük</text></svg>","steps":[{"t":"Ortada ne var?","a":"destek","d":"Tahterevallide destek noktası tam ortada, kuvvet ile yük iki uçtadır."},{"t":"Hangi tür?","a":"1. tür","d":"Destek ortada olan kaldıraçlara birinci tür kaldıraç denir."}],"ans":"Destek ortada olduğu için tahterevalli birinci tür kaldıraçtır."},{"q":"Şekildeki el arabasında yük (kum) ortadadır. Bu el arabası hangi tür kaldıraçtır?","fig":"<svg viewBox='0 0 320 170'><circle cx='60' cy='120' r='18' fill='#5b6b85' stroke='#1a2b45'/><text x='60' y='155' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='60' y1='120' x2='270' y2='70' stroke='#1a2b45' stroke-width='4'/><ellipse cx='160' cy='92' rx='34' ry='18' fill='#c79a5b' stroke='#1a2b45'/><text x='160' y='130' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük</text><circle cx='268' cy='71' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='268' y='55' font-size='11' text-anchor='middle' fill='#1a2b45'>Kuvvet</text></svg>","steps":[{"t":"Ortada ne var?","a":"yük","d":"El arabasında tekerlek destek, eller kuvvet, kum ise ortadaki yüktür."},{"t":"Hangi tür?","a":"2. tür","d":"Yük ortada olan kaldıraçlara ikinci tür kaldıraç denir."}],"ans":"Yük ortada olduğu için el arabası ikinci tür kaldıraçtır."},{"q":"Şekildeki cımbızda kuvvet (parmak basıncı) ortadadır. Bu cımbız hangi tür kaldıraçtır?","fig":"<svg viewBox='0 0 320 160'><circle cx='60' cy='80' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='60' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='60' y1='80' x2='270' y2='80' stroke='#1a2b45' stroke-width='4'/><circle cx='160' cy='80' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='118' font-size='11' text-anchor='middle' fill='#1a2b45'>Kuvvet</text><circle cx='265' cy='80' r='10' fill='#4aa3df' stroke='#1a2b45'/><text x='265' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük</text></svg>","steps":[{"t":"Ortada ne var?","a":"kuvvet","d":"Cımbızda dirsek destek, uç yük, ortadaki parmak basıncı ise kuvvettir."},{"t":"Hangi tür?","a":"3. tür","d":"Kuvvet ortada olan kaldıraçlara üçüncü tür kaldıraç denir."}],"ans":"Kuvvet ortada olduğu için cımbız üçüncü tür kaldıraçtır."},{"q":"Makas, kullanırken destek (vidanın olduğu nokta) tam ortada kalır. Makas hangi tür kaldıraçtır?","steps":[{"t":"Parçaları bul","a":"destek ortada","d":"Makasın iki kolu vidayla birleşir; bu vida destek noktasıdır ve ortadadır."},{"t":"Hangi tür?","a":"1. tür","d":"Destek ortada olduğu için makas birinci tür kaldıraçtır, tıpkı tahterevalli gibi."}],"ans":"Makasta destek (vida) ortada olduğu için makas birinci tür kaldıraçtır."},{"q":"Bir çocuk küreğin ucundan toprağı kaldırırken eline yakın yer kuvvet, ortadaki toprak yük olur. Hangi tür kaldıraçtır?","steps":[{"t":"Yeri belirle","a":"kuvvet ortada","d":"Küreğin sapını tutan üst el destek, alt el kuvvet, uçtaki toprak yüktür; kuvvet uç ile destek arasındadır."},{"t":"Hangi tür?","a":"3. tür","d":"Kuvvet ortada olduğu için kürek üçüncü tür kaldıraç gibi davranır."}],"ans":"Kürekte kuvvet ortada olduğu için kürek üçüncü tür kaldıraçtır."}],"zor":[{"q":"Şekilde üç tür kaldıraçtaki destek (D), yük (Y) ve kuvvet (K) sıralaması gösteriliyor. Buna göre el arabası hangi sıraya uyar?","fig":"<svg viewBox='0 0 320 180'><text x='30' y='30' font-size='12' fill='#1a2b45'>1. tür: K - D - Y</text><line x1='30' y1='45' x2='200' y2='45' stroke='#1a2b45' stroke-width='3'/><text x='30' y='75' font-size='12' fill='#1a2b45'>2. tür: D - Y - K</text><line x1='30' y1='90' x2='200' y2='90' stroke='#1a2b45' stroke-width='3'/><text x='30' y='120' font-size='12' fill='#1a2b45'>3. tür: D - K - Y</text><line x1='30' y1='135' x2='200' y2='135' stroke='#1a2b45' stroke-width='3'/><text x='30' y='165' font-size='11' fill='#1a2b45'>D destek, Y yük, K kuvvet</text></svg>","steps":[{"t":"El arabasını çöz","a":"yük ortada","d":"El arabasında tekerlek destek, kum yük, eller kuvvet; yani sıralama D - Y - K'dir."},{"t":"Türü eşle","a":"2. tür","d":"D - Y - K dizilimi şekildeki 2. türe uyar."}],"ans":"El arabasında yük ortada (D - Y - K) olduğu için ikinci tür kaldıraçtır."},{"q":"Tahterevallide ağır bir çocuğu kaldırmak için hafif çocuk desteğe daha mı yakın yoksa daha mı uzak oturmalıdır?","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='105' x2='280' y2='105' stroke='#1a2b45' stroke-width='5'/><polygon points='160,105 145,135 175,135' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek</text><circle cx='70' cy='92' r='14' fill='#e0552b' stroke='#1a2b45'/><text x='70' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>hafif</text><circle cx='235' cy='92' r='14' fill='#4aa3df' stroke='#1a2b45'/><text x='235' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>ağır</text></svg>","steps":[{"t":"Kaldıraç kuralı","a":"uzun kol kazandırır","d":"Birinci tür kaldıraçta desteğe uzak oturan kişi daha az kuvvetle dengeyi sağlar."},{"t":"Karar ver","a":"daha uzak","d":"Hafif çocuk desteğe daha uzak oturursa az ağırlığıyla ağır çocuğu kaldırabilir."}],"ans":"Hafif çocuk desteğe daha uzak oturmalıdır; uzun kol sayesinde az ağırlığıyla ağır çocuğu dengeler."},{"q":"El arabası ile aynı yükü elimizle taşımak yerine kullanmak neden daha kolaydır?","steps":[{"t":"Tür ne?","a":"2. tür","d":"El arabası ikinci tür kaldıraçtır; yük destek ile kuvvet arasındadır."},{"t":"Sağladığı yarar","a":"kuvvetten kazanç","d":"İkinci tür kaldıraç her zaman kuvvetten kazandırır; yükü az kuvvetle kaldırırız."}],"ans":"El arabası ikinci tür kaldıraç olduğu için kuvvetten kazandırır; ağır yükü daha az kuvvetle taşırız."},{"q":"Şekildeki pensede destek tam ortada, çene (yük) bir uçta, el (kuvvet) diğer uçtadır. Pense hangi tür kaldıraçtır ve neden işimizi kolaylaştırır?","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='80' x2='280' y2='80' stroke='#1a2b45' stroke-width='4'/><polygon points='160,80 148,108 172,108' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='128' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek</text><circle cx='70' cy='80' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='70' y='62' font-size='10' text-anchor='middle' fill='#1a2b45'>Yük</text><circle cx='255' cy='80' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='255' y='62' font-size='10' text-anchor='middle' fill='#1a2b45'>Kuvvet</text></svg>","steps":[{"t":"Diziliş","a":"K - D - Y","d":"Pensede destek ortada, kuvvet ve yük uçlarda; bu 1. tür kaldıraçtır."},{"t":"Kolay olma nedeni","a":"uzun kuvvet kolu","d":"Elin tuttuğu kol, çenenin kolundan uzun olduğu için az kuvvetle sert tellere bastırırız."}],"ans":"Pense birinci tür kaldıraçtır; kuvvet kolu uzun olduğu için az kuvvetle teli kesebiliriz."},{"q":"Ceviz kıracağında destek menteşede, ceviz (yük) ortada, el (kuvvet) uçtadır. Hangi tür kaldıraçtır ve cevizi kırmamızı neden kolaylaştırır?","fig":"<svg viewBox='0 0 320 160'><circle cx='60' cy='80' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='60' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='60' y1='80' x2='280' y2='80' stroke='#1a2b45' stroke-width='4'/><circle cx='160' cy='80' r='12' fill='#c79a5b' stroke='#1a2b45'/><text x='160' y='115' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük (ceviz)</text><circle cx='270' cy='80' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='270' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>Kuvvet</text></svg>","steps":[{"t":"Diziliş","a":"D - Y - K","d":"Destek menteşede, ceviz (yük) ortada, el (kuvvet) uçta; bu 2. tür kaldıraçtır."},{"t":"Kolay olma nedeni","a":"kuvvetten kazanç","d":"İkinci tür kaldıraç kuvvetten kazandırır; az kuvvetle sert cevizi kırarız."}],"ans":"Ceviz kıracağı ikinci tür kaldıraçtır; kuvvetten kazandırdığı için az kuvvetle cevizi kırabiliriz."}]},"ortaokul":{"kolay":[{"q":"Şekilde destek ortada, yük ve kuvvet uçlardadır. Bu kaldıracın türünü belirleyip iki örnek veriniz.","fig":"<svg viewBox='0 0 320 150'><line x1='40' y1='80' x2='280' y2='80' stroke='#1a2b45' stroke-width='5'/><polygon points='160,80 145,110 175,110' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='128' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek (D)</text><circle cx='70' cy='66' r='12' fill='#4aa3df' stroke='#1a2b45'/><text x='70' y='48' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük (Y)</text><circle cx='250' cy='66' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='250' y='48' font-size='11' text-anchor='middle' fill='#1a2b45'>Kuvvet (K)</text></svg>","steps":[{"t":"Dizilişi oku","a":"Y - D - K","d":"Şekilde destek ortada; yük ve kuvvet iki uçtadır."},{"t":"Tür ve örnek","a":"1. tür","d":"Destek ortada olan kaldıraç birinci türdür; tahterevalli, makas, pense örnektir."}],"ans":"Destek ortada (Y - D - K) olduğu için bu birinci tür kaldıraçtır; örnek olarak tahterevalli ve makas verilebilir."},{"q":"Şekilde yük ortada, destek ve kuvvet uçlardadır. Bu kaldıracın türünü belirleyip kuvvet kazancı durumunu açıklayınız.","fig":"<svg viewBox='0 0 320 150'><line x1='40' y1='80' x2='280' y2='80' stroke='#1a2b45' stroke-width='5'/><circle cx='60' cy='80' r='11' fill='#5b6b85' stroke='#1a2b45'/><text x='60' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek</text><circle cx='160' cy='66' r='12' fill='#4aa3df' stroke='#1a2b45'/><text x='160' y='48' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük</text><circle cx='265' cy='66' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='265' y='48' font-size='11' text-anchor='middle' fill='#1a2b45'>Kuvvet</text></svg>","steps":[{"t":"Dizilişi oku","a":"D - Y - K","d":"Yük destek ile kuvvet arasında, yani ortadadır."},{"t":"Kuvvet kazancı","a":"her zaman kazanç","d":"İkinci tür kaldıraçta kuvvet kolu daima yük kolundan uzundur; bu yüzden kuvvetten kazandırır."}],"ans":"Yük ortada (D - Y - K) olduğu için bu ikinci tür kaldıraçtır ve her zaman kuvvetten kazandırır."},{"q":"Şekilde kuvvet ortada, destek ve yük uçlardadır. Bu kaldıracın türünü belirleyip kuvvet kazancı durumunu açıklayınız.","fig":"<svg viewBox='0 0 320 150'><line x1='40' y1='80' x2='280' y2='80' stroke='#1a2b45' stroke-width='5'/><circle cx='60' cy='80' r='11' fill='#5b6b85' stroke='#1a2b45'/><text x='60' y='110' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek</text><circle cx='160' cy='66' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='160' y='48' font-size='11' text-anchor='middle' fill='#1a2b45'>Kuvvet</text><circle cx='265' cy='66' r='12' fill='#4aa3df' stroke='#1a2b45'/><text x='265' y='48' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük</text></svg>","steps":[{"t":"Dizilişi oku","a":"D - K - Y","d":"Kuvvet, destek ile yük arasında, yani ortadadır."},{"t":"Kuvvet kazancı","a":"kayıp","d":"Üçüncü tür kaldıraçta kuvvet kolu daima yük kolundan kısadır; kuvvetten kayıp olur, yoldan kazanılır."}],"ans":"Kuvvet ortada (D - K - Y) olduğu için bu üçüncü tür kaldıraçtır; kuvvetten kayıp, yoldan kazanç sağlar."},{"q":"Bir öğrenci 'tahterevalli, makas ve pense aynı tür kaldıraçtır' diyor. Bu üç araç hangi türdendir ve ortak özellikleri nedir?","steps":[{"t":"Ortak nokta","a":"destek ortada","d":"Üçünde de destek noktası kuvvet ile yükün arasında, yani ortadadır."},{"t":"Tür","a":"1. tür","d":"Destek ortada olduğundan üçü de birinci tür kaldıraçtır."}],"ans":"Tahterevalli, makas ve pensede destek ortada olduğu için üçü de birinci tür kaldıraçtır."},{"q":"İnsanın ön kolu, dirsek destek, avuçtaki yük uçta, pazu kasının çektiği nokta ortada olacak şekilde çalışır. Ön kol hangi tür kaldıraçtır?","fig":"<svg viewBox='0 0 320 160'><circle cx='60' cy='90' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='60' y='70' font-size='10' text-anchor='middle' fill='#1a2b45'>Dirsek (D)</text><line x1='60' y1='90' x2='270' y2='90' stroke='#1a2b45' stroke-width='5'/><line x1='120' y1='90' x2='120' y2='50' stroke='#e0552b' stroke-width='4'/><polygon points='120,50 115,62 125,62' fill='#e0552b'/><text x='120' y='42' font-size='10' text-anchor='middle' fill='#1a2b45'>Kuvvet</text><circle cx='268' cy='90' r='12' fill='#4aa3df' stroke='#1a2b45'/><text x='268' y='118' font-size='10' text-anchor='middle' fill='#1a2b45'>Yük</text></svg>","steps":[{"t":"Dizilişi belirle","a":"D - K - Y","d":"Dirsek destek, kasın bağlandığı nokta kuvvet (ortada), avuçtaki ağırlık yük (uçta)."},{"t":"Tür","a":"3. tür","d":"Kuvvet ortada olduğu için ön kol üçüncü tür kaldıraçtır."}],"ans":"Ön kolda kuvvet (kas) ortada olduğu için ön kol üçüncü tür kaldıraçtır."},{"q":"İkinci tür kaldıraç ile üçüncü tür kaldıracın kuvvet kazancı açısından farkı nedir?","steps":[{"t":"2. tür","a":"kuvvetten kazanç","d":"İkinci türde yük ortada, kuvvet kolu uzundur; daima kuvvetten kazandırır."},{"t":"3. tür","a":"kuvvetten kayıp","d":"Üçüncü türde kuvvet ortada, kuvvet kolu kısadır; kuvvetten kayıp olur ama yoldan/hızdan kazanılır."}],"ans":"İkinci tür kaldıraç her zaman kuvvetten kazandırır; üçüncü tür ise kuvvetten kaybettirir, buna karşılık yoldan (hızdan) kazandırır."}],"zor":[{"q":"Şekildeki kaldıraçta destek ortada; yük kolu 20 cm, kuvvet kolu 60 cm'dir. Türünü belirleyip 30 N'luk yükü dengeleyen kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='85' x2='290' y2='85' stroke='#1a2b45' stroke-width='5'/><polygon points='200,85 185,115 215,115' fill='#5b6b85' stroke='#1a2b45'/><text x='200' y='133' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='200' y1='85' x2='245' y2='85' stroke='#4aa3df' stroke-width='2' stroke-dasharray='3 3'/><text x='222' y='78' font-size='10' text-anchor='middle' fill='#1a2b45'>20 cm</text><circle cx='248' cy='70' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='248' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>30 N</text><line x1='60' y1='85' x2='200' y2='85' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='120' y='78' font-size='10' text-anchor='middle' fill='#1a2b45'>60 cm</text><circle cx='60' cy='70' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='60' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text></svg>","steps":[{"t":"Türü belirle","a":"1. tür","d":"Destek ortada, yük ve kuvvet uçlarda olduğu için birinci tür kaldıraçtır."},{"t":"Denge bağıntısı","a":"F·60 = 30·20","d":"Kaldıraç dengesi: kuvvet × kuvvet kolu = yük × yük kolu."},{"t":"Kuvveti çöz","a":"F = 10 N","d":"F = (30·20)/60 = 600/60 = 10 N."}],"ans":"Birinci tür kaldıraçtır; denge için F = (30·20)/60 = 10 N kuvvet gerekir."},{"q":"Şekildeki el arabasında destek tekerlekte, yük kolu 40 cm, kuvvet kolu 120 cm'dir. Türünü belirleyip 60 N'luk yükü kaldıran kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 165'><circle cx='55' cy='115' r='16' fill='#5b6b85' stroke='#1a2b45'/><text x='55' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='55' y1='115' x2='285' y2='60' stroke='#1a2b45' stroke-width='4'/><circle cx='148' cy='93' r='12' fill='#4aa3df' stroke='#1a2b45'/><text x='148' y='118' font-size='9' text-anchor='middle' fill='#1a2b45'>60 N</text><text x='100' y='90' font-size='9' fill='#1a2b45'>40 cm</text><circle cx='283' cy='61' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='283' y='46' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text><text x='220' y='72' font-size='9' fill='#1a2b45'>120 cm</text></svg>","steps":[{"t":"Türü belirle","a":"2. tür","d":"Yük (kum) destek ile kuvvet arasında, yani ortada olduğu için ikinci tür kaldıraçtır."},{"t":"Denge bağıntısı","a":"F·120 = 60·40","d":"Kuvvet × kuvvet kolu = yük × yük kolu yazılır."},{"t":"Kuvveti çöz","a":"F = 20 N","d":"F = (60·40)/120 = 2400/120 = 20 N; kuvvet yükten küçük, yani kazanç var."}],"ans":"İkinci tür kaldıraçtır; F = (60·40)/120 = 20 N gerekir ve 20 N < 60 N olduğu için kuvvetten kazanç sağlanır."},{"q":"Şekildeki cımbızda destek bir uçta, kuvvet kolu 4 cm, yük kolu 10 cm'dir. Türünü belirleyip 2 N'luk yükü tutmak için gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 150'><circle cx='55' cy='80' r='11' fill='#5b6b85' stroke='#1a2b45'/><text x='55' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='55' y1='80' x2='285' y2='80' stroke='#1a2b45' stroke-width='4'/><line x1='55' y1='95' x2='147' y2='95' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='100' y='112' font-size='10' text-anchor='middle' fill='#1a2b45'>4 cm</text><circle cx='147' cy='80' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='147' y='62' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text><circle cx='283' cy='80' r='10' fill='#4aa3df' stroke='#1a2b45'/><text x='283' y='62' font-size='9' text-anchor='middle' fill='#1a2b45'>2 N</text><text x='215' y='112' font-size='10' text-anchor='middle' fill='#1a2b45'>10 cm</text></svg>","steps":[{"t":"Türü belirle","a":"3. tür","d":"Kuvvet destek ile yük arasında, yani ortada olduğu için üçüncü tür kaldıraçtır."},{"t":"Denge bağıntısı","a":"F·4 = 2·10","d":"Kuvvet × kuvvet kolu = yük × yük kolu yazılır."},{"t":"Kuvveti çöz","a":"F = 5 N","d":"F = (2·10)/4 = 20/4 = 5 N; kuvvet yükten büyük, yani kuvvetten kayıp var."}],"ans":"Üçüncü tür kaldıraçtır; F = (2·10)/4 = 5 N gerekir ve 5 N > 2 N olduğu için kuvvetten kayıp (yoldan kazanç) vardır."},{"q":"Bir kaldıraçta kuvvet, daima yükten küçük çıkıyorsa bu kaldıraç hangi tür(ler) olabilir? Açıklayınız.","steps":[{"t":"Kuvvet kazancı koşulu","a":"kuvvet kolu uzun","d":"Kuvvetin yükten küçük olması için kuvvet kolunun yük kolundan uzun olması gerekir."},{"t":"Türleri ele al","a":"2. tür kesin, 1. tür olabilir","d":"İkinci tür her zaman kazandırır. Birinci türde destek ortaya göre kayarsa kazandırabilir. Üçüncü tür ise asla kazandırmaz."}],"ans":"Kuvvet daima yükten küçükse bu kesinlikle ikinci tür olabilir; birinci tür de (kuvvet kolu uzunsa) olabilir, ancak üçüncü tür olamaz çünkü o her zaman kuvvetten kaybettirir."},{"q":"Şekildeki makasın türünü belirleyiniz; kâğıt ucuna yakınken mi yoksa dibe yakınken mi daha kolay kesilir?","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='70' x2='280' y2='95' stroke='#1a2b45' stroke-width='4'/><line x1='40' y1='95' x2='280' y2='70' stroke='#1a2b45' stroke-width='4'/><circle cx='160' cy='82' r='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek (vida)</text><text x='60' y='55' font-size='10' fill='#1a2b45'>Kuvvet (el)</text><text x='235' y='55' font-size='10' fill='#1a2b45'>Yük (kâğıt)</text></svg>","steps":[{"t":"Türü belirle","a":"1. tür","d":"Makasta destek (vida) ortada olduğu için birinci tür kaldıraçtır."},{"t":"Yük kolu etkisi","a":"dipte küçük","d":"Kâğıt vidaya (desteğe) yakınken yük kolu kısalır; aynı kuvvetle daha büyük kesme etkisi oluşur."}],"ans":"Makas birinci tür kaldıraçtır; kâğıt vidaya yakın (dibe yakın) yerleştirildiğinde yük kolu kısaldığı için daha kolay kesilir."},{"q":"Bir araç hem destek hem yük hem de kuvvet noktasına sahiptir. Türünü kesin belirlemek için hangi tek bilgi yeterlidir? Açıklayınız.","steps":[{"t":"Belirleyici özellik","a":"ortadaki nokta","d":"Kaldıracın türü, destek-yük-kuvvet üçlüsünden hangisinin ortada (arada) olduğuna göre belirlenir."},{"t":"Eşleştir","a":"D/Y/K ortada","d":"Destek ortadaysa 1. tür, yük ortadaysa 2. tür, kuvvet ortadaysa 3. tür."}],"ans":"Türü belirlemek için hangi noktanın ortada olduğunu bilmek yeterlidir: destek ortada 1. tür, yük ortada 2. tür, kuvvet ortada 3. türdür."}]},"lise":{"kolay":[{"q":"Şekildeki kaldıraçta destek, yük ile kuvvetin arasındadır. Bu kaldıracın türünü belirleyip kuvvet kazancı durumunu tartışınız.","fig":"<svg viewBox='0 0 320 150'><line x1='40' y1='80' x2='280' y2='80' stroke='#1a2b45' stroke-width='5'/><polygon points='160,80 145,110 175,110' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='128' font-size='11' text-anchor='middle' fill='#1a2b45'>Destek</text><circle cx='70' cy='66' r='12' fill='#4aa3df' stroke='#1a2b45'/><text x='70' y='48' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük</text><circle cx='250' cy='66' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='250' y='48' font-size='11' text-anchor='middle' fill='#1a2b45'>Kuvvet</text></svg>","steps":[{"t":"Türü belirle","a":"1. tür","d":"Destek yük ile kuvvetin arasında (ortada) olduğu için birinci tür kaldıraçtır."},{"t":"Kuvvet kazancı","a":"değişken","d":"Birinci türde kuvvet kolu yük kolundan uzunsa kuvvetten kazanç, kısaysa kayıp, eşitse ne kazanç ne kayıp olur."}],"ans":"Destek ortada olduğu için birinci tür kaldıraçtır; kollar arasındaki orana göre kuvvetten kazanç da kayıp da olabilir."},{"q":"İnsan vücudunda ayak parmak ucunda yükselme hareketinde ayak bileği destek, vücut ağırlığı yük (ortada), aşil tendonu kuvvet (uçta) gibi çalışır. Bu hangi tür kaldıraçtır?","steps":[{"t":"Dizilişi çöz","a":"K - Y - D","d":"Topuktaki tendon kuvvet, ayağın ortasındaki vücut ağırlığı yük, parmak ucu destektir; yük ortadadır."},{"t":"Türü belirle","a":"2. tür","d":"Yük ortada olduğu için bu ikinci tür kaldıraçtır ve kuvvetten kazandırır."}],"ans":"Yük (vücut ağırlığı) ortada olduğu için ayak ucunda yükselme ikinci tür kaldıraç örneğidir ve kuvvetten kazandırır."},{"q":"Şekildeki birinci tür kaldıraçta yük kolu 15 cm, kuvvet kolu 45 cm, yük 90 N'dur. Dengeyi sağlayan kuvveti ve kuvvet kazancını bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='85' x2='290' y2='85' stroke='#1a2b45' stroke-width='5'/><polygon points='205,85 190,115 220,115' fill='#5b6b85' stroke='#1a2b45'/><text x='205' y='133' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='205' y1='85' x2='255' y2='85' stroke='#4aa3df' stroke-width='2' stroke-dasharray='3 3'/><text x='230' y='78' font-size='9' text-anchor='middle' fill='#1a2b45'>15 cm</text><circle cx='258' cy='70' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='258' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>90 N</text><line x1='60' y1='85' x2='205' y2='85' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='120' y='78' font-size='9' text-anchor='middle' fill='#1a2b45'>45 cm</text><circle cx='60' cy='70' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='60' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text></svg>","steps":[{"t":"Denge bağıntısı","a":"F·45 = 90·15","d":"Moment dengesi: kuvvet × kuvvet kolu = yük × yük kolu."},{"t":"Kuvveti çöz","a":"F = 30 N","d":"F = (90·15)/45 = 1350/45 = 30 N."},{"t":"Kuvvet kazancı","a":"3 kat","d":"Kazanç = yük/kuvvet = 90/30 = 3; ayrıca kuvvet kolu/yük kolu = 45/15 = 3."}],"ans":"Dengeyi sağlayan kuvvet F = 30 N'dur; kuvvet kazancı 90/30 = 3 kattır."},{"q":"Kuvvet kazancı, kaldıraç kollarının uzunluğuna nasıl bağlıdır? Üç tür için genel bir kural veriniz.","steps":[{"t":"Temel oran","a":"kuvvet kolu/yük kolu","d":"Kuvvet kazancı, kuvvet kolunun yük koluna oranına eşittir: Kazanç = bₖ/b_y."},{"t":"Türlere uygula","a":"2. tür hep >1","d":"İkinci türde kuvvet kolu daima uzun (kazanç>1); üçüncü türde daima kısa (kazanç<1); birinci türde değişkendir."}],"ans":"Kuvvet kazancı = kuvvet kolu/yük kolu'dur; ikinci türde bu oran daima 1'den büyük, üçüncü türde daima 1'den küçük, birinci türde ise kolların uzunluğuna göre değişkendir."},{"q":"Şekildeki ikinci tür kaldıraçta yük kolu 25 cm, kuvvet kolu 100 cm, yük 80 N'dur. Gereken kuvveti ve kuvvet kazancını bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='85' x2='290' y2='85' stroke='#1a2b45' stroke-width='5'/><circle cx='52' cy='85' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='52' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='52' y1='100' x2='130' y2='100' stroke='#4aa3df' stroke-width='2' stroke-dasharray='3 3'/><text x='90' y='118' font-size='9' text-anchor='middle' fill='#1a2b45'>25 cm</text><circle cx='130' cy='70' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='130' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>80 N</text><line x1='52' y1='100' x2='280' y2='100' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='220' y='118' font-size='9' text-anchor='middle' fill='#1a2b45'>100 cm</text><circle cx='280' cy='70' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='280' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text></svg>","steps":[{"t":"Denge bağıntısı","a":"F·100 = 80·25","d":"Moment dengesi yazılır: kuvvet × kuvvet kolu = yük × yük kolu."},{"t":"Kuvveti çöz","a":"F = 20 N","d":"F = (80·25)/100 = 2000/100 = 20 N."},{"t":"Kazanç","a":"4 kat","d":"Kazanç = 80/20 = 4; ikinci tür olduğu için kazanç 1'den büyüktür."}],"ans":"Gereken kuvvet F = 20 N'dur; kuvvet kazancı 80/20 = 4 kattır (ikinci tür daima kazandırır)."},{"q":"Üçüncü tür kaldıraç kuvvetten kaybettirdiği halde insan vücudunda (kol, bacak) neden bu kadar yaygındır?","steps":[{"t":"Kayıp ama kazanç","a":"yoldan kazanç","d":"Üçüncü tür kuvvetten kaybettirir ama yük ucu daha çok ve daha hızlı hareket eder; yoldan/hızdan kazandırır."},{"t":"Vücut için anlamı","a":"hız ve geniş hareket","d":"Kaslar kemiğe yakın bağlandığı için az kasılmayla el/ayak ucu geniş ve hızlı hareket eder."}],"ans":"Üçüncü tür kaldıraç kuvvetten kaybetse de yoldan ve hızdan kazandırır; vücutta kaslar eklemlere yakın bağlandığından küçük kasılmalarla uzuvlar hızlı ve geniş hareket eder."},{"q":"Şekildeki kürekte üst el destek, alt el kuvvet (ortada), uçtaki toprak yüktür. Türünü belirleyip kuvvet kazancı durumunu açıklayınız.","fig":"<svg viewBox='0 0 320 160'><circle cx='55' cy='55' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='55' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='55' y1='55' x2='275' y2='130' stroke='#1a2b45' stroke-width='4'/><circle cx='150' cy='88' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='130' y='80' font-size='9' fill='#1a2b45'>Kuvvet</text><polygon points='265,118 295,118 285,142 250,142' fill='#c79a5b' stroke='#1a2b45'/><text x='272' y='155' font-size='10' text-anchor='middle' fill='#1a2b45'>Yük</text></svg>","steps":[{"t":"Dizilişi çöz","a":"D - K - Y","d":"Üst el destek, alt el kuvvet (ortada), uçtaki toprak yüktür."},{"t":"Tür ve kazanç","a":"3. tür, kayıp","d":"Kuvvet ortada olduğu için üçüncü türdür; kuvvet kolu kısa olduğundan kuvvetten kaybeder, yoldan kazanır."}],"ans":"Kürek üçüncü tür kaldıraçtır; kuvvet ortada ve kuvvet kolu kısa olduğu için kuvvetten kayıp, yoldan kazanç sağlar."},{"q":"Aynı yükü kaldırmak için 1. tür ve 2. tür kaldıraç kullanılabilir. Hangi durumda 1. tür kaldıraç da 2. tür kadar kuvvet kazancı sağlayabilir?","steps":[{"t":"2. türün özelliği","a":"kuvvet kolu uzun","d":"İkinci türde kuvvet kolu hep yük kolundan uzundur, kazanç daima 1'den büyüktür."},{"t":"1. tür için koşul","a":"destek yüke yakın","d":"Birinci türde destek yük tarafına kaydırılırsa kuvvet kolu uzar, yük kolu kısalır; kazanç artar."}],"ans":"Birinci tür kaldıraçta destek noktası yüke yaklaştırılırsa kuvvet kolu uzar ve yük kolu kısalır; bu durumda birinci tür de ikinci tür gibi yüksek kuvvet kazancı sağlayabilir."},{"q":"Şekildeki üç kaldıraç türünün destek (D), yük (Y), kuvvet (K) dizilimleri veriliyor. Hangisi kuvvetten asla kazandırmaz?","fig":"<svg viewBox='0 0 320 180'><text x='20' y='28' font-size='12' fill='#1a2b45'>1. tür</text><line x1='90' y1='24' x2='280' y2='24' stroke='#1a2b45' stroke-width='3'/><text x='100' y='18' font-size='11' fill='#e0552b'>K</text><text x='185' y='18' font-size='11' fill='#5b6b85'>D</text><text x='270' y='18' font-size='11' fill='#4aa3df'>Y</text><text x='20' y='90' font-size='12' fill='#1a2b45'>2. tür</text><line x1='90' y1='86' x2='280' y2='86' stroke='#1a2b45' stroke-width='3'/><text x='100' y='80' font-size='11' fill='#5b6b85'>D</text><text x='185' y='80' font-size='11' fill='#4aa3df'>Y</text><text x='270' y='80' font-size='11' fill='#e0552b'>K</text><text x='20' y='150' font-size='12' fill='#1a2b45'>3. tür</text><line x1='90' y1='146' x2='280' y2='146' stroke='#1a2b45' stroke-width='3'/><text x='100' y='140' font-size='11' fill='#5b6b85'>D</text><text x='185' y='140' font-size='11' fill='#e0552b'>K</text><text x='270' y='140' font-size='11' fill='#4aa3df'>Y</text></svg>","steps":[{"t":"Kollara bak","a":"3. türde kuvvet kolu kısa","d":"Üçüncü türde kuvvet ortada olduğu için kuvvet kolu daima yük kolundan kısadır."},{"t":"Sonuç","a":"kazandırmaz","d":"Kuvvet kolu kısa olduğundan kazanç hep 1'den küçüktür; kuvvetten kayıp olur."}],"ans":"Üçüncü tür kaldıraç (D - K - Y) kuvvetten asla kazandırmaz; kuvvet kolu daima kısa olduğu için yalnızca yoldan kazandırır."},{"q":"Bir kaldıraçta kuvvet kazancı 1'e eşit çıkıyor. Bu kaldıraç hangi tür olabilir ve bu ne anlama gelir?","steps":[{"t":"Kazanç=1 koşulu","a":"kollar eşit","d":"Kuvvet kazancının 1 olması, kuvvet kolu ile yük kolunun eşit olması demektir."},{"t":"Türü belirle","a":"sadece 1. tür","d":"Yalnızca birinci türde destek tam ortada olursa kollar eşitlenebilir; 2. ve 3. türde kollar asla eşit olamaz."}],"ans":"Kuvvet kazancı 1 ise kollar eşittir; bu yalnızca birinci tür kaldıraçta (destek tam ortada) olur ve kuvvetten ne kazanç ne kayıp anlamına gelir, sadece yön değiştirir."},{"q":"Şekildeki el arabasında 50 kg'lık yük tekerlekten 50 cm, kollardan 150 cm uzaktadır. Kaldırmak için gereken kuvveti bulunuz (g = 10 N/kg).","fig":"<svg viewBox='0 0 320 165'><circle cx='52' cy='118' r='16' fill='#5b6b85' stroke='#1a2b45'/><text x='52' y='152' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='52' y1='118' x2='285' y2='62' stroke='#1a2b45' stroke-width='4'/><circle cx='130' cy='99' r='13' fill='#4aa3df' stroke='#1a2b45'/><text x='130' y='124' font-size='9' text-anchor='middle' fill='#1a2b45'>500 N</text><text x='85' y='95' font-size='9' fill='#1a2b45'>50 cm</text><circle cx='283' cy='63' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='283' y='48' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text><text x='215' y='75' font-size='9' fill='#1a2b45'>150 cm</text></svg>","steps":[{"t":"Yükü bul","a":"G = 500 N","d":"Yükün ağırlığı G = m·g = 50·10 = 500 N'dur."},{"t":"Türü ve dengeyi yaz","a":"F·150 = 500·50","d":"El arabası 2. tür; moment dengesi: F × 150 = 500 × 50."},{"t":"Kuvveti çöz","a":"F ≈ 167 N","d":"F = (500·50)/150 = 25000/150 ≈ 166,7 N."}],"ans":"El arabası ikinci tür kaldıraçtır; gereken kuvvet F = (500·50)/150 ≈ 166,7 N'dur ve yükten küçük olduğu için kuvvet kazancı sağlanır."},{"q":"Pense ve cımbız ikisi de elle kullanılır ama kuvvet kazancı bakımından zıttır. Bu farkın nedenini kaldıraç türleriyle açıklayınız.","steps":[{"t":"Türleri belirle","a":"pense 1., cımbız 3.","d":"Pensede destek ortada (1. tür), cımbızda kuvvet ortada (3. tür)."},{"t":"Kazancı kıyasla","a":"pense kazandırır","d":"Pensede kuvvet kolu uzun olup kuvvetten kazandırır; cımbızda kuvvet kolu kısa olup kuvvetten kaybeder ama hassas/geniş hareket sağlar."}],"ans":"Pense birinci tür olup kuvvet kolu uzun olduğundan kuvvetten kazandırır; cımbız üçüncü tür olup kuvvet kolu kısa olduğundan kuvvetten kaybeder, buna karşılık hassas ve geniş hareket sağlar."},{"q":"Şekildeki üçüncü tür kaldıraçta kuvvet kolu 6 cm, yük kolu 24 cm, kuvvet 60 N'dur. Kaldırılabilecek en büyük yükü ve kuvvet kazancını bulunuz.","fig":"<svg viewBox='0 0 320 155'><circle cx='52' cy='80' r='11' fill='#5b6b85' stroke='#1a2b45'/><text x='52' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='52' y1='80' x2='285' y2='80' stroke='#1a2b45' stroke-width='4'/><line x1='52' y1='95' x2='110' y2='95' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='80' y='112' font-size='9' text-anchor='middle' fill='#1a2b45'>6 cm</text><circle cx='110' cy='80' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='110' y='62' font-size='9' text-anchor='middle' fill='#1a2b45'>60 N</text><circle cx='283' cy='80' r='10' fill='#4aa3df' stroke='#1a2b45'/><text x='283' y='62' font-size='9' text-anchor='middle' fill='#1a2b45'>Y=?</text><text x='215' y='112' font-size='9' text-anchor='middle' fill='#1a2b45'>24 cm</text></svg>","steps":[{"t":"Denge bağıntısı","a":"60·6 = Y·24","d":"Moment dengesi: kuvvet × kuvvet kolu = yük × yük kolu."},{"t":"Yükü çöz","a":"Y = 15 N","d":"Y = (60·6)/24 = 360/24 = 15 N."},{"t":"Kazanç","a":"0,25 kat","d":"Kazanç = 15/60 = 0,25; 1'den küçük olduğu için kuvvetten kayıp vardır."}],"ans":"En çok 15 N'luk yük kaldırılır; kuvvet kazancı 15/60 = 0,25'tir (üçüncü tür olduğu için kuvvetten kayıp vardır)."},{"q":"Bir kaldıraçta yük 10 cm yukarı çıkarken kuvvetin uygulandığı uç 40 cm aşağı iniyor. Bu kaldıraç kuvvetten mi yoksa yoldan mı kazandırır?","steps":[{"t":"Yolları kıyasla","a":"kuvvet daha çok yol alır","d":"Kuvvet ucu 40 cm, yük ucu 10 cm hareket ediyor; kuvvet daha uzun yol alır."},{"t":"Sonucu çıkar","a":"kuvvetten kazanç","d":"İş korunduğundan, uzun yol alan kuvvet daha küçük olur; bu kaldıraç kuvvetten kazandırır (yoldan kaybeder)."}],"ans":"Kuvvet ucu yükten daha çok yol aldığı için bu kaldıraç kuvvetten kazandırır (4 kat), buna karşılık yoldan kaybeder."},{"q":"Şekildeki ceviz kıracağında menteşe destek, ceviz yük kolu 5 cm'de, el kuvvet kolu 20 cm'de. 200 N'luk kırma kuvveti gerektiren cevizi kırmak için ele uygulanan kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 155'><circle cx='52' cy='80' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='52' y='60' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='52' y1='80' x2='285' y2='80' stroke='#1a2b45' stroke-width='4'/><line x1='52' y1='95' x2='110' y2='95' stroke='#4aa3df' stroke-width='2' stroke-dasharray='3 3'/><text x='80' y='112' font-size='9' text-anchor='middle' fill='#1a2b45'>5 cm</text><circle cx='110' cy='80' r='11' fill='#c79a5b' stroke='#1a2b45'/><text x='110' y='62' font-size='9' text-anchor='middle' fill='#1a2b45'>200 N</text><line x1='52' y1='95' x2='280' y2='95' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='220' y='112' font-size='9' text-anchor='middle' fill='#1a2b45'>20 cm</text><circle cx='280' cy='80' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='280' y='62' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text></svg>","steps":[{"t":"Türü belirle","a":"2. tür","d":"Ceviz (yük) menteşe ile el arasında, yani ortada; bu ikinci tür kaldıraçtır."},{"t":"Denge bağıntısı","a":"F·20 = 200·5","d":"Moment dengesi: kuvvet × kuvvet kolu = yük × yük kolu."},{"t":"Kuvveti çöz","a":"F = 50 N","d":"F = (200·5)/20 = 1000/20 = 50 N; kazanç = 200/50 = 4."}],"ans":"Ceviz kıracağı ikinci tür kaldıraçtır; ele uygulanması gereken kuvvet F = (200·5)/20 = 50 N'dur (4 kat kuvvet kazancı)."}],"zor":[{"q":"Şekildeki birinci tür kaldıraçta sol uçta 40 N, desteğe 30 cm uzaklıkta; sağ uçta F kuvveti desteğe 60 cm uzaklıkta dengededir. F kuvvetini ve kuvvet kazancını bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='30' y1='90' x2='300' y2='90' stroke='#1a2b45' stroke-width='5'/><polygon points='150,90 135,120 165,120' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='60' y1='90' x2='150' y2='90' stroke='#4aa3df' stroke-width='2' stroke-dasharray='3 3'/><text x='100' y='82' font-size='9' text-anchor='middle' fill='#1a2b45'>30 cm</text><circle cx='60' cy='74' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='60' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>40 N</text><line x1='150' y1='90' x2='285' y2='90' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='225' y='82' font-size='9' text-anchor='middle' fill='#1a2b45'>60 cm</text><circle cx='285' cy='74' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='285' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text></svg>","steps":[{"t":"Türü belirle","a":"1. tür","d":"Destek ortada, yük ve kuvvet uçlarda; birinci tür kaldıraçtır."},{"t":"Moment dengesi","a":"F·60 = 40·30","d":"Desteğe göre momentler eşitlenir: kuvvet × 60 = yük × 30."},{"t":"Çöz ve kazanç","a":"F = 20 N","d":"F = (40·30)/60 = 1200/60 = 20 N; kazanç = 40/20 = 2."}],"ans":"Birinci tür kaldıraçtır; F = (40·30)/60 = 20 N'dur ve kuvvet kazancı 40/20 = 2 kattır."},{"q":"Bir manivelada (1. tür) destek yük tarafına kaydırılarak yük kolu yarıya indiriliyor, kuvvet kolu ise iki katına çıkıyor. Kuvvet kazancı nasıl değişir?","steps":[{"t":"Başlangıç kazancı","a":"bₖ/b_y","d":"Kuvvet kazancı kuvvet kolunun yük koluna oranıdır: Kazanç = bₖ/b_y."},{"t":"Yeni durumu yaz","a":"2bₖ / (b_y/2)","d":"Kuvvet kolu 2 katına, yük kolu yarıya inince yeni oran (2bₖ)/(b_y/2) = 4·(bₖ/b_y) olur."},{"t":"Sonuç","a":"4 kat artar","d":"Yeni kuvvet kazancı eski kazancın 4 katına çıkar."}],"ans":"Kuvvet kolu iki katına çıkıp yük kolu yarıya inince kuvvet kazancı eskinin 4 katına çıkar; aynı yük çok daha az kuvvetle kaldırılır."},{"q":"Şekilde ön kol (3. tür) modeli: dirsek destek, pazu kası kuvvet dirseğe 4 cm uzakta, eldeki yük dirseğe 32 cm uzakta. Elde 50 N yük tutulurken kasın uyguladığı kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='50' cy='95' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='50' y='75' font-size='10' text-anchor='middle' fill='#1a2b45'>Dirsek (D)</text><line x1='50' y1='95' x2='290' y2='95' stroke='#1a2b45' stroke-width='5'/><line x1='95' y1='95' x2='95' y2='48' stroke='#e0552b' stroke-width='4'/><polygon points='95,48 90,60 100,60' fill='#e0552b'/><text x='95' y='40' font-size='9' text-anchor='middle' fill='#1a2b45'>F kas</text><text x='72' y='118' font-size='9' fill='#1a2b45'>4 cm</text><circle cx='285' cy='95' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='285' y='123' font-size='9' text-anchor='middle' fill='#1a2b45'>50 N</text><text x='200' y='118' font-size='9' fill='#1a2b45'>32 cm</text></svg>","steps":[{"t":"Türü belirle","a":"3. tür","d":"Kuvvet (kas) destek (dirsek) ile yük (el) arasında; üçüncü tür kaldıraçtır."},{"t":"Moment dengesi","a":"F·4 = 50·32","d":"Dirseğe göre momentler eşitlenir: kuvvet × 4 = yük × 32."},{"t":"Kuvveti çöz","a":"F = 400 N","d":"F = (50·32)/4 = 1600/4 = 400 N; kuvvet kazancı = 50/400 = 0,125."}],"ans":"Ön kol üçüncü tür kaldıraçtır; kasın uyguladığı kuvvet F = (50·32)/4 = 400 N'dur; kuvvetten kaybeder ama el ucu kasa göre 8 kat daha hızlı/geniş hareket eder."},{"q":"İki kaldıraç aynı 100 N yükü kaldırıyor: biri 2. tür (kazanç 5), diğeri 3. tür (kazanç 0,2). Aynı yükü kaldırmak için gereken kuvvetleri kıyaslayınız.","steps":[{"t":"2. tür kuvveti","a":"20 N","d":"Kazanç = yük/kuvvet ⇒ kuvvet = yük/kazanç = 100/5 = 20 N."},{"t":"3. tür kuvveti","a":"500 N","d":"Kuvvet = 100/0,2 = 500 N; kuvvet kazancı 1'den küçük olduğu için kuvvet büyük çıkar."},{"t":"Kıyasla","a":"25 kat fark","d":"500/20 = 25; üçüncü tür için 25 kat daha fazla kuvvet gerekir."}],"ans":"İkinci tür için 20 N, üçüncü tür için 500 N gerekir; üçüncü tür kuvvetten kaybettiği için aynı yüke 25 kat daha fazla kuvvet ister, ama buna karşılık yoldan/hızdan kazandırır."},{"q":"Şekildeki kürek (3. tür) düzeneğinde 80 N toprak yükü, üst el desteğine 90 cm uzakta; alt el (kuvvet) desteğe 30 cm uzakta. Alt elin uyguladığı kuvveti ve kuvvet kazancını bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='52' cy='55' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='52' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='52' y1='55' x2='280' y2='135' stroke='#1a2b45' stroke-width='4'/><circle cx='128' cy='82' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='105' y='78' font-size='9' fill='#1a2b45'>F (30 cm)</text><polygon points='268,123 298,123 288,147 253,147' fill='#c79a5b' stroke='#1a2b45'/><text x='272' y='115' font-size='9' text-anchor='middle' fill='#1a2b45'>80 N</text><text x='200' y='128' font-size='9' fill='#1a2b45'>90 cm</text></svg>","steps":[{"t":"Türü belirle","a":"3. tür","d":"Alt el (kuvvet) destek ile yük arasında; üçüncü tür kaldıraçtır."},{"t":"Moment dengesi","a":"F·30 = 80·90","d":"Desteğe göre momentler: kuvvet × 30 = yük × 90."},{"t":"Çöz ve kazanç","a":"F = 240 N","d":"F = (80·90)/30 = 7200/30 = 240 N; kazanç = 80/240 ≈ 0,33."}],"ans":"Kürek üçüncü tür kaldıraçtır; alt elin uyguladığı kuvvet F = 240 N, kuvvet kazancı ≈ 0,33'tür (kuvvetten kayıp, yoldan kazanç)."},{"q":"Bir kaldıraç sisteminde kuvvetten kazanç 3 ise, aynı yükü aynı yüksekliğe çıkarmak için kuvvetin alması gereken yol nasıldır? İşin korunumuyla açıklayınız.","steps":[{"t":"İşin korunumu","a":"F·x = G·h","d":"Sürtünme yoksa kuvvetin yaptığı iş, yüke aktarılan işe eşittir: F·x = G·h."},{"t":"Yolu çöz","a":"x = 3h","d":"Kazanç = G/F = 3 ⇒ G = 3F. F·x = 3F·h ⇒ x = 3h."}],"ans":"Kuvvet kazancı 3 ise işin korunumu gereği kuvvet, yükün çıktığı yüksekliğin 3 katı kadar yol almalıdır; kuvvetten kazanılan, yoldan kaybedilir (basit makineler işten kazandırmaz)."},{"q":"Şekildeki birinci tür kaldıraç çubuğunun ağırlığı ihmal edilemiyor; çubuğun ağırlığı (G_çubuk) hesaba nasıl katılır?","fig":"<svg viewBox='0 0 320 165'><line x1='30' y1='85' x2='300' y2='85' stroke='#1a2b45' stroke-width='6'/><polygon points='130,85 115,115 145,115' fill='#5b6b85' stroke='#1a2b45'/><text x='130' y='133' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><circle cx='55' cy='70' r='10' fill='#4aa3df' stroke='#1a2b45'/><text x='55' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>Yük</text><circle cx='290' cy='70' r='10' fill='#e0552b' stroke='#1a2b45'/><text x='290' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>F</text><line x1='200' y1='85' x2='200' y2='118' stroke='#2e7d32' stroke-width='3'/><polygon points='200,118 195,108 205,108' fill='#2e7d32'/><text x='225' y='110' font-size='9' fill='#1a2b45'>G çubuk</text></svg>","steps":[{"t":"Ağırlık merkezini bul","a":"kütle merkezi","d":"Çubuğun ağırlığı, ağırlık merkezinde (homojen çubukta orta nokta) etki eden tek bir kuvvet gibi alınır."},{"t":"Momente kat","a":"ek moment","d":"Bu ağırlığın desteğe olan uzaklığıyla momenti hesaplanır ve denge denklemine eklenir: ΣM_destek = 0."},{"t":"Denge yaz","a":"F·bₖ = G_y·b_y ± G_çubuk·d","d":"Çubuğun momenti, ağırlık merkezi desteğin hangi tarafındaysa o yönde denkleme dahil edilir."}],"ans":"Çubuğun ağırlığı, ağırlık merkezinde etki eden tek kuvvet gibi alınır; bu kuvvetin desteğe göre momenti hesaplanıp denge denklemine (ΣM = 0) katılır, böylece gereken kuvvet doğru bulunur."},{"q":"Şekildeki düzenekte aynı çubuk önce 1. tür, sonra desteği uca kaydırarak 2. tür gibi kullanılıyor. Hangi kullanımda daha az kuvvet gerekir? Açıklayınız.","fig":"<svg viewBox='0 0 320 175'><text x='20' y='25' font-size='11' fill='#1a2b45'>1. tür: K-D-Y</text><line x1='40' y1='55' x2='280' y2='55' stroke='#1a2b45' stroke-width='4'/><polygon points='160,55 148,80 172,80' fill='#5b6b85' stroke='#1a2b45'/><circle cx='55' cy='44' r='8' fill='#e0552b' stroke='#1a2b45'/><circle cx='265' cy='44' r='8' fill='#4aa3df' stroke='#1a2b45'/><text x='20' y='115' font-size='11' fill='#1a2b45'>2. tür: D-Y-K</text><line x1='40' y1='140' x2='280' y2='140' stroke='#1a2b45' stroke-width='4'/><circle cx='50' cy='140' r='8' fill='#5b6b85' stroke='#1a2b45'/><circle cx='150' cy='128' r='8' fill='#4aa3df' stroke='#1a2b45'/><circle cx='270' cy='128' r='8' fill='#e0552b' stroke='#1a2b45'/></svg>","steps":[{"t":"Kuvvet kollarını kıyasla","a":"2. türde uzun","d":"İkinci türde kuvvet çubuğun en ucundadır ve kuvvet kolu daima yük kolundan uzundur."},{"t":"Kazancı değerlendir","a":"2. tür kesin >1","d":"İkinci türde kazanç her zaman 1'den büyüktür; birinci türde ise destek ortada olduğundan kazanç ona göre değişir, çoğu zaman daha azdır."}],"ans":"İkinci tür kullanımda kuvvet kolu daima yük kolundan uzun olduğundan kuvvet kazancı garanti 1'den büyüktür; bu nedenle ikinci tür kullanımda genelde daha az kuvvet gerekir."},{"q":"Bir vücut hareketinde kasın 5 cm kasılmasıyla el ucu 40 cm hareket ediyor. Bu kaldıracın türünü, kuvvet kazancını ve neden 'hızdan kazanç' sağladığını açıklayınız.","steps":[{"t":"Yolları kıyasla","a":"yük çok hareket eder","d":"Kuvvet ucu (kas) 5 cm, yük ucu (el) 40 cm hareket ediyor; yük ucu 8 kat fazla yol alır."},{"t":"Türü belirle","a":"3. tür","d":"Yük ucu kuvvet ucundan fazla hareket ettiğinden kuvvet kolu kısadır; bu üçüncü tür kaldıraçtır."},{"t":"Kazanç ve hız","a":"kazanç 0,125","d":"Kuvvet kazancı = 5/40 = 0,125 (<1, kuvvetten kayıp); ama el ucu 8 kat daha hızlı hareket eder, yani hızdan kazanılır."}],"ans":"Kuvvet ucu az, yük ucu çok hareket ettiği için bu üçüncü tür kaldıraçtır; kuvvet kazancı 0,125 olup kuvvetten kaybeder, fakat el ucu 8 kat daha hızlı ve geniş hareket ederek hızdan kazandırır."},{"q":"Şekildeki birinci tür kaldıraçta iki yük var: desteğin solunda 30 cm'de 60 N, sağında 90 cm'de F kuvveti dengededir. Çubuk ağırlıksız kabul edilerek F'yi bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='25' y1='90' x2='305' y2='90' stroke='#1a2b45' stroke-width='5'/><polygon points='140,90 125,120 155,120' fill='#5b6b85' stroke='#1a2b45'/><text x='140' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='55' y1='90' x2='140' y2='90' stroke='#4aa3df' stroke-width='2' stroke-dasharray='3 3'/><text x='95' y='82' font-size='9' text-anchor='middle' fill='#1a2b45'>30 cm</text><circle cx='55' cy='74' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='55' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>60 N</text><line x1='140' y1='90' x2='290' y2='90' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='220' y='82' font-size='9' text-anchor='middle' fill='#1a2b45'>90 cm</text><circle cx='290' cy='74' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='290' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text></svg>","steps":[{"t":"Moment dengesi","a":"ΣM = 0","d":"Destek etrafında saat yönü ve ters yönü momentleri eşitlenir."},{"t":"Denklemi yaz","a":"F·90 = 60·30","d":"Yükün momenti: 60·30 = 1800; kuvvetin momenti: F·90."},{"t":"Çöz","a":"F = 20 N","d":"F = 1800/90 = 20 N; kuvvet kazancı = 60/20 = 3."}],"ans":"Moment dengesinden F = (60·30)/90 = 20 N bulunur; birinci tür kaldıraçta kuvvet kolu uzun olduğu için 3 kat kuvvet kazancı sağlanır."},{"q":"Bir öğrenci 'tüm basit makineler işten kazandırır' diyor. Kaldıraç türlerini ve enerji korunumunu kullanarak bu ifadeyi değerlendiriniz.","steps":[{"t":"İşin tanımı","a":"W = F·x","d":"İş, kuvvet ile alınan yolun çarpımıdır; korunumlu sistemde kuvvetin işi yükün işine eşittir."},{"t":"Kaldıraçta uygula","a":"kazanç yere transfer","d":"Kuvvetten kazanılırsa (2. tür) yoldan kaybedilir; kuvvetten kaybedilirse (3. tür) yoldan kazanılır. Çarpım sabittir."},{"t":"Sonuç","a":"işten kazanç yok","d":"Sürtünmesiz durumda giren iş = çıkan iş; basit makine işten kazandırmaz, yalnızca kuvvet veya yolu dönüştürür."}],"ans":"İfade yanlıştır; kaldıraçlar (1., 2., 3. tür hepsi) işten kazandırmaz, yalnızca kuvvetten kazanılanı yoldan kaybeder veya tersini yapar. Enerji korunumu gereği sürtünmesiz makinede giren iş çıkan işe eşittir."},{"q":"Şekildeki ikinci tür kaldıraçta yük tam ortada değil; yük desteğe 20 cm, kuvvet desteğe 80 cm uzakta, yük 240 N'dur. Gereken kuvveti, kuvvet kazancını ve yükün 5 cm kalkması için kuvvetin aldığı yolu bulunuz.","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='85' x2='295' y2='85' stroke='#1a2b45' stroke-width='5'/><circle cx='52' cy='85' r='12' fill='#5b6b85' stroke='#1a2b45'/><text x='52' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='52' y1='100' x2='125' y2='100' stroke='#4aa3df' stroke-width='2' stroke-dasharray='3 3'/><text x='88' y='117' font-size='9' text-anchor='middle' fill='#1a2b45'>20 cm</text><circle cx='125' cy='70' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='125' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>240 N</text><line x1='52' y1='100' x2='285' y2='100' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='220' y='117' font-size='9' text-anchor='middle' fill='#1a2b45'>80 cm</text><circle cx='285' cy='70' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='285' y='55' font-size='9' text-anchor='middle' fill='#1a2b45'>F=?</text></svg>","steps":[{"t":"Kuvveti bul","a":"F = 60 N","d":"F·80 = 240·20 ⇒ F = 4800/80 = 60 N."},{"t":"Kazanç","a":"4 kat","d":"Kazanç = 240/60 = 4; ikinci tür olduğu için 1'den büyüktür."},{"t":"Kuvvetin yolu","a":"20 cm","d":"Kollar oranı 80/20 = 4 olduğundan kuvvet ucu yükün 4 katı yol alır: 4·5 = 20 cm."}],"ans":"Gereken kuvvet F = 60 N, kuvvet kazancı 4 kattır; yük 5 cm kalkarken kuvvet ucu 20 cm yol alır (kuvvetten kazanılan yoldan kaybedilir)."},{"q":"Eş kollu bir terazi birinci tür kaldıraçtır ama kuvvet kazancı sağlamaz. Bu nasıl mümkündür ve terazinin amacı nedir?","steps":[{"t":"Kollara bak","a":"eşit kollar","d":"Eş kollu terazide destek tam ortada olup kuvvet kolu = yük kolu."},{"t":"Kazancı belirle","a":"kazanç = 1","d":"Kollar eşit olduğundan kuvvet kazancı 1'dir; ne kuvvetten ne yoldan kazanç olur."},{"t":"Amacı","a":"kütle karşılaştırma","d":"Terazinin amacı kuvvet kazandırmak değil, iki kefedeki ağırlıkların momentlerini eşitleyerek kütle ölçmektir."}],"ans":"Eş kollu terazi birinci tür kaldıraçtır ama kolları eşit olduğu için kuvvet kazancı 1'dir; amacı kuvvet kazandırmak değil, momentleri eşitleyerek kütle/ağırlık karşılaştırmasıdır."},{"q":"Şekilde sol kolda 50 N (desteğe 40 cm), sağ kolda 80 N (desteğe x cm) bulunan birinci tür kaldıraç dengededir. Bilinmeyen uzaklığı (x) bulunuz.","fig":"<svg viewBox='0 0 320 165'><line x1='25' y1='90' x2='305' y2='90' stroke='#1a2b45' stroke-width='5'/><polygon points='160,90 145,120 175,120' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='138' font-size='10' text-anchor='middle' fill='#1a2b45'>Destek</text><line x1='55' y1='90' x2='160' y2='90' stroke='#4aa3df' stroke-width='2' stroke-dasharray='3 3'/><text x='105' y='82' font-size='9' text-anchor='middle' fill='#1a2b45'>40 cm</text><circle cx='55' cy='74' r='11' fill='#4aa3df' stroke='#1a2b45'/><text x='55' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>50 N</text><line x1='160' y1='90' x2='275' y2='90' stroke='#e0552b' stroke-width='2' stroke-dasharray='3 3'/><text x='220' y='82' font-size='9' text-anchor='middle' fill='#1a2b45'>x</text><circle cx='275' cy='74' r='11' fill='#e0552b' stroke='#1a2b45'/><text x='275' y='59' font-size='9' text-anchor='middle' fill='#1a2b45'>80 N</text></svg>","steps":[{"t":"Moment dengesi","a":"50·40 = 80·x","d":"Destek etrafında momentler eşit: sol moment = sağ moment."},{"t":"Hesapla","a":"2000 = 80x","d":"50·40 = 2000; 80·x = 2000."},{"t":"x'i çöz","a":"x = 25 cm","d":"x = 2000/80 = 25 cm."}],"ans":"Moment dengesinden 50·40 = 80·x ⇒ x = 2000/80 = 25 cm bulunur; ağır yük desteğe daha yakın olduğu için kısa kolda dengelenir."},{"q":"İnsan ön kolu (dirsek–pazu kası–eldeki yük) hangi tür kaldıraçtır ve bu yapı neden kuvvetten kayıp pahasına hız/yol kazandırır?","steps":[{"t":"Bileşenleri yerleştir","a":"Kuvvet ortada → 3. tür","d":"Destek dirsekte, yük elde, kas kuvveti ikisinin arasında uygulanır; bu 3. tür kaldıraçtır."},{"t":"Sonucu yorumla","a":"Kuvvet kolu kısa","d":"Kuvvet kolu yük kolundan kısa olduğundan kas büyük kuvvet uygular; karşılığında el küçük kas kısalmasıyla büyük yol ve hız kazanır."}],"ans":"3. tür kaldıraç; kuvvet kolu kısa olduğundan kuvvetten kayıp, yoldan ve hızdan kazanç sağlar"}]}},"palanga":{"ilkokul":{"kolay":[{"q":"Şekildeki gibi birkaç makaranın birleştiği düzeneğe ne ad verilir?","fig":"<svg viewBox='0 0 320 200'><line x1='40' y1='20' x2='280' y2='20' stroke='#1a2b45' stroke-width='4'/><circle cx='120' cy='45' r='20' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='200' cy='45' r='20' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='120' r='20' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='100' y1='45' x2='100' y2='120' stroke='#e0552b' stroke-width='2'/><line x1='100' y1='120' x2='140' y2='120' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='120' x2='220' y2='120' stroke='#e0552b' stroke-width='2'/><line x1='220' y1='120' x2='220' y2='45' stroke='#e0552b' stroke-width='2'/><line x1='220' y1='45' x2='240' y2='80' stroke='#e0552b' stroke-width='2'/><rect x='145' y='150' width='30' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='170' font-size='11' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"Düzeneğe bak","a":"birden çok makara","d":"Birden fazla makaranın iple birleşmesiyle oluşan düzenektir."},{"t":"Adını söyle","a":"palanga","d":"Bu düzeneğe palanga denir, ağır yükleri kolayca kaldırmaya yarar."}],"ans":"Bu düzeneğe palanga denir."},{"q":"Bir kova suyu tek başına çekmek mi, yoksa palanga kullanmak mı daha kolaydır?","fig":"<svg viewBox='0 0 320 200'><line x1='30' y1='18' x2='160' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='70' cy='40' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='110' cy='110' r='18' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='52' y1='40' x2='52' y2='110' stroke='#e0552b' stroke-width='2'/><line x1='52' y1='110' x2='92' y2='110' stroke='#e0552b' stroke-width='2'/><line x1='128' y1='110' x2='128' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='128' y1='40' x2='140' y2='70' stroke='#e0552b' stroke-width='2'/><rect x='95' y='135' width='30' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='110' y='154' font-size='10' text-anchor='middle' fill='#fff'>Kova</text><text x='220' y='100' font-size='12' text-anchor='middle' fill='#1a2b45'>az kuvvet</text></svg>","steps":[{"t":"Palanga ne yapar","a":"yükü böler","d":"Palanga, yükü birkaç ipe paylaştırarak elimize binen yükü azaltır."},{"t":"Karşılaştır","a":"palanga kolay","d":"Bu yüzden palangayla çekmek tek başına çekmekten daha kolaydır."}],"ans":"Palanga kullanmak daha kolaydır, çünkü daha az kuvvet harcarız."},{"q":"Palanga bize hangi konuda yardım eder: daha az kuvvetle kaldırmak mı, daha çok kuvvet harcamak mı?","steps":[{"t":"Palanganın işi","a":"kolaylaştırmak","d":"Palanga, ağır bir yükü daha küçük bir kuvvetle kaldırmamızı sağlar."},{"t":"Sonuç","a":"az kuvvet","d":"Yani palanga sayesinde daha az kuvvetle kaldırırız."}],"ans":"Palanga, daha az kuvvetle kaldırmamızı sağlar."},{"q":"Şekildeki palangada yükü taşıyan kaç tane ip kolu var?","fig":"<svg viewBox='0 0 320 200'><line x1='60' y1='18' x2='260' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='130' cy='42' r='20' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='120' r='22' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='138' y1='120' x2='138' y2='42' stroke='#e0552b' stroke-width='3'/><text x='124' y='85' font-size='12' text-anchor='middle' fill='#e0552b'>1</text><line x1='182' y1='120' x2='182' y2='42' stroke='#e0552b' stroke-width='3'/><text x='196' y='85' font-size='12' text-anchor='middle' fill='#e0552b'>2</text><line x1='182' y1='42' x2='210' y2='80' stroke='#e0552b' stroke-width='2'/><rect x='145' y='150' width='30' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='170' font-size='11' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"İp kollarını say","a":"hareketli makaraya bak","d":"Yükü tutan hareketli makaraya bağlı yukarı giden ipleri sayarız."},{"t":"Sonuç","a":"2 kol","d":"Şekilde yükü taşıyan iki ip kolu vardır."}],"ans":"Şekildeki palangada yükü taşıyan 2 ip kolu vardır."},{"q":"Tavana asılı duran ve hiç hareket etmeyen makaraya ne ad verilir?","fig":"<svg viewBox='0 0 320 180'><line x1='80' y1='25' x2='240' y2='25' stroke='#1a2b45' stroke-width='4'/><circle cx='160' cy='55' r='24' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='160' y1='25' x2='160' y2='40' stroke='#1a2b45' stroke-width='2'/><line x1='136' y1='55' x2='136' y2='140' stroke='#e0552b' stroke-width='2'/><line x1='184' y1='55' x2='184' y2='110' stroke='#e0552b' stroke-width='2'/><rect x='121' y='140' width='30' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='136' y='159' font-size='10' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"Yerine bak","a":"sabit duruyor","d":"Tavana bağlı, yerinden oynamayan bir makaradır."},{"t":"Adını söyle","a":"sabit makara","d":"Yerinden hareket etmeyen makaraya sabit makara denir."}],"ans":"Yerinden oynamayan bu makaraya sabit makara denir."}],"zor":[{"q":"Şekildeki palangada yük 1 sabit, 1 hareketli makarayla taşınıyor. Bu düzenek hangi iki çeşit makaradan oluşur?","fig":"<svg viewBox='0 0 320 210'><line x1='60' y1='18' x2='260' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='120' cy='42' r='20' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><text x='120' y='46' font-size='9' text-anchor='middle' fill='#fff'>sabit</text><circle cx='170' cy='125' r='22' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><text x='170' y='129' font-size='9' text-anchor='middle' fill='#1a2b45'>hare.</text><line x1='148' y1='125' x2='148' y2='25' stroke='#e0552b' stroke-width='2'/><line x1='192' y1='125' x2='192' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='100' y1='42' x2='100' y2='110' stroke='#e0552b' stroke-width='2'/><line x1='100' y1='110' x2='90' y2='130' stroke='#e0552b' stroke-width='2'/><rect x='155' y='155' width='30' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='170' y='175' font-size='11' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"Üstteki makara","a":"sabit","d":"Tavana bağlı, yerinden oynamayan makara sabit makaradır."},{"t":"Alttaki makara","a":"hareketli","d":"Yükle birlikte yukarı aşağı hareket eden makara hareketli makaradır."}],"ans":"Palanga, bir sabit ve bir hareketli makaradan oluşur."},{"q":"Palangada yükü taşıyan ip kolu sayısı arttıkça çekmek için harcadığımız kuvvet artar mı azalır mı?","steps":[{"t":"İp kolları ne yapar","a":"yükü paylaşır","d":"Daha fazla ip kolu, yükü daha çok parçaya bölerek her kola binen yükü azaltır."},{"t":"Sonuç","a":"kuvvet azalır","d":"İp kolu arttıkça çekmek için harcadığımız kuvvet azalır."}],"ans":"İp kolu sayısı arttıkça harcanan kuvvet azalır."},{"q":"Bir palangada yükü taşıyan 2 ip kolu var. Yük 20 kilogramsa, her ip kolu yaklaşık kaç kilogramlık yük taşır?","fig":"<svg viewBox='0 0 320 200'><line x1='70' y1='18' x2='250' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='135' cy='42' r='20' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='120' r='22' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='140' y1='120' x2='140' y2='42' stroke='#e0552b' stroke-width='3'/><text x='128' y='85' font-size='11' text-anchor='middle' fill='#e0552b'>10</text><line x1='180' y1='120' x2='180' y2='42' stroke='#e0552b' stroke-width='3'/><text x='194' y='85' font-size='11' text-anchor='middle' fill='#e0552b'>10</text><line x1='180' y1='42' x2='205' y2='75' stroke='#e0552b' stroke-width='2'/><rect x='145' y='150' width='30' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='170' font-size='10' text-anchor='middle' fill='#fff'>20 kg</text></svg>","steps":[{"t":"İp kolu sayısı","a":"2 kol","d":"Yükü taşıyan iki ip kolu vardır."},{"t":"Yükü böl","a":"20 ÷ 2","d":"Toplam yük, ip kolu sayısına bölünür: 20 kg ÷ 2."}],"ans":"Her ip kolu yaklaşık 10 kilogramlık yük taşır."},{"q":"İnşaatta ağır bir tuğla yığınını yukarı çıkarmak için işçi neden tek makara yerine palanga seçer?","steps":[{"t":"Tek makaranın işi","a":"yönü değiştirir","d":"Tek sabit makara sadece çekme yönünü değiştirir, kuvveti azaltmaz."},{"t":"Palanganın üstünlüğü","a":"kuvvet azaltır","d":"Palanga ip kollarıyla yükü paylaştırdığı için aynı yükü daha az kuvvetle çıkarır."}],"ans":"İşçi palangayı seçer, çünkü palanga aynı yükü daha az kuvvetle yukarı çıkarmayı sağlar."},{"q":"Şekildeki iki düzenekten hangisi aynı yükü daha az kuvvetle kaldırır: tek makara mı, palanga mı?","fig":"<svg viewBox='0 0 320 200'><line x1='20' y1='18' x2='120' y2='18' stroke='#1a2b45' stroke-width='3'/><circle cx='55' cy='40' r='16' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><line x1='39' y1='40' x2='39' y2='120' stroke='#e0552b' stroke-width='2'/><line x1='71' y1='40' x2='71' y2='90' stroke='#e0552b' stroke-width='2'/><rect x='25' y='120' width='28' height='26' fill='#5b6b85' stroke='#1a2b45'/><text x='55' y='175' font-size='10' text-anchor='middle' fill='#1a2b45'>Tek makara</text><line x1='190' y1='18' x2='300' y2='18' stroke='#1a2b45' stroke-width='3'/><circle cx='225' cy='40' r='16' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='250' cy='105' r='17' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='234' y1='105' x2='234' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='266' y1='105' x2='266' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='209' y1='40' x2='209' y2='90' stroke='#e0552b' stroke-width='2'/><rect x='236' y='128' width='28' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='245' y='175' font-size='10' text-anchor='middle' fill='#1a2b45'>Palanga</text></svg>","steps":[{"t":"Tek makara","a":"kuvvet eşit","d":"Tek sabit makarada çekme kuvveti yüke eşittir, kazanç yoktur."},{"t":"Palanga","a":"kuvvet az","d":"Palangada yük iki ip koluna paylaşıldığı için daha az kuvvet gerekir."}],"ans":"Palanga aynı yükü daha az kuvvetle kaldırır."}]},"ortaokul":{"kolay":[{"q":"Şekildeki palangada yükü taşıyan ip kolu sayısı n = 4'tür. Bu palanganın kuvvetten kazancı (mekanik avantajı) kaçtır?","fig":"<svg viewBox='0 0 320 210'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='110' cy='42' r='16' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='16' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='130' cy='130' r='18' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='180' cy='130' r='18' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='112' y1='130' x2='112' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='128' y1='42' x2='128' y2='130' stroke='#e0552b' stroke-width='2'/><line x1='162' y1='130' x2='162' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='178' y1='42' x2='178' y2='130' stroke='#e0552b' stroke-width='2'/><line x1='178' y1='42' x2='205' y2='80' stroke='#e0552b' stroke-width='2'/><rect x='128' y='150' width='54' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='155' y='169' font-size='11' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"Kural","a":"avantaj = n","d":"Palangada kuvvetten kazanç, yükü taşıyan ip kolu sayısına eşittir."},{"t":"Değeri yaz","a":"n = 4","d":"İp kolu sayısı 4 olduğundan kuvvetten kazanç 4'tür."}],"ans":"Bu palanganın mekanik avantajı (kuvvetten kazancı) 4'tür."},{"q":"Yükü taşıyan 3 ip koluna sahip bir palangaya 90 N'luk yük asılıyor. Yükü dengelemek için gereken kuvvet kaç N'dur?","fig":"<svg viewBox='0 0 320 210'><line x1='60' y1='18' x2='260' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='130' cy='42' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='130' r='20' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='140' y1='130' x2='140' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='160' y1='130' x2='160' y2='18' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='130' x2='180' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='42' x2='205' y2='80' stroke='#e0552b' stroke-width='2'/><text x='225' y='90' font-size='11' fill='#e0552b'>F=?</text><rect x='145' y='158' width='30' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='178' font-size='9' text-anchor='middle' fill='#fff'>90 N</text></svg>","steps":[{"t":"Bağıntı","a":"F = Yük ÷ n","d":"Palangada kuvvet, yükün ip kolu sayısına bölünmesiyle bulunur."},{"t":"Yerine koy","a":"90 ÷ 3","d":"Yük 90 N ve ip kolu sayısı 3 yerine konur."}],"ans":"Gereken kuvvet 30 N'dur."},{"q":"Bir palangada kuvvetten kazanç n ile yükü taşıyan ip kolu sayısı arasında nasıl bir ilişki vardır?","steps":[{"t":"Tanım","a":"kazanç = ip kolu","d":"Palangada kuvvetten kazanç, yükü taşıyan ip kolu sayısına eşittir."},{"t":"Sonuç","a":"doğru orantı","d":"İp kolu sayısı arttıkça kuvvetten kazanç da aynı oranda artar."}],"ans":"Kuvvetten kazanç, yükü taşıyan ip kolu sayısına (n) eşittir."},{"q":"Şekildeki palangada yükü taşıyan ip kollarını sayarak n değerini belirleyiniz.","fig":"<svg viewBox='0 0 320 210'><line x1='60' y1='18' x2='260' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='130' cy='42' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='128' r='22' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='138' y1='128' x2='138' y2='42' stroke='#e0552b' stroke-width='3'/><text x='126' y='88' font-size='12' fill='#e0552b'>1</text><line x1='160' y1='128' x2='160' y2='18' stroke='#e0552b' stroke-width='3'/><text x='168' y='88' font-size='12' fill='#e0552b'>2</text><line x1='182' y1='128' x2='182' y2='42' stroke='#e0552b' stroke-width='3'/><text x='196' y='88' font-size='12' fill='#e0552b'>3</text><line x1='182' y1='42' x2='208' y2='78' stroke='#e0552b' stroke-width='2'/><rect x='145' y='156' width='30' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='176' font-size='10' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"İp kollarını say","a":"hareketli makaraya bağlı","d":"Hareketli makarayı yukarı çeken ip kollarını sayarız."},{"t":"Sonuç","a":"n = 3","d":"Şekilde yükü taşıyan üç ip kolu olduğundan n = 3'tür."}],"ans":"Yükü taşıyan ip kolu sayısı n = 3'tür."},{"q":"Palanga kuvvetten kazanç sağlarken bedavaya mı kazandırır, yoksa bir şeyden mi kaybederiz?","steps":[{"t":"İş korunur","a":"bedava değil","d":"Palanga kuvveti azaltır ama yaptığımız iş aynı kalır, bedava kazanç yoktur."},{"t":"Kaybedilen","a":"yoldan kaybederiz","d":"Daha az kuvvetle çekeriz ama ipi daha uzun çekmemiz gerekir, yani yoldan kaybederiz."}],"ans":"Palanga kuvvetten kazandırır ama aynı oranda yoldan kaybettirir; bedava kazanç yoktur."}],"zor":[{"q":"Şekildeki palangada yük 240 N ve yükü taşıyan ip kolu sayısı 4'tür. Gereken çekme kuvvetini hesaplayınız.","fig":"<svg viewBox='0 0 320 210'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='110' cy='42' r='15' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='15' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='125' cy='130' r='17' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='175' cy='130' r='17' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='110' y1='130' x2='110' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='140' y1='42' x2='140' y2='130' stroke='#e0552b' stroke-width='2'/><line x1='160' y1='130' x2='160' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='190' y1='42' x2='190' y2='130' stroke='#e0552b' stroke-width='2'/><line x1='190' y1='42' x2='215' y2='80' stroke='#e0552b' stroke-width='2'/><text x='232' y='92' font-size='11' fill='#e0552b'>F=?</text><rect x='120' y='150' width='60' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='169' font-size='10' text-anchor='middle' fill='#fff'>240 N</text></svg>","steps":[{"t":"Bağıntı","a":"F = Yük ÷ n","d":"Çekme kuvveti, yükün ip kolu sayısına bölünmesiyle bulunur."},{"t":"Yerine koy","a":"240 ÷ 4","d":"Yük 240 N ve ip kolu sayısı 4 yerine konur."},{"t":"Sonuç","a":"60 N","d":"Bölme sonucu 60 N bulunur."}],"ans":"Gereken çekme kuvveti 60 N'dur."},{"q":"Bir palangada 50 N kuvvetle 300 N'luk yük dengeleniyor. Yükü taşıyan ip kolu sayısını bulunuz.","steps":[{"t":"Bağıntıyı düzenle","a":"n = Yük ÷ F","d":"İp kolu sayısı, yükün uygulanan kuvvete bölünmesiyle bulunur."},{"t":"Yerine koy","a":"300 ÷ 50","d":"Yük 300 N ve kuvvet 50 N yerine konur."},{"t":"Sonuç","a":"6","d":"Bölme sonucu n = 6 bulunur."}],"ans":"Yükü taşıyan ip kolu sayısı 6'dır."},{"q":"Yükü taşıyan 3 ip kollu bir palangada yükü 1,5 metre yukarı kaldırmak için ipin kaç metresini çekmemiz gerekir?","fig":"<svg viewBox='0 0 320 210'><line x1='60' y1='18' x2='260' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='130' cy='42' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='125' r='20' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='140' y1='125' x2='140' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='160' y1='125' x2='160' y2='18' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='125' x2='180' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='42' x2='205' y2='78' stroke='#e0552b' stroke-width='2'/><line x1='150' y1='148' x2='150' y2='178' stroke='#1a2b45' stroke-width='1'/><text x='118' y='168' font-size='10' fill='#1a2b45'>1,5 m</text><rect x='145' y='150' width='30' height='28' fill='#5b6b85' stroke='#1a2b45'/></svg>","steps":[{"t":"Bağıntı","a":"ip = n × yol","d":"Çekilen ip uzunluğu, ip kolu sayısı ile yükün çıktığı yolun çarpımıdır."},{"t":"Yerine koy","a":"3 × 1,5","d":"İp kolu sayısı 3 ve yol 1,5 m yerine konur."},{"t":"Sonuç","a":"4,5 m","d":"Çarpım sonucu 4,5 m bulunur."}],"ans":"İpin 4,5 metresini çekmemiz gerekir."},{"q":"Bir palangada kuvvet kazancı 5 ise, aynı palangada ipten çekilen yol yüke göre kaç katı olur?","steps":[{"t":"Altın kural","a":"kuvvetten kazanç = yoldan kayıp","d":"Bir basit makinede kuvvetten kazanç ne kadarsa yoldan kayıp da o kadardır."},{"t":"Sonuç","a":"5 katı","d":"Kuvvet kazancı 5 ise çekilen ip, yükün çıktığı yolun 5 katıdır."}],"ans":"İpten çekilen yol, yükün çıktığı yolun 5 katı olur."},{"q":"Şekildeki palangada yükü taşıyan ip kollarını sayıp, yük 400 N ise gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 210'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='115' cy='42' r='15' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='165' cy='42' r='15' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='130' cy='130' r='16' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='175' cy='130' r='16' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='114' y1='130' x2='114' y2='42' stroke='#e0552b' stroke-width='2'/><text x='104' y='90' font-size='10' fill='#e0552b'>1</text><line x1='146' y1='42' x2='146' y2='130' stroke='#e0552b' stroke-width='2'/><text x='150' y='90' font-size='10' fill='#e0552b'>2</text><line x1='159' y1='130' x2='159' y2='42' stroke='#e0552b' stroke-width='2'/><text x='163' y='90' font-size='10' fill='#e0552b'>3</text><line x1='191' y1='42' x2='191' y2='130' stroke='#e0552b' stroke-width='2'/><text x='195' y='90' font-size='10' fill='#e0552b'>4</text><line x1='191' y1='42' x2='215' y2='78' stroke='#e0552b' stroke-width='2'/><rect x='124' y='150' width='58' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='153' y='169' font-size='10' text-anchor='middle' fill='#fff'>400 N</text></svg>","steps":[{"t":"İp kollarını say","a":"n = 4","d":"Hareketli makaraları taşıyan dört ip kolu vardır."},{"t":"Kuvveti hesapla","a":"400 ÷ 4","d":"Kuvvet = Yük ÷ n = 400 N ÷ 4'tür."},{"t":"Sonuç","a":"100 N","d":"Bölme sonucu 100 N bulunur."}],"ans":"Yükü taşıyan ip kolu 4 olduğundan gereken kuvvet 100 N'dur."}]},"lise":{"kolay":[{"q":"İdeal bir palangada kuvvetten kazanç (mekanik avantaj) hangi büyüklüğe eşittir?","steps":[{"t":"Tanım","a":"MA = Yük ÷ F","d":"Mekanik avantaj, yükün uygulanan kuvvete oranıdır."},{"t":"Palangada karşılığı","a":"MA = n","d":"İdeal palangada bu oran, yükü taşıyan ip kolu sayısı n'ye eşittir."}],"ans":"İdeal palangada kuvvetten kazanç, yükü taşıyan ip kolu sayısı n'ye eşittir."},{"q":"Yükü taşıyan ip kolu sayısı 5 olan ideal bir palangaya 500 N yük asılıyor. Dengede tutmak için gereken kuvveti hesaplayınız.","fig":"<svg viewBox='0 0 320 210'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='115' cy='40' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='130' cy='128' r='15' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='172' cy='128' r='15' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='116' y1='128' x2='116' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='144' y1='40' x2='144' y2='128' stroke='#e0552b' stroke-width='2'/><line x1='158' y1='128' x2='158' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='174' y1='40' x2='174' y2='128' stroke='#e0552b' stroke-width='2'/><line x1='187' y1='128' x2='187' y2='18' stroke='#e0552b' stroke-width='2'/><text x='220' y='90' font-size='11' fill='#e0552b'>F=?</text><rect x='123' y='148' width='56' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='151' y='167' font-size='10' text-anchor='middle' fill='#fff'>500 N</text></svg>","steps":[{"t":"Bağıntı","a":"F = Yük ÷ n","d":"Kuvvet, yükün ip kolu sayısına bölünmesiyle bulunur."},{"t":"Yerine koy","a":"500 ÷ 5","d":"Yük 500 N, ip kolu sayısı 5 yerine konur."},{"t":"Sonuç","a":"100 N","d":"Bölme sonucu 100 N bulunur."}],"ans":"Gereken kuvvet 100 N'dur."},{"q":"İdeal palangada kuvvetten kazanç ile yoldan kayıp arasında nasıl bir ilişki vardır?","steps":[{"t":"İşin korunumu","a":"giriş işi = çıkış işi","d":"Sürtünmesiz bir basit makinede kuvvetin yaptığı iş, yüke aktarılan işe eşittir."},{"t":"Sonuç","a":"eşit ve ters","d":"Bu yüzden kuvvetten kazanç n ise, yoldan kayıp da n katıdır."}],"ans":"İdeal palangada kuvvetten kazanç n iken yoldan kayıp da n katıdır; biri kadar kazanılan diğerinden kaybedilir."},{"q":"Yükü taşıyan 4 ip kollu bir palangada yük 0,5 m yükseliyor. Serbest ucundan çekilen ip uzunluğunu bulunuz.","fig":"<svg viewBox='0 0 320 210'><line x1='60' y1='18' x2='260' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='120' cy='40' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='165' cy='40' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='135' cy='125' r='15' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='178' cy='125' r='15' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='121' y1='125' x2='121' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='149' y1='40' x2='149' y2='125' stroke='#e0552b' stroke-width='2'/><line x1='164' y1='125' x2='164' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='40' x2='180' y2='125' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='40' x2='205' y2='78' stroke='#e0552b' stroke-width='2'/><text x='150' y='168' font-size='10' fill='#1a2b45'>0,5 m</text><rect x='130' y='145' width='56' height='26' fill='#5b6b85' stroke='#1a2b45'/></svg>","steps":[{"t":"Bağıntı","a":"ip = n × h","d":"Çekilen ip uzunluğu, ip kolu sayısı ile yükün yükseldiği yolun çarpımıdır."},{"t":"Yerine koy","a":"4 × 0,5","d":"İp kolu sayısı 4 ve yol 0,5 m yerine konur."},{"t":"Sonuç","a":"2 m","d":"Çarpım sonucu 2 m bulunur."}],"ans":"Serbest uçtan çekilen ip uzunluğu 2 metredir."},{"q":"İdeal bir basit makinenin verimi neden %100, gerçek palangada ise %100'den küçüktür?","steps":[{"t":"İdeal durum","a":"sürtünme yok","d":"İdeal makinede sürtünme ve makara ağırlığı yoktur, tüm giriş işi yüke aktarılır."},{"t":"Gerçek durum","a":"kayıplar var","d":"Gerçek palangada sürtünme ve makaraların ağırlığı bir miktar işi tükettiği için verim %100'ün altındadır."}],"ans":"İdeal palangada kayıp olmadığından verim %100, gerçek palangada sürtünme ve makara ağırlığı nedeniyle %100'den küçüktür."},{"q":"Şekildeki palangada yükü taşıyan ip kollarını sayarak mekanik avantajı belirleyiniz.","fig":"<svg viewBox='0 0 320 210'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='115' cy='40' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='162' cy='40' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='130' cy='128' r='15' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='172' cy='128' r='15' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='116' y1='128' x2='116' y2='40' stroke='#e0552b' stroke-width='2'/><text x='106' y='88' font-size='10' fill='#e0552b'>1</text><line x1='144' y1='40' x2='144' y2='128' stroke='#e0552b' stroke-width='2'/><text x='148' y='88' font-size='10' fill='#e0552b'>2</text><line x1='158' y1='128' x2='158' y2='40' stroke='#e0552b' stroke-width='2'/><text x='162' y='88' font-size='10' fill='#e0552b'>3</text><line x1='174' y1='40' x2='174' y2='128' stroke='#e0552b' stroke-width='2'/><text x='178' y='88' font-size='10' fill='#e0552b'>4</text><line x1='187' y1='128' x2='187' y2='18' stroke='#e0552b' stroke-width='2'/><rect x='123' y='148' width='56' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='151' y='167' font-size='10' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"İp kollarını say","a":"n = 5","d":"İki hareketli makarayı taşıyan ve dengeleyen toplam ip kolu sayısı 5'tir."},{"t":"Avantajı yaz","a":"MA = n = 5","d":"İdeal palangada mekanik avantaj, ip kolu sayısına eşittir."}],"ans":"Mekanik avantaj 5'tir."},{"q":"İdeal palangada uygulanan kuvvetin yaptığı iş ile yüke aktarılan iş niçin birbirine eşittir?","steps":[{"t":"Giriş işi","a":"W = F × (n·h)","d":"Kuvvet F, n·h kadar ip çekildiğinden giriş işi F çarpı n·h'tir."},{"t":"Çıkış işi","a":"W = (n·F) × h","d":"Yük n·F olup h kadar yükseldiğinden çıkış işi de n·F çarpı h'tir."}],"ans":"İki ifade de n·F·h'ye eşit olduğundan, sürtünmesiz palangada giriş işi yüke aktarılan işe eşittir."},{"q":"Bir palangada 300 N yük 75 N kuvvetle dengeleniyor. Yükü taşıyan ip kolu sayısını ve mekanik avantajı bulunuz.","steps":[{"t":"İp kolu sayısı","a":"n = Yük ÷ F","d":"İp kolu sayısı, yükün uygulanan kuvvete oranıdır: 300 ÷ 75."},{"t":"Hesapla","a":"n = 4","d":"Bölme sonucu n = 4 bulunur."},{"t":"Mekanik avantaj","a":"MA = n = 4","d":"İdeal palangada mekanik avantaj ip kolu sayısına eşit olduğundan MA = 4'tür."}],"ans":"İp kolu sayısı 4, mekanik avantaj da 4'tür."},{"q":"Yükü taşıyan ip kolu sayısı artarken kuvvetten kazanç artar; bunun bedeli nedir?","steps":[{"t":"Kazanç","a":"kuvvet azalır","d":"İp kolu sayısı n arttıkça gereken kuvvet F = Yük ÷ n ile azalır."},{"t":"Bedel","a":"yol artar","d":"Aynı oranda, çekilmesi gereken ip uzunluğu (n × h) artar; daha uzun yol çekilir."}],"ans":"Kuvvetten kazanç arttıkça aynı oranda yoldan kaybedilir; daha uzun ip çekmek gerekir."},{"q":"İdeal palangada yük 600 N, ip kolu sayısı 6 ise hem kuvveti hem de yükü 1 m kaldırmak için çekilecek ipi bulunuz.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='120' cy='40' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='165' cy='40' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='130' cy='120' r='14' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='170' cy='120' r='14' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='117' y1='120' x2='117' y2='40' stroke='#e0552b' stroke-width='1.5'/><line x1='143' y1='40' x2='143' y2='120' stroke='#e0552b' stroke-width='1.5'/><line x1='157' y1='120' x2='157' y2='40' stroke='#e0552b' stroke-width='1.5'/><line x1='171' y1='40' x2='171' y2='120' stroke='#e0552b' stroke-width='1.5'/><line x1='183' y1='120' x2='183' y2='40' stroke='#e0552b' stroke-width='1.5'/><line x1='183' y1='40' x2='205' y2='72' stroke='#e0552b' stroke-width='1.5'/><rect x='122' y='140' width='56' height='26' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='158' font-size='10' text-anchor='middle' fill='#fff'>600 N</text></svg>","steps":[{"t":"Kuvveti bul","a":"600 ÷ 6 = 100 N","d":"Kuvvet, yükün ip kolu sayısına bölünmesiyle 100 N bulunur."},{"t":"İpi bul","a":"6 × 1 m","d":"Çekilecek ip = ip kolu sayısı × yol = 6 × 1 m'dir."},{"t":"Sonuç","a":"6 m","d":"Yükü 1 m kaldırmak için 6 m ip çekilir."}],"ans":"Gereken kuvvet 100 N, çekilecek ip uzunluğu 6 metredir."},{"q":"Bir palangada mekanik avantaj 3 ise, yükü 2 m kaldırmak için ipin kaç metresi çekilir?","steps":[{"t":"İlişki","a":"ip = MA × h","d":"Çekilen ip, mekanik avantaj ile yükün çıktığı yolun çarpımıdır."},{"t":"Yerine koy","a":"3 × 2","d":"MA = 3 ve yol 2 m yerine konur."}],"ans":"İpin 6 metresi çekilir."},{"q":"Sürtünme nedeniyle bir palangada uygulanan gerçek kuvvet, ideal kuvvetten büyük müdür küçük müdür? Niçin?","steps":[{"t":"İdeal kuvvet","a":"F = Yük ÷ n","d":"Sürtünme yokken yalnızca yükü dengelemek için bu kuvvet yeterlidir."},{"t":"Gerçek durum","a":"daha büyük","d":"Sürtünme ve makara ağırlığını da yenmek gerektiğinden gerçek kuvvet ideal kuvvetten büyüktür."}],"ans":"Gerçek kuvvet, ideal kuvvetten büyüktür; çünkü sürtünme ve makara ağırlığı da yenilmelidir."},{"q":"Yükü taşıyan 2 ip kollu bir palangada 80 N kuvvet uygulanıyor. Kaldırılabilecek ideal yükü bulunuz.","fig":"<svg viewBox='0 0 320 200'><line x1='70' y1='18' x2='250' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='135' cy='42' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='120' r='20' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='140' y1='120' x2='140' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='120' x2='180' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='42' x2='205' y2='78' stroke='#e0552b' stroke-width='2'/><text x='222' y='90' font-size='11' fill='#e0552b'>80 N</text><rect x='145' y='148' width='30' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='167' font-size='9' text-anchor='middle' fill='#fff'>Yük=?</text></svg>","steps":[{"t":"Bağıntı","a":"Yük = F × n","d":"Kaldırılabilecek yük, uygulanan kuvvet ile ip kolu sayısının çarpımıdır."},{"t":"Yerine koy","a":"80 × 2","d":"Kuvvet 80 N ve ip kolu sayısı 2 yerine konur."}],"ans":"İdeal olarak kaldırılabilecek yük 160 N'dur."},{"q":"İdeal palangada verim %100 iken aynı palanga gerçekte verimini hangi etkenler düşürür?","steps":[{"t":"Sürtünme","a":"ısıya dönüşür","d":"Makara milindeki ve ip ile makara arasındaki sürtünme, işin bir kısmını ısıya dönüştürür."},{"t":"Makara ağırlığı","a":"ek iş","d":"Hareketli makaraların kendi ağırlığını da kaldırmak fazladan iş gerektirir."}],"ans":"Gerçek palangada verimi sürtünme ve hareketli makaraların ağırlığı düşürür."},{"q":"Yükü taşıyan ip kolu sayısı 4 olan bir palanga sisteminde mekanik avantaj kaçtır ve 600 N'luk yük için gereken ideal kuvvet nedir?","steps":[{"t":"Mekanik avantaj","a":"MA = n = 4","d":"Palangada yükü taşıyan ip kolu sayısı mekanik avantaja eşittir."},{"t":"Kuvveti bul","a":"150 N","d":"F = Yük/n = 600/4 = 150 N (ideal, sürtünmesiz)."}],"ans":"Mekanik avantaj 4; gereken ideal kuvvet 150 N"}],"zor":[{"q":"Yükü taşıyan 4 ip kollu ideal bir palangada 1200 N'luk yük 2 m yükseltiliyor. Uygulanan kuvveti, çekilen ipi ve yapılan işi hesaplayınız.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='115' cy='40' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='162' cy='40' r='14' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='130' cy='120' r='15' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='172' cy='120' r='15' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='116' y1='120' x2='116' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='144' y1='40' x2='144' y2='120' stroke='#e0552b' stroke-width='2'/><line x1='158' y1='120' x2='158' y2='40' stroke='#e0552b' stroke-width='2'/><line x1='190' y1='40' x2='190' y2='120' stroke='#e0552b' stroke-width='2'/><line x1='190' y1='40' x2='212' y2='74' stroke='#e0552b' stroke-width='2'/><text x='150' y='162' font-size='10' fill='#1a2b45'>h=2 m</text><rect x='120' y='142' width='60' height='26' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='160' font-size='10' text-anchor='middle' fill='#fff'>1200 N</text></svg>","steps":[{"t":"Kuvveti bul","a":"1200 ÷ 4 = 300 N","d":"Kuvvet = Yük ÷ n = 1200 N ÷ 4 = 300 N'dur."},{"t":"İpi bul","a":"4 × 2 = 8 m","d":"Çekilen ip = n × h = 4 × 2 = 8 m'dir."},{"t":"İşi bul","a":"300 × 8","d":"İş = kuvvet × çekilen ip = 300 N × 8 m = 2400 J'dür (yük işi 1200 × 2 = 2400 J)."}],"ans":"Kuvvet 300 N, çekilen ip 8 m, yapılan iş 2400 J'dür."},{"q":"Gerçek bir palangada 250 N'luk yük 100 N kuvvetle, yükü taşıyan ip kolu sayısı 3 ile kaldırılıyor. Bu palanganın verimini hesaplayınız.","fig":"<svg viewBox='0 0 320 200'><line x1='60' y1='18' x2='260' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='130' cy='42' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='120' r='20' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='140' y1='120' x2='140' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='160' y1='120' x2='160' y2='18' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='120' x2='180' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='42' x2='205' y2='78' stroke='#e0552b' stroke-width='2'/><text x='222' y='90' font-size='11' fill='#e0552b'>100 N</text><rect x='145' y='148' width='30' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='167' font-size='9' text-anchor='middle' fill='#fff'>250 N</text></svg>","steps":[{"t":"İdeal kuvvet","a":"250 ÷ 3 ≈ 83,3 N","d":"Sürtünmesiz halde gerekecek ideal kuvvet, yükün ip kolu sayısına bölümüdür."},{"t":"Verim bağıntısı","a":"verim = ideal F ÷ gerçek F","d":"Aynı yük için verim, ideal kuvvetin gerçek kuvvete oranıdır."},{"t":"Hesapla","a":"83,3 ÷ 100","d":"Oran 0,833 olup yüzde olarak yaklaşık %83,3'tür."}],"ans":"Palanganın verimi yaklaşık %83'tür."},{"q":"Bir palangada mekanik avantaj 5'tir. Yükü 0,8 m kaldırmak için ipin serbest ucu kaç metre çekilir ve bu ipi çeken kuvvet, yükün kaçta kaçıdır?","steps":[{"t":"Çekilen ip","a":"5 × 0,8 = 4 m","d":"Çekilen ip = MA × yol = 5 × 0,8 = 4 m'dir."},{"t":"Kuvvet oranı","a":"F = Yük ÷ 5","d":"İdeal palangada kuvvet, yükün ip kolu sayısına bölümüdür."},{"t":"Sonuç","a":"yükün 1/5'i","d":"Kuvvet yükün beşte biridir."}],"ans":"İpin 4 metresi çekilir; çeken kuvvet yükün beşte biri (1/5) kadardır."},{"q":"Şekildeki palangada yükü taşıyan ip kollarını sayıp, yük 720 N ise gereken kuvveti ve yükü 1,5 m kaldırmak için çekilecek ipi bulunuz.","fig":"<svg viewBox='0 0 320 210'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='110' cy='40' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='125' cy='128' r='14' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='170' cy='128' r='14' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='111' y1='128' x2='111' y2='40' stroke='#e0552b' stroke-width='2'/><text x='102' y='90' font-size='9' fill='#e0552b'>1</text><line x1='139' y1='40' x2='139' y2='128' stroke='#e0552b' stroke-width='2'/><text x='143' y='90' font-size='9' fill='#e0552b'>2</text><line x1='153' y1='128' x2='153' y2='40' stroke='#e0552b' stroke-width='2'/><text x='157' y='90' font-size='9' fill='#e0552b'>3</text><line x1='181' y1='40' x2='181' y2='128' stroke='#e0552b' stroke-width='2'/><text x='185' y='90' font-size='9' fill='#e0552b'>4</text><line x1='181' y1='40' x2='205' y2='74' stroke='#e0552b' stroke-width='2'/><rect x='118' y='148' width='58' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='147' y='167' font-size='10' text-anchor='middle' fill='#fff'>720 N</text></svg>","steps":[{"t":"İp kollarını say","a":"n = 4","d":"Hareketli makaraları taşıyan dört ip kolu vardır."},{"t":"Kuvveti bul","a":"720 ÷ 4 = 180 N","d":"Kuvvet = Yük ÷ n = 720 ÷ 4 = 180 N'dur."},{"t":"İpi bul","a":"4 × 1,5 = 6 m","d":"Çekilecek ip = n × yol = 4 × 1,5 = 6 m'dir."}],"ans":"Gereken kuvvet 180 N, çekilecek ip uzunluğu 6 metredir."},{"q":"Yükü taşıyan ip kolu sayısı 6 olan ideal palangaya uygulanan kuvvet 50 N'dur. Bu palangayla kaldırılabilecek en büyük yükü ve bu yükü 0,5 m kaldırmak için çekilecek ipi bulunuz.","steps":[{"t":"Yükü bul","a":"Yük = F × n","d":"Kaldırılabilecek yük, kuvvet ile ip kolu sayısının çarpımıdır: 50 × 6."},{"t":"Hesapla","a":"300 N","d":"Çarpım sonucu yük 300 N bulunur."},{"t":"İpi bul","a":"6 × 0,5 = 3 m","d":"Çekilecek ip = n × yol = 6 × 0,5 = 3 m'dir."}],"ans":"Kaldırılabilecek en büyük yük 300 N, çekilecek ip uzunluğu 3 metredir."},{"q":"Bir palangada giriş işi 1000 J, yüke aktarılan iş 850 J ölçülmüştür. Verimi ve kayıp olan işi hesaplayınız.","steps":[{"t":"Verim bağıntısı","a":"verim = çıkış ÷ giriş","d":"Verim, yüke aktarılan işin giriş işine oranıdır: 850 ÷ 1000."},{"t":"Hesapla","a":"0,85 → %85","d":"Oran 0,85 olup yüzde olarak %85'tir."},{"t":"Kaybı bul","a":"1000 − 850","d":"Kayıp iş, giriş işi ile çıkış işinin farkıdır: 150 J."}],"ans":"Palanganın verimi %85, sürtünmeyle kaybolan iş 150 J'dür."},{"q":"İki palangadan birincisinde yükü taşıyan ip kolu 3, ikincisinde 6'dır. Aynı 360 N yük için gereken kuvvetleri ve kuvvetler oranını bulunuz.","steps":[{"t":"Birinci kuvvet","a":"360 ÷ 3 = 120 N","d":"İlk palangada kuvvet, yükün 3'e bölünmesiyle 120 N'dur."},{"t":"İkinci kuvvet","a":"360 ÷ 6 = 60 N","d":"İkinci palangada kuvvet, yükün 6'ya bölünmesiyle 60 N'dur."},{"t":"Oranı bul","a":"120 ÷ 60 = 2","d":"Birinci kuvvet ikincisinin 2 katıdır."}],"ans":"Kuvvetler 120 N ve 60 N'dur; birinci palangada gereken kuvvet ikincisinin 2 katıdır."},{"q":"Hareketli makaraların kendi ağırlığı 40 N olan bir palangada yük 200 N, ip kolu sayısı 4 ise gereken gerçek kuvveti yaklaşık hesaplayınız.","steps":[{"t":"Toplam dengelenecek yük","a":"200 + 40 = 240 N","d":"Hareketli makara ağırlığı da yük gibi ip kollarınca taşınır, toplam 240 N olur."},{"t":"Kuvveti bul","a":"240 ÷ 4","d":"Toplam ağırlık, ip kolu sayısına bölünür."},{"t":"Sonuç","a":"60 N","d":"Bölme sonucu 60 N bulunur (ideal 200 ÷ 4 = 50 N'dan büyüktür)."}],"ans":"Gereken gerçek kuvvet yaklaşık 60 N'dur; makara ağırlığı kuvveti ideal değerin üzerine çıkarır."},{"q":"Şekildeki palangada yükü taşıyan ip kollarını sayıp, 100 N kuvvetle dengelenen yükü hesaplayınız.","fig":"<svg viewBox='0 0 320 210'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='115' cy='40' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='162' cy='40' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='128' cy='128' r='14' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='172' cy='128' r='14' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='114' y1='128' x2='114' y2='40' stroke='#e0552b' stroke-width='2'/><text x='105' y='88' font-size='9' fill='#e0552b'>1</text><line x1='142' y1='40' x2='142' y2='128' stroke='#e0552b' stroke-width='2'/><text x='146' y='88' font-size='9' fill='#e0552b'>2</text><line x1='158' y1='128' x2='158' y2='40' stroke='#e0552b' stroke-width='2'/><text x='162' y='88' font-size='9' fill='#e0552b'>3</text><line x1='174' y1='40' x2='174' y2='128' stroke='#e0552b' stroke-width='2'/><text x='178' y='88' font-size='9' fill='#e0552b'>4</text><line x1='187' y1='128' x2='187' y2='18' stroke='#e0552b' stroke-width='2'/><text x='192' y='88' font-size='9' fill='#e0552b'>5</text><rect x='120' y='148' width='58' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='149' y='167' font-size='10' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"İp kollarını say","a":"n = 5","d":"İki hareketli makarayı taşıyan toplam beş ip kolu vardır."},{"t":"Yükü bul","a":"Yük = F × n","d":"Yük, kuvvet ile ip kolu sayısının çarpımıdır: 100 × 5."},{"t":"Sonuç","a":"500 N","d":"Çarpım sonucu 500 N bulunur."}],"ans":"Yükü taşıyan ip kolu 5 olduğundan dengelenen yük 500 N'dur."},{"q":"Bir palangada kuvvet 75 N, yük 450 N ve yük 1,2 m kaldırılıyor. İp kolu sayısını, çekilen ipi ve giriş işini bulunuz.","steps":[{"t":"İp kolu sayısı","a":"450 ÷ 75 = 6","d":"İp kolu sayısı, yükün kuvvete oranıdır: 450 ÷ 75 = 6."},{"t":"Çekilen ip","a":"6 × 1,2 = 7,2 m","d":"Çekilen ip = n × yol = 6 × 1,2 = 7,2 m'dir."},{"t":"Giriş işi","a":"75 × 7,2","d":"Giriş işi = kuvvet × çekilen ip = 75 × 7,2 = 540 J'dür."}],"ans":"İp kolu sayısı 6, çekilen ip 7,2 m, giriş işi 540 J'dür."},{"q":"İdeal palangada yük 4 kat artırılırsa, aynı kuvveti korumak için yükü taşıyan ip kolu sayısı nasıl değişmelidir?","steps":[{"t":"Bağıntı","a":"F = Yük ÷ n","d":"Kuvvetin sabit kalması için yük ile n'nin oranı sabit kalmalıdır."},{"t":"Yük 4 katı","a":"n de 4 katı","d":"Yük 4 katına çıkarsa aynı kuvveti korumak için ip kolu sayısı da 4 katına çıkmalıdır."}],"ans":"Yükü taşıyan ip kolu sayısı da 4 katına çıkarılmalıdır."},{"q":"Yükü taşıyan ip kolu 3 olan gerçek bir palangada verim %75'tir. 600 N'luk yük için gereken gerçek kuvveti hesaplayınız.","fig":"<svg viewBox='0 0 320 200'><line x1='60' y1='18' x2='260' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='130' cy='42' r='18' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='120' r='20' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='140' y1='120' x2='140' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='160' y1='120' x2='160' y2='18' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='120' x2='180' y2='42' stroke='#e0552b' stroke-width='2'/><line x1='180' y1='42' x2='205' y2='78' stroke='#e0552b' stroke-width='2'/><text x='222' y='90' font-size='11' fill='#e0552b'>F=?</text><rect x='145' y='148' width='30' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='167' font-size='9' text-anchor='middle' fill='#fff'>600 N</text></svg>","steps":[{"t":"İdeal kuvvet","a":"600 ÷ 3 = 200 N","d":"Sürtünmesiz halde gerekecek kuvvet, yükün ip kolu sayısına bölümüdür."},{"t":"Verimi uygula","a":"gerçek F = ideal F ÷ verim","d":"Verim %75 olduğundan gerçek kuvvet, ideal kuvvetin 0,75'e bölünmesiyle bulunur."},{"t":"Sonuç","a":"200 ÷ 0,75","d":"200 N'u 0,75'e bölünce yaklaşık 266,7 N bulunur."}],"ans":"Gereken gerçek kuvvet yaklaşık 267 N'dur."},{"q":"Bir palangada yük 2 m kaldırılırken serbest uç 10 m çekiliyor. Bu palanganın mekanik avantajını ve 500 N yük için gereken kuvveti bulunuz.","steps":[{"t":"Mekanik avantaj","a":"MA = çekilen ip ÷ yol","d":"İdeal palangada MA, çekilen ip uzunluğunun yük yoluna oranıdır: 10 ÷ 2 = 5."},{"t":"Kuvveti bul","a":"500 ÷ 5","d":"Kuvvet = Yük ÷ MA = 500 ÷ 5'tir."},{"t":"Sonuç","a":"100 N","d":"Bölme sonucu 100 N bulunur."}],"ans":"Mekanik avantaj 5'tir; 500 N yük için gereken kuvvet 100 N'dur."},{"q":"Şekildeki palangada yükü taşıyan ip kollarını sayarak, ipin serbest ucu 12 m çekildiğinde yükün kaç metre yükseleceğini bulunuz.","fig":"<svg viewBox='0 0 320 210'><line x1='50' y1='18' x2='270' y2='18' stroke='#1a2b45' stroke-width='4'/><circle cx='115' cy='40' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='162' cy='40' r='13' fill='#5b6b85' stroke='#1a2b45' stroke-width='2'/><circle cx='128' cy='128' r='14' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><circle cx='172' cy='128' r='14' fill='#cfa14a' stroke='#1a2b45' stroke-width='2'/><line x1='114' y1='128' x2='114' y2='40' stroke='#e0552b' stroke-width='2'/><text x='105' y='88' font-size='9' fill='#e0552b'>1</text><line x1='142' y1='40' x2='142' y2='128' stroke='#e0552b' stroke-width='2'/><text x='146' y='88' font-size='9' fill='#e0552b'>2</text><line x1='158' y1='128' x2='158' y2='40' stroke='#e0552b' stroke-width='2'/><text x='162' y='88' font-size='9' fill='#e0552b'>3</text><line x1='174' y1='40' x2='174' y2='128' stroke='#e0552b' stroke-width='2'/><text x='178' y='88' font-size='9' fill='#e0552b'>4</text><line x1='174' y1='40' x2='200' y2='74' stroke='#e0552b' stroke-width='2'/><rect x='120' y='148' width='58' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='149' y='167' font-size='10' text-anchor='middle' fill='#fff'>Yük</text></svg>","steps":[{"t":"İp kollarını say","a":"n = 4","d":"Hareketli makaraları taşıyan dört ip kolu vardır."},{"t":"Bağıntı","a":"yol = çekilen ip ÷ n","d":"Yükün yolu, çekilen ip uzunluğunun ip kolu sayısına bölümüdür."},{"t":"Hesapla","a":"12 ÷ 4","d":"12 m'yi 4'e bölünce 3 m bulunur."}],"ans":"Yük 3 metre yükselir."},{"q":"İdeal palangada mekanik avantaj 8'dir. Yük 1600 N ve yükü 0,25 m kaldırmak isteniyor. Kuvveti, çekilen ipi ve yapılan işi (giriş = çıkış) hesaplayınız.","steps":[{"t":"Kuvveti bul","a":"1600 ÷ 8 = 200 N","d":"Kuvvet = Yük ÷ MA = 1600 ÷ 8 = 200 N'dur."},{"t":"İpi bul","a":"8 × 0,25 = 2 m","d":"Çekilen ip = MA × yol = 8 × 0,25 = 2 m'dir."},{"t":"İşi bul","a":"200 × 2 = 400 J","d":"Giriş işi = 200 × 2 = 400 J; çıkış işi = 1600 × 0,25 = 400 J olup eşittir."}],"ans":"Kuvvet 200 N, çekilen ip 2 m, yapılan iş 400 J'dür (giriş ve çıkış işi eşit)."}]}},"sabitMakara":{"ilkokul":{"kolay":[{"q":"Şekildeki kuyudan su çekme düzeneğinde, kovayı yukarı çıkarmak için ipi hangi yöne çekeriz?","fig":"<svg viewBox='0 0 320 200'><line x1='40' y1='30' x2='280' y2='30' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='45' r='18' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='45' r='3' fill='#1a2b45'/><text x='160' y='20' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='143' y1='45' x2='143' y2='150' stroke='#1a2b45' stroke-width='2'/><line x1='177' y1='45' x2='177' y2='110' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='150' width='30' height='24' fill='#4aa3df' stroke='#1a2b45'/><text x='143' y='192' font-size='11' text-anchor='middle' fill='#1a2b45'>Kova (yük)</text><polygon points='177,118 172,108 182,108' fill='#e0552b'/><line x1='177' y1='135' x2='177' y2='112' stroke='#e0552b' stroke-width='2'/><text x='220' y='128' font-size='11' fill='#e0552b'>Çekme (aşağı)</text></svg>","steps":[{"t":"Makara ne yapar","a":"yönü değiştirir","d":"Sabit makara, uyguladığımız kuvvetin yönünü değiştiren bir araçtır."},{"t":"İpi nasıl çekeriz","a":"aşağı","d":"İpi aşağı doğru çekeriz, kova ise yukarı çıkar."}],"ans":"İpi aşağı çekeriz; sabit makara yönü değiştirdiği için kova yukarı çıkar."},{"q":"Bayrak direğindeki sabit makara, bayrağı yukarı çekmemize nasıl yardım eder?","fig":"<svg viewBox='0 0 320 200'><line x1='120' y1='15' x2='120' y2='190' stroke='#1a2b45' stroke-width='4'/><circle cx='120' cy='30' r='12' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='120' cy='30' r='2' fill='#1a2b45'/><text x='180' y='25' font-size='12' fill='#1a2b45'>Sabit makara</text><polygon points='114,30 114,60 150,45' fill='#e0552b'/><text x='160' y='52' font-size='11' fill='#1a2b45'>Bayrak (yük)</text><line x1='126' y1='30' x2='126' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='126,140 121,130 131,130' fill='#e0552b'/><line x1='126' y1='160' x2='126' y2='134' stroke='#e0552b' stroke-width='2'/><text x='140' y='175' font-size='11' fill='#e0552b'>Aşağı çek</text></svg>","steps":[{"t":"Direğin tepesine çıkmadan","a":"aşağıdan çek","d":"Makara sayesinde tepeye çıkmadan, aşağıda durup ipi çekeriz."},{"t":"Kuvvetin yönü","a":"değişir","d":"Biz ipi aşağı çekeriz, bayrak yukarı çıkar."}],"ans":"Sabit makara kuvvetin yönünü değiştirir; aşağı çekeriz, bayrak yukarı çıkar."},{"q":"Sabit makara, çekmemiz gereken kuvveti azaltır mı?","steps":[{"t":"Sabit makara ne yapar","a":"sadece yön","d":"Sabit makara yalnızca kuvvetin yönünü değiştirir."},{"t":"Kuvvete etkisi","a":"azaltmaz","d":"Uyguladığımız kuvvet, yükün ağırlığına eşittir; kuvvetten kazanç yoktur."}],"ans":"Hayır, sabit makara kuvveti azaltmaz; sadece çekme yönünü değiştirir."},{"q":"Şekildeki sabit makarada 1 kutu yük asılı. Yukarı çekmek için uyguladığımız kuvvet, yükten daha mı azdır?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='145' y1='40' x2='145' y2='140' stroke='#1a2b45' stroke-width='2'/><rect x='130' y='140' width='30' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='145' y='185' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük</text><line x1='175' y1='40' x2='175' y2='130' stroke='#1a2b45' stroke-width='2'/><polygon points='175,138 170,128 180,128' fill='#e0552b'/><line x1='175' y1='150' x2='175' y2='132' stroke='#e0552b' stroke-width='2'/><text x='195' y='150' font-size='11' fill='#e0552b'>Kuvvet</text></svg>","steps":[{"t":"Kuvvet ile yükü karşılaştır","a":"eşit","d":"Sabit makarada uygulanan kuvvet, yükün ağırlığına eşittir."},{"t":"Sonuç","a":"daha az değil","d":"Kuvvetten kazanç olmadığı için kuvvet, yükten az olmaz."}],"ans":"Hayır; sabit makarada uygulanan kuvvet, yükün ağırlığına eşittir."},{"q":"Sabit makara en çok hangi işlerde işimizi kolaylaştırır?","steps":[{"t":"Sağladığı kolaylık","a":"yön değişimi","d":"Yükü yukarı kaldırmak için ipi rahat bir yönde, örneğin aşağı çekeriz."},{"t":"Örnek","a":"kuyu, bayrak","d":"Kuyudan su çekmek ve bayrak çekmek bu yüzden kolaylaşır."}],"ans":"Sabit makara, kuvvetin yönünü değiştirerek kuyudan su çekme veya bayrak çekme gibi işleri kolaylaştırır."}],"zor":[{"q":"Şekildeki sabit makarada yük 1 metre yukarı çıktığında, çektiğimiz ipten kaç metre çekmiş oluruz?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='145' y1='40' x2='145' y2='135' stroke='#1a2b45' stroke-width='2'/><rect x='130' y='135' width='30' height='26' fill='#5b6b85' stroke='#1a2b45'/><polygon points='138,128 133,118 143,118' fill='#4aa3df'/><line x1='138' y1='135' x2='138' y2='120' stroke='#4aa3df' stroke-width='2'/><text x='145' y='180' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük 1 m ↑</text><line x1='175' y1='40' x2='175' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='175,142 170,132 180,132' fill='#e0552b'/><text x='198' y='110' font-size='11' fill='#e0552b'>Çekilen ip</text></svg>","steps":[{"t":"İp boyu ile yol","a":"eşit","d":"Sabit makarada çekilen ip boyu, yükün çıktığı yola eşittir."},{"t":"Hesapla","a":"1 metre","d":"Yük 1 m çıktığı için ipten de 1 m çekmiş oluruz."}],"ans":"İpten 1 metre çekmiş oluruz; çünkü çekilen ip boyu yükün yoluna eşittir."},{"q":"Bir çocuk sabit makarayla 5 kg'lık yükü kaldırıyor. Yükü kaldırmak için uygulaması gereken kuvvet kaç kg-kuvvet kadardır?","steps":[{"t":"Sabit makarada kuvvet","a":"yüke eşit","d":"Sabit makara kuvvetten kazanç sağlamaz, kuvvet yükün ağırlığına eşittir."},{"t":"Sonuç","a":"5 kg-kuvvet","d":"Yük 5 kg olduğundan uygulanan kuvvet de 5 kg-kuvvet kadar olmalıdır."}],"ans":"Yaklaşık 5 kg-kuvvet uygulamalıdır; sabit makara kuvveti azaltmaz."},{"q":"Şekildeki bayrak direğinde bayrağı 3 metre yukarı çekmek isteyen biri, ipi kaç metre aşağı çekmelidir?","fig":"<svg viewBox='0 0 320 210'><line x1='120' y1='15' x2='120' y2='200' stroke='#1a2b45' stroke-width='4'/><circle cx='120' cy='30' r='12' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='120' cy='30' r='2' fill='#1a2b45'/><text x='175' y='24' font-size='12' fill='#1a2b45'>Sabit makara</text><polygon points='114,30 114,58 148,44' fill='#e0552b'/><text x='158' y='50' font-size='11' fill='#1a2b45'>Bayrak 3 m ↑</text><line x1='126' y1='30' x2='126' y2='160' stroke='#1a2b45' stroke-width='2'/><polygon points='126,152 121,142 131,142' fill='#e0552b'/><line x1='126' y1='172' x2='126' y2='144' stroke='#e0552b' stroke-width='2'/><text x='140' y='188' font-size='11' fill='#e0552b'>İp aşağı çekilir</text></svg>","steps":[{"t":"Çekilen ip ve yol","a":"eşit","d":"Sabit makarada çekilen ip uzunluğu, bayrağın çıktığı yola eşittir."},{"t":"Hesapla","a":"3 metre","d":"Bayrak 3 m çıkacaksa ipi de 3 m aşağı çekmek gerekir."}],"ans":"İpi 3 metre aşağı çekmelidir; çekilen ip boyu yükün yoluna eşittir."},{"q":"Sabit makara işimizi neden hafifletmez de yine de işe yarar?","steps":[{"t":"Kuvvet kazancı","a":"yok","d":"Sabit makara kuvveti azaltmaz, yükün ağırlığı kadar kuvvet uygularız."},{"t":"Sağladığı yarar","a":"yön kolaylığı","d":"Buna karşılık kuvvetin yönünü değiştirir; örneğin aşağı çekerek yukarı kaldırırız."}],"ans":"Kuvveti azaltmaz ama yönünü değiştirdiği için, çekmesi daha rahat olan bir konumda çalışmamızı sağlar."},{"q":"İki arkadaş aynı kuyudan su çekiyor; biri sabit makara kullanıyor, diğeri kovayı doğrudan elle yukarı çekiyor. Hangisi daha az kuvvet harcar?","steps":[{"t":"Sabit makaralı","a":"aynı kuvvet","d":"Sabit makara kuvveti azaltmadığı için kuvvet, kovanın ağırlığına eşittir."},{"t":"Karşılaştır","a":"kuvvet eşit","d":"İkisi de yaklaşık aynı büyüklükte kuvvet harcar; makara sadece çekme yönünü kolaylaştırır."}],"ans":"İkisi de yaklaşık aynı kuvveti harcar; sabit makara kuvveti azaltmaz, yalnızca yönü değiştirip işi rahatlatır."}]},"ortaokul":{"kolay":[{"q":"Şekildeki sabit makarada yük 60 N ağırlığındadır. Yükü dengede tutmak için uygulanması gereken kuvvet kaç N'dur?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='42' r='17' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='42' x2='144' y2='140' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='140' width='32' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='185' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük 60 N</text><line x1='176' y1='42' x2='176' y2='135' stroke='#1a2b45' stroke-width='2'/><polygon points='176,143 171,133 181,133' fill='#e0552b'/><line x1='176' y1='160' x2='176' y2='135' stroke='#e0552b' stroke-width='2'/><text x='198' y='150' font-size='11' fill='#e0552b'>F = ?</text></svg>","steps":[{"t":"Denge koşulu","a":"F = Yük","d":"Sabit makarada kuvvetten kazanç olmadığı için uygulanan kuvvet, yükün ağırlığına eşittir."},{"t":"Hesapla","a":"60 N","d":"Yük 60 N olduğundan uygulanan kuvvet de 60 N olmalıdır."}],"ans":"Uygulanması gereken kuvvet 60 N'dur; F = Yük."},{"q":"Sabit makaranın mekanik avantajı (kuvvet kazancı) kaçtır?","steps":[{"t":"Mekanik avantaj tanımı","a":"Yük / Kuvvet","d":"Mekanik avantaj, yükün uygulanan kuvvete oranıdır."},{"t":"Sabit makarada","a":"1","d":"Kuvvet yüke eşit olduğundan oran 1 çıkar."}],"ans":"Sabit makaranın mekanik avantajı 1'dir; kuvvetten kazanç sağlamaz."},{"q":"Şekildeki sabit makarada yükün ipi 80 cm yukarı çekildi. Çekme tarafındaki ipten kaç cm çekilmiştir?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='42' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='42' x2='144' y2='125' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='125' width='32' height='26' fill='#5b6b85' stroke='#1a2b45'/><polygon points='136,118 131,108 141,108' fill='#4aa3df'/><line x1='136' y1='125' x2='136' y2='110' stroke='#4aa3df' stroke-width='2'/><text x='144' y='178' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük 80 cm ↑</text><line x1='176' y1='42' x2='176' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='176,142 171,132 181,132' fill='#e0552b'/><text x='198' y='115' font-size='11' fill='#e0552b'>çekilen ip</text></svg>","steps":[{"t":"İp boyu = yol","a":"eşit","d":"Sabit makarada çekilen ip boyu, yükün aldığı yola eşittir."},{"t":"Hesapla","a":"80 cm","d":"Yük 80 cm çıktığı için çekme tarafından da 80 cm ip çekilmiştir."}],"ans":"Çekme tarafından 80 cm ip çekilmiştir; ip boyu yükün yoluna eşittir."},{"q":"Sabit makara hangi tür kaldıraca eşdeğerdir ve neden?","steps":[{"t":"Destek noktası","a":"makaranın ekseni","d":"Sabit makarada destek noktası makaranın dönme eksenidir; yük ve kuvvet kolları eşittir (makara yarıçapı kadar)."},{"t":"Karşılaştır","a":"eşit kollu kaldıraç","d":"Kuvvet ve yük kolları eşit olduğundan sabit makara eşit kollu kaldıraca eşdeğerdir."}],"ans":"Sabit makara, kuvvet ve yük kolları eşit olduğu için eşit kollu kaldıraca eşdeğerdir."},{"q":"Bir öğrenci sabit makarayla yükü kaldırırken hiç kuvvetten kazanç sağlayamıyor. Bu makara yine de neden tercih edilir?","steps":[{"t":"Sağladığı avantaj","a":"yön değişimi","d":"Sabit makara kuvvetin yönünü değiştirir; yükü yukarı çıkarmak için ipi aşağı çekmek daha rahattır."},{"t":"Sonuç","a":"kolaylık","d":"Vücut ağırlığından yararlanarak aşağı asılmak, yukarı itmekten daha kolaydır."}],"ans":"Kuvvetten kazanç sağlamaz ama kuvvetin yönünü değiştirip çekmeyi kolaylaştırdığı için tercih edilir."}],"zor":[{"q":"Şekildeki sabit makarada 120 N'luk yük dengede tutuluyor. Uygulanan kuvveti ve makaranın mekanik avantajını bulunuz.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='42' r='17' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='42' x2='144' y2='140' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='140' width='32' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='185' font-size='11' text-anchor='middle' fill='#1a2b45'>120 N</text><line x1='176' y1='42' x2='176' y2='140' stroke='#1a2b45' stroke-width='2'/><polygon points='176,148 171,138 181,138' fill='#e0552b'/><line x1='176' y1='165' x2='176' y2='140' stroke='#e0552b' stroke-width='2'/><text x='198' y='155' font-size='11' fill='#e0552b'>F = ?</text></svg>","steps":[{"t":"Kuvveti bul","a":"F = Yük","d":"Sabit makarada uygulanan kuvvet, yükün ağırlığına eşittir."},{"t":"Değeri yaz","a":"120 N","d":"Yük 120 N olduğundan kuvvet de 120 N olur."},{"t":"Mekanik avantaj","a":"120/120 = 1","d":"Mekanik avantaj = Yük ÷ Kuvvet = 120 ÷ 120 = 1'dir."}],"ans":"Uygulanan kuvvet 120 N, mekanik avantaj 1'dir."},{"q":"Sabit makarayla 40 N'luk bir yük 2,5 m yukarı kaldırılıyor. Yapılan iş kaç joule'dür?","steps":[{"t":"Kuvveti belirle","a":"40 N","d":"Sabit makarada uygulanan kuvvet yüke eşittir, yani 40 N'dur."},{"t":"İş bağıntısı","a":"W = F × yol","d":"İş, kuvvet ile alınan yolun çarpımıdır; ip boyu yola eşittir."},{"t":"Hesapla","a":"40 × 2,5","d":"40 N kuvveti 2,5 m yol ile çarparız, sonuç 100 J'dür."}],"ans":"Yapılan iş 100 joule'dür."},{"q":"Şekildeki sabit makarada yük 50 N. İpi 30 N kuvvetle çekersek yük yukarı çıkar mı?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='42' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='42' x2='144' y2='140' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='140' width='32' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='185' font-size='11' text-anchor='middle' fill='#1a2b45'>Yük 50 N</text><line x1='176' y1='42' x2='176' y2='140' stroke='#1a2b45' stroke-width='2'/><polygon points='176,148 171,138 181,138' fill='#e0552b'/><line x1='176' y1='160' x2='176' y2='140' stroke='#e0552b' stroke-width='2'/><text x='196' y='155' font-size='11' fill='#e0552b'>F = 30 N</text></svg>","steps":[{"t":"Gerekli kuvvet","a":"50 N","d":"Sabit makarada yükü kaldırmak için en az yük kadar, yani 50 N kuvvet gerekir."},{"t":"Karşılaştır","a":"30 < 50","d":"Uygulanan 30 N, gerekli 50 N'dan küçüktür."},{"t":"Sonuç","a":"çıkmaz","d":"Kuvvet yetersiz olduğu için yük yukarı çıkmaz."}],"ans":"Hayır, çıkmaz; sabit makarada yükü kaldırmak için en az yüke eşit (50 N) kuvvet gerekir."},{"q":"Sabit makarada uygulanan kuvvet 70 N ve yük 4 m kaldırılıyor. Çekme tarafından kaç metre ip çekilir ve yapılan iş kaç J'dür?","steps":[{"t":"Çekilen ip","a":"4 m","d":"Sabit makarada çekilen ip boyu yükün yoluna eşittir, yani 4 m'dir."},{"t":"İş bağıntısı","a":"W = F × yol","d":"İş, kuvvet ile yolun çarpımıdır."},{"t":"Hesapla","a":"70 × 4","d":"70 N ile 4 m çarpılır, sonuç 280 J bulunur."}],"ans":"Çekme tarafından 4 m ip çekilir; yapılan iş 280 joule'dür."},{"q":"Şekildeki düzenekte bir kişi vücut ağırlığıyla aşağı asılarak yükü kaldırıyor. Sabit makaranın bu kişiye sağladığı temel kolaylık nedir?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='150' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='150' cy='40' r='3' fill='#1a2b45'/><text x='150' y='15' font-size='11' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='134' y1='40' x2='134' y2='120' stroke='#1a2b45' stroke-width='2'/><rect x='118' y='120' width='32' height='26' fill='#5b6b85' stroke='#1a2b45'/><text x='134' y='162' font-size='10' text-anchor='middle' fill='#1a2b45'>Yük</text><line x1='166' y1='40' x2='166' y2='110' stroke='#1a2b45' stroke-width='2'/><circle cx='166' cy='122' r='10' fill='#5b6b85' stroke='#1a2b45'/><line x1='166' y1='132' x2='166' y2='160' stroke='#5b6b85' stroke-width='4'/><polygon points='166,150 161,140 171,140' fill='#e0552b'/><text x='205' y='130' font-size='10' fill='#e0552b'>aşağı asılır</text></svg>","steps":[{"t":"Kuvvet kazancı","a":"yok","d":"Mekanik avantaj 1 olduğu için kişi yine yük kadar kuvvet uygular."},{"t":"Yön avantajı","a":"vücut ağırlığı","d":"Kuvvetin yönü aşağı olduğundan kişi kendi ağırlığından yararlanarak ipe asılabilir, bu çok rahattır."}],"ans":"Kuvvetten kazanç sağlamaz ama kuvvetin yönünü aşağı çevirdiği için kişi vücut ağırlığını kullanarak yükü daha rahat kaldırır."},{"q":"İdeal (sürtünmesiz) bir sabit makarada verim kaç olur ve bunun anlamı nedir?","steps":[{"t":"Verim tanımı","a":"alınan/verilen iş","d":"Verim, makaradan alınan işin makaraya verilen işe oranıdır."},{"t":"İdeal makarada","a":"%100","d":"Sürtünme yokken kayıp olmaz; uygulanan iş, yüke aktarılan işe eşittir."},{"t":"Anlamı","a":"iş korunur","d":"Kuvvet kazancı olmasa da harcanan iş tümüyle yükü kaldırmaya gider."}],"ans":"İdeal sabit makarada verim %100'dür; harcanan iş tümüyle yükü kaldırmaya aktarılır."}]},"lise":{"kolay":[{"q":"Şekildeki sabit makarada 200 N'luk yük dengededir. Uygulanan kuvveti yazınız.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='42' r='17' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='143' y1='42' x2='143' y2='140' stroke='#1a2b45' stroke-width='2'/><rect x='127' y='140' width='32' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='143' y='185' font-size='11' text-anchor='middle' fill='#1a2b45'>200 N</text><line x1='177' y1='42' x2='177' y2='140' stroke='#1a2b45' stroke-width='2'/><polygon points='177,148 172,138 182,138' fill='#e0552b'/><line x1='177' y1='165' x2='177' y2='140' stroke='#e0552b' stroke-width='2'/><text x='199' y='155' font-size='11' fill='#e0552b'>F = ?</text></svg>","steps":[{"t":"Denge koşulu","a":"F = G","d":"Sabit makarada kuvvet, yükün ağırlığına eşittir (mekanik avantaj 1)."},{"t":"Değer","a":"200 N","d":"Yük 200 N olduğundan uygulanan kuvvet de 200 N'dur."}],"ans":"Uygulanan kuvvet 200 N'dur."},{"q":"Sabit makarada mekanik avantajın 1 olması momentlerle nasıl açıklanır?","steps":[{"t":"Moment dengesi","a":"F·r = G·r","d":"Makaranın iki yanındaki kuvvet kolları, makaranın yarıçapı r'ye eşittir."},{"t":"Sadeleştir","a":"F = G","d":"r eşit olduğundan moment dengesinden kuvvet, yüke eşit çıkar; MA = G/F = 1'dir."}],"ans":"Kuvvet ve yük kolları makara yarıçapına eşit olduğundan moment dengesinden F = G çıkar; mekanik avantaj 1'dir."},{"q":"Şekildeki sabit makarada yük 90 N kaldırılıyor. Yükü 3 m yukarı çıkarmak için ip ne kadar çekilir ve yapılan iş kaç J'dür?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='40' x2='144' y2='128' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='128' width='32' height='26' fill='#5b6b85' stroke='#1a2b45'/><polygon points='136,121 131,111 141,111' fill='#4aa3df'/><line x1='136' y1='128' x2='136' y2='113' stroke='#4aa3df' stroke-width='2'/><text x='144' y='170' font-size='11' text-anchor='middle' fill='#1a2b45'>90 N, 3 m ↑</text><line x1='176' y1='40' x2='176' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='176,142 171,132 181,132' fill='#e0552b'/><text x='197' y='110' font-size='11' fill='#e0552b'>çekilen ip</text></svg>","steps":[{"t":"Çekilen ip","a":"3 m","d":"Sabit makarada çekilen ip boyu, yükün yoluna eşittir; yani 3 m'dir."},{"t":"Kuvvet","a":"90 N","d":"Kuvvet yüke eşittir, 90 N'dur."},{"t":"İş","a":"90 × 3","d":"İş = kuvvet × yol = 90 N × 3 m = 270 J'dür."}],"ans":"İp 3 m çekilir; yapılan iş 270 joule'dür."},{"q":"Sabit makara ile hareketli makaranın kuvvet kazancı yönünden temel farkı nedir?","steps":[{"t":"Sabit makara","a":"MA = 1","d":"Sabit makarada kuvvet yüke eşittir, kuvvetten kazanç yoktur, sadece yön değişir."},{"t":"Hareketli makara","a":"MA = 2","d":"Tek hareketli makarada yükü iki ip taşıdığından kuvvet yarıya iner, kuvvet kazancı vardır."}],"ans":"Sabit makarada kuvvet kazancı yoktur (MA = 1, yalnız yön değişir); hareketli makarada ise kuvvet kazancı vardır."},{"q":"Sürtünmesiz bir sabit makarada iş korunumu nasıl ifade edilir?","steps":[{"t":"Verilen iş","a":"F × ip","d":"Uygulanan kuvvet ile çekilen ip boyunun çarpımı, verilen iştir."},{"t":"Alınan iş","a":"G × h","d":"Yükün ağırlığı ile çıktığı yükseklik çarpımı, alınan iştir."},{"t":"Korunum","a":"eşit","d":"F = G ve ip = h olduğundan F·ip = G·h; verilen iş alınan işe eşittir."}],"ans":"İdeal sabit makarada F = G ve çekilen ip = yükseklik olduğundan F·ip = G·h olur; iş korunur."},{"q":"Şekildeki sabit makarada yük 150 N. İpi 150 N'dan büyük bir kuvvetle çekersek ne olur?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='42' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='42' x2='144' y2='140' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='140' width='32' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='185' font-size='11' text-anchor='middle' fill='#1a2b45'>150 N</text><line x1='176' y1='42' x2='176' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='176,142 171,132 181,132' fill='#e0552b'/><line x1='176' y1='168' x2='176' y2='134' stroke='#e0552b' stroke-width='2'/><text x='196' y='160' font-size='11' fill='#e0552b'>F &gt; 150 N</text></svg>","steps":[{"t":"Net kuvvet","a":"yukarı","d":"Çekme kuvveti yükten büyük olunca yük tarafında net kuvvet yukarı yönde olur."},{"t":"Sonuç","a":"ivmeli çıkar","d":"Yük dengeyi aşıp ivmelenerek yukarı doğru hareket eder."}],"ans":"Yük tarafında net yukarı kuvvet doğacağı için yük ivmelenerek yukarı çıkar."},{"q":"Sabit makarada yarıçap 10 cm, yük 60 N ise yük tarafının makaraya uyguladığı moment kaç N·m'dir?","steps":[{"t":"Moment tanımı","a":"M = kuvvet × kol","d":"Moment, kuvvet ile dönme eksenine olan dik uzaklığın çarpımıdır."},{"t":"Kol uzunluğu","a":"0,10 m","d":"Yük ipi makara kenarından geçtiği için kol, yarıçapa eşittir: 10 cm = 0,10 m."},{"t":"Hesapla","a":"60 × 0,10","d":"60 N ile 0,10 m çarpılır, sonuç 6 N·m bulunur."}],"ans":"Yük tarafının uyguladığı moment 6 N·m'dir."},{"q":"Şekildeki sabit makarada ip, yükün ağırlığı kadar gerilime maruzdur. 250 N'luk yük için ipteki gerilme kaç N'dur?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='42' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='42' x2='144' y2='140' stroke='#1a2b45' stroke-width='2'/><text x='118' y='95' font-size='10' fill='#1a2b45'>T</text><rect x='128' y='140' width='32' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='185' font-size='11' text-anchor='middle' fill='#1a2b45'>250 N</text><line x1='176' y1='42' x2='176' y2='140' stroke='#1a2b45' stroke-width='2'/><text x='184' y='95' font-size='10' fill='#1a2b45'>T</text><polygon points='176,148 171,138 181,138' fill='#e0552b'/><text x='198' y='150' font-size='11' fill='#e0552b'>F</text></svg>","steps":[{"t":"Yük tarafı dengesi","a":"T = G","d":"Yük dengedeyken ipteki gerilme, yükün ağırlığına eşittir."},{"t":"Değer","a":"250 N","d":"Yük 250 N olduğundan ip boyunca gerilme 250 N'dur."}],"ans":"İpteki gerilme 250 N'dur; sabit makarada ip gerilmesi yükün ağırlığına eşittir."},{"q":"Bir kişi 80 N kuvvetle sabit makaranın ipini sabit hızla çekiyor. Yük dengelenmiş midir, açıklayınız.","steps":[{"t":"Sabit hız anlamı","a":"net kuvvet sıfır","d":"Sabit hızda hareket dengelidir, ivme yoktur, net kuvvet sıfırdır."},{"t":"Kuvvet ilişkisi","a":"F = G = 80 N","d":"Sabit makarada denge için kuvvet yüke eşit olmalıdır; yük 80 N'dur."}],"ans":"Evet dengelenmiştir; sabit hızda net kuvvet sıfır olduğundan kuvvet yüke eşittir, yük 80 N'dur."},{"q":"Şekildeki sabit makarada kuvvet ve yük kolları neden eşittir ve bu, kuvvetten kazancı nasıl belirler?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='55' r='30' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='55' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='11' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='130' y1='55' x2='160' y2='55' stroke='#e0552b' stroke-width='2'/><text x='138' y='48' font-size='10' fill='#e0552b'>r</text><line x1='160' y1='55' x2='190' y2='55' stroke='#e0552b' stroke-width='2'/><text x='176' y='48' font-size='10' fill='#e0552b'>r</text><line x1='130' y1='55' x2='130' y2='150' stroke='#1a2b45' stroke-width='2'/><rect x='116' y='150' width='28' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='130' y='192' font-size='10' text-anchor='middle' fill='#1a2b45'>Yük</text><line x1='190' y1='55' x2='190' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='190,142 185,132 195,132' fill='#e0552b'/><text x='205' y='130' font-size='10' fill='#e0552b'>F</text></svg>","steps":[{"t":"Kollar","a":"ikisi de r","d":"Hem yük ipi hem kuvvet ipi makara kenarından geçtiği için iki kol da yarıçap r kadardır."},{"t":"Moment dengesi","a":"F·r = G·r","d":"Eşit kollar moment dengesinde sadeleşir ve F = G çıkar; mekanik avantaj 1 olur."}],"ans":"Kuvvet ve yük kolları makara yarıçapı r'ye eşit olduğundan F = G olur; bu yüzden sabit makara kuvvetten kazanç sağlamaz."},{"q":"Şekildeki sabit makarada yükün hızı 0,5 m/s ile yukarı çıkıyorsa, çekilen ip ucunun hızı kaç m/s'dir?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='40' x2='144' y2='125' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='125' width='32' height='26' fill='#5b6b85' stroke='#1a2b45'/><polygon points='136,118 131,108 141,108' fill='#4aa3df'/><line x1='136' y1='125' x2='136' y2='110' stroke='#4aa3df' stroke-width='2'/><text x='144' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>v = 0,5 m/s ↑</text><line x1='176' y1='40' x2='176' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='176,142 171,132 181,132' fill='#e0552b'/><text x='197' y='110' font-size='10' fill='#e0552b'>ip ucu</text></svg>","steps":[{"t":"İp uzayan miktar","a":"eşit","d":"Sabit makarada bir taraf ne kadar inerse diğer taraf o kadar çıkar; ip uzunlukları eşit değişir."},{"t":"Hız ilişkisi","a":"v_ip = v_yük","d":"Eşit yer değiştirme aynı zamanda olduğundan ip ucunun hızı yükün hızına eşittir."}],"ans":"Çekilen ip ucunun hızı 0,5 m/s'dir; sabit makarada iki ucun hızları eşittir."},{"q":"Sabit makara, kaldıraç çeşitleri içinde hangisine karşılık gelir? Destek, yük ve kuvvet konumlarıyla açıklayınız.","steps":[{"t":"Destek noktası","a":"merkez","d":"Makaranın dönme ekseni (merkezi) destek noktası gibi davranır."},{"t":"Yük ve kuvvet","a":"iki yanda eşit kol","d":"Yük bir kenardan, kuvvet diğer kenardan etkir; ikisi de yarıçap kadar koldadır."},{"t":"Karşılık","a":"eşit kollu kaldıraç","d":"Eşit kollar nedeniyle sabit makara, destek ortada olan eşit kollu (I. tip) kaldıraca karşılık gelir."}],"ans":"Sabit makara, destek noktası ortada ve kolları eşit olan eşit kollu (birinci tip) kaldıraca karşılık gelir."},{"q":"İdeal sabit makarada uygulanan kuvvetin yaptığı iş ile yükün kazandığı potansiyel enerji arasındaki ilişki nedir?","steps":[{"t":"Yapılan iş","a":"W = F × ip","d":"Uygulanan kuvvet ile çekilen ip boyunun çarpımı, kişinin yaptığı iştir."},{"t":"Potansiyel enerji","a":"ΔE = G × h","d":"Yükün kazandığı potansiyel enerji, ağırlık ile yükselme çarpımına eşittir."},{"t":"İlişki","a":"eşit","d":"F = G, ip = h olduğundan W = ΔE; yapılan iş tümüyle potansiyel enerjiye dönüşür."}],"ans":"İdeal sabit makarada yapılan iş, yükün kazandığı potansiyel enerjiye eşittir (W = ΔE)."},{"q":"Bir vinçte sabit makara kullanmanın kuvvet açısından bir kazancı olmadığı halde, mühendisler neden sabit makara ekler?","steps":[{"t":"Kuvvet kazancı","a":"yok","d":"Sabit makara mekanik avantaj sağlamaz, kuvvet yüke eşit kalır."},{"t":"Sağladığı yarar","a":"yön / erişim","d":"Kuvvetin yönünü değiştirip çekme noktasını uygun bir konuma taşır, motoru veya işçiyi rahat yerleştirir."}],"ans":"Kuvvetten kazanç sağlamasa da kuvvetin yönünü ve uygulama noktasını uygun hâle getirdiği için sabit makara eklenir."},{"q":"Sabit bir makaradan 250 N'luk yük sabit hızla yukarı çekiliyor. Sürtünme yokken çekme kuvveti ne kadardır ve sabit makara hangi kolaylığı sağlar?","steps":[{"t":"Kuvveti belirle","a":"250 N","d":"Sabit makara kuvvetten kazanç sağlamaz; mekanik avantajı 1 olduğundan F = Yük = 250 N."},{"t":"Kolaylığı söyle","a":"Yön değiştirir","d":"Sabit makara yalnızca kuvvetin yönünü değiştirir; ipi aşağı çekerek yükü yukarı kaldırma imkânı verir."}],"ans":"250 N; sabit makara yalnızca kuvvetin yönünü değiştirir (MA = 1)"}],"zor":[{"q":"Şekildeki sabit makarada 300 N'luk yük 2 m yükseğe çıkarılıyor. Mekanik avantajı, çekilen ip boyunu ve yapılan işi bulunuz.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='40' x2='144' y2='128' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='128' width='32' height='26' fill='#5b6b85' stroke='#1a2b45'/><polygon points='136,121 131,111 141,111' fill='#4aa3df'/><line x1='136' y1='128' x2='136' y2='113' stroke='#4aa3df' stroke-width='2'/><text x='144' y='170' font-size='10' text-anchor='middle' fill='#1a2b45'>300 N, 2 m ↑</text><line x1='176' y1='40' x2='176' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='176,142 171,132 181,132' fill='#e0552b'/><text x='197' y='110' font-size='10' fill='#e0552b'>F</text></svg>","steps":[{"t":"Mekanik avantaj","a":"1","d":"Sabit makarada kuvvet yüke eşit olduğundan MA = G/F = 1'dir."},{"t":"Çekilen ip","a":"2 m","d":"Çekilen ip boyu, yükün yoluna eşittir; yani 2 m'dir."},{"t":"İş","a":"300 × 2","d":"Kuvvet 300 N, yol 2 m; iş = 300 × 2 = 600 J'dür."}],"ans":"Mekanik avantaj 1, çekilen ip boyu 2 m, yapılan iş 600 joule'dür."},{"q":"Verimi %80 olan bir sabit makarada (sürtünmeli) 100 N'luk yükü kaldırmak için uygulanması gereken kuvvet kaç N'dur?","steps":[{"t":"Verim bağıntısı","a":"η = G/F","d":"Sürtünmeli makarada verim, ideal kuvvetin gerçek kuvvete oranıdır; G yük, F uygulanan kuvvettir."},{"t":"Düzenle","a":"F = G/η","d":"Kuvvet = yük ÷ verim olarak yazılır."},{"t":"Hesapla","a":"100 ÷ 0,80","d":"100 N'u 0,80'e böleriz, sonuç 125 N bulunur."}],"ans":"Uygulanması gereken kuvvet 125 N'dur (sürtünme nedeniyle yükten büyüktür)."},{"q":"Şekildeki sabit makarada 40 kg'lık yük asılı (g = 10 m/s²). Yükü 1,5 m/s² ivmeyle yukarı çıkarmak için uygulanması gereken kuvveti bulunuz.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='40' x2='144' y2='130' stroke='#1a2b45' stroke-width='2'/><rect x='126' y='130' width='36' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>40 kg, a=1,5</text><line x1='176' y1='40' x2='176' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='176,142 171,132 181,132' fill='#e0552b'/><line x1='176' y1='168' x2='176' y2='134' stroke='#e0552b' stroke-width='2'/><text x='197' y='150' font-size='10' fill='#e0552b'>F</text></svg>","steps":[{"t":"Newton'ın 2. yasası","a":"F − G = m·a","d":"Yük ivmeli çıkarken net kuvvet, kütle ile ivmenin çarpımına eşittir."},{"t":"Ağırlığı bul","a":"G = 40 × 10","d":"Yükün ağırlığı G = m·g = 400 N'dur."},{"t":"Kuvveti çöz","a":"F = 400 + 60","d":"F = G + m·a = 400 + 40 × 1,5 = 400 + 60 = 460 N'dur."}],"ans":"Uygulanması gereken kuvvet 460 N'dur."},{"q":"Bir sabit makarada yük 120 N, makara yarıçapı 15 cm. İdeal durumda denge için kuvvet ipine etkiyen kuvvetin oluşturduğu momenti bulunuz.","steps":[{"t":"Denge kuvveti","a":"F = 120 N","d":"Sabit makarada kuvvet yüke eşittir, yani F = 120 N'dur."},{"t":"Kol uzunluğu","a":"0,15 m","d":"Kuvvet ipi makara kenarından geçtiği için kol, yarıçapa eşittir: 15 cm = 0,15 m."},{"t":"Moment","a":"120 × 0,15","d":"Moment = kuvvet × kol = 120 × 0,15 = 18 N·m'dir."}],"ans":"Kuvvetin oluşturduğu moment 18 N·m'dir (yük momentiyle dengelenir)."},{"q":"Şekildeki sabit makarada yük 1 dakikada 12 m yukarı çıkarılıyor; yük 50 N'dur. Uygulanan kuvvetin gücünü (watt) bulunuz.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='40' x2='144' y2='128' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='128' width='32' height='26' fill='#5b6b85' stroke='#1a2b45'/><polygon points='136,121 131,111 141,111' fill='#4aa3df'/><line x1='136' y1='128' x2='136' y2='113' stroke='#4aa3df' stroke-width='2'/><text x='144' y='170' font-size='10' text-anchor='middle' fill='#1a2b45'>50 N, 12 m / 60 s</text><line x1='176' y1='40' x2='176' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='176,142 171,132 181,132' fill='#e0552b'/><text x='197' y='110' font-size='10' fill='#e0552b'>F</text></svg>","steps":[{"t":"İşi bul","a":"W = F × yol","d":"Kuvvet yüke eşit (50 N) ve çekilen ip = yol = 12 m; iş = 50 × 12 = 600 J'dür."},{"t":"Güç bağıntısı","a":"P = W / t","d":"Güç, yapılan işin geçen zamana oranıdır."},{"t":"Hesapla","a":"600 ÷ 60","d":"600 J'yi 60 s'ye böleriz, sonuç 10 W bulunur."}],"ans":"Uygulanan kuvvetin gücü 10 watt'tır."},{"q":"Sabit makarada kuvvet kazancı olmadığı halde 'iş kolaylığı' sağladığı söylenir. Bu ifadenin doğru yorumu nedir?","steps":[{"t":"Kuvvet ve iş","a":"değişmez","d":"Sabit makara ne kuvveti ne de yapılan işi azaltır; ikisi de aynı kalır."},{"t":"Değişen şey","a":"kuvvetin yönü","d":"Sadece kuvvetin uygulanış yönünü ve noktasını değiştirir."},{"t":"Doğru yorum","a":"kolaylık ≠ kazanç","d":"Buradaki kolaylık, işin azalması değil; çekmenin daha rahat (örneğin aşağı, vücut ağırlığıyla) yapılabilmesidir."}],"ans":"İfade, işin veya kuvvetin azaldığı anlamına gelmez; sabit makara yalnızca kuvvetin yönünü değiştirerek çekmeyi pratik hâle getirir."},{"q":"Şekildeki sabit makara sisteminde ipin çekme ucu sabit 90 N gerilim altındadır. Yük dengede olduğuna göre yükün kütlesi kaç kg'dır (g = 10 m/s²)?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='25' x2='270' y2='25' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='42' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='42' r='3' fill='#1a2b45'/><text x='160' y='16' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='42' x2='144' y2='140' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='140' width='32' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='185' font-size='11' text-anchor='middle' fill='#1a2b45'>m = ?</text><line x1='176' y1='42' x2='176' y2='140' stroke='#1a2b45' stroke-width='2'/><text x='186' y='95' font-size='10' fill='#1a2b45'>T=90 N</text><polygon points='176,148 171,138 181,138' fill='#e0552b'/><text x='198' y='150' font-size='11' fill='#e0552b'>F</text></svg>","steps":[{"t":"Gerilme = ağırlık","a":"T = G","d":"Dengede ip gerilmesi yükün ağırlığına eşittir; G = 90 N'dur."},{"t":"Kütleyi bul","a":"m = G / g","d":"Ağırlık G = m·g olduğundan kütle = ağırlık ÷ yer çekimi ivmesidir."},{"t":"Hesapla","a":"90 ÷ 10","d":"90 N'u 10 m/s²'ye böleriz, sonuç 9 kg bulunur."}],"ans":"Yükün kütlesi 9 kg'dır."},{"q":"İdeal bir sabit makarada 60 N kuvvetle yük 4 m kaldırıldığında; verilen iş, yüke aktarılan iş ve verim nedir?","steps":[{"t":"Verilen iş","a":"60 × 4","d":"Uygulanan kuvvet 60 N ve çekilen ip 4 m; verilen iş = 240 J'dür."},{"t":"Aktarılan iş","a":"240 J","d":"İdeal makarada kayıp olmadığından yüke aktarılan iş de 240 J'dür (G = 60 N, h = 4 m)."},{"t":"Verim","a":"240/240","d":"Verim = alınan iş ÷ verilen iş = 240 ÷ 240 = 1, yani %100'dür."}],"ans":"Verilen iş 240 J, yüke aktarılan iş 240 J, verim %100'dür."},{"q":"Şekildeki sabit makarada kişi ipi 75 N'luk sabit kuvvetle 2 m çekiyor, ancak sürtünme nedeniyle yük yalnızca 60 N. Bu makaranın verimini bulunuz.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='40' x2='144' y2='130' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='130' width='32' height='26' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='172' font-size='10' text-anchor='middle' fill='#1a2b45'>Yük 60 N</text><line x1='176' y1='40' x2='176' y2='155' stroke='#1a2b45' stroke-width='2'/><polygon points='176,147 171,137 181,137' fill='#e0552b'/><line x1='176' y1='170' x2='176' y2='139' stroke='#e0552b' stroke-width='2'/><text x='196' y='150' font-size='10' fill='#e0552b'>F=75 N, 2 m</text></svg>","steps":[{"t":"Verilen iş","a":"75 × 2","d":"Kişinin yaptığı iş = uygulanan kuvvet × çekilen ip = 75 × 2 = 150 J'dür."},{"t":"Alınan iş","a":"60 × 2","d":"Yüke aktarılan iş = yük × yükseklik = 60 × 2 = 120 J'dür (yol eşit)."},{"t":"Verim","a":"120/150","d":"Verim = 120 ÷ 150 = 0,80 = %80'dir."}],"ans":"Makaranın verimi %80'dir."},{"q":"Sabit makarada yükün ipi ile kuvvet ipi paralel ve düşey iken sistem dengededir. İpler düşeyden 0° açıyla aşağı sarkıyorsa, kuvvet ile yük arasındaki ilişki neden tam olarak F = G olur?","steps":[{"t":"İp boyunca gerilme","a":"sabit","d":"Sürtünmesiz makarada ip boyunca gerilme her noktada aynıdır."},{"t":"Yük tarafı","a":"T = G","d":"Düşey asılı yük dengedeyken gerilme yükün ağırlığına eşittir."},{"t":"Kuvvet tarafı","a":"F = T","d":"Aynı ipin diğer ucundaki kuvvet de gerilmeye eşit olduğundan F = T = G çıkar."}],"ans":"İp boyunca gerilme sabit olduğundan T = G ve F = T olur; bu yüzden düşey düzenekte F = G'dir."},{"q":"Şekildeki sabit makarada 500 N'luk yükü sabit hızla kaldıran motor, ipi 0,4 m/s hızla sarıyor. Motorun harcadığı gücü bulunuz.","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='40' x2='144' y2='130' stroke='#1a2b45' stroke-width='2'/><rect x='126' y='130' width='36' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='144' y='178' font-size='10' text-anchor='middle' fill='#1a2b45'>500 N</text><line x1='176' y1='40' x2='176' y2='150' stroke='#1a2b45' stroke-width='2'/><polygon points='176,142 171,132 181,132' fill='#e0552b'/><line x1='176' y1='168' x2='176' y2='134' stroke='#e0552b' stroke-width='2'/><text x='196' y='150' font-size='10' fill='#e0552b'>v=0,4 m/s</text></svg>","steps":[{"t":"Kuvvet","a":"F = 500 N","d":"Sabit hızda denge olduğundan ve sabit makara MA = 1 olduğundan kuvvet yüke eşittir."},{"t":"Güç bağıntısı","a":"P = F × v","d":"Sabit hızda güç, kuvvet ile hızın çarpımına eşittir."},{"t":"Hesapla","a":"500 × 0,4","d":"500 N ile 0,4 m/s çarpılır, sonuç 200 W bulunur."}],"ans":"Motorun harcadığı güç 200 watt'tır."},{"q":"Bir sabit makara ve bir hareketli makara aynı 240 N'luk yükü kaldırıyor. İki sistemde uygulanan kuvvetleri karşılaştırınız (ideal).","steps":[{"t":"Sabit makara","a":"F = 240 N","d":"Sabit makarada MA = 1 olduğundan kuvvet yüke eşittir, 240 N'dur."},{"t":"Hareketli makara","a":"F = 120 N","d":"Tek hareketli makarada yükü iki ip taşır, MA = 2; kuvvet yarıya iner: 240 ÷ 2 = 120 N'dur."},{"t":"Karşılaştır","a":"2 kat fark","d":"Sabit makaradaki kuvvet, hareketli makaradakinin 2 katıdır."}],"ans":"Sabit makarada 240 N, hareketli makarada 120 N kuvvet gerekir; sabit makara kuvvet kazancı sağlamaz."},{"q":"Şekildeki sabit makarada yük yukarı çıkarken kişi ipi 1,2 m çekti. Yük aynı anda kaç metre yükseldi ve neden?","fig":"<svg viewBox='0 0 320 200'><line x1='50' y1='22' x2='270' y2='22' stroke='#1a2b45' stroke-width='3'/><circle cx='160' cy='40' r='16' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='3' fill='#1a2b45'/><text x='160' y='14' font-size='12' text-anchor='middle' fill='#1a2b45'>Sabit makara</text><line x1='144' y1='40' x2='144' y2='126' stroke='#1a2b45' stroke-width='2'/><rect x='128' y='126' width='32' height='26' fill='#5b6b85' stroke='#1a2b45'/><polygon points='136,119 131,109 141,109' fill='#4aa3df'/><line x1='136' y1='126' x2='136' y2='111' stroke='#4aa3df' stroke-width='2'/><text x='144' y='168' font-size='10' text-anchor='middle' fill='#1a2b45'>yük ? m ↑</text><line x1='176' y1='40' x2='176' y2='155' stroke='#1a2b45' stroke-width='2'/><polygon points='176,147 171,137 181,137' fill='#e0552b'/><line x1='176' y1='172' x2='176' y2='139' stroke='#e0552b' stroke-width='2'/><text x='196' y='150' font-size='10' fill='#e0552b'>ip 1,2 m</text></svg>","steps":[{"t":"İp ve yük yolu","a":"eşit","d":"Sabit makarada çekilen ip boyu, yükün çıktığı yola eşittir; kazanç olmadığı için yollar aynıdır."},{"t":"Sonuç","a":"1,2 m","d":"İp 1,2 m çekildiğinden yük de 1,2 m yükselir."}],"ans":"Yük 1,2 m yükseldi; sabit makarada çekilen ip boyu yükün yoluna eşittir."},{"q":"Sabit makaranın mekanik avantajı 1, hareketli makaranın 2 ise; bir sistemde 1 sabit + 1 hareketli makara birlikte kullanıldığında toplam kuvvet kazancı genelde kaç olur ve sabit makaranın bu sistemdeki rolü nedir?","steps":[{"t":"Hareketli makara katkısı","a":"MA = 2","d":"Hareketli makara yükü iki iple taşıdığı için kuvvet kazancını 2 yapar."},{"t":"Sabit makara katkısı","a":"yön","d":"Sabit makara kuvvet kazancı eklemez (çarpan 1), yalnızca çekme yönünü değiştirir."},{"t":"Toplam","a":"2","d":"Toplam kuvvet kazancı 1 × 2 = 2'dir; çekme rahat yönden yapılır."}],"ans":"Toplam kuvvet kazancı 2'dir; hareketli makara kazancı sağlar, sabit makara yalnızca çekme yönünü uygun hâle getirir."},{"q":"Sürtünmesiz sabit makarada 'kuvvetten kaybedilmez, yoldan da kazanılmaz' ifadesini iş korunumu ile gerekçelendiriniz.","steps":[{"t":"Kuvvet","a":"F = G","d":"Mekanik avantaj 1 olduğundan ne kuvvetten kazanılır ne kaybedilir; kuvvet yüke eşittir."},{"t":"Yol","a":"ip = h","d":"Çekilen ip boyu yükün yoluna eşit olduğundan yoldan da kazanç olmaz."},{"t":"İş korunumu","a":"F·ip = G·h","d":"İkisi de değişmediği için verilen iş alınan işe eşittir; ne kuvvet ne yol avantajı doğar."}],"ans":"F = G ve ip = h olduğundan F·ip = G·h olur; sabit makarada ne kuvvetten ne yoldan kazanç sağlanmaz, yalnızca yön değişir."}]}},"verim":{"ilkokul":{"kolay":[{"q":"Bir makineyi çalıştırmak için verdiğimiz gücün bir kısmı sürtünme yüzünden ısıya gider. Verdiğimiz işin tamamı işe yarar mı?","fig":"<svg viewBox='0 0 320 160'><rect x='120' y='55' width='80' height='50' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='85' font-size='12' text-anchor='middle' fill='#fff'>Makine</text><polygon points='30,75 110,75 110,68 30,68' fill='#e0552b'/><polygon points='110,71 122,71 116,62' fill='#e0552b'/><text x='65' y='55' font-size='11' text-anchor='middle' fill='#1a2b45'>verilen iş</text><polygon points='200,75 280,75 280,82 200,82' fill='#4aa3df'/><text x='240' y='102' font-size='11' text-anchor='middle' fill='#1a2b45'>faydalı iş</text><line x1='160' y1='105' x2='160' y2='140' stroke='#1a2b45' stroke-width='1.5'/><text x='160' y='154' font-size='10' text-anchor='middle' fill='#e0552b'>ısı (kayıp)</text></svg>","steps":[{"t":"İş nereye gidiyor","a":"bir kısmı kaybolur","d":"Makinedeki sürtünme verdiğimiz işin bir kısmını ısıya çevirir."},{"t":"Sonuç","a":"tamamı işe yaramaz","d":"Bu yüzden verdiğimiz işin sadece bir bölümü gerçek işe dönüşür."}],"ans":"Hayır; sürtünme yüzünden verdiğimiz işin bir kısmı ısıya gider, tamamı işe yaramaz."},{"q":"İki kızaktan biri paslı ve gıcırdıyor, diğeri yağlı ve kayıyor. Hangisini çekmek daha az yorar?","fig":"<svg viewBox='0 0 320 160'><rect x='30' y='60' width='60' height='30' rx='4' fill='#8a6d3b' stroke='#1a2b45'/><text x='60' y='80' font-size='10' text-anchor='middle' fill='#fff'>paslı</text><text x='60' y='112' font-size='10' text-anchor='middle' fill='#e0552b'>çok sürtünme</text><rect x='210' y='60' width='60' height='30' rx='4' fill='#4aa3df' stroke='#1a2b45'/><text x='240' y='80' font-size='10' text-anchor='middle' fill='#fff'>yağlı</text><text x='240' y='112' font-size='10' text-anchor='middle' fill='#1a2b45'>az sürtünme</text></svg>","steps":[{"t":"Sürtünmeye bak","a":"yağlı az","d":"Yağlı kızakta sürtünme az olduğu için işin çoğu işe yarar."},{"t":"Karşılaştır","a":"yağlı kızak","d":"Az sürtünen kızağı çekmek için daha az kuvvet gerekir."}],"ans":"Yağlı kızağı çekmek daha az yorar, çünkü sürtünmesi azdır."},{"q":"Bir oyuncak arabayı iterken tekerlekler ısınıyor. Bu ısı, harcadığımız enerjinin işe yarayan kısmı mıdır?","fig":"<svg viewBox='0 0 320 150'><rect x='110' y='55' width='90' height='30' rx='5' fill='#5b6b85' stroke='#1a2b45'/><circle cx='130' cy='90' r='12' fill='#1a2b45'/><circle cx='180' cy='90' r='12' fill='#1a2b45'/><polygon points='40,70 105,70 105,63 40,63' fill='#e0552b'/><text x='65' y='52' font-size='10' text-anchor='middle' fill='#1a2b45'>itme</text><line x1='130' y1='102' x2='130' y2='128' stroke='#e0552b' stroke-width='1.5'/><line x1='180' y1='102' x2='180' y2='128' stroke='#e0552b' stroke-width='1.5'/><text x='155' y='142' font-size='10' text-anchor='middle' fill='#e0552b'>ısı (kayıp)</text></svg>","steps":[{"t":"Isı ne demek","a":"kayıp enerji","d":"Tekerleklerin ısınması sürtünmeden gelir ve arabayı ileri götürmez."},{"t":"Sonuç","a":"işe yaramayan kısım","d":"Bu ısı, harcadığımız enerjinin boşa giden (kayıp) kısmıdır."}],"ans":"Hayır; tekerleklerin ısınması enerjinin işe yaramayan, kayıp kısmıdır."},{"q":"Bir makara ne kadar pürüzsüz ve iyi dönerse yükü kaldırmak daha kolay olur mu zor olur mu?","fig":"<svg viewBox='0 0 320 160'><circle cx='160' cy='45' r='26' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='45' r='4' fill='#1a2b45'/><line x1='134' y1='45' x2='134' y2='120' stroke='#1a2b45' stroke-width='2'/><line x1='186' y1='45' x2='186' y2='120' stroke='#1a2b45' stroke-width='2'/><rect x='118' y='120' width='32' height='24' fill='#5b6b85' stroke='#1a2b45'/><text x='134' y='137' font-size='9' text-anchor='middle' fill='#fff'>yük</text><polygon points='186,120 186,105 178,112 194,112' fill='#e0552b'/><text x='205' y='90' font-size='10' fill='#1a2b45'>çekme</text></svg>","steps":[{"t":"Pürüzsüz makara","a":"az sürtünme","d":"İyi dönen pürüzsüz bir makarada sürtünme azdır."},{"t":"Sonuç","a":"daha kolay","d":"Az sürtünme olunca yükü kaldırmak için daha az kuvvet gerekir."}],"ans":"Makara ne kadar pürüzsüz ve iyi dönerse yükü kaldırmak o kadar kolay olur."},{"q":"Mükemmel (hayali) bir makinede hiç sürtünme olmasaydı, verdiğimiz işin ne kadarı işe yarardı?","steps":[{"t":"Sürtünme yok","a":"kayıp yok","d":"Hayali mükemmel makinede sürtünme olmadığı için hiç enerji kaybolmaz."},{"t":"Sonuç","a":"tamamı","d":"Verdiğimiz işin tamamı faydalı işe dönüşürdü."}],"ans":"Sürtünme hiç olmasaydı verdiğimiz işin tamamı işe yarardı."}],"zor":[{"q":"İki vinçten biri yeni ve yağlı, diğeri eski ve paslı. Aynı yükü kaldırmak için hangisine daha çok güç vermek gerekir?","fig":"<svg viewBox='0 0 320 170'><rect x='40' y='40' width='40' height='90' rx='4' fill='#4aa3df' stroke='#1a2b45'/><text x='60' y='90' font-size='10' text-anchor='middle' fill='#fff'>yeni</text><text x='60' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>az kayıp</text><rect x='240' y='40' width='40' height='90' rx='4' fill='#8a6d3b' stroke='#1a2b45'/><text x='260' y='90' font-size='10' text-anchor='middle' fill='#fff'>eski</text><text x='260' y='150' font-size='10' text-anchor='middle' fill='#e0552b'>çok kayıp</text><rect x='140' y='100' width='40' height='30' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='120' font-size='9' text-anchor='middle' fill='#fff'>yük</text></svg>","steps":[{"t":"Kayba bak","a":"paslı çok kaybeder","d":"Paslı vinçte sürtünme fazladır, enerjinin çoğu ısıya gider."},{"t":"Sonuç","a":"eski vinç","d":"Kayıp fazla olduğu için eski vince daha çok güç vermek gerekir."}],"ans":"Eski ve paslı vince daha çok güç vermek gerekir, çünkü sürtünme kaybı fazladır."},{"q":"Bir kaydıraktan inerken altımız ısınıyorsa, kayma enerjimizin bir kısmı nereye gitmiştir?","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='30' x2='240' y2='130' stroke='#1a2b45' stroke-width='4'/><circle cx='90' cy='52' r='12' fill='#5b6b85' stroke='#1a2b45'/><polygon points='110,70 130,82 122,68 134,72' fill='#e0552b'/><text x='150' y='70' font-size='10' fill='#e0552b'>sürtünme</text><text x='200' y='150' font-size='10' text-anchor='middle' fill='#e0552b'>ısı</text></svg>","steps":[{"t":"Isı nereden","a":"sürtünmeden","d":"Kaydırakla vücudumuz arasındaki sürtünme ısı oluşturur."},{"t":"Sonuç","a":"ısıya gitti","d":"Kayma enerjimizin bir kısmı bu sürtünme ısısına dönüşmüştür."}],"ans":"Kayma enerjimizin bir kısmı sürtünme yüzünden ısıya gitmiştir."},{"q":"Bir bisikletin zinciri yağlanırsa pedal çevirmek neden kolaylaşır?","steps":[{"t":"Yağ ne yapar","a":"sürtünmeyi azaltır","d":"Yağ, zincir ile dişliler arasındaki sürtünmeyi azaltır."},{"t":"Sonuç","a":"daha az kayıp","d":"Sürtünme azalınca enerji daha az boşa gider, pedal hafifler."}],"ans":"Yağ sürtünmeyi azalttığı için enerji daha az boşa gider ve pedal çevirmek kolaylaşır."},{"q":"Aynı yükü kaldıran iki makaradan biri çok az gıcırdıyor, diğeri hiç ses çıkarmıyor. Hangisi enerjiyi daha az boşa harcar?","fig":"<svg viewBox='0 0 320 160'><circle cx='90' cy='45' r='22' fill='#9aa6b8' stroke='#1a2b45'/><text x='90' y='90' font-size='10' text-anchor='middle' fill='#e0552b'>gıcırtılı</text><circle cx='230' cy='45' r='22' fill='#4aa3df' stroke='#1a2b45'/><text x='230' y='90' font-size='10' text-anchor='middle' fill='#1a2b45'>sessiz</text><text x='160' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>gıcırtı = sürtünme = kayıp</text></svg>","steps":[{"t":"Gıcırtı ne demek","a":"sürtünme var","d":"Gıcırdayan makarada sürtünme fazladır ve enerji ısı, sese gider."},{"t":"Sonuç","a":"sessiz olan","d":"Sessiz makarada sürtünme az olduğu için enerji daha az boşa gider."}],"ans":"Sessiz makara enerjiyi daha az boşa harcar, çünkü sürtünmesi azdır."},{"q":"Hiçbir makine verdiğimiz işin tamamını işe çeviremez. Bunun temel sebebi nedir?","steps":[{"t":"Engele bak","a":"sürtünme","d":"Her gerçek makinede parçalar birbirine sürtünür."},{"t":"Sonuç","a":"bir kısmı kaybolur","d":"Sürtünme enerjinin bir kısmını ısıya çevirir, bu yüzden tamamı işe yaramaz."}],"ans":"Sürtünme yüzünden enerjinin bir kısmı ısıya gittiği için hiçbir makine verdiğimiz işin tamamını işe çeviremez."}]},"ortaokul":{"kolay":[{"q":"Bir makineye 100 J iş veriliyor, bunun 80 J'si faydalı işe dönüşüyor. Makinenin verimi yüzde kaçtır?","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='50' width='90' height='55' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='82' font-size='12' text-anchor='middle' fill='#fff'>Makine</text><polygon points='25,72 108,72 108,64 25,64' fill='#e0552b'/><polygon points='108,68 120,68 113,58' fill='#e0552b'/><text x='65' y='52' font-size='11' text-anchor='middle' fill='#1a2b45'>100 J</text><polygon points='205,72 290,72 290,80 205,80' fill='#4aa3df'/><text x='248' y='100' font-size='11' text-anchor='middle' fill='#1a2b45'>80 J faydalı</text></svg>","steps":[{"t":"Formülü yaz","a":"verim = faydalı/verilen","d":"Verim, faydalı işin verilen işe oranının 100 ile çarpımıdır."},{"t":"Hesapla","a":"(80/100)×100","d":"80 J faydalıyı 100 J verilene bölüp 100 ile çarpıyoruz."}],"ans":"Makinenin verimi %80'dir."},{"q":"Bir makinenin verimi %100'den küçükse, verilen işin bir kısmı nereye gitmiştir?","fig":"<svg viewBox='0 0 320 150'><rect x='115' y='50' width='90' height='50' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='80' font-size='11' text-anchor='middle' fill='#fff'>Makine</text><polygon points='30,72 108,72 108,64 30,64' fill='#e0552b'/><polygon points='108,68 120,68 113,58' fill='#e0552b'/><text x='65' y='52' font-size='10' text-anchor='middle' fill='#1a2b45'>verilen iş</text><polygon points='205,72 285,72 285,80 205,80' fill='#4aa3df'/><text x='245' y='98' font-size='10' text-anchor='middle' fill='#1a2b45'>faydalı iş</text><line x1='160' y1='100' x2='160' y2='132' stroke='#e0552b' stroke-width='1.5'/><text x='160' y='145' font-size='10' text-anchor='middle' fill='#e0552b'>? (kayıp)</text></svg>","steps":[{"t":"Eksik işi bul","a":"kayıp iş","d":"Verim %100 değilse verilen işin hepsi faydalıya dönmemiştir."},{"t":"Nereye gitti","a":"sürtünme ısısı","d":"Eksik kalan kısım sürtünme yüzünden ısıya dönüşmüştür."}],"ans":"Verimi %100'den az ise verilen işin bir kısmı sürtünme nedeniyle ısıya gitmiştir."},{"q":"Bir makineye 200 J veriliyor, 50 J'si sürtünmeyle ısıya gidiyor. Faydalı iş kaç J'dir?","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='45' width='90' height='55' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='77' font-size='11' text-anchor='middle' fill='#fff'>Makine</text><text x='65' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>200 J</text><polygon points='205,70 285,70 285,78 205,78' fill='#4aa3df'/><text x='248' y='98' font-size='10' text-anchor='middle' fill='#1a2b45'>faydalı=?</text><line x1='160' y1='100' x2='160' y2='135' stroke='#e0552b' stroke-width='1.5'/><text x='160' y='150' font-size='10' text-anchor='middle' fill='#e0552b'>50 J ısı</text></svg>","steps":[{"t":"Bağıntıyı yaz","a":"faydalı = verilen − kayıp","d":"Faydalı iş, verilen işten kayıp işin çıkarılmasıyla bulunur."},{"t":"Hesapla","a":"200 − 50","d":"200 J verilenden 50 J kaybı çıkarıyoruz."}],"ans":"Faydalı iş 150 J'dir."},{"q":"İdeal bir makinede hiç enerji kaybı olmasaydı verim yüzde kaç olurdu?","steps":[{"t":"İdeal makine","a":"kayıp yok","d":"İdeal makinede sürtünme ve kayıp olmadığı varsayılır."},{"t":"Sonuç","a":"faydalı = verilen","d":"Faydalı iş verilen işe eşit olur, oran 1, yani %100 çıkar."}],"ans":"İdeal bir makinenin verimi %100 olurdu."},{"q":"Bir makinenin verimi neden hiçbir zaman tam %100 olamaz?","steps":[{"t":"Gerçek makine","a":"sürtünme var","d":"Gerçek makinelerde hareketli parçalar arasında sürtünme vardır."},{"t":"Sonuç","a":"kayıp kaçınılmaz","d":"Bir miktar enerji daima ısıya gittiği için faydalı iş verilenden azdır."}],"ans":"Gerçek makinelerde sürtünme kaybı kaçınılmaz olduğu için verim hiçbir zaman tam %100 olamaz."}],"zor":[{"q":"Bir makineye 500 J iş veriliyor, faydalı iş 300 J. Verimi ve kayıp işi bulunuz.","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='45' width='90' height='55' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='77' font-size='11' text-anchor='middle' fill='#fff'>Makine</text><text x='62' y='60' font-size='11' text-anchor='middle' fill='#1a2b45'>500 J</text><polygon points='205,70 285,70 285,78 205,78' fill='#4aa3df'/><text x='248' y='98' font-size='10' text-anchor='middle' fill='#1a2b45'>300 J</text><line x1='160' y1='100' x2='160' y2='135' stroke='#e0552b' stroke-width='1.5'/><text x='160' y='150' font-size='10' text-anchor='middle' fill='#e0552b'>kayıp=?</text></svg>","steps":[{"t":"Verimi hesapla","a":"(300/500)×100","d":"Verim, faydalı işin verilen işe oranının 100 katıdır: %60."},{"t":"Kayıp işi bul","a":"500 − 300","d":"Kayıp iş, verilen işten faydalı işin çıkarılmasıyla 200 J bulunur."}],"ans":"Makinenin verimi %60, kayıp iş 200 J'dir."},{"q":"Verimi %75 olan bir makineye 400 J iş veriliyor. Faydalı iş kaç J'dir?","fig":"<svg viewBox='0 0 320 150'><rect x='115' y='48' width='90' height='50' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='78' font-size='11' text-anchor='middle' fill='#fff'>η=%75</text><polygon points='30,68 108,68 108,60 30,60' fill='#e0552b'/><polygon points='108,64 120,64 113,54' fill='#e0552b'/><text x='65' y='50' font-size='10' text-anchor='middle' fill='#1a2b45'>400 J</text><polygon points='205,68 285,68 285,76 205,76' fill='#4aa3df'/><text x='245' y='94' font-size='10' text-anchor='middle' fill='#1a2b45'>faydalı=?</text></svg>","steps":[{"t":"Bağıntıyı düzenle","a":"faydalı = verim × verilen","d":"Faydalı iş, verim oranı (0,75) ile verilen işin çarpımıdır."},{"t":"Hesapla","a":"0,75 × 400","d":"0,75 ile 400 J çarpılır."}],"ans":"Faydalı iş 300 J'dir."},{"q":"Bir eğik düzlemde yükü kaldırmak için 240 J harcanıyor, faydalı iş 180 J. Sürtünmeye giden enerji ve verim nedir?","fig":"<svg viewBox='0 0 320 160'><line x1='40' y1='130' x2='260' y2='40' stroke='#1a2b45' stroke-width='3'/><line x1='40' y1='130' x2='260' y2='130' stroke='#1a2b45' stroke-width='2'/><rect x='150' y='72' width='26' height='18' fill='#5b6b85' stroke='#1a2b45'/><polygon points='150,81 132,90 140,78 128,82' fill='#e0552b'/><text x='110' y='70' font-size='10' fill='#e0552b'>sürtünme</text><text x='235' y='60' font-size='10' fill='#1a2b45'>240 J giriş</text></svg>","steps":[{"t":"Kaybı bul","a":"240 − 180","d":"Sürtünmeye giden enerji, verilen işten faydalı işin farkıdır: 60 J."},{"t":"Verimi hesapla","a":"(180/240)×100","d":"Faydalı işi verilene bölüp 100 ile çarpıyoruz: %75."}],"ans":"Sürtünmeye giden enerji 60 J, makinenin verimi %75'tir."},{"q":"İki makineye eşit 600 J iş veriliyor. Birinin faydalı işi 480 J, diğerininki 360 J. Hangisinin verimi yüksektir?","fig":"<svg viewBox='0 0 320 160'><rect x='30' y='50' width='70' height='45' rx='5' fill='#4aa3df' stroke='#1a2b45'/><text x='65' y='77' font-size='10' text-anchor='middle' fill='#fff'>A</text><text x='65' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>480 J faydalı</text><rect x='220' y='50' width='70' height='45' rx='5' fill='#8a6d3b' stroke='#1a2b45'/><text x='255' y='77' font-size='10' text-anchor='middle' fill='#fff'>B</text><text x='255' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>360 J faydalı</text><text x='160' y='40' font-size='10' text-anchor='middle' fill='#1a2b45'>her ikisi 600 J giriş</text></svg>","steps":[{"t":"A'nın verimi","a":"(480/600)×100","d":"A makinesinin verimi %80'dir."},{"t":"B'nin verimi","a":"(360/600)×100","d":"B makinesinin verimi %60'tır."},{"t":"Karşılaştır","a":"A büyük","d":"%80, %60'tan büyük olduğu için A daha verimlidir."}],"ans":"A makinesinin verimi (%80) daha yüksektir."},{"q":"Verimi %90 olan bir makinenin faydalı işi 270 J ise kendisine kaç J iş verilmiştir?","steps":[{"t":"Bağıntıyı düzenle","a":"verilen = faydalı/verim","d":"Verilen iş, faydalı işin verim oranına (0,90) bölünmesiyle bulunur."},{"t":"Hesapla","a":"270 ÷ 0,90","d":"270 J'yi 0,90'a bölüyoruz."}],"ans":"Makineye 300 J iş verilmiştir."}]},"lise":{"kolay":[{"q":"Bir makinenin verimi nasıl tanımlanır ve formülü nedir?","steps":[{"t":"Tanım","a":"faydalı/verilen oranı","d":"Verim, makinenin yaptığı faydalı işin, kendisine verilen işe oranıdır."},{"t":"Formül","a":"η = (W_faydalı/W_verilen)×100","d":"Yüzde olarak verim, bu oranın 100 ile çarpımıyla bulunur."}],"ans":"Verim η = (faydalı iş / verilen iş) × 100 bağıntısıyla tanımlanır."},{"q":"Bir makineye 800 J iş verilmiş, 600 J'si faydalı işe dönüşmüştür. Verimi hesaplayınız.","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='45' width='90' height='55' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='77' font-size='11' text-anchor='middle' fill='#fff'>Makine</text><polygon points='25,68 108,68 108,60 25,60' fill='#e0552b'/><polygon points='108,64 120,64 113,54' fill='#e0552b'/><text x='62' y='50' font-size='11' text-anchor='middle' fill='#1a2b45'>800 J</text><polygon points='205,68 288,68 288,76 205,76' fill='#4aa3df'/><text x='246' y='96' font-size='10' text-anchor='middle' fill='#1a2b45'>600 J</text></svg>","steps":[{"t":"Formülü yaz","a":"η = (faydalı/verilen)×100","d":"Verim, faydalı işin verilen işe oranının 100 katıdır."},{"t":"Yerine koy","a":"(600/800)×100","d":"600 J faydalıyı 800 J verilene bölüp 100 ile çarpıyoruz."},{"t":"Sonuç","a":"%75","d":"Bölme 0,75, çarpım %75 verir."}],"ans":"Makinenin verimi %75'tir."},{"q":"İdeal makine kabulü ne anlama gelir ve verimi kaçtır?","steps":[{"t":"İdeal kabul","a":"sürtünme yok","d":"İdeal makinede sürtünme ve diğer kayıplar ihmal edilir, makinenin ağırlığı dikkate alınmaz."},{"t":"Verim","a":"%100","d":"Kayıp olmadığı için faydalı iş verilen işe eşittir, verim %100'dür."}],"ans":"İdeal makinede kayıp olmadığı varsayılır; verimi %100 kabul edilir."},{"q":"Gerçek bir makinede uygulanan kuvvet, ideal duruma göre neden daha büyüktür?","steps":[{"t":"İdeal durum","a":"sadece yükü dengeler","d":"İdeal makinede uygulanan kuvvet yalnızca yükü dengelemeye yeter."},{"t":"Gerçek durum","a":"sürtünme + ağırlık","d":"Gerçekte ayrıca sürtünme ve makinenin kendi ağırlığı da yenilmelidir."}],"ans":"Gerçek makinede sürtünme ve makinenin ağırlığı da yenildiğinden uygulanan kuvvet idealden büyüktür."},{"q":"Bir makineye 1000 J veriliyor, 250 J'si sürtünmeyle kaybediliyor. Verimi bulunuz.","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='45' width='90' height='55' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='77' font-size='11' text-anchor='middle' fill='#fff'>Makine</text><text x='60' y='58' font-size='11' text-anchor='middle' fill='#1a2b45'>1000 J</text><polygon points='205,68 288,68 288,76 205,76' fill='#4aa3df'/><text x='246' y='96' font-size='10' text-anchor='middle' fill='#1a2b45'>faydalı</text><line x1='160' y1='100' x2='160' y2='138' stroke='#e0552b' stroke-width='1.5'/><text x='160' y='152' font-size='10' text-anchor='middle' fill='#e0552b'>250 J kayıp</text></svg>","steps":[{"t":"Faydalı işi bul","a":"1000 − 250","d":"Faydalı iş = verilen − kayıp = 750 J'dir."},{"t":"Verimi hesapla","a":"(750/1000)×100","d":"750 J'yi 1000 J'ye bölüp 100 ile çarpıyoruz."},{"t":"Sonuç","a":"%75","d":"Sonuç %75 bulunur."}],"ans":"Makinenin verimi %75'tir."},{"q":"Kayıp iş hangi bağıntıyla bulunur ve fiziksel olarak çoğunlukla neye dönüşür?","steps":[{"t":"Bağıntı","a":"W_kayıp = W_verilen − W_faydalı","d":"Kayıp iş, verilen iş ile faydalı iş arasındaki farktır."},{"t":"Dönüşüm","a":"ısı","d":"Bu kayıp enerji çoğunlukla sürtünme nedeniyle ısıya dönüşür."}],"ans":"Kayıp iş = verilen iş − faydalı iş olup çoğunlukla sürtünme ısısına dönüşür."},{"q":"Verimi %40 olan bir makineye 500 J iş verilirse faydalı iş kaç J olur?","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='50' width='90' height='52' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='80' font-size='11' text-anchor='middle' fill='#fff'>η=%40</text><text x='62' y='62' font-size='11' text-anchor='middle' fill='#1a2b45'>500 J</text><polygon points='25,70 108,70 108,62 25,62' fill='#e0552b'/><polygon points='205,72 288,72 288,80 205,80' fill='#4aa3df'/><text x='246' y='100' font-size='10' text-anchor='middle' fill='#1a2b45'>faydalı=?</text></svg>","steps":[{"t":"Bağıntıyı düzenle","a":"faydalı = (η/100)×verilen","d":"Faydalı iş, verim kesriyle (0,40) verilen işin çarpımıdır."},{"t":"Yerine koy","a":"0,40 × 500","d":"0,40 ile 500 J çarpılır."},{"t":"Sonuç","a":"200 J","d":"Çarpım 200 J verir."}],"ans":"Faydalı iş 200 J'dir."},{"q":"Bir makinenin verimini artırmak için alınabilecek temel önlemler nelerdir?","steps":[{"t":"Sürtünmeyi azalt","a":"yağlama, rulman","d":"Yağlama ve rulman kullanımı sürtünme kaybını düşürür."},{"t":"Ağırlığı azalt","a":"hafif malzeme","d":"Makinenin kendi ağırlığını azaltmak da kaybı düşürüp verimi yükseltir."}],"ans":"Sürtünmeyi azaltmak (yağlama, rulman) ve makinenin ağırlığını düşürmek verimi artırır."},{"q":"Verimi %80 olan bir makinenin faydalı işi 320 J ise verilen iş kaç J'dir?","steps":[{"t":"Bağıntıyı düzenle","a":"verilen = faydalı/(η/100)","d":"Verilen iş, faydalı işin verim kesrine (0,80) bölünmesiyle bulunur."},{"t":"Yerine koy","a":"320 ÷ 0,80","d":"320 J'yi 0,80'e bölüyoruz."},{"t":"Sonuç","a":"400 J","d":"Bölme 400 J verir."}],"ans":"Verilen iş 400 J'dir."},{"q":"Verim bağıntısı η = (faydalı/verilen)×100 içindeki ifadeler neyi gösterir?","steps":[{"t":"Faydalı iş","a":"yükü hareket ettiren iş","d":"Faydalı iş, makinenin asıl amacını yerine getiren (yükü kaldıran) iştir."},{"t":"Verilen iş","a":"kuvvete harcanan iş","d":"Verilen iş, makineyi çalıştırmak için uyguladığımız kuvvetin yaptığı toplam iştir."}],"ans":"Faydalı iş yükü hareket ettiren iş, verilen iş ise makineye uyguladığımız toplam iştir; η bunların yüzde oranıdır."},{"q":"Bir makineye 600 J verilmiş, 150 J kayıp oluşmuştur. Faydalı işi ve verimi bulunuz.","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='45' width='90' height='52' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='76' font-size='11' text-anchor='middle' fill='#fff'>Makine</text><text x='60' y='58' font-size='11' text-anchor='middle' fill='#1a2b45'>600 J</text><polygon points='205,68 288,68 288,76 205,76' fill='#4aa3df'/><text x='246' y='96' font-size='10' text-anchor='middle' fill='#1a2b45'>faydalı</text><line x1='160' y1='97' x2='160' y2='135' stroke='#e0552b' stroke-width='1.5'/><text x='160' y='150' font-size='10' text-anchor='middle' fill='#e0552b'>150 J kayıp</text></svg>","steps":[{"t":"Faydalı işi bul","a":"600 − 150","d":"Faydalı iş = verilen − kayıp = 450 J'dir."},{"t":"Verimi hesapla","a":"(450/600)×100","d":"450 J'yi 600 J'ye bölüp 100 ile çarpıyoruz."},{"t":"Sonuç","a":"%75","d":"Sonuç %75 bulunur."}],"ans":"Faydalı iş 450 J, verim %75'tir."},{"q":"İdeal ve gerçek makine arasındaki temel fark verim açısından nasıl ifade edilir?","steps":[{"t":"İdeal makine","a":"η = %100","d":"İdeal makinede kayıp olmadığı için faydalı iş verilen işe eşittir."},{"t":"Gerçek makine","a":"η < %100","d":"Gerçek makinede sürtünme ve ağırlık kaybı nedeniyle verim daima %100'den küçüktür."}],"ans":"İdeal makinenin verimi %100 kabul edilirken gerçek makinenin verimi daima %100'den küçüktür."},{"q":"Verimi %50 olan bir makinede kayıp iş, faydalı işe oranla ne kadardır?","steps":[{"t":"Verim anlamı","a":"yarısı faydalı","d":"Verim %50 ise verilen işin yarısı faydalı işe dönüşür."},{"t":"Kalan yarı","a":"kayıp = faydalı","d":"Diğer yarısı kayıp olduğundan kayıp iş faydalı işe eşittir."}],"ans":"Verim %50 ise kayıp iş, faydalı işe eşittir (her ikisi de verilen işin yarısıdır)."},{"q":"Bir makineye 250 J verildiğinde 200 J faydalı iş elde ediliyor. Verim ve kayıp iş oranı (kayıp/verilen) nedir?","steps":[{"t":"Verimi bul","a":"(200/250)×100","d":"Verim, faydalı işin verilen işe yüzde oranıdır: %80."},{"t":"Kaybı bul","a":"250 − 200 = 50 J","d":"Kayıp iş, verilen ile faydalı arasındaki farktır."},{"t":"Kayıp oranı","a":"50/250","d":"Kayıp işin verilen işe oranı 0,20, yani %20'dir."}],"ans":"Makinenin verimi %80, kayıp işin oranı %20'dir."},{"q":"Verim her zaman 1'den (yani %100'den) küçük çıkar. Bu durum enerjinin korunumu ilkesiyle çelişir mi?","steps":[{"t":"Enerji nereye gidiyor","a":"ısıya dönüşüyor","d":"Kayıp enerji yok olmaz, sürtünmeyle ısıya dönüşerek korunur."},{"t":"Sonuç","a":"çelişmez","d":"Verim, yalnızca faydalı işe dönüşen kısmı ölçer; toplam enerji korunduğu için çelişki yoktur."}],"ans":"Çelişmez; kayıp enerji yok olmayıp ısıya dönüşerek korunur, verim sadece faydalı kısmı ölçer."}],"zor":[{"q":"Bir makineye 1200 J iş veriliyor; 300 J'si sürtünmeyle kaybediliyor. Makinenin verimini hesaplayınız.","fig":"<svg viewBox='0 0 320 160'><rect x='115' y='45' width='90' height='55' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='77' font-size='11' text-anchor='middle' fill='#fff'>Makine</text><text x='58' y='58' font-size='11' text-anchor='middle' fill='#1a2b45'>1200 J</text><polygon points='205,68 288,68 288,76 205,76' fill='#4aa3df'/><text x='246' y='96' font-size='10' text-anchor='middle' fill='#1a2b45'>faydalı</text><line x1='160' y1='100' x2='160' y2='138' stroke='#e0552b' stroke-width='1.5'/><text x='160' y='152' font-size='10' text-anchor='middle' fill='#e0552b'>300 J ısı</text></svg>","steps":[{"t":"Faydalı işi bul","a":"1200 − 300","d":"Faydalı iş = verilen − kayıp = 900 J'dir."},{"t":"Verimi hesapla","a":"(900/1200)×100","d":"900 J'yi 1200 J'ye bölüp 100 ile çarpıyoruz."},{"t":"Sonuç","a":"%75","d":"Bölme 0,75, verim %75 bulunur."}],"ans":"Makinenin verimi %75'tir."},{"q":"Bir eğik düzlemde 50 N'luk yük, 2 m yüksekliğe çıkarılıyor. Bunun için 5 m boyunca 30 N kuvvet uygulanıyor. Verimi bulunuz.","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='140' x2='280' y2='50' stroke='#1a2b45' stroke-width='3'/><line x1='40' y1='140' x2='280' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='280' y1='50' x2='280' y2='140' stroke='#1a2b45' stroke-width='2'/><text x='292' y='98' font-size='10' fill='#1a2b45'>h=2 m</text><text x='150' y='90' font-size='10' fill='#1a2b45'>L=5 m</text><rect x='150' y='86' width='24' height='16' fill='#5b6b85' stroke='#1a2b45'/><polygon points='150,94 132,102 140,90 128,94' fill='#e0552b'/><text x='110' y='86' font-size='10' fill='#e0552b'>F=30 N</text></svg>","steps":[{"t":"Faydalı işi bul","a":"50 × 2 = 100 J","d":"Faydalı iş, yükün ağırlığı ile çıkılan yüksekliğin çarpımıdır."},{"t":"Verilen işi bul","a":"30 × 5 = 150 J","d":"Verilen iş, uygulanan kuvvet ile yol boyu çarpımıdır."},{"t":"Verimi hesapla","a":"(100/150)×100","d":"Faydalı işi verilene bölüp 100 ile çarparız."}],"ans":"Makinenin verimi yaklaşık %66,7'dir."},{"q":"Verimi %60 olan bir vinç, 1800 J faydalı iş yapıyor. Bu sırada sürtünmeye giden kayıp iş kaç J'dir?","steps":[{"t":"Verilen işi bul","a":"1800 ÷ 0,60","d":"Verilen iş, faydalı işin verim kesrine bölünmesiyle 3000 J bulunur."},{"t":"Kaybı bul","a":"3000 − 1800","d":"Kayıp iş, verilen ile faydalı işin farkıdır."},{"t":"Sonuç","a":"1200 J","d":"3000 J'den 1800 J çıkarılınca 1200 J kayıp bulunur."}],"ans":"Sürtünmeye giden kayıp iş 1200 J'dir."},{"q":"Bir makarada 200 N yükü 3 m kaldırmak için 250 N kuvvet, 3 m çekiliyor (tek hareketli makara değil sabit makara). Verimi hesaplayınız.","fig":"<svg viewBox='0 0 320 170'><circle cx='160' cy='40' r='24' fill='#9aa6b8' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='40' r='4' fill='#1a2b45'/><line x1='136' y1='40' x2='136' y2='130' stroke='#1a2b45' stroke-width='2'/><line x1='184' y1='40' x2='184' y2='130' stroke='#1a2b45' stroke-width='2'/><rect x='120' y='130' width='32' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='136' y='146' font-size='9' text-anchor='middle' fill='#fff'>200 N</text><polygon points='184,130 184,114 176,121 192,121' fill='#e0552b'/><text x='200' y='120' font-size='10' fill='#e0552b'>F=250 N</text></svg>","steps":[{"t":"Faydalı işi bul","a":"200 × 3 = 600 J","d":"Faydalı iş, yük ağırlığı ile kaldırılan yüksekliğin çarpımıdır."},{"t":"Verilen işi bul","a":"250 × 3 = 750 J","d":"Verilen iş, uygulanan kuvvet ile çekilen yolun çarpımıdır."},{"t":"Verimi hesapla","a":"(600/750)×100","d":"Faydalı işi verilen işe bölüp 100 ile çarparız."}],"ans":"Makinenin verimi %80'dir."},{"q":"İki vinç aynı yükü kaldırıyor. A vincine 400 J veriliyor, kaybı 80 J; B vincine 500 J veriliyor, kaybı 200 J. Hangisinin verimi yüksektir?","fig":"<svg viewBox='0 0 320 160'><rect x='30' y='45' width='80' height='48' rx='5' fill='#4aa3df' stroke='#1a2b45'/><text x='70' y='66' font-size='10' text-anchor='middle' fill='#fff'>A: 400 J</text><text x='70' y='82' font-size='9' text-anchor='middle' fill='#fff'>kayıp 80</text><rect x='210' y='45' width='80' height='48' rx='5' fill='#8a6d3b' stroke='#1a2b45'/><text x='250' y='66' font-size='10' text-anchor='middle' fill='#fff'>B: 500 J</text><text x='250' y='82' font-size='9' text-anchor='middle' fill='#fff'>kayıp 200</text></svg>","steps":[{"t":"A'nın verimi","a":"(320/400)×100","d":"A'nın faydalı işi 400 − 80 = 320 J, verimi %80'dir."},{"t":"B'nin verimi","a":"(300/500)×100","d":"B'nin faydalı işi 500 − 200 = 300 J, verimi %60'tır."},{"t":"Karşılaştır","a":"A büyük","d":"%80 > %60 olduğundan A daha verimlidir."}],"ans":"A vincinin verimi (%80), B'nin veriminden (%60) yüksektir."},{"q":"Bir makinenin verimi %25'ten %75'e çıkarılırsa, aynı faydalı işi yapmak için verilen iş kaç kat azalır?","steps":[{"t":"İlk verilen iş","a":"W/0,25 = 4W","d":"%25 verimde faydalı iş W için verilen iş W ÷ 0,25 = 4W'dir."},{"t":"Yeni verilen iş","a":"W/0,75 ≈ 1,33W","d":"%75 verimde verilen iş W ÷ 0,75 ≈ 1,33W'dir."},{"t":"Oranı bul","a":"4W ÷ 1,33W = 3","d":"İlk verileni yeniye bölünce 3 katı azalma bulunur."}],"ans":"Verilen iş 3 kat azalır."},{"q":"Eğik düzlemde 60 N yük 1,5 m yüksekliğe çıkarılıyor; düzlem boyu 6 m ve uygulanan kuvvet 20 N. Verimi ve kayıp işi bulunuz.","fig":"<svg viewBox='0 0 320 170'><line x1='40' y1='140' x2='285' y2='55' stroke='#1a2b45' stroke-width='3'/><line x1='40' y1='140' x2='285' y2='140' stroke='#1a2b45' stroke-width='2'/><line x1='285' y1='55' x2='285' y2='140' stroke='#1a2b45' stroke-width='2'/><text x='296' y='100' font-size='9' fill='#1a2b45'>1,5 m</text><text x='150' y='92' font-size='10' fill='#1a2b45'>L=6 m</text><rect x='150' y='88' width='24' height='16' fill='#5b6b85' stroke='#1a2b45'/><polygon points='150,96 132,104 140,92 128,96' fill='#e0552b'/><text x='108' y='88' font-size='10' fill='#e0552b'>F=20 N</text></svg>","steps":[{"t":"Faydalı işi bul","a":"60 × 1,5 = 90 J","d":"Faydalı iş, yük ağırlığı ile yüksekliğin çarpımıdır."},{"t":"Verilen işi bul","a":"20 × 6 = 120 J","d":"Verilen iş, kuvvet ile düzlem boyunun çarpımıdır."},{"t":"Verim ve kayıp","a":"(90/120)×100 = %75; kayıp 30 J","d":"Verim %75, kayıp iş 120 − 90 = 30 J'dir."}],"ans":"Makinenin verimi %75, kayıp iş 30 J'dir."},{"q":"Bir makinenin verimi %80. Faydalı iş 480 J ise verilen iş, kayıp iş ve sürtünmeye giden enerjiyi bulunuz.","steps":[{"t":"Verilen işi bul","a":"480 ÷ 0,80 = 600 J","d":"Verilen iş, faydalı işin verim kesrine bölümüdür."},{"t":"Kaybı bul","a":"600 − 480 = 120 J","d":"Kayıp iş, verilen ile faydalı işin farkıdır."},{"t":"Sürtünme","a":"120 J","d":"Bu makinede tüm kayıp sürtünme ısısına gittiği için sürtünme enerjisi 120 J'dir."}],"ans":"Verilen iş 600 J, kayıp iş ve sürtünme enerjisi 120 J'dir."},{"q":"Verimi %90 olan bir makinede kuvvetin yaptığı toplam iş 2000 J'dir. Kayıp iş hangi büyüklükte olur ve fiziksel olarak ne anlama gelir?","steps":[{"t":"Faydalı işi bul","a":"0,90 × 2000 = 1800 J","d":"Faydalı iş, verim kesriyle verilen işin çarpımıdır."},{"t":"Kaybı bul","a":"2000 − 1800 = 200 J","d":"Kayıp iş, verilen ile faydalı işin farkıdır."},{"t":"Anlam","a":"ısıya gitti","d":"Bu 200 J, sürtünme ve makine ağırlığını yenmek için harcanıp ısıya dönüşmüştür."}],"ans":"Kayıp iş 200 J'dir; bu enerji sürtünme ve makine ağırlığını yenmek için harcanıp ısıya dönüşmüştür."},{"q":"Şekildeki iki eğik düzlemde aynı yük aynı yüksekliğe çıkarılıyor; biri pürüzlü biri yağlı. Hangisinin verimi yüksektir ve neden?","fig":"<svg viewBox='0 0 320 170'><line x1='20' y1='130' x2='150' y2='60' stroke='#8a6d3b' stroke-width='4'/><text x='75' y='100' font-size='9' fill='#e0552b'>pürüzlü</text><rect x='80' y='86' width='18' height='12' fill='#5b6b85' stroke='#1a2b45'/><line x1='180' y1='130' x2='310' y2='60' stroke='#4aa3df' stroke-width='4'/><text x='240' y='100' font-size='9' fill='#1a2b45'>yağlı</text><rect x='240' y='86' width='18' height='12' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='160' font-size='9' text-anchor='middle' fill='#1a2b45'>aynı yük, aynı yükseklik</text></svg>","steps":[{"t":"Faydalı iş eşit","a":"aynı","d":"Aynı yük aynı yüksekliğe çıktığı için iki düzlemde de faydalı iş eşittir."},{"t":"Sürtünmeye bak","a":"yağlı az kayıp","d":"Yağlı düzlemde sürtünme az olduğu için kayıp iş küçük, verilen iş daha azdır."},{"t":"Sonuç","a":"yağlı verimli","d":"Verim faydalı/verilen olduğundan verileni az olan yağlı düzlemin verimi yüksektir."}],"ans":"Yağlı eğik düzlemin verimi daha yüksektir, çünkü sürtünme kaybı az olduğundan verilen iş daha küçüktür."},{"q":"Bir makaralı sistemde 100 N yükü 2 m kaldırmak için ipin ucundan 5 m çekiliyor ve 50 N kuvvet uygulanıyor. Verimi hesaplayınız.","fig":"<svg viewBox='0 0 320 175'><circle cx='110' cy='35' r='18' fill='#9aa6b8' stroke='#1a2b45'/><circle cx='200' cy='35' r='18' fill='#9aa6b8' stroke='#1a2b45'/><line x1='92' y1='35' x2='92' y2='110' stroke='#1a2b45' stroke-width='2'/><line x1='128' y1='35' x2='182' y2='35' stroke='#1a2b45' stroke-width='2'/><line x1='218' y1='35' x2='218' y2='130' stroke='#1a2b45' stroke-width='2'/><rect x='76' y='110' width='32' height='22' fill='#5b6b85' stroke='#1a2b45'/><text x='92' y='126' font-size='9' text-anchor='middle' fill='#fff'>100 N</text><polygon points='218,130 218,114 210,121 226,121' fill='#e0552b'/><text x='234' y='124' font-size='10' fill='#e0552b'>F=50 N</text></svg>","steps":[{"t":"Faydalı işi bul","a":"100 × 2 = 200 J","d":"Faydalı iş, yük ağırlığı ile kaldırılan yüksekliğin çarpımıdır."},{"t":"Verilen işi bul","a":"50 × 5 = 250 J","d":"Verilen iş, uygulanan kuvvet ile çekilen ipin uzunluğunun çarpımıdır."},{"t":"Verimi hesapla","a":"(200/250)×100","d":"Faydalı işi verilen işe bölüp 100 ile çarparız."}],"ans":"Makaralı sistemin verimi %80'dir."},{"q":"Bir makinenin faydalı işi 600 J, kayıp işi 150 J'dir. Verimi bulunuz ve verimin %100 olabilmesi için ne gerektiğini açıklayınız.","steps":[{"t":"Verilen işi bul","a":"600 + 150 = 750 J","d":"Verilen iş, faydalı iş ile kayıp işin toplamıdır."},{"t":"Verimi hesapla","a":"(600/750)×100 = %80","d":"Faydalı işi verilene bölüp 100 ile çarparız."},{"t":"%100 koşulu","a":"kayıp = 0","d":"Verimin %100 olması için kayıp işin sıfır, yani sürtünmenin hiç olmaması gerekir; bu yalnızca ideal makinede mümkündür."}],"ans":"Makinenin verimi %80'dir; %100 olabilmesi için kayıp işin sıfır olması, yani sürtünmenin tamamen ortadan kalkması gerekir ki bu yalnızca ideal makinede mümkündür."},{"q":"Verimi %50 olan bir makineyle 900 J faydalı iş yapmak isteniyor. Gereken verilen iş ve toplam kayıp iş nedir?","steps":[{"t":"Verilen işi bul","a":"900 ÷ 0,50 = 1800 J","d":"Verilen iş, faydalı işin verim kesrine bölünmesiyle bulunur."},{"t":"Kaybı bul","a":"1800 − 900 = 900 J","d":"Kayıp iş, verilen ile faydalı işin farkıdır."},{"t":"Yorum","a":"yarısı kayıp","d":"Verim %50 olduğu için verilen işin yarısı faydalı, yarısı kayıptır."}],"ans":"Gereken verilen iş 1800 J, toplam kayıp iş 900 J'dir."},{"q":"Bir makinede yük ağırlığı 80 N, ideal kuvvet 20 N olması beklenirken gerçekte 25 N uygulanıyor. Yük yolu ile kuvvet yolu eşit oranlıysa (yol oranı 4) verimi hesaplayınız.","fig":"<svg viewBox='0 0 320 165'><rect x='40' y='60' width='100' height='50' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='90' y='90' font-size='11' text-anchor='middle' fill='#fff'>Makine</text><polygon points='150,75 230,75 230,67 150,67' fill='#e0552b'/><polygon points='230,71 244,71 237,60' fill='#e0552b'/><text x='190' y='58' font-size='10' text-anchor='middle' fill='#e0552b'>F=25 N</text><rect x='250' y='80' width='30' height='28' fill='#5b6b85' stroke='#1a2b45'/><text x='265' y='98' font-size='9' text-anchor='middle' fill='#fff'>80 N</text></svg>","steps":[{"t":"İdeal kuvveti yaz","a":"F_ideal = 80/4 = 20 N","d":"Yol oranı 4 olduğu için ideal (sürtünmesiz) kuvvet, yükün yol oranına bölümüdür."},{"t":"Verimi kur","a":"η = F_ideal/F_gerçek","d":"Verim, ideal kuvvetin gerçekte uygulanan kuvvete oranıyla bulunabilir."},{"t":"Hesapla","a":"(20/25)×100","d":"20 N'yi 25 N'ye bölüp 100 ile çarparız."}],"ans":"Makinenin verimi %80'dir; gerçek kuvvet idealden büyük olduğu için verim %100'den küçüktür."},{"q":"Bir makinenin verimi %75'ten %90'a yükseltiliyor. Aynı 1800 J verilen iş için faydalı iş ne kadar artar?","steps":[{"t":"İlk faydalı iş","a":"0,75 × 1800 = 1350 J","d":"İlk durumda faydalı iş, verim kesriyle verilen işin çarpımıdır."},{"t":"Yeni faydalı iş","a":"0,90 × 1800 = 1620 J","d":"Yeni verimle faydalı iş yeniden hesaplanır."},{"t":"Farkı bul","a":"1620 − 1350","d":"İki faydalı iş değerinin farkı alınır."}],"ans":"Faydalı iş 270 J artar (1350 J'den 1620 J'ye çıkar)."}]}},"vida":{"ilkokul":{"kolay":[{"q":"Bir vidayı tahtaya tutturmak için tornavida ile çevirirsin. Vida nasıl içeri girer?","fig":"<svg viewBox='0 0 320 180'><rect x='30' y='90' width='200' height='60' fill='#caa472' stroke='#1a2b45'/><text x='130' y='168' font-size='12' text-anchor='middle' fill='#1a2b45'>Tahta</text><line x1='130' y1='90' x2='130' y2='25' stroke='#1a2b45' stroke-width='4'/><polygon points='130,150 120,130 140,130' fill='#9aa6b8' stroke='#1a2b45'/><line x1='118' y1='100' x2='142' y2='106' stroke='#1a2b45'/><line x1='118' y1='110' x2='142' y2='116' stroke='#1a2b45'/><line x1='118' y1='120' x2='142' y2='126' stroke='#1a2b45'/><text x='175' y='40' font-size='11' fill='#1a2b45'>çevir</text><polygon points='150,30 165,28 158,40' fill='#e0552b'/></svg>","steps":[{"t":"Vidayı çevir","a":"döner","d":"Tornavida ile vidayı çevirdikçe vida kendi etrafında döner."},{"t":"Ne olur","a":"içeri girer","d":"Vidanın dişleri tahtayı kavrar ve döndükçe vida içeri ilerler."}],"ans":"Vidayı çevirdikçe dişleri tahtaya tutunur ve vida içeri girer."},{"q":"Vidanın üzerindeki sarmal çizgilere ne denir?","fig":"<svg viewBox='0 0 320 160'><line x1='160' y1='20' x2='160' y2='140' stroke='#9aa6b8' stroke-width='14'/><polygon points='160,150 148,128 172,128' fill='#9aa6b8' stroke='#1a2b45'/><line x1='150' y1='35' x2='170' y2='42' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='55' x2='170' y2='62' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='75' x2='170' y2='82' stroke='#1a2b45' stroke-width='2'/><line x1='150' y1='95' x2='170' y2='102' stroke='#1a2b45' stroke-width='2'/><text x='210' y='70' font-size='12' fill='#1a2b45'>sarmal diş</text></svg>","steps":[{"t":"Vidaya bak","a":"sarmal çizgi","d":"Vidanın gövdesini saran çıkıntılı çizgiler vardır."},{"t":"Adı ne","a":"diş","d":"Bu sarmal çıkıntılara vida dişi denir; tutmayı sağlar."}],"ans":"Vidanın üzerindeki sarmal çıkıntılara vida dişi denir."},{"q":"Çiviyi çekiçle çakarız, vidayı ise nasıl yerleştiririz?","fig":"<svg viewBox='0 0 320 170'><rect x='20' y='90' width='120' height='60' fill='#caa472' stroke='#1a2b45'/><line x1='80' y1='90' x2='80' y2='40' stroke='#1a2b45' stroke-width='4'/><rect x='66' y='30' width='28' height='12' fill='#5b6b85' stroke='#1a2b45'/><text x='80' y='165' font-size='11' text-anchor='middle' fill='#1a2b45'>çivi: çakılır</text><rect x='180' y='90' width='120' height='60' fill='#caa472' stroke='#1a2b45'/><line x1='240' y1='90' x2='240' y2='40' stroke='#1a2b45' stroke-width='4'/><line x1='230' y1='100' x2='250' y2='106' stroke='#1a2b45'/><line x1='230' y1='112' x2='250' y2='118' stroke='#1a2b45'/><polygon points='250,40 268,38 258,50' fill='#e0552b'/><text x='240' y='165' font-size='11' text-anchor='middle' fill='#1a2b45'>vida: çevrilir</text></svg>","steps":[{"t":"Çivi nasıl","a":"çakılır","d":"Çivi çekiçle vurularak içeri çakılır."},{"t":"Vida nasıl","a":"çevrilir","d":"Vida ise tornavida ile döndürülerek içeri yerleştirilir."}],"ans":"Vidayı çevirerek yerleştiririz; çivi gibi çakmayız."},{"q":"Araba lastiği patlayınca arabayı yukarı kaldıran alete ne denir?","fig":"<svg viewBox='0 0 320 170'><rect x='40' y='40' width='240' height='28' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='30' font-size='11' text-anchor='middle' fill='#1a2b45'>Araba</text><polygon points='120,68 200,68 175,120 145,120' fill='#9aa6b8' stroke='#1a2b45'/><line x1='160' y1='75' x2='160' y2='112' stroke='#1a2b45' stroke-width='2'/><circle cx='160' cy='120' r='10' fill='#caa472' stroke='#1a2b45'/><line x1='160' y1='120' x2='200' y2='120' stroke='#1a2b45' stroke-width='2'/><text x='160' y='155' font-size='12' text-anchor='middle' fill='#1a2b45'>Kriko</text></svg>","steps":[{"t":"Ne işe yarar","a":"kaldırır","d":"Bu alet kolunu çevirince ağır arabayı yukarı kaldırır."},{"t":"Adı ne","a":"kriko","d":"Vida ile çalışan bu kaldırma aletine kriko denir."}],"ans":"Arabayı kaldıran bu vidalı alete kriko denir."},{"q":"Bir kavanozun metal kapağını açarken kapağı ne yaparız?","fig":"<svg viewBox='0 0 320 160'><rect x='110' y='70' width='100' height='80' rx='6' fill='#4aa3df' stroke='#1a2b45'/><rect x='100' y='45' width='120' height='30' rx='4' fill='#9aa6b8' stroke='#1a2b45'/><line x1='110' y1='52' x2='210' y2='52' stroke='#1a2b45'/><line x1='110' y1='60' x2='210' y2='60' stroke='#1a2b45'/><line x1='110' y1='68' x2='210' y2='68' stroke='#1a2b45'/><path d='M150 30 a18 10 0 0 1 36 0' fill='none' stroke='#e0552b' stroke-width='2'/><polygon points='186,30 196,26 192,38' fill='#e0552b'/><text x='160' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>çevir</text></svg>","steps":[{"t":"Kapakta ne var","a":"vida dişi","d":"Kavanoz kapağının içinde vida gibi sarmal dişler bulunur."},{"t":"Nasıl açılır","a":"çevirerek","d":"Kapağı çevirdikçe dişler boşalır ve kapak açılır."}],"ans":"Kavanoz kapağını çevirerek açarız; çünkü kapakta vida dişi vardır."}],"zor":[{"q":"İki vidadan biri çok sık dişli, biri seyrek dişli. Tahtaya daha sıkı tutunan hangisidir?","fig":"<svg viewBox='0 0 320 170'><line x1='90' y1='30' x2='90' y2='130' stroke='#9aa6b8' stroke-width='12'/><polygon points='90,140 80,122 100,122' fill='#9aa6b8' stroke='#1a2b45'/><line x1='82' y1='40' x2='98' y2='45' stroke='#1a2b45'/><line x1='82' y1='52' x2='98' y2='57' stroke='#1a2b45'/><line x1='82' y1='64' x2='98' y2='69' stroke='#1a2b45'/><line x1='82' y1='76' x2='98' y2='81' stroke='#1a2b45'/><line x1='82' y1='88' x2='98' y2='93' stroke='#1a2b45'/><line x1='82' y1='100' x2='98' y2='105' stroke='#1a2b45'/><text x='90' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>sık dişli</text><line x1='230' y1='30' x2='230' y2='130' stroke='#9aa6b8' stroke-width='12'/><polygon points='230,140 220,122 240,122' fill='#9aa6b8' stroke='#1a2b45'/><line x1='222' y1='50' x2='238' y2='55' stroke='#1a2b45'/><line x1='222' y1='78' x2='238' y2='83' stroke='#1a2b45'/><line x1='222' y1='106' x2='238' y2='111' stroke='#1a2b45'/><text x='230' y='160' font-size='10' text-anchor='middle' fill='#1a2b45'>seyrek dişli</text></svg>","steps":[{"t":"Dişlere bak","a":"sık olan","d":"Dişler ne kadar sık ise tahtaya o kadar çok tutunma noktası olur."},{"t":"Karşılaştır","a":"sık dişli","d":"Sık dişli vida tahtayı daha çok kavrar ve daha sıkı tutar."}],"ans":"Sık dişli vida tahtaya daha sıkı tutunur."},{"q":"Kriko kolunu çevirmeden de arabayı tek elimizle kaldırabilir miyiz? Neden?","fig":"<svg viewBox='0 0 320 170'><rect x='40' y='35' width='240' height='26' rx='6' fill='#5b6b85' stroke='#1a2b45'/><text x='160' y='26' font-size='11' text-anchor='middle' fill='#1a2b45'>ağır araba</text><polygon points='115,61 205,61 180,118 140,118' fill='#9aa6b8' stroke='#1a2b45'/><circle cx='160' cy='118' r='10' fill='#caa472' stroke='#1a2b45'/><line x1='160' y1='118' x2='210' y2='118' stroke='#1a2b45' stroke-width='3'/><circle cx='215' cy='118' r='6' fill='#e0552b'/><text x='160' y='150' font-size='11' text-anchor='middle' fill='#1a2b45'>kriko kolu</text></svg>","steps":[{"t":"Araba çok ağır","a":"el yetmez","d":"Araba çok ağır olduğu için onu doğrudan elimizle kaldıramayız."},{"t":"Kriko ne yapar","a":"kolu çeviririz","d":"Krikonun kolunu çevirince küçük kuvvetimiz çok büyür ve arabayı kaldırır."}],"ans":"Hayır; arabayı ancak kriko kolunu çevirerek kaldırabiliriz, çünkü kriko kuvvetimizi büyütür."},{"q":"Bir vidanın eğri bir rampaya (eğik düzleme) benzeyen yanı nedir?","fig":"<svg viewBox='0 0 320 160'><polygon points='40,130 250,130 250,60' fill='#caa472' stroke='#1a2b45'/><text x='150' y='148' font-size='11' text-anchor='middle' fill='#1a2b45'>eğik düzlem (rampa)</text><line x1='40' y1='130' x2='250' y2='60' stroke='#e0552b' stroke-width='2'/><text x='280' y='90' font-size='10' fill='#1a2b45'>silindire</text><text x='280' y='104' font-size='10' fill='#1a2b45'>sarılır</text></svg>","steps":[{"t":"Vidayı düşün","a":"sarmal yol","d":"Vidanın dişleri gövdesini saran eğri bir yol gibidir."},{"t":"Neye benzer","a":"eğik düzlem","d":"Bu sarmal yol, bir silindire sarılmış eğik düzlem (rampa) gibidir."}],"ans":"Vidanın dişleri, bir silindire sarılmış eğik düzlem (rampa) gibidir."},{"q":"Tornavidayı kalın saplı seçersek vidayı çevirmek neden kolaylaşır?","fig":"<svg viewBox='0 0 320 160'><ellipse cx='90' cy='80' rx='30' ry='45' fill='#e0552b' stroke='#1a2b45'/><text x='90' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>kalın sap</text><rect x='118' y='74' width='90' height='12' fill='#9aa6b8' stroke='#1a2b45'/><line x1='208' y1='80' x2='240' y2='80' stroke='#1a2b45' stroke-width='4'/><path d='M90 35 a30 14 0 0 1 0 90' fill='none' stroke='#1a2b45' stroke-width='1.5'/><polygon points='90,125 80,120 86,132' fill='#1a2b45'/><text x='150' y='30' font-size='10' text-anchor='middle' fill='#1a2b45'>geniş döndürme</text></svg>","steps":[{"t":"Kalın sap","a":"geniş daire","d":"Sap kalın olunca elimiz daha geniş bir daire çizerek döner."},{"t":"Sonuç","a":"daha kolay","d":"Geniş daire daha büyük kuvvet kazancı verir, vidayı çevirmek kolaylaşır."}],"ans":"Kalın sap geniş bir döndürme dairesi yaratır, bu da kuvvet kazandırır ve çevirmeyi kolaylaştırır."},{"q":"Mengene ile bir tahtayı sıkıştırırken kolu çevirdikçe ne olur?","fig":"<svg viewBox='0 0 320 160'><rect x='40' y='60' width='40' height='60' fill='#5b6b85' stroke='#1a2b45'/><rect x='150' y='60' width='40' height='60' fill='#5b6b85' stroke='#1a2b45'/><rect x='80' y='75' width='70' height='30' fill='#caa472' stroke='#1a2b45'/><text x='115' y='135' font-size='10' text-anchor='middle' fill='#1a2b45'>tahta</text><line x1='190' y1='90' x2='280' y2='90' stroke='#9aa6b8' stroke-width='8'/><line x1='198' y1='84' x2='198' y2='96' stroke='#1a2b45'/><line x1='216' y1='84' x2='216' y2='96' stroke='#1a2b45'/><line x1='234' y1='84' x2='234' y2='96' stroke='#1a2b45'/><circle cx='280' cy='90' r='12' fill='#e0552b' stroke='#1a2b45'/><text x='245' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>vidalı kol</text></svg>","steps":[{"t":"Kolu çevir","a":"vida döner","d":"Mengenenin kolunu çevirdikçe vida döner ve çene yavaşça ilerler."},{"t":"Sonuç","a":"sıkışır","d":"Çene ilerledikçe tahtayı giderek daha sıkı kavrar."}],"ans":"Kolu çevirdikçe vidalı çene ilerler ve tahtayı giderek daha sıkı sıkıştırır."}]},"ortaokul":{"kolay":[{"q":"Vida hangi basit makinenin bir silindire sarılmış biçimidir? Şekildeki gibi açıklayınız.","fig":"<svg viewBox='0 0 320 160'><polygon points='30,120 210,120 210,55' fill='#caa472' stroke='#1a2b45'/><line x1='30' y1='120' x2='210' y2='55' stroke='#e0552b' stroke-width='2.5'/><text x='120' y='138' font-size='11' text-anchor='middle' fill='#1a2b45'>eğik düzlem</text><line x1='270' y1='30' x2='270' y2='130' stroke='#9aa6b8' stroke-width='12'/><path d='M262 45 q16 6 0 12' fill='none' stroke='#1a2b45'/><path d='M262 65 q16 6 0 12' fill='none' stroke='#1a2b45'/><path d='M262 85 q16 6 0 12' fill='none' stroke='#1a2b45'/><text x='270' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>vida</text></svg>","steps":[{"t":"Vidanın dişi","a":"sarmal eğri","d":"Vidanın dişi, gövdeyi saran sürekli bir eğri yoldur."},{"t":"Hangi makine","a":"eğik düzlem","d":"Bu eğri, bir silindire sarılmış eğik düzlemdir."}],"ans":"Vida, bir silindire sarılmış eğik düzlemdir."},{"q":"Vidanın bir tam tur dönüşünde ilerlediği mesafeye ne ad verilir?","steps":[{"t":"Bir tur dönüş","a":"belli mesafe","d":"Vida bir tam tur döndüğünde gövdesi boyunca belirli bir mesafe ilerler."},{"t":"Adı","a":"vida adımı","d":"Bu mesafeye vida adımı (hatve) denir."}],"ans":"Vidanın bir tam turda ilerlediği mesafeye vida adımı denir."},{"q":"Şekildeki vida bir turda 2 mm ilerliyor. 5 tam tur çevrilirse kaç mm ilerler?","fig":"<svg viewBox='0 0 320 150'><line x1='160' y1='20' x2='160' y2='130' stroke='#9aa6b8' stroke-width='14'/><line x1='148' y1='35' x2='172' y2='40' stroke='#1a2b45'/><line x1='148' y1='55' x2='172' y2='60' stroke='#1a2b45'/><line x1='148' y1='75' x2='172' y2='80' stroke='#1a2b45'/><line x1='200' y1='35' x2='200' y2='55' stroke='#e0552b' stroke-width='1.5'/><polygon points='200,35 196,43 204,43' fill='#e0552b'/><polygon points='200,55 196,47 204,47' fill='#e0552b'/><text x='225' y='50' font-size='10' fill='#1a2b45'>adım=2 mm</text></svg>","steps":[{"t":"Bir tur","a":"2 mm","d":"Vida her tam turda adımı kadar, yani 2 mm ilerler."},{"t":"5 tur","a":"5 × 2 mm","d":"İlerleme = tur sayısı × adım = 5 × 2 mm hesaplanır."}],"ans":"Vida 5 turda 10 mm ilerler."},{"q":"Adımı küçük olan bir vida ile adımı büyük olan vidadan hangisi daha hassas (yavaş) ilerler?","fig":"<svg viewBox='0 0 320 150'><line x1='90' y1='20' x2='90' y2='130' stroke='#9aa6b8' stroke-width='12'/><line x1='80' y1='35' x2='100' y2='39' stroke='#1a2b45'/><line x1='80' y1='48' x2='100' y2='52' stroke='#1a2b45'/><line x1='80' y1='61' x2='100' y2='65' stroke='#1a2b45'/><line x1='80' y1='74' x2='100' y2='78' stroke='#1a2b45'/><text x='90' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>küçük adım</text><line x1='230' y1='20' x2='230' y2='130' stroke='#9aa6b8' stroke-width='12'/><line x1='220' y1='40' x2='240' y2='46' stroke='#1a2b45'/><line x1='220' y1='75' x2='240' y2='81' stroke='#1a2b45'/><text x='230' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>büyük adım</text></svg>","steps":[{"t":"Adım nedir","a":"bir turluk yol","d":"Adım, bir turda ilerlenen mesafedir."},{"t":"Küçük adım","a":"yavaş ilerler","d":"Adım küçükse her turda az ilerler, bu da daha hassas ve yavaş ilerleme demektir."}],"ans":"Adımı küçük olan vida her turda daha az, yani daha yavaş ve hassas ilerler."},{"q":"Kriko, mengene ve civata günlük hayatta vidanın hangi ortak özelliğinden yararlanır?","steps":[{"t":"Ortak iş","a":"kuvvet kazancı","d":"Hepsinde kolu çevirerek uygulanan kuvvet büyütülür."},{"t":"Sonuç","a":"küçük kuvvet büyür","d":"Vida sayesinde küçük bir döndürme kuvveti büyük bir itme/sıkıştırma kuvvetine dönüşür."}],"ans":"Kriko, mengene ve civata vidanın kuvvet kazandırma özelliğinden yararlanır."}],"zor":[{"q":"Şekildeki vidanın adımı 3 mm. Vidayı 12 mm ilerletmek için kaç tam tur çevirmek gerekir?","fig":"<svg viewBox='0 0 320 150'><line x1='150' y1='20' x2='150' y2='130' stroke='#9aa6b8' stroke-width='14'/><line x1='138' y1='40' x2='162' y2='46' stroke='#1a2b45'/><line x1='138' y1='62' x2='162' y2='68' stroke='#1a2b45'/><line x1='138' y1='84' x2='162' y2='90' stroke='#1a2b45'/><line x1='195' y1='40' x2='195' y2='62' stroke='#e0552b' stroke-width='1.5'/><polygon points='195,40 191,48 199,48' fill='#e0552b'/><polygon points='195,62 191,54 199,54' fill='#e0552b'/><text x='220' y='55' font-size='10' fill='#1a2b45'>adım=3 mm</text></svg>","steps":[{"t":"Bağıntı","a":"tur = yol / adım","d":"Tur sayısı, toplam ilerleme yolunun bir adıma bölünmesidir."},{"t":"Yerine koy","a":"12 ÷ 3","d":"Toplam yol 12 mm, adım 3 mm değerleri yazılır."},{"t":"Sonuç","a":"4 tur","d":"12'yi 3'e bölünce 4 bulunur."}],"ans":"Vidayı 12 mm ilerletmek için 4 tam tur çevirmek gerekir."},{"q":"Bir vidalı kriko bir turda 4 mm yükseliyor. Kol 16 tur çevrilirse araba kaç cm yükselir?","fig":"<svg viewBox='0 0 320 160'><rect x='40' y='30' width='220' height='22' rx='5' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='24' font-size='10' text-anchor='middle' fill='#1a2b45'>araba</text><polygon points='110,52 200,52 178,115 132,115' fill='#9aa6b8' stroke='#1a2b45'/><line x1='155' y1='60' x2='155' y2='108' stroke='#1a2b45'/><line x1='200' y1='60' x2='200' y2='80' stroke='#e0552b' stroke-width='1.5'/><polygon points='200,60 196,68 204,68' fill='#e0552b'/><text x='225' y='75' font-size='10' fill='#1a2b45'>1 tur=4 mm</text></svg>","steps":[{"t":"Toplam yol","a":"tur × adım","d":"Yükselme = tur sayısı × adım = 16 × 4 mm'dir."},{"t":"Hesapla","a":"64 mm","d":"16 ile 4 çarpılınca 64 mm bulunur."},{"t":"cm çevir","a":"64 mm = 6,4 cm","d":"64 mm'yi 10'a bölünce 6,4 cm elde edilir."}],"ans":"Araba 6,4 cm yükselir."},{"q":"İki vidadan birinin adımı 1 mm, diğerininki 4 mm. Aynı sayıda turda hangisi daha çok ilerler ve hangisi kuvvet kazancı bakımından üstündür?","fig":"<svg viewBox='0 0 320 150'><line x1='90' y1='20' x2='90' y2='130' stroke='#9aa6b8' stroke-width='12'/><line x1='80' y1='32' x2='100' y2='36' stroke='#1a2b45'/><line x1='80' y1='44' x2='100' y2='48' stroke='#1a2b45'/><line x1='80' y1='56' x2='100' y2='60' stroke='#1a2b45'/><line x1='80' y1='68' x2='100' y2='72' stroke='#1a2b45'/><line x1='80' y1='80' x2='100' y2='84' stroke='#1a2b45'/><text x='90' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>adım=1 mm</text><line x1='230' y1='20' x2='230' y2='130' stroke='#9aa6b8' stroke-width='12'/><line x1='220' y1='42' x2='240' y2='48' stroke='#1a2b45'/><line x1='220' y1='80' x2='240' y2='86' stroke='#1a2b45'/><text x='230' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>adım=4 mm</text></svg>","steps":[{"t":"İlerleme","a":"adım büyük olan","d":"Aynı turda ilerleme adımla doğru orantılıdır; 4 mm adımlı vida daha çok ilerler."},{"t":"Kuvvet kazancı","a":"adım küçük olan","d":"Adım küçüldükçe kuvvet kazancı artar; bu yüzden 1 mm adımlı vida üstündür."}],"ans":"4 mm adımlı vida daha çok ilerler, ancak 1 mm adımlı vida daha çok kuvvet kazancı sağlar."},{"q":"Bir mengenenin vida adımı 2 mm. Çeneyi 1 cm kapatmak için kaç tam tur çevrilir?","steps":[{"t":"Birim eşitle","a":"1 cm = 10 mm","d":"Önce kapatma mesafesini mm'ye çeviririz: 1 cm = 10 mm."},{"t":"Bağıntı","a":"tur = yol / adım","d":"Tur sayısı, ilerleme yolunun adıma bölünmesidir: 10 ÷ 2."},{"t":"Sonuç","a":"5 tur","d":"10'u 2'ye bölünce 5 bulunur."}],"ans":"Çeneyi 1 cm kapatmak için 5 tam tur çevrilir."},{"q":"Vidalarda adım küçüldükçe kuvvet kazancı neden artar? Şekildeki iki vidayı karşılaştırınız.","fig":"<svg viewBox='0 0 320 150'><line x1='90' y1='20' x2='90' y2='130' stroke='#9aa6b8' stroke-width='12'/><line x1='80' y1='34' x2='100' y2='38' stroke='#1a2b45'/><line x1='80' y1='48' x2='100' y2='52' stroke='#1a2b45'/><line x1='80' y1='62' x2='100' y2='66' stroke='#1a2b45'/><line x1='80' y1='76' x2='100' y2='80' stroke='#1a2b45'/><text x='90' y='148' font-size='9' text-anchor='middle' fill='#1a2b45'>küçük adım</text><text x='90' y='16' font-size='9' text-anchor='middle' fill='#e0552b'>çok kazanç</text><line x1='230' y1='20' x2='230' y2='130' stroke='#9aa6b8' stroke-width='12'/><line x1='220' y1='45' x2='240' y2='51' stroke='#1a2b45'/><line x1='220' y1='82' x2='240' y2='88' stroke='#1a2b45'/><text x='230' y='148' font-size='9' text-anchor='middle' fill='#1a2b45'>büyük adım</text><text x='230' y='16' font-size='9' text-anchor='middle' fill='#1a2b45'>az kazanç</text></svg>","steps":[{"t":"Bir turda iş","a":"aynı çevre yolu","d":"Kol her turda aynı uzun çevre yolunu kat eder."},{"t":"Adım küçükse","a":"az ilerler","d":"Aynı uzun yola karşılık vida çok az ilerlerse, küçük kuvvetle büyük itme elde edilir."}],"ans":"Adım küçüldükçe bir turda az ilerlenip aynı döndürme yoluna karşılık daha büyük kuvvet elde edildiği için kuvvet kazancı artar."}]},"lise":{"kolay":[{"q":"Vidanın mekanik avantajı (MA) hangi büyüklüklerle hesaplanır?","steps":[{"t":"Döndürme yolu","a":"2πr","d":"Kola r yarıçapında bir tam tur attırınca uygulanan kuvvetin yolu 2πr olur."},{"t":"Yük yolu","a":"adım p","d":"Aynı turda vida yalnızca bir adım (p) kadar ilerler; MA = 2πr ÷ p'dir."}],"ans":"Vidanın mekanik avantajı MA = 2πr / p ile hesaplanır (r kol yarıçapı, p adım)."},{"q":"Kol yarıçapı 14 cm, adımı 0,5 cm olan bir vidalı kriko için mekanik avantajı bulunuz (π ≈ 22/7).","fig":"<svg viewBox='0 0 320 160'><circle cx='150' cy='80' r='55' fill='none' stroke='#1a2b45' stroke-width='1.5' stroke-dasharray='4 3'/><line x1='150' y1='80' x2='205' y2='80' stroke='#e0552b' stroke-width='2'/><polygon points='205,80 197,76 197,84' fill='#e0552b'/><text x='178' y='73' font-size='10' fill='#1a2b45'>r=14 cm</text><circle cx='150' cy='80' r='6' fill='#9aa6b8' stroke='#1a2b45'/><text x='150' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>adım p=0,5 cm</text></svg>","steps":[{"t":"Bağıntı","a":"MA = 2πr / p","d":"Mekanik avantaj, kol çevresinin adıma oranıdır."},{"t":"Yerine koy","a":"2 × 22/7 × 14 ÷ 0,5","d":"r = 14 cm, p = 0,5 cm değerleri konur; 2 × 22/7 × 14 = 88 cm."},{"t":"Sonuç","a":"88 ÷ 0,5 = 176","d":"88'i 0,5'e bölünce 176 elde edilir."}],"ans":"Krikonun mekanik avantajı 176'dır."},{"q":"Vidada bir tam turda kuvvetin aldığı yol neden adımdan çok büyüktür?","fig":"<svg viewBox='0 0 320 160'><circle cx='120' cy='80' r='48' fill='none' stroke='#1a2b45' stroke-width='1.5'/><line x1='120' y1='80' x2='168' y2='80' stroke='#e0552b' stroke-width='2'/><text x='145' y='73' font-size='10' fill='#1a2b45'>2πr</text><line x1='240' y1='50' x2='240' y2='62' stroke='#4aa3df' stroke-width='5'/><text x='240' y='95' font-size='10' text-anchor='middle' fill='#1a2b45'>adım p</text></svg>","steps":[{"t":"Kuvvetin yolu","a":"çember 2πr","d":"Kol bir turda 2πr uzunluğunda bir çember çizer."},{"t":"Yükün yolu","a":"sadece p","d":"Aynı turda vida yalnızca bir adım (p) kadar ilerler; 2πr ≫ p'dir."}],"ans":"Kuvvet bir turda 2πr'lik uzun bir çember çizerken vida yalnızca p kadar ilerlediği için kuvvetin yolu adımdan çok büyüktür."},{"q":"Mekanik avantajı 100 olan bir kriko, kola uygulanan 30 N'luk kuvvetle (sürtünmesiz) kaç N'luk yükü kaldırır?","steps":[{"t":"Bağıntı","a":"Yük = MA × F","d":"İdeal makinede kaldırılan yük, mekanik avantaj ile uygulanan kuvvetin çarpımıdır."},{"t":"Yerine koy","a":"100 × 30","d":"MA = 100 ve F = 30 N yerine konur."},{"t":"Sonuç","a":"3000 N","d":"Çarpım sonucu 3000 N bulunur."}],"ans":"Kriko 3000 N'luk yükü kaldırır."},{"q":"Kol yarıçapı 7 cm, adımı 1 cm olan vidanın mekanik avantajını bulunuz (π ≈ 22/7).","fig":"<svg viewBox='0 0 320 160'><circle cx='150' cy='80' r='50' fill='none' stroke='#1a2b45' stroke-width='1.5' stroke-dasharray='4 3'/><line x1='150' y1='80' x2='200' y2='80' stroke='#e0552b' stroke-width='2'/><polygon points='200,80 192,76 192,84' fill='#e0552b'/><text x='176' y='73' font-size='10' fill='#1a2b45'>r=7 cm</text><circle cx='150' cy='80' r='6' fill='#9aa6b8' stroke='#1a2b45'/><text x='150' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>p=1 cm</text></svg>","steps":[{"t":"Bağıntı","a":"MA = 2πr / p","d":"Mekanik avantaj kol çevresinin adıma oranıdır."},{"t":"Çevreyi bul","a":"2 × 22/7 × 7","d":"2πr = 2 × 22/7 × 7 = 44 cm hesaplanır."},{"t":"Sonuç","a":"44 ÷ 1 = 44","d":"44'ü 1'e bölünce mekanik avantaj 44 bulunur."}],"ans":"Vidanın mekanik avantajı 44'tür."},{"q":"Adım sabitken kol yarıçapı iki katına çıkarılırsa vidanın mekanik avantajı nasıl değişir?","steps":[{"t":"Bağıntıya bak","a":"MA = 2πr/p","d":"Mekanik avantaj, kol yarıçapı r ile doğru orantılıdır."},{"t":"r iki katı","a":"MA iki katı","d":"p sabitken r iki katına çıkınca MA da iki katına çıkar."}],"ans":"Kol yarıçapı iki katına çıkınca mekanik avantaj da iki katına çıkar."},{"q":"Kol yarıçapı sabitken vida adımı yarıya indirilirse mekanik avantaj nasıl değişir?","steps":[{"t":"Bağıntıya bak","a":"MA = 2πr/p","d":"Mekanik avantaj, adım p ile ters orantılıdır."},{"t":"p yarıya iner","a":"MA iki katı","d":"r sabitken p yarıya inince MA iki katına çıkar."}],"ans":"Vida adımı yarıya indirilince mekanik avantaj iki katına çıkar."},{"q":"Bir civatanın somununu sıkarken kullanılan anahtarın kolu uzatılırsa sıkma kuvveti neden artar?","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='80' r='22' fill='#9aa6b8' stroke='#1a2b45'/><polygon points='90,58 100,64 100,96 90,102 80,96 80,64' fill='#5b6b85' stroke='#1a2b45'/><rect x='112' y='74' width='150' height='12' fill='#9aa6b8' stroke='#1a2b45'/><text x='185' y='105' font-size='10' text-anchor='middle' fill='#1a2b45'>uzun anahtar kolu (r)</text><line x1='262' y1='80' x2='290' y2='80' stroke='#e0552b' stroke-width='2'/><polygon points='290,80 282,76 282,84' fill='#e0552b'/><text x='278' y='70' font-size='10' fill='#1a2b45'>F</text></svg>","steps":[{"t":"Kol yarıçapı artar","a":"r büyür","d":"Anahtar uzatılınca kuvvetin uygulandığı yarıçap r büyür."},{"t":"MA artar","a":"2πr/p","d":"MA = 2πr/p olduğundan r büyüyünce mekanik avantaj artar."}],"ans":"Anahtar kolu uzatılınca r büyür, MA = 2πr/p artar ve aynı kuvvetle somun daha büyük kuvvetle sıkılır."},{"q":"Vidalarda yüksek kuvvet kazancı (büyük MA) elde etmek için adım ve kol nasıl seçilmelidir?","steps":[{"t":"Adım","a":"küçük olmalı","d":"MA = 2πr/p ifadesinde adım p küçüldükçe MA büyür."},{"t":"Kol","a":"uzun olmalı","d":"Kol yarıçapı r büyüdükçe MA büyür; yani küçük adım + uzun kol gerekir."}],"ans":"Yüksek kuvvet kazancı için vida adımı küçük, kol yarıçapı büyük seçilmelidir."},{"q":"Kriko, çıkrık ve mengenenin hepsi vidalı sistemdir. Vidanın bu araçlardaki ortak görevi nedir?","steps":[{"t":"Ortak ilke","a":"kuvvet büyütme","d":"Hepsinde dönme hareketi, küçük bir kuvveti çok daha büyük bir doğrusal kuvvete dönüştürür."},{"t":"Sonuç","a":"yüksek MA","d":"Vidanın küçük adımı sayesinde MA çok büyük olur."}],"ans":"Vidanın bu araçlardaki ortak görevi, küçük bir döndürme kuvvetini büyük bir itme/sıkıştırma/kaldırma kuvvetine dönüştürmektir."},{"q":"Bir vidalı krikoda 50 N kuvvet uygulanıyor ve mekanik avantaj 60'tır. İdeal durumda kaldırılan yük kaç N'dur?","steps":[{"t":"Bağıntı","a":"Yük = MA × F","d":"İdeal makinede yük, mekanik avantaj ile kuvvetin çarpımıdır."},{"t":"Yerine koy","a":"60 × 50","d":"MA = 60 ve F = 50 N yerine konur."},{"t":"Sonuç","a":"3000 N","d":"Çarpım sonucu 3000 N bulunur."}],"ans":"İdeal durumda kaldırılan yük 3000 N'dur."},{"q":"Şekildeki vidanın bir tam turda kol ucunun çizdiği çember uzunluğu 88 cm ise ve adım 2 cm ise mekanik avantajı bulunuz.","fig":"<svg viewBox='0 0 320 160'><circle cx='150' cy='80' r='52' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='150' y='20' font-size='10' text-anchor='middle' fill='#1a2b45'>çember=2πr=88 cm</text><line x1='150' y1='80' x2='202' y2='80' stroke='#e0552b' stroke-width='2'/><polygon points='202,80 194,76 194,84' fill='#e0552b'/><circle cx='150' cy='80' r='5' fill='#9aa6b8' stroke='#1a2b45'/><text x='150' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>adım=2 cm</text></svg>","steps":[{"t":"Bağıntı","a":"MA = çevre / adım","d":"Mekanik avantaj, kol çevresinin (2πr) adıma oranıdır."},{"t":"Yerine koy","a":"88 ÷ 2","d":"Çevre 88 cm, adım 2 cm değerleri yazılır."},{"t":"Sonuç","a":"44","d":"88'i 2'ye bölünce 44 bulunur."}],"ans":"Vidanın mekanik avantajı 44'tür."},{"q":"Vidanın mekanik avantajı çok büyük olmasına rağmen krikoyu çevirmek neden uzun zaman alır?","steps":[{"t":"İş korunumu","a":"kazanç yok","d":"Kuvvetten kazanılan, yoldan kaybedilir; vida az ilerlediği için çok tur gerekir."},{"t":"Sonuç","a":"uzun yol","d":"Büyük MA için adım küçüktür, bu da yükü az yükseltmek için çok dönüş demektir."}],"ans":"Kuvvetten kazanç, yoldan kayıpla dengelenir; büyük MA küçük adım gerektirdiğinden yükü kaldırmak için çok sayıda tur ve uzun süre gerekir."},{"q":"İki vidalı kriko aynı adıma sahip, ancak birinin kol yarıçapı diğerinin 3 katı. Mekanik avantajları arasındaki oran nedir?","steps":[{"t":"Bağıntı","a":"MA ∝ r","d":"Adım sabitken MA = 2πr/p ifadesinde MA, r ile doğru orantılıdır."},{"t":"Oranı kur","a":"3 katı","d":"Bir kolun yarıçapı 3 kat ise mekanik avantajı da 3 kat olur."}],"ans":"Kolu uzun olan krikonun mekanik avantajı, diğerininkinin 3 katıdır."},{"q":"Vidayı (silindire sarılı eğik düzlem) açarken eğik düzlem mantığıyla 'yokuş' uzunluğu neye, 'yükseklik' neye karşılık gelir?","fig":"<svg viewBox='0 0 320 150'><polygon points='40,120 250,120 250,70' fill='#caa472' stroke='#1a2b45'/><line x1='40' y1='120' x2='250' y2='70' stroke='#e0552b' stroke-width='2'/><text x='130' y='115' font-size='10' text-anchor='middle' fill='#1a2b45'>yokuş = çevre 2πr</text><line x1='255' y1='120' x2='255' y2='70' stroke='#4aa3df' stroke-width='3'/><text x='285' y='98' font-size='10' fill='#1a2b45'>yükseklik</text><text x='285' y='112' font-size='10' fill='#1a2b45'>= adım p</text></svg>","steps":[{"t":"Yokuş uzunluğu","a":"2πr","d":"Eğik düzlemin uzun kenarı, vidanın bir turdaki çevresi 2πr'ye karşılık gelir."},{"t":"Yükseklik","a":"adım p","d":"Eğik düzlemin yüksekliği, bir turda ilerlenen adım p'ye karşılık gelir."}],"ans":"Eğik düzlem mantığında yokuş uzunluğu 2πr çevreye, yükseklik ise vida adımı p'ye karşılık gelir; MA = yokuş/yükseklik = 2πr/p olur."}],"zor":[{"q":"Kol yarıçapı 21 cm, adımı 0,3 cm olan vidalı krikoya 40 N kuvvet uygulanıyor. İdeal kaldırılan yükü bulunuz (π ≈ 22/7).","fig":"<svg viewBox='0 0 320 160'><circle cx='150' cy='75' r='52' fill='none' stroke='#1a2b45' stroke-width='1.5' stroke-dasharray='4 3'/><line x1='150' y1='75' x2='202' y2='75' stroke='#e0552b' stroke-width='2'/><polygon points='202,75 194,71 194,79' fill='#e0552b'/><text x='176' y='68' font-size='10' fill='#1a2b45'>r=21 cm</text><circle cx='150' cy='75' r='6' fill='#9aa6b8' stroke='#1a2b45'/><text x='150' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>p=0,3 cm, F=40 N</text></svg>","steps":[{"t":"MA'yı bul","a":"2πr/p","d":"2πr = 2 × 22/7 × 21 = 132 cm; MA = 132 ÷ 0,3 = 440'tır."},{"t":"Yük bağıntısı","a":"Yük = MA × F","d":"İdeal yük, mekanik avantaj ile kuvvetin çarpımıdır."},{"t":"Sonuç","a":"440 × 40","d":"440 ile 40 N çarpılınca 17600 N bulunur."}],"ans":"İdeal kaldırılan yük 17600 N'dur."},{"q":"Bir vidalı kriko bir turda 5 mm yükseliyor. 800 kg'lık (g = 10 N/kg) aracı 4 cm kaldırmak için yapılan iş ve gereken tur sayısını bulunuz.","steps":[{"t":"Ağırlık","a":"8000 N","d":"Ağırlık G = m × g = 800 × 10 = 8000 N'dur."},{"t":"İş","a":"G × h","d":"İş = ağırlık × yükselme = 8000 N × 0,04 m = 320 J'dür."},{"t":"Tur sayısı","a":"40 mm / 5 mm","d":"4 cm = 40 mm; tur = 40 ÷ 5 = 8 turdur."}],"ans":"Yapılan iş 320 J ve gereken tur sayısı 8'dir."},{"q":"Şekildeki vidalı krikonun mekanik avantajı 200, verimi %80'dir. 25 N kuvvetle kaldırılan gerçek yükü bulunuz.","fig":"<svg viewBox='0 0 320 160'><rect x='40' y='28' width='220' height='22' rx='5' fill='#5b6b85' stroke='#1a2b45'/><text x='150' y='22' font-size='10' text-anchor='middle' fill='#1a2b45'>yük</text><polygon points='110,50 200,50 178,118 132,118' fill='#9aa6b8' stroke='#1a2b45'/><line x1='155' y1='58' x2='155' y2='112' stroke='#1a2b45'/><circle cx='200' cy='118' r='8' fill='#caa472' stroke='#1a2b45'/><line x1='200' y1='118' x2='240' y2='118' stroke='#1a2b45' stroke-width='2'/><line x1='240' y1='118' x2='262' y2='118' stroke='#e0552b' stroke-width='2'/><text x='250' y='110' font-size='10' fill='#1a2b45'>F=25 N</text><text x='150' y='150' font-size='10' text-anchor='middle' fill='#1a2b45'>MA=200, verim %80</text></svg>","steps":[{"t":"İdeal yük","a":"MA × F","d":"İdeal yük = 200 × 25 = 5000 N'dur."},{"t":"Verimi uygula","a":"× 0,80","d":"Gerçek yük = ideal yük × verim = 5000 × 0,80'dir."},{"t":"Sonuç","a":"4000 N","d":"5000 ile 0,80 çarpılınca 4000 N bulunur."}],"ans":"Gerçek kaldırılan yük 4000 N'dur."},{"q":"Bir vida 4 turda 6 mm ilerliyor. Kol yarıçapı 10,5 cm ise mekanik avantajını bulunuz (π ≈ 22/7).","steps":[{"t":"Adımı bul","a":"6 ÷ 4 = 1,5 mm","d":"Bir tam turdaki ilerleme adımdır: 6 mm ÷ 4 = 1,5 mm = 0,15 cm."},{"t":"Çevreyi bul","a":"2πr","d":"2πr = 2 × 22/7 × 10,5 = 66 cm hesaplanır."},{"t":"MA","a":"66 ÷ 0,15","d":"66 cm'yi 0,15 cm'ye bölünce 440 bulunur."}],"ans":"Vidanın mekanik avantajı 440'tır."},{"q":"İki vidalı krikodan A'nın adımı 2 mm, kolu 14 cm; B'nin adımı 1 mm, kolu 7 cm. Mekanik avantajlarını karşılaştırınız (π ≈ 22/7).","fig":"<svg viewBox='0 0 320 150'><circle cx='90' cy='70' r='42' fill='none' stroke='#1a2b45' stroke-dasharray='3 3'/><line x1='90' y1='70' x2='132' y2='70' stroke='#e0552b' stroke-width='2'/><text x='90' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>A: r=14, p=2 mm</text><circle cx='235' cy='70' r='28' fill='none' stroke='#1a2b45' stroke-dasharray='3 3'/><line x1='235' y1='70' x2='263' y2='70' stroke='#e0552b' stroke-width='2'/><text x='235' y='130' font-size='10' text-anchor='middle' fill='#1a2b45'>B: r=7, p=1 mm</text></svg>","steps":[{"t":"A'nın MA","a":"2×22/7×140 ÷ 2","d":"r = 14 cm = 140 mm; 2πr = 880 mm; MA_A = 880 ÷ 2 = 440'tır."},{"t":"B'nin MA","a":"2×22/7×70 ÷ 1","d":"r = 7 cm = 70 mm; 2πr = 440 mm; MA_B = 440 ÷ 1 = 440'tır."},{"t":"Karşılaştır","a":"eşit","d":"İki krikonun da mekanik avantajı 440 çıkar, yani eşittir."}],"ans":"Her iki krikonun mekanik avantajı da 440'tır; eşittirler."},{"q":"Mekanik avantajı 150 olan ideal bir krikoyla yükü 12 cm kaldırmak için kol ucu toplam kaç metre yol alır?","steps":[{"t":"İş korunumu","a":"kuvvet yolu = MA × yük yolu","d":"İdeal makinede kuvvetin aldığı yol, mekanik avantaj ile yükün yolunun çarpımıdır."},{"t":"Yerine koy","a":"150 × 12 cm","d":"MA = 150 ve yük yolu 12 cm değerleri konur."},{"t":"Sonuç","a":"1800 cm = 18 m","d":"150 ile 12 çarpılınca 1800 cm, yani 18 m bulunur."}],"ans":"Kol ucu toplam 18 metre yol alır."},{"q":"Bir vidalı krikoda kol yarıçapı 14 cm, adım 4 mm. Yükü 1 cm kaldırmak için kol ucunun aldığı yolu bulunuz (π ≈ 22/7).","steps":[{"t":"Tur sayısı","a":"10 mm / 4 mm = 2,5","d":"Yükselme 1 cm = 10 mm; tur = 10 ÷ 4 = 2,5 turdur."},{"t":"Bir tur yolu","a":"2πr","d":"2πr = 2 × 22/7 × 14 = 88 cm'dir."},{"t":"Toplam yol","a":"2,5 × 88","d":"Tur sayısı ile bir tur yolu çarpılır: 2,5 × 88 = 220 cm'dir."}],"ans":"Kol ucu toplam 220 cm (2,2 m) yol alır."},{"q":"Adımı 0,5 cm, kol yarıçapı 10 cm olan bir mengeneye 60 N kuvvet uygulanıyor. İdeal sıkıştırma kuvvetini bulunuz (π ≈ 3,14).","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='55' width='34' height='55' fill='#5b6b85' stroke='#1a2b45'/><rect x='130' y='55' width='34' height='55' fill='#5b6b85' stroke='#1a2b45'/><rect x='74' y='68' width='56' height='28' fill='#caa472' stroke='#1a2b45'/><line x1='164' y1='82' x2='250' y2='82' stroke='#9aa6b8' stroke-width='8'/><circle cx='262' cy='82' r='14' fill='none' stroke='#1a2b45' stroke-dasharray='3 3'/><line x1='262' y1='82' x2='276' y2='82' stroke='#e0552b' stroke-width='2'/><text x='262' y='128' font-size='10' text-anchor='middle' fill='#1a2b45'>r=10, p=0,5, F=60 N</text></svg>","steps":[{"t":"Çevreyi bul","a":"2πr","d":"2πr = 2 × 3,14 × 10 = 62,8 cm'dir."},{"t":"MA","a":"62,8 ÷ 0,5","d":"Mekanik avantaj = çevre ÷ adım = 62,8 ÷ 0,5 = 125,6'dır."},{"t":"Sıkıştırma kuvveti","a":"MA × F","d":"İdeal kuvvet = 125,6 × 60 = 7536 N'dur."}],"ans":"İdeal sıkıştırma kuvveti 7536 N'dur."},{"q":"Bir vidalı kriko 6000 N'luk yükü 30 N kuvvetle kaldırıyor (ideal). Adım 2 mm ise kol yarıçapını bulunuz (π ≈ 22/7).","steps":[{"t":"MA'yı bul","a":"6000 ÷ 30 = 200","d":"Mekanik avantaj = yük ÷ kuvvet = 6000 ÷ 30 = 200'dür."},{"t":"r bağıntısı","a":"r = MA × p / (2π)","d":"MA = 2πr/p ifadesinden r = (MA × p) ÷ (2π)'dir."},{"t":"Hesapla","a":"(200 × 2) / (2×22/7)","d":"r = 400 ÷ 6,2857 ≈ 63,6 mm ≈ 6,36 cm bulunur."}],"ans":"Kol yarıçapı yaklaşık 6,36 cm (63,6 mm) olmalıdır."},{"q":"Şekildeki krikonun mekanik avantajı 314, kuvvet 20 N. Yükü 5 cm kaldırmak için yapılan işi ve kaldırılan yükü bulunuz (ideal).","fig":"<svg viewBox='0 0 320 150'><rect x='40' y='28' width='220' height='20' rx='5' fill='#5b6b85' stroke='#1a2b45'/><polygon points='110,48 200,48 178,110 132,110' fill='#9aa6b8' stroke='#1a2b45'/><line x1='155' y1='55' x2='155' y2='104' stroke='#1a2b45'/><line x1='200' y1='110' x2='240' y2='110' stroke='#1a2b45' stroke-width='2'/><line x1='240' y1='110' x2='262' y2='110' stroke='#e0552b' stroke-width='2'/><text x='250' y='102' font-size='10' fill='#1a2b45'>F=20 N</text><text x='150' y='140' font-size='10' text-anchor='middle' fill='#1a2b45'>MA=314, h=5 cm</text></svg>","steps":[{"t":"Yükü bul","a":"MA × F","d":"İdeal yük = 314 × 20 = 6280 N'dur."},{"t":"İşi bul","a":"Yük × h","d":"İş = yük × yükselme = 6280 N × 0,05 m'dir."},{"t":"Sonuç","a":"314 J","d":"6280 ile 0,05 çarpılınca 314 J bulunur."}],"ans":"Kaldırılan yük 6280 N ve yapılan iş 314 J'dür."},{"q":"İdeal bir vidada kuvvet 25 N, kol yarıçapı 14 cm, adım 0,7 cm. Hem mekanik avantajı hem kaldırılan yükü bulunuz (π ≈ 22/7).","steps":[{"t":"Çevre","a":"2πr = 88 cm","d":"2πr = 2 × 22/7 × 14 = 88 cm'dir."},{"t":"MA","a":"88 ÷ 0,7 ≈ 125,7","d":"Mekanik avantaj = çevre ÷ adım = 88 ÷ 0,7 ≈ 125,7'dir."},{"t":"Yük","a":"125,7 × 25","d":"İdeal yük = MA × F = 125,7 × 25 ≈ 3142 N'dur."}],"ans":"Mekanik avantaj yaklaşık 125,7 ve kaldırılan yük yaklaşık 3142 N'dur."},{"q":"Aynı yükü kaldıran iki vidalı kriko karşılaştırılıyor. A'nın adımı B'ninkinin yarısı, kolları eşit. Gereken kuvvetler arasındaki oran nedir?","steps":[{"t":"MA ilişkisi","a":"MA ∝ 1/p","d":"Kol eşitken MA = 2πr/p; adım yarıysa MA iki katıdır."},{"t":"Kuvvet ilişkisi","a":"F = Yük/MA","d":"Aynı yük için MA iki katı olan A, yarı kuvvet ister."},{"t":"Oran","a":"F_A = F_B / 2","d":"A'nın gerektirdiği kuvvet, B'ninkinin yarısıdır."}],"ans":"Adımı yarı olan A krikosu, aynı yükü kaldırmak için B'nin yarısı kadar kuvvet gerektirir."},{"q":"Şekildeki vidanın bir turda çizdiği çember 132 cm, adımı 6 mm. 18000 N yükü kaldırmak için gereken kuvveti bulunuz (ideal).","fig":"<svg viewBox='0 0 320 160'><circle cx='150' cy='75' r='52' fill='none' stroke='#1a2b45' stroke-width='1.5'/><text x='150' y='18' font-size='10' text-anchor='middle' fill='#1a2b45'>çember=132 cm</text><line x1='150' y1='75' x2='202' y2='75' stroke='#e0552b' stroke-width='2'/><polygon points='202,75 194,71 194,79' fill='#e0552b'/><circle cx='150' cy='75' r='5' fill='#9aa6b8' stroke='#1a2b45'/><text x='150' y='148' font-size='10' text-anchor='middle' fill='#1a2b45'>adım=6 mm, yük=18000 N</text></svg>","steps":[{"t":"Birim eşitle","a":"132 cm = 1320 mm","d":"Çevre ve adımı aynı birime çeviririz: 132 cm = 1320 mm."},{"t":"MA","a":"1320 ÷ 6 = 220","d":"Mekanik avantaj = çevre ÷ adım = 1320 ÷ 6 = 220'dir."},{"t":"Kuvvet","a":"18000 ÷ 220","d":"Gereken kuvvet = yük ÷ MA = 18000 ÷ 220 ≈ 81,8 N'dur."}],"ans":"Yükü kaldırmak için gereken kuvvet yaklaşık 81,8 N'dur."},{"q":"Bir vidalı krikonun verimi %75, mekanik avantajı 160. Gerçekte 50 N kuvvetle kaldırılan yükü ve kaybolan iş oranını yorumlayınız.","steps":[{"t":"İdeal yük","a":"160 × 50 = 8000 N","d":"İdeal yük = MA × F = 160 × 50 = 8000 N'dur."},{"t":"Gerçek yük","a":"× 0,75","d":"Gerçek yük = ideal × verim = 8000 × 0,75 = 6000 N'dur."},{"t":"Kayıp","a":"%25","d":"Verim %75 olduğundan enerjinin %25'i sürtünmeyle ısıya dönüşüp kaybolur."}],"ans":"Gerçek kaldırılan yük 6000 N'dur; enerjinin %25'i sürtünme nedeniyle kaybolur."},{"q":"İki özdeş yükü kaldıran adımı 1 mm ve 2 mm olan iki kriko, kolları eşit. Hangisi daha az kuvvet ister ve neden yükü kaldırmak daha uzun sürer?","fig":"<svg viewBox='0 0 320 150'><line x1='90' y1='25' x2='90' y2='120' stroke='#9aa6b8' stroke-width='12'/><line x1='80' y1='35' x2='100' y2='39' stroke='#1a2b45'/><line x1='80' y1='47' x2='100' y2='51' stroke='#1a2b45'/><line x1='80' y1='59' x2='100' y2='63' stroke='#1a2b45'/><line x1='80' y1='71' x2='100' y2='75' stroke='#1a2b45'/><text x='90' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>p=1 mm</text><line x1='230' y1='25' x2='230' y2='120' stroke='#9aa6b8' stroke-width='12'/><line x1='220' y1='40' x2='240' y2='46' stroke='#1a2b45'/><line x1='220' y1='72' x2='240' y2='78' stroke='#1a2b45'/><text x='230' y='140' font-size='9' text-anchor='middle' fill='#1a2b45'>p=2 mm</text></svg>","steps":[{"t":"MA karşılaştır","a":"p=1 mm büyük","d":"Kol eşitken MA = 2πr/p; adımı küçük olanın (1 mm) mekanik avantajı daha büyüktür."},{"t":"Kuvvet","a":"daha az","d":"Büyük MA daha az kuvvet ister; 1 mm adımlı kriko daha az kuvvet gerektirir."},{"t":"Süre","a":"daha çok tur","d":"Adım küçük olduğundan aynı yüksekliğe çıkmak için daha çok tur, yani daha uzun süre gerekir."}],"ans":"Adımı 1 mm olan kriko daha az kuvvet ister; ancak küçük adım çok tur gerektirdiğinden yükü kaldırmak daha uzun sürer."}]}}};
